) VALUES (
  'b0170000-0000-0000-0000-000000000001', 'Mathematiques', 'grandeurs_mesures', 'math_aires_perimetres_composees',
  'Aires et périmètres — Figures composées', 'Intermediaire', 'qcm',
  'Quelle est l''aire d''un triangle de base 8 cm et de hauteur 5 cm ?', NULL,
  '[{"id":"a","label":"40 cm²"},{"id":"b","label":"13 cm²"},{"id":"c","label":"20 cm²"},{"id":"d","label":"25 cm²"}]'::jsonb,
  '{"mode":"single","value":"c"}'::jsonb,
  'L''aire d''un triangle se calcule avec la formule : A = (base × hauteur) / 2. Ici : A = (8 × 5) / 2 = 40 / 2 = 20 cm².',
  'Oublier de diviser par 2 et répondre 40 cm² (aire du rectangle correspondant).',
  'valide', 'Génération Claude — Terminologie Éduscol', 'free', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'b0170000-0000-0000-0000-000000000002', 'Mathematiques', 'grandeurs_mesures', 'math_aires_perimetres_composees',
  'Aires et périmètres — Figures composées', 'Intermediaire', 'vrai_faux',
  'Le périmètre d''un cercle de rayon 7 cm est 44 cm.', NULL,
  '[{"id":"vrai","label":"Vrai"},{"id":"faux","label":"Faux"}]'::jsonb,
  '{"mode":"single","value":"vrai"}'::jsonb,
  'Le périmètre (circonférence) d''un cercle se calcule avec la formule P = 2 × π × r. Ici : P = 2 × 3,14 × 7 = 43,96 cm, que l''on arrondit à 44 cm. L''affirmation est donc vraie.',
  'Confondre rayon et diamètre, ou utiliser la formule de l''aire (π × r²) au lieu de celle du périmètre.',
  'valide', 'Génération Claude — Terminologie Éduscol', 'free', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'b0170000-0000-0000-0000-000000000003', 'Mathematiques', 'grandeurs_mesures', 'math_aires_perimetres_composees',
  'Aires et périmètres — Figures composées', 'Intermediaire', 'reponse_courte',
  'Un terrain rectangulaire de 40 m × 25 m contient une piscine circulaire de diamètre 10 m. Quelle est l''aire de la zone enherbée autour de la piscine ? Arrondir au m².', NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["921","921 m²","921 m2"]}'::jsonb,
  'Aire du terrain rectangulaire : 40 × 25 = 1 000 m². Aire de la piscine circulaire (rayon = 10 / 2 = 5 m) : π × 5² = 3,14 × 25 = 78,5 m². Aire de la zone enherbée : 1 000 − 78,5 ≈ 921 m².',
  'Utiliser le diamètre (10 m) au lieu du rayon (5 m) dans la formule de l''aire du cercle, ce qui donnerait une aire de piscine de 314 m².',
  'valide', 'Génération Claude — Terminologie Éduscol', 'free', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'b0170000-0000-0000-0000-000000000004', 'Mathematiques', 'grandeurs_mesures', 'math_aires_perimetres_composees',
  'Aires et périmètres — Figures composées', 'Intermediaire', 'qcm',
  'Une piste d''athlétisme est composée d''un rectangle de 100 m × 60 m et de deux demi-cercles de diamètre 60 m aux extrémités. Quel est le périmètre de la piste ? Arrondir au m.', NULL,
  '[{"id":"a","label":"320 m"},{"id":"b","label":"389 m"},{"id":"c","label":"508 m"},{"id":"d","label":"440 m"}]'::jsonb,
  '{"mode":"single","value":"b"}'::jsonb,
  'Le périmètre de la piste se compose des deux longueurs du rectangle et des deux demi-cercles (qui forment un cercle complet de diamètre 60 m). P = 2 × 100 + π × 60 = 200 + 3,14 × 60 = 200 + 188,4 = 388,4 m ≈ 389 m.',
  'Additionner les quatre côtés du rectangle (320 m) sans tenir compte des demi-cercles, ou ajouter le périmètre complet du rectangle plus les demi-cercles.',
  'valide', 'Génération Claude — Terminologie Éduscol', 'free', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'b0170000-0000-0000-0000-000000000005', 'Mathematiques', 'grandeurs_mesures', 'math_aires_perimetres_composees',
  'Aires et périmètres — Figures composées', 'Intermediaire', 'reponse_courte',
  'Un losange a des diagonales de 12 cm et 16 cm. Calculez son aire.', NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["96","96 cm²","96 cm2"]}'::jsonb,
  'L''aire d''un losange se calcule avec la formule : A = (d₁ × d₂) / 2. Ici : A = (12 × 16) / 2 = 192 / 2 = 96 cm². Pour information, le côté du losange vaut √(6² + 8²) = √(36 + 64) = √100 = 10 cm, et le périmètre vaut 4 × 10 = 40 cm.',
  'Oublier de diviser par 2 et répondre 192 cm², ou confondre la formule avec celle du rectangle.',
  'valide', 'Génération Claude — Terminologie Éduscol', 'free', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'b0170000-0000-0000-0000-000000000006', 'Mathematiques', 'grandeurs_mesures', 'math_aires_perimetres_composees',
  'Aires et périmètres — Figures composées', 'Intermediaire', 'qcm',
  'On découpe un quart de cercle de rayon 6 cm dans un carré de côté 6 cm. Quelle est l''aire de la partie restante ? Arrondir au dixième.', NULL,
  '[{"id":"a","label":"7,7 cm²"},{"id":"b","label":"9,0 cm²"},{"id":"c","label":"28,3 cm²"},{"id":"d","label":"14,1 cm²"}]'::jsonb,
  '{"mode":"single","value":"a"}'::jsonb,
  'Aire du carré : 6 × 6 = 36 cm². Aire du quart de cercle : (π × 6²) / 4 = (3,14 × 36) / 4 = 113,04 / 4 = 28,26 cm². Aire restante : 36 − 28,26 = 7,74 cm² ≈ 7,7 cm².',
  'Calculer l''aire d''un demi-cercle au lieu d''un quart de cercle, ou soustraire dans le mauvais sens.',
  'valide', 'Génération Claude — Terminologie Éduscol', 'free', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'b0170000-0000-0000-0000-000000000007', 'Mathematiques', 'grandeurs_mesures', 'math_aires_perimetres_composees',
  'Aires et périmètres — Figures composées', 'Intermediaire', 'reponse_courte',
  'Une figure est composée d''un rectangle de 12 cm × 8 cm surmonté d''un triangle isocèle de base 12 cm et de hauteur 5 cm. Calculez l''aire totale de cette figure.', NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["126","126 cm²","126 cm2"]}'::jsonb,
  'Aire du rectangle : 12 × 8 = 96 cm². Aire du triangle : (12 × 5) / 2 = 30 cm². Aire totale : 96 + 30 = 126 cm². Pour le périmètre : côté du triangle = √(6² + 5²) = √61 ≈ 7,81 cm. Périmètre = 12 + 8 + 7,81 + 7,81 + 8 = 43,62 ≈ 43,6 cm.',
  'Oublier de diviser par 2 pour l''aire du triangle et répondre 156 cm², ou ne calculer que l''aire d''une des deux figures.',
  'valide', 'Génération Claude — Terminologie Éduscol', 'free', true
) ON CONFLICT (id) DO NOTHING;

-- math_aires_unites_agraires (grandeurs_mesures) : 3 -> 10 questions
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fa0d0000-0000-0000-0000-000000000001', 'Mathematiques', 'grandeurs_mesures', 'math_aires_unites_agraires', 'Aires et unités agraires — Hectares et ares', 'Intermediaire',
  'qcm', 'Combien de mètres carrés représente 1 hectare ?', NULL,
  '[{"id":"a","label":"1 000 m²"},{"id":"b","label":"10 000 m²"},{"id":"c","label":"100 000 m²"},{"id":"d","label":"100 m²"}]'::jsonb,
  '{"mode":"single","value":"b"}'::jsonb,
  '1 hectare (ha) = 10 000 m². L''hectare correspond à l''aire d''un carré de 100 m de côté : 100 × 100 = 10 000 m². L''option a (1 000 m²) correspond à 10 ares, et l''option d (100 m²) correspond à 1 are.',
  'Confondre hectare et are : l''élève retient 1 ha = 1 000 m² au lieu de 10 000 m², oubliant que chaque unité agraire vaut 100 fois la précédente.',
  'valide', 'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fa0d0000-0000-0000-0000-000000000002', 'Mathematiques', 'grandeurs_mesures', 'math_aires_unites_agraires', 'Aires et unités agraires — Hectares et ares', 'Intermediaire',
  'vrai_faux', '1 are est égal à 100 m².', NULL,
  NULL,
  '{"mode":"single","value":"vrai"}'::jsonb,
  '1 are (a) = 100 m². L''are correspond à l''aire d''un carré de 10 m de côté : 10 × 10 = 100 m². C''est l''unité intermédiaire entre le mètre carré et l''hectare. On a la progression : 1 m² → 1 a = 100 m² → 1 ha = 100 a = 10 000 m².',
  'Confondre l''are avec l''hectare ou penser que 1 a = 10 m² en appliquant un facteur 10 au lieu de 100.',
  'valide', 'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fa0d0000-0000-0000-0000-000000000003', 'Mathematiques', 'grandeurs_mesures', 'math_aires_unites_agraires', 'Aires et unités agraires — Hectares et ares', 'Intermediaire',
  'reponse_courte', 'Convertissez 3,5 hectares en mètres carrés.', NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["35000","35 000","35000 m²","35 000 m²"]}'::jsonb,
  '1 ha = 10 000 m², donc 3,5 ha = 3,5 × 10 000 = 35 000 m². Pour convertir des hectares en mètres carrés, on multiplie par 10 000 (on déplace la virgule de 4 rangs vers la droite).',
  'Multiplier par 1 000 au lieu de 10 000 et obtenir 3 500 m² : l''élève confond le facteur de conversion des unités agraires avec celui des unités de longueur.',
  'valide', 'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fa0d0000-0000-0000-0000-000000000004', 'Mathematiques', 'grandeurs_mesures', 'math_aires_unites_agraires', 'Aires et unités agraires — Hectares et ares', 'Intermediaire',
  'qcm', 'Un terrain de 4 500 m² représente combien d''ares ?', NULL,
  '[{"id":"a","label":"4,5 a"},{"id":"b","label":"45 a"},{"id":"c","label":"450 a"},{"id":"d","label":"0,45 a"}]'::jsonb,
  '{"mode":"single","value":"b"}'::jsonb,
  '1 are = 100 m², donc pour convertir des m² en ares, on divise par 100. 4 500 ÷ 100 = 45 ares. L''option a (4,5 a) résulte d''une division par 1 000, et l''option c (450 a) d''une division par 10 seulement.',
  'Diviser par 10 ou par 1 000 au lieu de 100 : l''élève ne maîtrise pas le facteur de conversion entre m² et are.',
  'valide', 'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fa0d0000-0000-0000-0000-000000000005', 'Mathematiques', 'grandeurs_mesures', 'math_aires_unites_agraires', 'Aires et unités agraires — Hectares et ares', 'Intermediaire',
  'reponse_courte', 'Un champ rectangulaire mesure 200 m de long et 150 m de large. Quelle est son aire en hectares ?', NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["3","3 ha","3ha"]}'::jsonb,
  'Aire du champ = 200 × 150 = 30 000 m². Pour convertir en hectares : 30 000 ÷ 10 000 = 3 ha. Ce champ a donc une superficie de 3 hectares. En contexte agricole, l''hectare est l''unité la plus courante pour exprimer la superficie des parcelles.',
  'Ne pas convertir en hectares et laisser la réponse en m², ou diviser par 100 (ares) au lieu de 10 000 (hectares).',
  'valide', 'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fa0d0000-0000-0000-0000-000000000006', 'Mathematiques', 'grandeurs_mesures', 'math_aires_unites_agraires', 'Aires et unités agraires — Hectares et ares', 'Intermediaire',
  'qcm', 'Quelle surface est la plus grande : 250 ares ou 2,4 hectares ?', NULL,
  '[{"id":"a","label":"250 ares"},{"id":"b","label":"2,4 hectares"},{"id":"c","label":"Elles sont égales"},{"id":"d","label":"On ne peut pas comparer"}]'::jsonb,
  '{"mode":"single","value":"a"}'::jsonb,
  'Convertissons dans la même unité. 250 ares = 250 × 100 = 25 000 m². 2,4 ha = 2,4 × 10 000 = 24 000 m². 25 000 > 24 000, donc 250 ares est plus grand que 2,4 hectares. On peut aussi convertir en hectares : 250 a = 2,5 ha > 2,4 ha.',
  'Comparer directement les nombres (250 > 2,4) sans tenir compte de l''unité, ou au contraire penser que l''hectare étant plus grand, 2,4 ha est forcément supérieur.',
  'valide', 'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fa0d0000-0000-0000-0000-000000000007', 'Mathematiques', 'grandeurs_mesures', 'math_aires_unites_agraires', 'Aires et unités agraires — Hectares et ares', 'Intermediaire',
  'reponse_courte', 'Un agriculteur possède trois parcelles : la première fait 1,2 ha, la deuxième 85 ares et la troisième 7 500 m². Quelle est la superficie totale de son exploitation en hectares ?', NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["2,8","2,8 ha","2,80","2,80 ha"]}'::jsonb,
  'Convertissons tout en hectares. Parcelle 1 : 1,2 ha. Parcelle 2 : 85 a = 85 ÷ 100 = 0,85 ha. Parcelle 3 : 7 500 m² = 7 500 ÷ 10 000 = 0,75 ha. Total = 1,2 + 0,85 + 0,75 = 2,8 ha. Ce problème nécessite de maîtriser les conversions entre les trois unités agraires avant d''additionner.',
  'Additionner les valeurs brutes (1,2 + 85 + 7 500) sans convertir dans la même unité, ou se tromper dans les facteurs de conversion.',
  'valide', 'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

-- math_analyse_productions_numeration (didactique_maths) : 3 -> 10 questions
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fbc294ed-5580-49dc-aabf-a1058d39ffcd',
  'Mathematiques',
  'didactique_maths',
  'math_analyse_productions_numeration',
  'Analyse de productions d''élèves — Numération',
  'Intermediaire',
  'qcm',
  'Un élève de CM1 écrit : « 3,15 > 3,9 car 15 > 9. » Quel obstacle didactique est en jeu ?',
  NULL,
  '[{"id":"a","label":"L''élève applique la règle de comparaison des entiers à la partie décimale (« plus de chiffres = plus grand »)"},{"id":"b","label":"L''élève ne connaît pas la signification du séparateur décimal"},{"id":"c","label":"L''élève confond l''ordre croissant et décroissant"},{"id":"d","label":"L''élève ne sait pas lire les nombres décimaux"}]',
  '{"mode":"single","value":"a"}',
  'L''élève traite la partie décimale comme un entier indépendant : il compare 15 et 9, et conclut que 3,15 > 3,9 puisque 15 > 9. C''est l''obstacle didactique le plus documenté sur les décimaux, appelé « conception entière de la partie décimale ». L''élève n''a pas compris que 3,15 = 3 + 1/10 + 5/100 = 3 + 0,15, tandis que 3,9 = 3 + 9/10 = 3 + 0,90. En réalité, 3,9 > 3,15 car 0,90 > 0,15. Remédiation : compléter avec des zéros (3,15 vs 3,90) pour rendre la comparaison visible, ou utiliser le tableau de numération.',
  'Ne pas identifier cet obstacle comme une « conception entière de la partie décimale ». C''est la terminologie didactique attendue au CRPE (recherches de Brousseau sur les décimaux).',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  '9fcf7954-6bcb-41ed-a41e-bdf73b99140e',
  'Mathematiques',
  'didactique_maths',
  'math_analyse_productions_numeration',
  'Analyse de productions d''élèves — Numération',
  'Intermediaire',
  'vrai_faux',
  'Un élève écrit la décomposition suivante : « 4 507 = 4 × 1 000 + 5 × 100 + 7. » Cette décomposition est-elle correcte ?',
  NULL,
  NULL,
  '{"mode":"single","value":"vrai"}',
  'VRAI. 4 × 1 000 + 5 × 100 + 7 = 4 000 + 500 + 7 = 4 507. La décomposition est correcte. L''élève a simplement omis le terme « 0 × 10 » puisque le chiffre des dizaines est 0. Écrire 4 × 1 000 + 5 × 100 + 0 × 10 + 7 × 1 est plus complet, mais omettre un terme nul est mathématiquement acceptable. Au CRPE, il faut savoir reconnaître qu''une décomposition incomplète en apparence peut être correcte si les termes omis sont nuls. Le zéro dans 4 507 est un « zéro intercalaire » : il marque l''absence de dizaines.',
  'Penser que la décomposition est incorrecte parce qu''elle ne mentionne pas le terme « 0 × 10 ». Au CRPE, il faut distinguer une erreur d''une écriture simplifiée mais correcte.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  '8591a682-9f8c-455c-a275-f98b1903ffd7',
  'Mathematiques',
  'didactique_maths',
  'math_analyse_productions_numeration',
  'Analyse de productions d''élèves — Numération',
  'Intermediaire',
  'qcm',
  'Un élève écrit en chiffres le nombre « douze mille quarante-trois » : 120 043. Quelle est la nature de son erreur ?',
  NULL,
  '[{"id":"a","label":"Il a juxtaposé les tranches orales : « douze » → 12, « mille » → 000, « quarante-trois » → 43, donnant 12 + 000 + 43 = 120 043"},{"id":"b","label":"Il a confondu « mille » et « million »"},{"id":"c","label":"Il a ajouté un zéro par erreur de frappe"},{"id":"d","label":"Il ne connaît pas le nombre douze mille"}]',
  '{"mode":"single","value":"a"}',
  'L''élève a juxtaposé les morceaux de l''énoncé oral : « douze » → 12, « mille » → il ajoute trois zéros (000), « quarante-trois » → 43. Résultat : 12|000|43 = 120 043. C''est une erreur de transcodage (passage de l''oral à l''écrit en chiffres). La bonne écriture est 12 043. L''obstacle ici est la non-compréhension du principe de position : « douze mille » signifie 12 × 1 000 = 12 000, et on AJOUTE 43, on ne juxtapose pas 43 après les zéros. Cette erreur de transcodage est documentée dans les recherches de Fayol et Seron et est un classique des analyses de productions d''élèves au CRPE.',
  'Ne pas identifier cette erreur comme une erreur de transcodage numérique (passage de la forme verbale à la forme écrite en chiffres). C''est un concept didactique fondamental au CRPE.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  '672fcf7b-1386-4870-a417-6427336fb925',
  'Mathematiques',
  'didactique_maths',
  'math_analyse_productions_numeration',
  'Analyse de productions d''élèves — Numération',
  'Intermediaire',
  'reponse_courte',
  'Un élève répond à la question « Quel est le chiffre des centaines dans 28 647 ? » par « 600 ». L''élève confond deux notions. Lesquelles ? (Répondez en nommant les deux notions.)',
  NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["chiffre et nombre de centaines","chiffre des centaines et nombre de centaines","le chiffre et le nombre","chiffre et nombre","le chiffre des centaines et le nombre de centaines"]}',
  'L''élève confond le CHIFFRE des centaines et le NOMBRE de centaines. Le chiffre des centaines dans 28 647 est 6 (c''est le chiffre qui occupe la position des centaines). Le nombre de centaines est 286 (car 28 647 = 286 centaines et 47 unités, soit 28 647 ÷ 100 = 286 reste 47). L''élève a répondu 600, ce qui ne correspond ni à l''un ni à l''autre : il a probablement identifié la bonne position (6) mais a ajouté les zéros correspondants (600 = 6 × 100). Cette distinction chiffre/nombre est fondamentale en numération positionnelle et constitue un objectif d''apprentissage clé au cycle 3.',
  'Ne pas connaître la distinction entre « chiffre de » et « nombre de » en numération. Le chiffre est un symbole (0 à 9) occupant une position ; le nombre est la quantité correspondante (combien de centaines en tout).',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  '67b9995d-f8e7-4863-a3b5-2ad27fdf8566',
  'Mathematiques',
  'didactique_maths',
  'math_analyse_productions_numeration',
  'Analyse de productions d''élèves — Numération',
  'Intermediaire',
  'qcm',
  'On demande à un élève de placer 1,7 sur une droite graduée de 0 à 2, divisée en 10 intervalles égaux. L''élève place le point à l''emplacement de 1,07. Quel diagnostic didactique posez-vous ?',
  NULL,
  '[{"id":"a","label":"L''élève confond dixièmes et centièmes : il interprète le 7 de 1,7 comme 7 centièmes au lieu de 7 dixièmes"},{"id":"b","label":"L''élève ne sait pas lire une droite graduée"},{"id":"c","label":"L''élève a fait une erreur d''inattention"},{"id":"d","label":"L''élève pense que 1,7 est plus petit que 1,1"}]',
  '{"mode":"single","value":"a"}',
  'L''élève interprète 1,7 comme « 1 et 7 centièmes » (1,07) au lieu de « 1 et 7 dixièmes ». Il confond la position des dixièmes et des centièmes. Sur la droite graduée de 0 à 2 avec 10 intervalles, chaque intervalle vaut 0,2. Le point 1,7 se situe donc entre le 8e et le 9e repère (1,6 et 1,8), à mi-chemin. L''élève l''a placé juste après 1,0, ce qui correspond à 1,07 ≈ 1. Cette confusion dixièmes/centièmes traduit un déficit de compréhension de la numération positionnelle étendue aux décimaux. Remédiation : travailler systématiquement avec le tableau de numération incluant la partie décimale (dixièmes | centièmes | millièmes).',
  'Diagnostiquer une simple « erreur de lecture » au lieu d''identifier le déficit conceptuel (confusion dixièmes/centièmes dans la numération positionnelle).',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  '4752b24c-bfbd-481e-afa0-f1e43ee82d1b',
  'Mathematiques',
  'didactique_maths',
  'math_analyse_productions_numeration',
  'Analyse de productions d''élèves — Numération',
  'Intermediaire',
  'qcm',
  'Un élève de CE2 range systématiquement les nombres suivants dans l''ordre : 92 < 108 < 310 < 1 205 < 87. Il pense que 87 est le plus grand « parce qu''il commence par 8 et 8 est le plus grand chiffre ». Quelle remédiation est la plus adaptée ?',
  NULL,
  '[{"id":"a","label":"Lui faire apprendre la comptine numérique jusqu''à 10 000"},{"id":"b","label":"Lui faire comparer le nombre de chiffres d''abord, puis les chiffres de même rang en partant de la gauche"},{"id":"c","label":"Lui donner plus d''exercices de rangement pour qu''il s''entraîne"},{"id":"d","label":"Lui expliquer que 1 205 est le plus grand car il a 4 chiffres"}]',
  '{"mode":"single","value":"b"}',
  'La remédiation la plus efficace est de structurer l''algorithme de comparaison : (1) comparer d''abord le NOMBRE DE CHIFFRES — le nombre qui en a le plus est le plus grand ; (2) à nombre de chiffres égal, comparer les chiffres de même rang en partant de la gauche. L''élève utilise une stratégie erronée : il compare le premier chiffre sans tenir compte du nombre de chiffres total. La réponse D est trop restrictive (elle donne la solution mais pas la méthode). La réponse A est inadaptée (l''élève sait compter, il ne comprend pas le principe de comparaison). La réponse C ne corrige pas l''obstacle : sans travail explicite sur l''algorithme, l''élève reproduira la même erreur.',
  'Proposer une remédiation qui ne cible pas l''obstacle identifié. Au CRPE, la remédiation doit être spécifiquement adaptée à l''erreur diagnostiquée, pas être un exercice générique « pour s''entraîner ».',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'cdc82bcf-fa91-4e8b-aab6-0812b5414502',
  'Mathematiques',
  'didactique_maths',
  'math_analyse_productions_numeration',
  'Analyse de productions d''élèves — Numération',
  'Intermediaire',
  'reponse_courte',
  'Un enseignant propose l''exercice suivant : « Écris en chiffres : trois mille six cent quatre-vingts. » Il modifie ensuite l''exercice en : « Écris en chiffres : trois mille six cent huit. » Quelle variable didactique a-t-il modifiée ?',
  NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["la présence d''un zéro intercalaire","le zéro intercalaire","zéro intercalaire","présence du zéro intercalaire","la présence du zéro","le zéro","présence d''un zéro intercalaire"]}',
  'L''enseignant a modifié la variable didactique liée à la présence d''un zéro intercalaire. « Trois mille six cent quatre-vingts » = 3 680 (pas de zéro intercalaire). « Trois mille six cent huit » = 3 608 (zéro intercalaire à la position des dizaines). Le zéro intercalaire complexifie le transcodage car le mot « zéro » n''est jamais prononcé à l''oral (on ne dit pas « trois mille six cent zéro dizaines huit »). C''est une variable didactique au sens de Brousseau : un paramètre de l''exercice que l''enseignant peut modifier pour changer la stratégie de résolution requise sans changer la nature de la tâche.',
  'Confondre variable didactique et simple modification de l''énoncé. La variable didactique est un concept précis de la théorie des situations didactiques (Brousseau) : c''est un paramètre qui modifie la stratégie de résolution attendue.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

-- math_angles_alternes_correspondants (geometrie) : 3 -> 10 questions
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f90c0000-0000-0000-0000-000000000001', 'Mathematiques', 'geometrie', 'math_angles_alternes_correspondants', 'Angles alternes-internes et correspondants', 'Intermediaire',
  'qcm', 'Deux droites parallèles (d₁) et (d₂) sont coupées par une sécante. On obtient un angle de 65° sur (d₁) du côté gauche de la sécante, entre les deux parallèles. Que vaut l''angle alterne-interne correspondant sur (d₂) ?', NULL,
  '[{"id":"a","label":"65°"},{"id":"b","label":"115°"},{"id":"c","label":"25°"},{"id":"d","label":"130°"}]'::jsonb,
  '{"mode":"single","value":"a"}'::jsonb,
  'Lorsque deux droites parallèles sont coupées par une sécante, les angles alternes-internes sont égaux. L''angle alterne-interne est situé de l''autre côté de la sécante, entre les deux parallèles. Il mesure donc également 65°. L''option b (115°) correspond à l''angle supplémentaire (180° − 65°), qui serait un angle co-intérieur, pas un angle alterne-interne.',
  'Confondre angles alternes-internes et angles co-intérieurs (ou angles intérieurs du même côté) : l''élève calcule 180° − 65° = 115° au lieu de reconnaître l''égalité.',
  'valide', 'Génération Claude — Terminologie Éduscol', 'free', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f90c0000-0000-0000-0000-000000000002', 'Mathematiques', 'geometrie', 'math_angles_alternes_correspondants', 'Angles alternes-internes et correspondants', 'Intermediaire',
  'vrai_faux', 'Si deux droites parallèles sont coupées par une sécante, les angles correspondants sont supplémentaires (leur somme vaut 180°).', NULL,
  NULL,
  '{"mode":"single","value":"faux"}'::jsonb,
  'Cette affirmation est fausse. Lorsque deux droites parallèles sont coupées par une sécante, les angles correspondants sont égaux, pas supplémentaires. Ce sont les angles co-intérieurs (angles intérieurs situés du même côté de la sécante) qui sont supplémentaires et dont la somme vaut 180°. Deux angles correspondants occupent la même position relative par rapport à la sécante et à chaque parallèle.',
  'Confondre les propriétés : l''élève mélange « angles correspondants = égaux » et « angles co-intérieurs = supplémentaires ».',
  'valide', 'Génération Claude — Terminologie Éduscol', 'free', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f90c0000-0000-0000-0000-000000000003', 'Mathematiques', 'geometrie', 'math_angles_alternes_correspondants', 'Angles alternes-internes et correspondants', 'Intermediaire',
  'qcm', 'Deux droites parallèles sont coupées par une sécante. Un angle co-intérieur (angle intérieur du même côté de la sécante) mesure 72°. Que vaut l''autre angle co-intérieur ?', NULL,
  '[{"id":"a","label":"72°"},{"id":"b","label":"108°"},{"id":"c","label":"288°"},{"id":"d","label":"36°"}]'::jsonb,
  '{"mode":"single","value":"b"}'::jsonb,
  'Les angles co-intérieurs (ou angles intérieurs situés du même côté de la sécante) sont supplémentaires lorsque les droites sont parallèles : leur somme vaut 180°. Donc l''autre angle co-intérieur mesure 180° − 72° = 108°. Cette propriété est la réciproque utile : si deux angles co-intérieurs sont supplémentaires, alors les droites sont parallèles.',
  'Penser que les angles co-intérieurs sont égaux (comme les alternes-internes) et répondre 72° au lieu de 108°.',
  'valide', 'Génération Claude — Terminologie Éduscol', 'free', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f90c0000-0000-0000-0000-000000000004', 'Mathematiques', 'geometrie', 'math_angles_alternes_correspondants', 'Angles alternes-internes et correspondants', 'Intermediaire',
  'reponse_courte', 'Les droites (d₁) et (d₂) sont parallèles, coupées par une sécante (s). On donne l''angle formé entre (d₁) et (s) du côté supérieur gauche : 130°. Quel est l''angle formé entre (d₂) et (s) du côté inférieur droit, entre les deux parallèles ? (en degrés)', NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["50","50°","50 °"]}'::jsonb,
  'L''angle de 130° est situé au-dessus de (d₁) à gauche de (s). L''angle demandé est situé en dessous de (d₂) à droite de (s), entre les parallèles. Ces deux angles ne sont ni alternes-internes ni correspondants : il faut décomposer. L''angle correspondant sur (d₂) du côté supérieur gauche mesure aussi 130°. L''angle adjacent (supplémentaire) mesure 180° − 130° = 50°. L''angle alterne-interne de cet angle de 50° (côté gauche, entre les parallèles) est aussi 50°.',
  'Répondre 130° en confondant avec un angle correspondant : l''élève ne repère pas correctement la position de l''angle demandé par rapport à la sécante.',
  'valide', 'Génération Claude — Terminologie Éduscol', 'free', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f90c0000-0000-0000-0000-000000000005', 'Mathematiques', 'geometrie', 'math_angles_alternes_correspondants', 'Angles alternes-internes et correspondants', 'Intermediaire',
  'qcm', 'Deux droites (d₁) et (d₂) sont coupées par une sécante. On mesure deux angles alternes-internes : l''un vaut 55° et l''autre 55°. Que peut-on conclure ?', NULL,
  '[{"id":"a","label":"Les droites (d₁) et (d₂) sont parallèles"},{"id":"b","label":"Les droites (d₁) et (d₂) sont perpendiculaires"},{"id":"c","label":"On ne peut rien conclure"},{"id":"d","label":"Les droites (d₁) et (d₂) sont sécantes en un point"}]'::jsonb,
  '{"mode":"single","value":"a"}'::jsonb,
  'Si deux droites coupées par une sécante forment des angles alternes-internes égaux, alors ces droites sont parallèles. C''est la réciproque du théorème des angles alternes-internes. Cette propriété est très utilisée en géométrie pour démontrer le parallélisme de deux droites. On peut aussi utiliser l''égalité des angles correspondants ou la supplémentarité des angles co-intérieurs pour prouver le parallélisme.',
  'Répondre « on ne peut rien conclure » : l''élève ne connaît pas la réciproque du théorème et pense qu''il ne fonctionne que dans un sens.',
  'valide', 'Génération Claude — Terminologie Éduscol', 'free', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f90c0000-0000-0000-0000-000000000006', 'Mathematiques', 'geometrie', 'math_angles_alternes_correspondants', 'Angles alternes-internes et correspondants', 'Intermediaire',
  'qcm', 'Trois droites parallèles (d₁), (d₂) et (d₃) sont coupées par une sécante. L''angle entre (d₁) et la sécante vaut 40°. On sait que l''angle entre (d₂) et la sécante (angle correspondant) vaut x, et que l''angle co-intérieur entre (d₂) et (d₃) vaut y. Quelles sont les valeurs de x et y ?', NULL,
  '[{"id":"a","label":"x = 40° et y = 140°"},{"id":"b","label":"x = 140° et y = 40°"},{"id":"c","label":"x = 40° et y = 40°"},{"id":"d","label":"x = 140° et y = 140°"}]'::jsonb,
  '{"mode":"single","value":"a"}'::jsonb,
  'Puisque (d₁) // (d₂), les angles correspondants sont égaux : x = 40°. Puisque (d₂) // (d₃), les angles co-intérieurs sont supplémentaires : y = 180° − 40° = 140°. Ce problème combine deux propriétés distinctes dans une configuration à trois parallèles, ce qui exige de l''élève une lecture attentive de la position des angles.',
  'Appliquer la même propriété aux deux paires d''angles : l''élève répond x = 40° et y = 40° en oubliant que les angles co-intérieurs sont supplémentaires et non égaux.',
  'valide', 'Génération Claude — Terminologie Éduscol', 'free', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f90c0000-0000-0000-0000-000000000007', 'Mathematiques', 'geometrie', 'math_angles_alternes_correspondants', 'Angles alternes-internes et correspondants', 'Intermediaire',
  'reponse_courte', 'Deux rails de chemin de fer sont parallèles. Une traverse les coupe en formant un angle de 78° avec le rail gauche. Un ingénieur doit vérifier l''angle formé entre la traverse et le rail droit (angle correspondant). Quelle valeur doit-il trouver pour confirmer que les rails sont bien parallèles ? (en degrés)', NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["78","78°","78 °"]}'::jsonb,
  'Si les rails sont parallèles, les angles correspondants formés par la traverse (sécante) sont égaux. L''ingénieur doit donc mesurer un angle de 78° entre la traverse et le rail droit. Si cet angle diffère de 78°, cela signifie que les rails ne sont pas parfaitement parallèles. Ce problème illustre une application concrète de la propriété des angles correspondants dans le domaine ferroviaire.',
  'Calculer le supplémentaire (180° − 78° = 102°) : l''élève confond angles correspondants (égaux) et angles co-intérieurs (supplémentaires).',
  'valide', 'Génération Claude — Terminologie Éduscol', 'free', true
) ON CONFLICT (id) DO NOTHING;

-- math_angles_mesures_proprietes (geometrie) : 3 -> 10 questions
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'c0100000-0000-0000-0000-000000000001',
  'Mathematiques',
  'geometrie',
  'math_angles_mesures_proprietes',
  'Angles — Mesures et propriétés',
  'Intermediaire',
  'qcm',
  'Un angle mesure 135°. Comment le qualifie-t-on ?',
  NULL,
  '[{"id":"a","label":"Aigu"},{"id":"b","label":"Droit"},{"id":"c","label":"Obtus"},{"id":"d","label":"Plat"}]',
  '{"mode":"single","value":"c"}',
  'Un angle de 135° est obtus. Classification des angles : aigu (0° < a < 90°), droit (a = 90°), obtus (90° < a < 180°), plat (a = 180°), rentrant (180° < a < 360°), plein (a = 360°). 135° est strictement compris entre 90° et 180°, donc c''est un angle obtus. Au CRPE, la connaissance précise du vocabulaire géométrique (angle aigu, obtus, complémentaire, supplémentaire) est attendue dans les questions de géométrie et de didactique.',
  'Confondre obtus et plat. L''angle plat mesure exactement 180° (les deux côtés forment une droite). L''angle obtus est « ouvert » mais pas plat.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'c0100000-0000-0000-0000-000000000002',
  'Mathematiques',
  'geometrie',
  'math_angles_mesures_proprietes',
  'Angles — Mesures et propriétés',
  'Intermediaire',
  'reponse_courte',
  'Deux angles sont complémentaires. L''un mesure 37°. Combien mesure l''autre ?',
  NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["53°","53","53 °","53 degrés"]}',
  'Deux angles complémentaires ont une somme de 90°. Si l''un mesure 37°, l''autre mesure 90° − 37° = 53°. Ne pas confondre avec supplémentaires (somme = 180°) : si les angles étaient supplémentaires, la réponse serait 180° − 37° = 143°. Moyen mnémotechnique : Complémentaire → 90° (C comme Coin d''un angle droit), Supplémentaire → 180° (S comme Straight/droit, angle plat).',
  'Confondre complémentaires (somme = 90°) et supplémentaires (somme = 180°). C''est la confusion la plus fréquente.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'c0100000-0000-0000-0000-000000000003',
  'Mathematiques',
  'geometrie',
  'math_angles_mesures_proprietes',
  'Angles — Mesures et propriétés',
  'Intermediaire',
  'qcm',
  'Deux droites parallèles sont coupées par une sécante. Un angle aigu formé mesure 62°. Combien mesure l''angle obtus adjacent ?',
  NULL,
  '[{"id":"a","label":"62°"},{"id":"b","label":"118°"},{"id":"c","label":"128°"},{"id":"d","label":"28°"}]',
  '{"mode":"single","value":"b"}',
  'Deux angles adjacents formés par une sécante coupant une droite sont supplémentaires : leur somme vaut 180°. Angle obtus = 180° − 62° = 118°. Quand deux parallèles sont coupées par une sécante, on distingue : les angles alternes-internes (égaux), les angles correspondants (égaux), et les angles supplémentaires (somme = 180°). L''angle aigu (62°) et l''angle obtus adjacent (118°) sont supplémentaires. Tous les angles aigus formés par ces parallèles et cette sécante mesurent 62°, et tous les angles obtus mesurent 118°.',
  'Confondre supplémentaires (180°) et complémentaires (90°), ce qui donnerait 90° − 62° = 28° (faux).',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'c0100000-0000-0000-0000-000000000004',
  'Mathematiques',
  'geometrie',
  'math_angles_mesures_proprietes',
  'Angles — Mesures et propriétés',
  'Intermediaire',
  'vrai_faux',
  'Vrai ou faux : si deux droites sont coupées par une sécante et forment des angles alternes-internes égaux, alors ces droites sont parallèles.',
  NULL,
  NULL,
  '{"mode":"single","value":"vrai"}',
  'VRAI. C''est la RÉCIPROQUE du théorème des angles alternes-internes. Le théorème direct dit : « si deux droites sont parallèles, alors les angles alternes-internes sont égaux ». La réciproque dit : « si les angles alternes-internes sont égaux, alors les droites sont parallèles ». Cette réciproque est VRAIE et sert à DÉMONTRER que deux droites sont parallèles. C''est un outil de démonstration fondamental au CRPE. Les angles alternes-internes sont situés de part et d''autre de la sécante, entre les deux droites (« internes »), et en positions « alternées » (l''un à gauche, l''autre à droite de la sécante).',
  'Confondre le théorème et sa réciproque, ou ne pas savoir que la réciproque est vraie. Les deux sens sont valides pour les angles alternes-internes avec des parallèles.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'c0100000-0000-0000-0000-000000000005',
  'Mathematiques',
  'geometrie',
  'math_angles_mesures_proprietes',
  'Angles — Mesures et propriétés',
  'Intermediaire',
  'reponse_courte',
  'Dans le triangle ABC, l''angle en A mesure 48° et l''angle en B mesure 65°. Quelle est la mesure de l''angle en C ?',
  NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["67°","67","67 °","67 degrés"]}',
  'La somme des angles d''un triangle est toujours 180°. Angle C = 180° − 48° − 65° = 67°. Vérification : 48° + 65° + 67° = 180° ✓. Ce triangle est acutangle (les 3 angles sont aigus, tous < 90°). Classification des triangles selon les angles : acutangle (3 angles aigus), rectangle (1 angle droit), obtusangle (1 angle obtus). Ici, tous les angles sont entre 0° et 90°, donc acutangle. La propriété « somme des angles = 180° » est l''une des propriétés les plus utilisées en géométrie au CRPE.',
  'Faire 180° − 48° = 132° en oubliant de soustraire aussi l''angle B, ou se tromper dans la soustraction.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'c0100000-0000-0000-0000-000000000006',
  'Mathematiques',
  'geometrie',
  'math_angles_mesures_proprietes',
  'Angles — Mesures et propriétés',
  'Intermediaire',
  'qcm',
  'Dans un cercle, un angle au centre mesure 120°. Quel est l''angle inscrit qui intercepte le même arc ?',
  NULL,
  '[{"id":"a","label":"120°"},{"id":"b","label":"60°"},{"id":"c","label":"240°"},{"id":"d","label":"30°"}]',
  '{"mode":"single","value":"b"}',
  'L''angle inscrit est toujours égal à la MOITIÉ de l''angle au centre qui intercepte le même arc. Angle inscrit = 120° / 2 = 60°. Cette relation est fondamentale en géométrie du cercle. Cas particulier important : si l''angle au centre vaut 180° (demi-cercle), l''angle inscrit vaut 90°. C''est le théorème de Thalès pour le cercle : tout angle inscrit dans un demi-cercle est un angle droit. Au CRPE, la relation angle inscrit = angle au centre / 2 est régulièrement utilisée dans les problèmes de géométrie du cercle.',
  'Croire que l''angle inscrit est égal à l''angle au centre (donner 120°). L''angle inscrit est toujours la MOITIÉ de l''angle au centre correspondant.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'c0100000-0000-0000-0000-000000000007',
  'Mathematiques',
  'geometrie',
  'math_angles_mesures_proprietes',
  'Angles — Mesures et propriétés',
  'Intermediaire',
  'reponse_courte',
  'Quelle est la somme des angles intérieurs d''un hexagone (polygone à 6 côtés) ?',
  NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["720°","720","720 °","720 degrés"]}',
  'La somme des angles intérieurs d''un polygone à n côtés est (n − 2) × 180°. Pour un hexagone (n = 6) : (6 − 2) × 180° = 4 × 180° = 720°. Justification : on peut découper tout polygone convexe à n côtés en (n − 2) triangles à partir d''un sommet. Chaque triangle a une somme d''angles de 180°, d''où le résultat. Cas particuliers à connaître : triangle (180°), quadrilatère (360°), pentagone (540°), hexagone (720°). Pour un hexagone régulier, chaque angle mesure 720°/6 = 120°.',
  'Appliquer la formule n × 180° au lieu de (n − 2) × 180°, ce qui donnerait 1 080° (faux). Le « − 2 » est crucial.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

-- math_angles_polygones (geometrie) : 3 -> 10 questions
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f9100000-0000-0000-0000-000000000001',
  'Mathematiques', 'geometrie', 'math_angles_polygones',
  'Angles dans les polygones — Calculs', 'Intermediaire',
  'qcm',
  'La somme des angles intérieurs d''un polygone à n côtés est donnée par une formule. Quelle est cette formule ?',
  NULL,
  '[{"id":"a","label":"n × 180°"},{"id":"b","label":"(n − 2) × 180°"},{"id":"c","label":"(n − 1) × 180°"},{"id":"d","label":"(n + 2) × 180°"}]'::jsonb,
  '{"mode":"single","value":"b"}'::jsonb,
  'La somme des angles intérieurs d''un polygone convexe à n côtés vaut (n − 2) × 180°. Cette formule se démontre en décomposant le polygone en triangles à partir d''un sommet : depuis un sommet donné, on peut tracer (n − 3) diagonales qui découpent le polygone en (n − 2) triangles. Comme la somme des angles de chaque triangle vaut 180°, la somme totale vaut (n − 2) × 180°. Exemples : triangle (n = 3) → (3 − 2) × 180° = 180° ; quadrilatère (n = 4) → (4 − 2) × 180° = 360° ; pentagone (n = 5) → (5 − 2) × 180° = 540° ; hexagone (n = 6) → (6 − 2) × 180° = 720°. Cette formule est fondamentale en géométrie et revient très fréquemment au CRPE, aussi bien dans les exercices de calcul que dans les problèmes de pavage.',
  'Utiliser n × 180° au lieu de (n − 2) × 180°. Ne pas oublier de soustraire 2 au nombre de côtés avant de multiplier par 180°.',
  'valide',
  'Génération Claude — Programmes cycle 3-collège / Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f9100000-0000-0000-0000-000000000002',
  'Mathematiques', 'geometrie', 'math_angles_polygones',
  'Angles dans les polygones — Calculs', 'Intermediaire',
  'reponse_courte',
  'Un quadrilatère a trois angles mesurant 85°, 110° et 72°. Quelle est la mesure du quatrième angle ?',
  NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["93°","93","93 degrés"]}'::jsonb,
  'La somme des angles intérieurs d''un quadrilatère vaut (4 − 2) × 180° = 360°. On connaît trois angles : 85° + 110° + 72° = 267°. Le quatrième angle mesure donc 360° − 267° = 93°. Vérification : 85° + 110° + 72° + 93° = 360°. Ce type de calcul est un classique du CRPE. Il repose sur la connaissance de la somme des angles d''un quadrilatère (360°) et sur la capacité à résoudre une équation simple : a + 85 + 110 + 72 = 360, donc a = 360 − 267 = 93. Attention : il faut toujours vérifier que le résultat est cohérent (un angle d''un polygone convexe doit être compris entre 0° et 360° exclu). Ici, 93° est bien un angle plausible pour un quadrilatère convexe.',
  'Utiliser 180° comme somme des angles d''un quadrilatère (confusion avec le triangle). La somme des angles d''un quadrilatère est 360°, pas 180°.',
  'valide',
  'Génération Claude — Programmes cycle 3-collège / Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f9100000-0000-0000-0000-000000000003',
  'Mathematiques', 'geometrie', 'math_angles_polygones',
  'Angles dans les polygones — Calculs', 'Intermediaire',
  'qcm',
  'Quelle est la mesure de chaque angle intérieur d''un hexagone régulier ?',
  NULL,
  '[{"id":"a","label":"108°"},{"id":"b","label":"120°"},{"id":"c","label":"135°"},{"id":"d","label":"150°"}]'::jsonb,
  '{"mode":"single","value":"b"}'::jsonb,
  'Un hexagone régulier a 6 côtés égaux et 6 angles égaux. La somme de ses angles intérieurs vaut (6 − 2) × 180° = 4 × 180° = 720°. Comme les 6 angles sont égaux, chaque angle mesure 720° ÷ 6 = 120°. Pour un polygone régulier à n côtés, la formule de l''angle intérieur est : (n − 2) × 180° / n. Récapitulatif des angles intérieurs des polygones réguliers courants : triangle équilatéral (n = 3) → 60° ; carré (n = 4) → 90° ; pentagone régulier (n = 5) → 108° ; hexagone régulier (n = 6) → 120° ; octogone régulier (n = 8) → 135° ; décagone régulier (n = 10) → 144°. L''hexagone régulier est particulièrement important car son angle de 120° permet un pavage du plan (3 × 120° = 360°), ce qui explique la forme des alvéoles d''abeilles.',
  'Confondre les angles des différents polygones réguliers. 108° est l''angle du pentagone régulier, 135° celui de l''octogone. Toujours recalculer avec la formule (n − 2) × 180° / n.',
  'valide',
  'Génération Claude — Programmes cycle 3-collège / Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f9100000-0000-0000-0000-000000000004',
  'Mathematiques', 'geometrie', 'math_angles_polygones',
  'Angles dans les polygones — Calculs', 'Intermediaire',
  'qcm',
  'La somme des angles extérieurs d''un polygone convexe (un angle extérieur à chaque sommet) est une valeur remarquable. Quelle est cette somme pour un décagone régulier (10 côtés) ?',
  NULL,
  '[{"id":"a","label":"1 440°"},{"id":"b","label":"180°"},{"id":"c","label":"360°"},{"id":"d","label":"3 600°"}]'::jsonb,
  '{"mode":"single","value":"c"}'::jsonb,
  'La somme des angles extérieurs d''un polygone convexe est toujours égale à 360°, quel que soit le nombre de côtés. C''est un résultat remarquable et universel. Chaque angle extérieur est le supplément de l''angle intérieur correspondant : angle extérieur = 180° − angle intérieur. Pour un polygone régulier à n côtés, chaque angle extérieur mesure 360° / n. Pour le décagone régulier : chaque angle extérieur = 360° / 10 = 36°. Vérification : l''angle intérieur = 180° − 36° = 144°, et (10 − 2) × 180° / 10 = 1 440° / 10 = 144°. La propriété « somme des angles extérieurs = 360° » s''explique intuitivement : si l''on parcourt le contour du polygone en tournant à chaque sommet, on effectue un tour complet (360°) pour revenir au point de départ. Cette propriété est très utile au CRPE pour calculer rapidement les angles extérieurs.',
  'Croire que la somme des angles extérieurs dépend du nombre de côtés. Elle vaut toujours 360° pour tout polygone convexe.',
  'valide',
  'Génération Claude — Programmes cycle 3-collège / Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f9100000-0000-0000-0000-000000000005',
  'Mathematiques', 'geometrie', 'math_angles_polygones',
  'Angles dans les polygones — Calculs', 'Intermediaire',
  'vrai_faux',
  'Un polygone possède 5 angles intérieurs mesurant respectivement 108°, 108°, 108°, 108° et 108°. Ce polygone est nécessairement un pentagone régulier.',
  NULL,
  NULL,
  '{"mode":"single","value":"faux"}'::jsonb,
  'C''est faux. Avoir 5 angles égaux à 108° est une condition nécessaire mais pas suffisante pour qu''un pentagone soit régulier. Un pentagone régulier a à la fois 5 angles égaux ET 5 côtés égaux. On peut construire un pentagone dont les 5 angles mesurent tous 108° mais dont les côtés ont des longueurs différentes : c''est un pentagone équiangle mais non équilatéral. Par analogie, un rectangle a 4 angles de 90° mais n''est pas forcément un carré (ses côtés ne sont pas nécessairement égaux). La régularité d''un polygone exige deux conditions simultanées : équiangularité (tous les angles égaux) ET équilatéralité (tous les côtés égaux). Vérifions la somme : 5 × 108° = 540° = (5 − 2) × 180°. La somme est bien correcte pour un pentagone. Mais l''égalité des angles seule ne garantit pas la régularité.',
  'Croire que l''égalité des angles suffit à garantir la régularité d''un polygone. Il faut aussi vérifier l''égalité des côtés. (Exception : pour le triangle, équiangle implique équilatéral.)',
  'valide',
  'Génération Claude — Programmes cycle 3-collège / Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f9100000-0000-0000-0000-000000000006',
  'Mathematiques', 'geometrie', 'math_angles_polygones',
  'Angles dans les polygones — Calculs', 'Intermediaire',
  'qcm',
  'Depuis un sommet d''un polygone convexe à n côtés, on trace toutes les diagonales possibles, ce qui divise le polygone en triangles. Combien de triangles obtient-on ainsi ?',
  NULL,
  '[{"id":"a","label":"n triangles"},{"id":"b","label":"(n − 1) triangles"},{"id":"c","label":"(n − 2) triangles"},{"id":"d","label":"(n − 3) triangles"}]'::jsonb,
  '{"mode":"single","value":"c"}'::jsonb,
  'Depuis un sommet d''un polygone convexe à n côtés, on peut tracer (n − 3) diagonales (on ne peut pas tracer de diagonale vers les deux sommets adjacents ni vers le sommet lui-même). Ces diagonales découpent le polygone en exactement (n − 2) triangles. C''est d''ailleurs la base de la démonstration de la formule de la somme des angles : chaque triangle a une somme d''angles de 180°, donc la somme totale vaut (n − 2) × 180°. Exemples concrets : un quadrilatère (n = 4) se découpe en 4 − 2 = 2 triangles ; un pentagone (n = 5) se découpe en 5 − 2 = 3 triangles ; un hexagone (n = 6) se découpe en 6 − 2 = 4 triangles. Cette propriété de triangulation est fondamentale en géométrie : elle permet de ramener l''étude d''un polygone quelconque à celle de triangles, figures dont on connaît parfaitement les propriétés.',
  'Répondre (n − 3), qui est le nombre de diagonales depuis un sommet, et non le nombre de triangles formés. Les diagonales créent un triangle de plus qu''il n''y a de diagonales.',
  'valide',
  'Génération Claude — Programmes cycle 3-collège / Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f9100000-0000-0000-0000-000000000007',
  'Mathematiques', 'geometrie', 'math_angles_polygones',
  'Angles dans les polygones — Calculs', 'Intermediaire',
  'reponse_courte',
  'Pour réaliser un pavage du plan avec un seul type de polygone régulier, il faut que l''angle intérieur de ce polygone divise exactement 360°. Parmi le triangle équilatéral, le carré et l''hexagone régulier, combien de ces polygones permettent un pavage régulier du plan ?',
  NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["3","trois","les trois","les 3"]}'::jsonb,
  'Les trois polygones réguliers permettent un pavage du plan, et ce sont les seuls polygones réguliers à le permettre. Pour paver le plan, il faut que plusieurs polygones se rejoignent en chaque sommet et que la somme des angles en ce sommet soit exactement 360°. Triangle équilatéral : angle = 60°, et 360° ÷ 60° = 6. Six triangles équilatéraux se rejoignent en chaque sommet → pavage possible. Carré : angle = 90°, et 360° ÷ 90° = 4. Quatre carrés se rejoignent en chaque sommet → pavage possible. Hexagone régulier : angle = 120°, et 360° ÷ 120° = 3. Trois hexagones se rejoignent en chaque sommet → pavage possible. Pour le pentagone régulier : angle = 108°, et 360° ÷ 108° = 3,33... Ce n''est pas un entier, donc le pavage est impossible. De même pour l''heptagone (128,57°) et tous les polygones réguliers à plus de 6 côtés. Ce résultat est un classique du CRPE, souvent posé dans les problèmes de pavage et de carrelage.',
  'Oublier l''un des trois polygones, en particulier le triangle équilatéral. Ou croire que le pentagone régulier pave le plan (son angle de 108° ne divise pas 360°).',
  'valide',
  'Génération Claude — Programmes cycle 3-collège / Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

-- math_arithmetique_pgcd_ppcm (nombres_calcul) : 3 -> 10 questions
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'c0060000-0000-0000-0000-000000000001',
  'Mathematiques',
  'nombres_calcul',
  'math_arithmetique_pgcd_ppcm',
  'Arithmétique — Divisibilité, PGCD et PPCM',
  'Difficile',
  'qcm',
  'Lequel de ces nombres est divisible à la fois par 3 et par 4 ?',
  NULL,
  '[{"id":"a","label":"246"},{"id":"b","label":"312"},{"id":"c","label":"515"},{"id":"d","label":"138"}]',
  '{"mode":"single","value":"b"}',
  'Un nombre est divisible par 3 si la somme de ses chiffres est divisible par 3. Un nombre est divisible par 4 si le nombre formé par ses deux derniers chiffres est divisible par 4. Vérifions chaque candidat : (A) 246 : somme 2+4+6 = 12, div. par 3 ✓. Deux derniers chiffres : 46, 46÷4 = 11,5 ✗. (B) 312 : somme 3+1+2 = 6, div. par 3 ✓. Deux derniers chiffres : 12, 12÷4 = 3 ✓. Divisible par 3 ET par 4. (C) 515 : somme 5+1+5 = 11, pas div. par 3 ✗. (D) 138 : somme 1+3+8 = 12, div. par 3 ✓. Deux derniers chiffres : 38, 38÷4 = 9,5 ✗. Seul 312 satisfait les deux critères. Note : divisible par 3 ET par 4 ⟺ divisible par 12 (car PGCD(3,4) = 1).',
  'Confondre le critère de divisibilité par 4 (les deux derniers chiffres) avec celui par 2 (le dernier chiffre). Ou croire que divisible par 6 = divisible par 3 et par 4 (faux : divisible par 6 = divisible par 2 et par 3).',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'c0060000-0000-0000-0000-000000000002',
  'Mathematiques',
  'nombres_calcul',
  'math_arithmetique_pgcd_ppcm',
  'Arithmétique — Divisibilité, PGCD et PPCM',
  'Difficile',
  'reponse_courte',
  'Décomposez 180 en produit de facteurs premiers.',
  NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["2² × 3² × 5","2^2 × 3^2 × 5","2² x 3² x 5","4 × 9 × 5","2×2×3×3×5","2 × 2 × 3 × 3 × 5","2^2 x 3^2 x 5"]}'  ,
  '180 = 2 × 90 = 2 × 2 × 45 = 2 × 2 × 3 × 15 = 2 × 2 × 3 × 3 × 5 = 2² × 3² × 5. Méthode systématique : on divise par le plus petit facteur premier possible à chaque étape. 180 ÷ 2 = 90, 90 ÷ 2 = 45, 45 ÷ 3 = 15, 15 ÷ 3 = 5, 5 ÷ 5 = 1. La décomposition en facteurs premiers est UNIQUE (théorème fondamental de l''arithmétique). Elle est la base du calcul du PGCD et du PPCM. Vérification : 4 × 9 × 5 = 36 × 5 = 180 ✓.',
  'S''arrêter trop tôt dans la décomposition (écrire 4 × 45 ou 12 × 15 — ce ne sont pas des facteurs PREMIERS). La décomposition doit n''utiliser que des nombres premiers (2, 3, 5, 7, 11…).',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'c0060000-0000-0000-0000-000000000003',
  'Mathematiques',
  'nombres_calcul',
  'math_arithmetique_pgcd_ppcm',
  'Arithmétique — Divisibilité, PGCD et PPCM',
  'Difficile',
  'reponse_courte',
  'Calculez le PGCD de 84 et 120.',
  NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["12","PGCD = 12","PGCD(84,120) = 12"]}'  ,
  'Méthode 1 — Décomposition : 84 = 2² × 3 × 7 et 120 = 2³ × 3 × 5. PGCD = produit des facteurs communs avec le plus petit exposant = 2² × 3 = 4 × 3 = 12. Méthode 2 — Algorithme d''Euclide : 120 = 1 × 84 + 36, puis 84 = 2 × 36 + 12, puis 36 = 3 × 12 + 0. Le dernier reste non nul est 12, donc PGCD(84, 120) = 12. Vérification : 84 = 12 × 7 et 120 = 12 × 10. Effectivement, 84 et 120 sont tous deux divisibles par 12, et 7 et 10 sont premiers entre eux (PGCD(7,10) = 1).',
  'Confondre PGCD et PPCM. Le PGCD est le PLUS GRAND diviseur commun (toujours ≤ au plus petit des deux nombres). Le PPCM est le plus petit multiple commun (toujours ≥ au plus grand des deux nombres).',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'c0060000-0000-0000-0000-000000000004',
  'Mathematiques',
  'nombres_calcul',
  'math_arithmetique_pgcd_ppcm',
  'Arithmétique — Divisibilité, PGCD et PPCM',
  'Difficile',
  'qcm',
  'Un fleuriste dispose de 48 roses et 36 tulipes. Il veut composer des bouquets identiques en utilisant TOUTES les fleurs, chaque bouquet contenant le même nombre de roses et le même nombre de tulipes. Quel est le nombre maximal de bouquets ?',
  NULL,
  '[{"id":"a","label":"6 bouquets"},{"id":"b","label":"12 bouquets"},{"id":"c","label":"4 bouquets"},{"id":"d","label":"8 bouquets"}]',
  '{"mode":"single","value":"b"}',
  'Le nombre de bouquets doit diviser à la fois 48 (roses) et 36 (tulipes). Le nombre maximal est le PGCD(48, 36). Décomposition : 48 = 2⁴ × 3 et 36 = 2² × 3². PGCD = 2² × 3 = 12. Donc 12 bouquets, chacun contenant 48/12 = 4 roses et 36/12 = 3 tulipes. Vérification : 12 × 4 = 48 roses ✓ et 12 × 3 = 36 tulipes ✓. Ce type de problème (« partager en parts maximales identiques ») est un classique du PGCD au CRPE. Le mot-clé est « nombre maximal de parts identiques » → PGCD.',
  'Confondre PGCD et PPCM. Le PPCM(48, 36) = 144, ce qui n''a pas de sens ici (on ne peut pas faire 144 bouquets avec seulement 48 roses). Le PGCD correspond au partage MAXIMAL.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'c0060000-0000-0000-0000-000000000005',
  'Mathematiques',
  'nombres_calcul',
  'math_arithmetique_pgcd_ppcm',
  'Arithmétique — Divisibilité, PGCD et PPCM',
  'Difficile',
  'reponse_courte',
  'Deux bus partent du même arrêt : l''un passe toutes les 12 minutes, l''autre toutes les 18 minutes. Ils partent ensemble à 8 h 00. À quelle heure se retrouveront-ils à nouveau ensemble ?',
  NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["8 h 36","8h36","8:36","08:36","8 h 36 min","8h36min"]}'  ,
  'On cherche le premier moment où les deux bus sont à nouveau ensemble, soit le PPCM(12, 18) minutes après le départ. Décomposition : 12 = 2² × 3 et 18 = 2 × 3². PPCM = produit des facteurs avec le PLUS GRAND exposant = 2² × 3² = 4 × 9 = 36. Les deux bus se retrouvent après 36 minutes, soit à 8 h 36. Vérification : 36 = 3 × 12 (le bus A passe 3 fois) et 36 = 2 × 18 (le bus B passe 2 fois). Le mot-clé « se retrouver ensemble » → PPCM. Relation utile : PGCD(a,b) × PPCM(a,b) = a × b. Ici : 6 × 36 = 216 = 12 × 18 ✓.',
  'Multiplier 12 × 18 = 216 (trop grand) ou prendre le plus grand des deux (18 minutes — les bus ne se retrouvent pas à 8 h 18 car 18 n''est pas multiple de 12).',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'c0060000-0000-0000-0000-000000000006',
  'Mathematiques',
  'nombres_calcul',
  'math_arithmetique_pgcd_ppcm',
  'Arithmétique — Divisibilité, PGCD et PPCM',
  'Difficile',
  'vrai_faux',
  'Vrai ou faux : deux nombres consécutifs (comme 14 et 15) sont toujours premiers entre eux.',
  NULL,
  NULL,
  '{"mode":"single","value":"vrai"}',
  'VRAI. Deux nombres consécutifs n et n+1 sont toujours premiers entre eux (PGCD = 1). Démonstration : si d divise n et n+1, alors d divise (n+1) − n = 1. Le seul diviseur de 1 est 1 lui-même, donc d = 1. Donc PGCD(n, n+1) = 1. Exemple : 14 = 2 × 7 et 15 = 3 × 5. Aucun facteur premier commun → PGCD(14, 15) = 1. Attention : « premiers entre eux » ne signifie PAS « premiers ». 14 et 15 ne sont pas des nombres premiers, mais ils sont premiers ENTRE EUX (leur seul diviseur commun est 1).',
  'Confondre « nombre premier » (divisible uniquement par 1 et lui-même) et « premiers entre eux » (PGCD = 1). 14 n''est pas premier, mais 14 et 15 sont premiers entre eux.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'c0060000-0000-0000-0000-000000000007',
  'Mathematiques',
  'nombres_calcul',
  'math_arithmetique_pgcd_ppcm',
  'Arithmétique — Divisibilité, PGCD et PPCM',
  'Difficile',
  'qcm',
  'On veut carreler exactement (sans découpe) un rectangle de 120 cm × 84 cm avec des carreaux carrés les plus grands possible. Quel est le côté de chaque carreau, et combien en faut-il ?',
  NULL,
  '[{"id":"a","label":"Côté 12 cm, il faut 70 carreaux"},{"id":"b","label":"Côté 6 cm, il faut 280 carreaux"},{"id":"c","label":"Côté 24 cm, il faut 35 carreaux"},{"id":"d","label":"Côté 12 cm, il faut 84 carreaux"}]',
  '{"mode":"single","value":"a"}',
  'Le côté du carreau doit diviser à la fois 120 et 84. Le plus grand possible est le PGCD(120, 84). Décomposition : 120 = 2³ × 3 × 5 et 84 = 2² × 3 × 7. PGCD = 2² × 3 = 12 cm. Nombre de carreaux : (120/12) × (84/12) = 10 × 7 = 70 carreaux. Vérification : 70 carreaux de 12 cm couvrent 70 × 144 cm² = 10 080 cm². Aire du rectangle = 120 × 84 = 10 080 cm² ✓. Le distracteur C (24 cm) ne fonctionne pas car 84/24 = 3,5 — il faudrait découper des carreaux. Le PGCD garantit un pavage exact sans découpe.',
  'Essayer des diviseurs par tâtonnement au lieu d''utiliser le PGCD. Ou choisir un carreau trop grand qui ne divise pas les deux dimensions exactement.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

-- math_boite_moustaches (organisation_donnees) : 3 -> 10 questions
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fb0c0000-0000-0000-0000-000000000001',
  'Mathematiques', 'organisation_donnees', 'math_boite_moustaches',
  'Boîte à moustaches — Lecture et interprétation', 'Difficile',
  'qcm',
  'On lit sur un diagramme en boîte (box plot) les valeurs suivantes : minimum = 22, Q₁ = 35, médiane = 42, Q₃ = 51, maximum = 68. Quelles sont les valeurs du premier quartile, de la médiane et du troisième quartile ?',
  NULL,
  '[{"id":"a","label":"Q₁ = 35, médiane = 42, Q₃ = 51"},{"id":"b","label":"Q₁ = 22, médiane = 42, Q₃ = 68"},{"id":"c","label":"Q₁ = 35, médiane = 45, Q₃ = 51"},{"id":"d","label":"Q₁ = 22, médiane = 35, Q₃ = 51"}]'::jsonb,
  '{"mode":"single","value":"a"}'::jsonb,
  'Dans un diagramme en boîte, la « boîte » est délimitée par Q₁ (bord gauche ou inférieur) et Q₃ (bord droit ou supérieur). Le trait vertical à l''intérieur de la boîte indique la médiane. Les « moustaches » s''étendent du minimum à Q₁ et de Q₃ au maximum. On lit donc directement : Q₁ = 35, médiane = 42, Q₃ = 51. Le minimum (22) et le maximum (68) ne sont pas des quartiles, ce sont les valeurs extrêmes de la série. Le diagramme en boîte synthétise cinq indicateurs statistiques essentiels en une seule représentation graphique.',
  'Confondre le minimum avec Q₁ ou le maximum avec Q₃. Les extrémités des moustaches représentent le minimum et le maximum, pas les quartiles.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fb0c0000-0000-0000-0000-000000000002',
  'Mathematiques', 'organisation_donnees', 'math_boite_moustaches',
  'Boîte à moustaches — Lecture et interprétation', 'Difficile',
  'reponse_courte',
  'Un diagramme en boîte indique Q₁ = 18 et Q₃ = 34. Calculer l''écart interquartile (IQR) de cette série.',
  NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["16","IQR = 16","Q3 - Q1 = 16"]}'::jsonb,
  'L''écart interquartile se lit directement sur le diagramme en boîte : c''est la largeur de la boîte, soit IQR = Q₃ − Q₁ = 34 − 18 = 16. Cet indicateur représente l''étendue des 50 % de valeurs centrales de la série. Plus la boîte est large, plus la distribution est dispersée autour de la médiane. L''IQR est un indicateur robuste de dispersion : contrairement à l''étendue (max − min), il n''est pas sensible aux valeurs extrêmes. Il sert aussi de base pour détecter les valeurs atypiques (règle des 1,5 × IQR).',
  'Calculer l''étendue (max − min) au lieu de l''écart interquartile (Q₃ − Q₁). L''étendue mesure la dispersion totale, l''IQR mesure la dispersion des 50 % centraux.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fb0c0000-0000-0000-0000-000000000003',
  'Mathematiques', 'organisation_donnees', 'math_boite_moustaches',
  'Boîte à moustaches — Lecture et interprétation', 'Difficile',
  'qcm',
  'On compare les diagrammes en boîte de deux classes ayant passé le même examen. Classe A : min = 4, Q₁ = 8, médiane = 12, Q₃ = 16, max = 20. Classe B : min = 9, Q₁ = 11, médiane = 13, Q₃ = 15, max = 17. Quelle affirmation est correcte ?',
  NULL,
  '[{"id":"a","label":"La classe A a de meilleurs résultats car son maximum est plus élevé"},{"id":"b","label":"La classe B est plus homogène car son écart interquartile est plus petit"},{"id":"c","label":"Les deux classes ont des résultats équivalents car leurs médianes sont proches"},{"id":"d","label":"La classe A est plus homogène car elle a plus de valeurs"}]'::jsonb,
  '{"mode":"single","value":"b"}'::jsonb,
  'Comparons les deux distributions. Médianes : A = 12, B = 13, très proches. Écarts interquartiles : IQR(A) = 16 − 8 = 8, IQR(B) = 15 − 11 = 4. Étendues : A = 20 − 4 = 16, B = 17 − 9 = 8. La classe B est nettement plus homogène : sa boîte est deux fois plus étroite et ses moustaches sont plus courtes. La classe A a certes le maximum le plus élevé (20), mais aussi le minimum le plus bas (4), signe d''une grande dispersion. Un maximum élevé seul ne signifie pas « meilleurs résultats » : il faut regarder l''ensemble de la distribution.',
  'Se focaliser uniquement sur les valeurs extrêmes (min ou max) pour comparer les distributions, au lieu de comparer les indicateurs de position (médiane) et de dispersion (IQR).',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fb0c0000-0000-0000-0000-000000000004',
  'Mathematiques', 'organisation_donnees', 'math_boite_moustaches',
  'Boîte à moustaches — Lecture et interprétation', 'Difficile',
  'qcm',
  'Un diagramme en boîte montre : min = 15, Q₁ = 20, médiane = 35, Q₃ = 40, max = 45. Que peut-on dire de l''asymétrie de cette distribution ?',
  NULL,
  '[{"id":"a","label":"La distribution est symétrique car la boîte est centrée"},{"id":"b","label":"La distribution est étalée vers la gauche (asymétrie négative) car la médiane est plus proche de Q₃"},{"id":"c","label":"La distribution est étalée vers la droite (asymétrie positive) car la médiane est plus proche de Q₁"},{"id":"d","label":"On ne peut pas déterminer l''asymétrie à partir d''un diagramme en boîte"}]'::jsonb,
  '{"mode":"single","value":"b"}'::jsonb,
  'La médiane (35) est plus proche de Q₃ (40) que de Q₁ (20) : la distance médiane − Q₁ = 15 est bien plus grande que Q₃ − médiane = 5. La partie gauche de la boîte (de Q₁ à la médiane) est donc trois fois plus large que la partie droite (de la médiane à Q₃). Les 25 % de valeurs entre Q₁ et la médiane sont plus dispersées que celles entre la médiane et Q₃. La distribution est étalée vers les petites valeurs (queue à gauche) : c''est une asymétrie négative. Les moustaches gauche (20 − 15 = 5) et droite (45 − 40 = 5) sont de même longueur, confirmant que l''asymétrie provient de la position décentrée de la médiane dans la boîte.',
  'Croire que la distribution est symétrique parce que les moustaches sont de même longueur. L''asymétrie se lit aussi dans la position de la médiane à l''intérieur de la boîte.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fb0c0000-0000-0000-0000-000000000005',
  'Mathematiques', 'organisation_donnees', 'math_boite_moustaches',
  'Boîte à moustaches — Lecture et interprétation', 'Difficile',
  'vrai_faux',
  'Un diagramme en boîte indique Q₁ = 30 et Q₃ = 50. En appliquant la règle des 1,5 × IQR, une valeur de 85 est considérée comme une valeur atypique (outlier).',
  NULL,
  NULL,
  '{"mode":"single","value":"vrai"}'::jsonb,
  'C''est vrai. L''écart interquartile vaut IQR = Q₃ − Q₁ = 50 − 30 = 20. La règle des 1,5 × IQR définit les bornes au-delà desquelles une valeur est considérée comme atypique : borne inférieure = Q₁ − 1,5 × IQR = 30 − 30 = 0, borne supérieure = Q₃ + 1,5 × IQR = 50 + 30 = 80. Toute valeur inférieure à 0 ou supérieure à 80 est considérée comme atypique. Ici, 85 > 80, donc 85 est bien une valeur atypique. Sur un diagramme en boîte, ces valeurs atypiques sont souvent représentées par des points isolés au-delà des moustaches, et les moustaches s''arrêtent à la dernière valeur non atypique.',
  'Confondre la borne de détection des outliers (Q₃ + 1,5 × IQR) avec le maximum de la série. La moustache supérieure ne s''étend pas nécessairement jusqu''au maximum si des valeurs atypiques existent.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fb0c0000-0000-0000-0000-000000000006',
  'Mathematiques', 'organisation_donnees', 'math_boite_moustaches',
  'Boîte à moustaches — Lecture et interprétation', 'Difficile',
  'reponse_courte',
  'On dispose de la série ordonnée suivante de 12 valeurs : 5, 8, 10, 12, 14, 16, 18, 20, 22, 25, 28, 32. Construire mentalement le diagramme en boîte : quelle est la valeur de la médiane ?',
  NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["17","médiane = 17"]}'::jsonb,
  'La série comporte 12 valeurs (effectif pair). La médiane est la demi-somme des valeurs de rang 6 et 7. La 6ᵉ valeur est 16 et la 7ᵉ valeur est 18. Donc la médiane = (16 + 18) / 2 = 17. Pour construire le diagramme en boîte complet, on calcule aussi : Q₁ = médiane de la première moitié (5, 8, 10, 12, 14, 16) = (10 + 12) / 2 = 11. Q₃ = médiane de la seconde moitié (18, 20, 22, 25, 28, 32) = (22 + 25) / 2 = 23,5. Le diagramme en boîte s''étend de min = 5 à max = 32, avec la boîte de Q₁ = 11 à Q₃ = 23,5 et le trait de médiane à 17.',
  'Prendre la 6ᵉ valeur (16) ou la 7ᵉ valeur (18) comme médiane sans calculer leur demi-somme. Pour un effectif pair, la médiane est toujours la moyenne des deux valeurs centrales.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fb0c0000-0000-0000-0000-000000000007',
  'Mathematiques', 'organisation_donnees', 'math_boite_moustaches',
  'Boîte à moustaches — Lecture et interprétation', 'Difficile',
  'qcm',
  'Un professeur compare les résultats de ses classes à l''examen final sur trois années consécutives à l''aide de diagrammes en boîte. Année 1 : Q₁ = 8, médiane = 11, Q₃ = 14. Année 2 : Q₁ = 9, médiane = 12, Q₃ = 15. Année 3 : Q₁ = 11, médiane = 14, Q₃ = 16. Quelle conclusion peut-on tirer de cette comparaison ?',
  NULL,
  '[{"id":"a","label":"Les résultats se sont dégradés car l''écart interquartile a diminué"},{"id":"b","label":"Les résultats se sont améliorés : la médiane et les quartiles ont augmenté chaque année"},{"id":"c","label":"Les résultats sont stables car l''écart interquartile est resté constant"},{"id":"d","label":"On ne peut rien conclure sans connaître les moyennes"}]'::jsonb,
  '{"mode":"single","value":"b"}'::jsonb,
  'On observe une progression nette des indicateurs de position d''année en année. Les médianes augmentent : 11, 12, 14. Les premiers quartiles augmentent : 8, 9, 11. Les troisièmes quartiles augmentent : 14, 15, 16. Cela signifie que l''ensemble de la distribution se décale vers les valeurs supérieures chaque année : les résultats s''améliorent globalement. L''écart interquartile reste relativement stable (6, 6, 5), ce qui indique que l''homogénéité des résultats est préservée voire légèrement améliorée. La comparaison de diagrammes en boîte sur plusieurs périodes est un outil puissant pour suivre l''évolution d''une distribution au fil du temps.',
  'Se limiter à observer que l''IQR est presque constant et en conclure que « rien n''a changé ». L''IQR mesure la dispersion, pas le niveau : il faut aussi comparer les indicateurs de position (médiane, quartiles) pour évaluer l''évolution globale.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

-- math_calcul_litteral (nombres_calcul) : 3 -> 10 questions
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'b0280000-0000-0000-0000-000000000001', 'Mathematiques', 'nombres_calcul', 'math_calcul_litteral',
  'Calcul littéral — Expressions et identités remarquables', 'Intermediaire', 'qcm',
  'Développer (x + 3)².', NULL,
  '[{"id":"a","label":"x² + 9"},{"id":"b","label":"x² + 6x + 9"},{"id":"c","label":"x² + 3x + 9"},{"id":"d","label":"2x + 6"}]'::jsonb,
  '{"mode":"single","value":"b"}'::jsonb,
  'On applique l''identité remarquable (a + b)² = a² + 2ab + b². Ici a = x et b = 3, donc (x + 3)² = x² + 2 × x × 3 + 3² = x² + 6x + 9.',
  'Oublier le double produit 2ab et écrire directement x² + 9.',
  'valide',
  'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'b0280000-0000-0000-0000-000000000002', 'Mathematiques', 'nombres_calcul', 'math_calcul_litteral',
  'Calcul littéral — Expressions et identités remarquables', 'Intermediaire', 'vrai_faux',
  '(a + b)² = a² + b².', NULL,
  '[{"id":"vrai","label":"Vrai"},{"id":"faux","label":"Faux"}]'::jsonb,
  '{"mode":"single","value":"faux"}'::jsonb,
  'C''est faux. L''identité remarquable correcte est (a + b)² = a² + 2ab + b². Le terme « double produit » 2ab est indispensable. Par exemple, (3 + 2)² = 25, alors que 3² + 2² = 13.',
  'Confondre (a + b)² avec a² + b² en oubliant le double produit 2ab.',
  'valide',
  'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'b0280000-0000-0000-0000-000000000003', 'Mathematiques', 'nombres_calcul', 'math_calcul_litteral',
  'Calcul littéral — Expressions et identités remarquables', 'Intermediaire', 'reponse_courte',
  'Factoriser x² - 25.', NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["(x-5)(x+5)","(x+5)(x-5)","(x - 5)(x + 5)","(x + 5)(x - 5)"]}'::jsonb,
  'On reconnaît une différence de deux carrés : x² - 25 = x² - 5². On applique l''identité remarquable a² - b² = (a - b)(a + b). Donc x² - 25 = (x - 5)(x + 5).',
  'Ne pas reconnaître la forme a² - b² ou tenter de développer au lieu de factoriser.',
  'valide',
  'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'b0280000-0000-0000-0000-000000000004', 'Mathematiques', 'nombres_calcul', 'math_calcul_litteral',
  'Calcul littéral — Expressions et identités remarquables', 'Intermediaire', 'qcm',
  'Développer (2x - 3)(2x + 3).', NULL,
  '[{"id":"a","label":"4x² - 6x - 9"},{"id":"b","label":"4x² + 9"},{"id":"c","label":"4x² - 9"},{"id":"d","label":"2x² - 9"}]'::jsonb,
  '{"mode":"single","value":"c"}'::jsonb,
  'On reconnaît le produit (a - b)(a + b) = a² - b² avec a = 2x et b = 3. Donc (2x - 3)(2x + 3) = (2x)² - 3² = 4x² - 9.',
  'Ajouter un terme en x (comme -6x) en développant par double distribution au lieu d''utiliser l''identité remarquable.',
  'valide',
  'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'b0280000-0000-0000-0000-000000000005', 'Mathematiques', 'nombres_calcul', 'math_calcul_litteral',
  'Calcul littéral — Expressions et identités remarquables', 'Intermediaire', 'qcm',
  'Quel est le résultat de 101² calculé mentalement en utilisant une identité remarquable ?', NULL,
  '[{"id":"a","label":"10201"},{"id":"b","label":"10101"},{"id":"c","label":"10001"},{"id":"d","label":"10401"}]'::jsonb,
  '{"mode":"single","value":"a"}'::jsonb,
  'On écrit 101 = 100 + 1, puis on applique (a + b)² = a² + 2ab + b². Donc 101² = (100 + 1)² = 100² + 2 × 100 × 1 + 1² = 10 000 + 200 + 1 = 10 201.',
  'Oublier le double produit et calculer 100² + 1² = 10 001, ou mal évaluer 2 × 100 × 1.',
  'valide',
  'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'b0280000-0000-0000-0000-000000000006', 'Mathematiques', 'nombres_calcul', 'math_calcul_litteral',
  'Calcul littéral — Expressions et identités remarquables', 'Intermediaire', 'reponse_courte',
  'Résoudre l''équation x² - 9x + 20 = 0.', NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["4 et 5","5 et 4","x=4 ou x=5","x=5 ou x=4","x = 4 ou x = 5","x = 5 ou x = 4"]}'::jsonb,
  'On cherche deux nombres dont la somme est 9 et le produit est 20 : ce sont 4 et 5. On factorise : x² - 9x + 20 = (x - 4)(x - 5) = 0. Un produit est nul si et seulement si l''un de ses facteurs est nul, donc x = 4 ou x = 5. On peut aussi utiliser le discriminant : Δ = 81 - 80 = 1, puis x = (9 ± 1) / 2.',
  'Faire une erreur de signe dans la factorisation ou oublier l''une des deux solutions.',
  'valide',
  'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'b0280000-0000-0000-0000-000000000007', 'Mathematiques', 'nombres_calcul', 'math_calcul_litteral',
  'Calcul littéral — Expressions et identités remarquables', 'Intermediaire', 'qcm',
  'Un carré a un côté de longueur (x + 2) cm. On lui retire un carré de côté x cm. Quelle expression représente l''aire restante ?', NULL,
  '[{"id":"a","label":"4"},{"id":"b","label":"4(x + 1)"},{"id":"c","label":"2x + 2"},{"id":"d","label":"x² + 4"}]'::jsonb,
  '{"mode":"single","value":"b"}'::jsonb,
  'L''aire du grand carré est (x + 2)² = x² + 4x + 4. L''aire du petit carré est x². L''aire restante est donc (x² + 4x + 4) - x² = 4x + 4 = 4(x + 1).',
  'Calculer (x + 2)² - x² = 4 en simplifiant trop vite, ou oublier de développer correctement (x + 2)².',
  'valide',
  'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

-- math_calcul_mental_multiplication (nombres_calcul) : 3 -> 10 questions
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f8100000-0000-0000-0000-000000000001',
  'Mathematiques', 'nombres_calcul', 'math_calcul_mental_multiplication',
  'Calcul mental — Stratégies de multiplication', 'Intermediaire',
  'qcm',
  'Pour multiplier mentalement un nombre par 10, 100 ou 1 000, on utilise une règle simple. Quel est le résultat de 47 × 1 000 ?',
  NULL,
  '[{"id":"a","label":"4 700"},{"id":"b","label":"47 000"},{"id":"c","label":"470 000"},{"id":"d","label":"470"}]'::jsonb,
  '{"mode":"single","value":"b"}'::jsonb,
  'Multiplier par 10, 100 ou 1 000 revient à décaler la virgule (ou ajouter des zéros) vers la droite. Pour 47 × 1 000, on ajoute trois zéros à droite de 47, ce qui donne 47 000. Attention : on ne « déplace pas les chiffres », on déplace la position de chaque chiffre dans le tableau de numération. Ainsi, le 4 (dizaines) passe en dizaines de milliers et le 7 (unités) passe en milliers. Cette compréhension positionnelle est essentielle pour éviter les erreurs avec les nombres décimaux : 4,7 × 100 = 470 (et non 4 700). Au CRPE, les questions portent souvent sur la justification de cette règle par le système de numération décimale de position.',
  'Ajouter trop ou trop peu de zéros, ou confondre multiplication par 100 et par 1 000. Toujours vérifier le nombre de zéros du multiplicateur.',
  'valide',
  'Génération Claude — Programmes cycle 2-3 / Éduscol',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f8100000-0000-0000-0000-000000000002',
  'Mathematiques', 'nombres_calcul', 'math_calcul_mental_multiplication',
  'Calcul mental — Stratégies de multiplication', 'Intermediaire',
  'vrai_faux',
  'Pour multiplier un nombre par 5, une stratégie efficace consiste à diviser ce nombre par 2 puis à multiplier le résultat par 10. Par exemple, 48 × 5 = (48 ÷ 2) × 10 = 24 × 10 = 240.',
  NULL,
  NULL,
  '{"mode":"single","value":"vrai"}'::jsonb,
  'Cette stratégie repose sur la décomposition de 5 en 10 ÷ 2 (ou 10/2). Ainsi, n × 5 = n × (10/2) = (n ÷ 2) × 10. Pour 48 × 5 : on calcule d''abord 48 ÷ 2 = 24, puis 24 × 10 = 240. Cette méthode est particulièrement efficace quand le nombre de départ est pair, car la division par 2 tombe juste. Pour un nombre impair comme 37 × 5, on peut faire (37 ÷ 2) × 10 = 18,5 × 10 = 185, ou utiliser une autre stratégie : 37 × 5 = (40 − 3) × 5 = 200 − 15 = 185. Au CRPE, on attend du candidat qu''il maîtrise plusieurs stratégies de calcul mental et qu''il sache les justifier mathématiquement.',
  'Appliquer la stratégie dans le mauvais ordre : multiplier par 10 d''abord puis diviser par 2 fonctionne aussi, mais oublier l''une des deux étapes conduit à une erreur.',
  'valide',
  'Génération Claude — Programmes cycle 2-3 / Éduscol',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f8100000-0000-0000-0000-000000000003',
  'Mathematiques', 'nombres_calcul', 'math_calcul_mental_multiplication',
  'Calcul mental — Stratégies de multiplication', 'Intermediaire',
  'reponse_courte',
  'Calculez mentalement 36 × 25 en utilisant la stratégie « multiplier par 25 = diviser par 4 puis multiplier par 100 ». Quel est le résultat ?',
  NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["900","900."]}'::jsonb,
  'La stratégie repose sur la décomposition de 25 en 100/4. Ainsi, n × 25 = n × (100/4) = (n ÷ 4) × 100. Pour 36 × 25 : on calcule d''abord 36 ÷ 4 = 9, puis 9 × 100 = 900. Cette méthode est redoutablement efficace quand le nombre est divisible par 4. Si le nombre n''est pas divisible par 4, on peut adapter : 37 × 25 = (36 + 1) × 25 = 900 + 25 = 925. On peut aussi voir 25 comme le quart de 100, ce qui ramène la multiplication par 25 à une division par 4 suivie d''une multiplication par 100 — deux opérations simples en calcul mental. Les programmes Éduscol insistent sur l''importance d''enseigner ces stratégies dès le cycle 3 pour développer le sens du nombre et la flexibilité calculatoire.',
  'Diviser par 2 au lieu de 4 (confusion entre multiplier par 25 et multiplier par 50), ou oublier de multiplier par 100 à la fin.',
  'valide',
  'Génération Claude — Programmes cycle 2-3 / Éduscol',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f8100000-0000-0000-0000-000000000004',
  'Mathematiques', 'nombres_calcul', 'math_calcul_mental_multiplication',
  'Calcul mental — Stratégies de multiplication', 'Intermediaire',
  'qcm',
  'Il existe une astuce pour multiplier un nombre à deux chiffres par 11. Par exemple, 34 × 11 : on écrit le premier chiffre (3), la somme des deux chiffres (3 + 4 = 7), puis le dernier chiffre (4), ce qui donne 374. Quel est le résultat de 63 × 11 ?',
  NULL,
  '[{"id":"a","label":"693"},{"id":"b","label":"639"},{"id":"c","label":"6 930"},{"id":"d","label":"673"}]'::jsonb,
  '{"mode":"single","value":"a"}'::jsonb,
  'Pour multiplier 63 par 11, on applique la stratégie : premier chiffre = 6, somme des chiffres = 6 + 3 = 9, dernier chiffre = 3. On obtient donc 693. Justification algébrique : si le nombre est de la forme (10a + b), alors (10a + b) × 11 = 110a + 11b = 100a + 10(a + b) + b. Le chiffre des centaines est a, celui des dizaines est (a + b), celui des unités est b. Attention au cas où a + b ≥ 10 : par exemple, 85 × 11 → 8, (8 + 5 = 13), 5. On retient 1 : le résultat est 935 (8 + 1 = 9, 3, 5). Cette stratégie illustre la puissance de la décomposition en calcul mental et la compréhension de la numération positionnelle.',
  'Oublier de gérer la retenue quand la somme des deux chiffres dépasse 9. Par exemple, pour 85 × 11, écrire 8-13-5 au lieu de 935.',
  'valide',
  'Génération Claude — Programmes cycle 2-3 / Éduscol',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f8100000-0000-0000-0000-000000000005',
  'Mathematiques', 'nombres_calcul', 'math_calcul_mental_multiplication',
  'Calcul mental — Stratégies de multiplication', 'Intermediaire',
  'qcm',
  'Un élève doit calculer mentalement 19 × 6. Quelle stratégie de distributivité est la plus efficace ?',
  NULL,
  '[{"id":"a","label":"19 × 6 = 10 × 6 + 9 × 6 = 60 + 54 = 114"},{"id":"b","label":"19 × 6 = 20 × 6 − 1 × 6 = 120 − 6 = 114"},{"id":"c","label":"19 × 6 = 19 × 3 × 2 = 57 × 2 = 114"},{"id":"d","label":"Les trois stratégies sont correctes, mais la stratégie (b) est souvent la plus rapide car elle remplace 19 par le nombre rond 20"}]'::jsonb,
  '{"mode":"single","value":"d"}'::jsonb,
  'Les trois stratégies sont mathématiquement correctes et donnent toutes 114. Cependant, la stratégie (b) — 20 × 6 − 6 = 114 — est généralement la plus efficace en calcul mental car elle utilise la distributivité avec un nombre rond (20), ce qui simplifie le calcul intermédiaire. On remplace 19 par (20 − 1), puis on applique la distributivité : (20 − 1) × 6 = 20 × 6 − 1 × 6 = 120 − 6 = 114. La stratégie (a) — décomposer 19 en 10 + 9 — fonctionne aussi mais nécessite de calculer 9 × 6, ce qui est un peu moins immédiat. La stratégie (c) — factoriser 6 en 3 × 2 — est élégante mais requiert de garder en mémoire le résultat intermédiaire 57. Le choix de la stratégie la plus adaptée dépend du contexte et des nombres en jeu. Au CRPE, on attend du candidat qu''il sache proposer et comparer plusieurs stratégies de calcul mental.',
  'Croire qu''il n''existe qu''une seule bonne méthode. La flexibilité calculatoire consiste justement à choisir la stratégie la mieux adaptée aux nombres en jeu.',
  'valide',
  'Génération Claude — Programmes cycle 2-3 / Éduscol',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f8100000-0000-0000-0000-000000000006',
  'Mathematiques', 'nombres_calcul', 'math_calcul_mental_multiplication',
  'Calcul mental — Stratégies de multiplication', 'Intermediaire',
  'vrai_faux',
  'Pour calculer mentalement le carré d''un nombre terminant par 5, on peut utiliser la formule suivante : n5² = n × (n + 1) suivi de 25. Par exemple, 35² = 3 × 4 = 12, puis on ajoute 25 → 1 225. Ainsi, 75² = 5 625.',
  NULL,
  NULL,
  '{"mode":"single","value":"vrai"}'::jsonb,
  'Cette stratégie est correcte. Démontrons-la algébriquement : un nombre terminant par 5 s''écrit sous la forme (10n + 5). Son carré vaut (10n + 5)² = 100n² + 100n + 25 = 100 × n(n + 1) + 25. Le résultat s''obtient donc en calculant n × (n + 1), puis en écrivant 25 à la fin. Vérifions avec 75 : n = 7, donc 7 × 8 = 56, on ajoute 25 → 5 625. Vérification : 75 × 75 = 75 × 70 + 75 × 5 = 5 250 + 375 = 5 625. Autres exemples : 15² → 1 × 2 = 2, puis 25 → 225 ; 45² → 4 × 5 = 20, puis 25 → 2 025 ; 95² → 9 × 10 = 90, puis 25 → 9 025. Cette astuce, bien qu''elle relève d''une identité remarquable, illustre comment la compréhension algébrique nourrit le calcul mental. Au CRPE, la connaissance de telles propriétés des carrés est régulièrement mobilisée.',
  'Confondre n × (n + 1) avec n² + 1 ou n × n. Il faut bien multiplier le chiffre des dizaines par son successeur, pas par lui-même.',
  'valide',
  'Génération Claude — Programmes cycle 2-3 / Éduscol',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f8100000-0000-0000-0000-000000000007',
  'Mathematiques', 'nombres_calcul', 'math_calcul_mental_multiplication',
  'Calcul mental — Stratégies de multiplication', 'Intermediaire',
  'reponse_courte',
  'Un commerçant vend 12 caisses de 25 bouteilles. Sans poser l''opération, estimez rapidement le nombre total de bouteilles en utilisant une stratégie de calcul mental adaptée.',
  NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["300","300 bouteilles"]}'::jsonb,
  'Pour calculer 12 × 25 mentalement, plusieurs stratégies sont possibles. Stratégie 1 : utiliser la propriété × 25 = ÷ 4 × 100. On a 12 ÷ 4 = 3, puis 3 × 100 = 300. Stratégie 2 : décomposer 12 = 4 × 3, donc 12 × 25 = 4 × 3 × 25 = 4 × 75 = 300 (car 3 × 25 = 75 et 4 × 75 = 300). Stratégie 3 : utiliser la distributivité : 12 × 25 = 10 × 25 + 2 × 25 = 250 + 50 = 300. Stratégie 4 : remarquer que 12 × 25 = 12 × 100 ÷ 4 = 1 200 ÷ 4 = 300. La richesse du calcul mental réside dans cette multiplicité d''approches. L''important est de choisir la stratégie la plus fluide selon ses connaissances et les nombres en jeu. Ce type de problème contextualisé est fréquent au CRPE : il évalue à la fois la capacité de calcul et l''aptitude à modéliser une situation concrète.',
  'Poser la multiplication en colonnes au lieu d''utiliser une stratégie mentale. L''objectif du calcul mental est de mobiliser des propriétés des opérations (commutativité, distributivité, associativité) pour simplifier le calcul.',
  'valide',
  'Génération Claude — Programmes cycle 2-3 / Éduscol',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

-- math_calcul_mental_strategies (nombres_calcul) : 3 -> 10 questions
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'b00f0000-0000-0000-0000-000000000001', 'Mathematiques', 'nombres_calcul', 'math_calcul_mental_strategies',
  'Calcul mental — Stratégies', 'Facile', 'qcm',
  'Pour calculer mentalement 99 × 7, quelle stratégie est la plus efficace ?', NULL,
  '[{"id":"a","label":"Poser la multiplication en colonnes mentalement"},{"id":"b","label":"Calculer 100 × 7 − 1 × 7 = 693"},{"id":"c","label":"Calculer 90 × 7 + 9 × 7"},{"id":"d","label":"Additionner 99 sept fois"}]'::jsonb,
  '{"mode":"single","value":"b"}'::jsonb,
  'La stratégie la plus efficace consiste à utiliser la distributivité de la multiplication par rapport à la soustraction en s''appuyant sur un nombre « rond » proche :

99 × 7 = (100 − 1) × 7 = 100 × 7 − 1 × 7 = 700 − 7 = 693.

Cette technique repose sur la propriété de distributivité : a × (b − c) = a × b − a × c.

Pourquoi est-ce plus efficace ?
• 100 × 7 est un calcul immédiat (nombre rond).
• La soustraction finale (700 − 7) est triviale.

La proposition c) (90 × 7 + 9 × 7 = 630 + 63 = 693) est correcte mais nécessite deux multiplications non triviales, ce qui la rend moins rapide.

En didactique, on parle de « stratégie de passage par un nombre rond » ou de « compensation multiplicative ». Les programmes (cycle 3) encouragent l''apprentissage de ces stratégies pour développer le sens du nombre et la flexibilité calculatoire.',
  'Choisir la décomposition 90 × 7 + 9 × 7 qui, bien que correcte, est moins efficace car elle nécessite deux produits intermédiaires plus coûteux mentalement.', 'valide',
  'Génération Claude — Terminologie Éduscol', 'free', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'b00f0000-0000-0000-0000-000000000002', 'Mathematiques', 'nombres_calcul', 'math_calcul_mental_strategies',
  'Calcul mental — Stratégies', 'Facile', 'vrai_faux',
  'Pour calculer 25 × 32, on peut calculer 25 × 4 × 8 = 100 × 8 = 800.', NULL,
  '[{"id":"vrai","label":"Vrai"},{"id":"faux","label":"Faux"}]'::jsonb,
  '{"mode":"single","value":"vrai"}'::jsonb,
  'L''affirmation est vraie.

La stratégie repose sur deux propriétés fondamentales :

1. La décomposition multiplicative : 32 = 4 × 8.
2. L''associativité de la multiplication : 25 × (4 × 8) = (25 × 4) × 8.

Étapes du calcul :
25 × 32 = 25 × (4 × 8) = (25 × 4) × 8 = 100 × 8 = 800.

L''intérêt pédagogique de cette stratégie est de repérer un « couple produit remarquable » : 25 × 4 = 100. Ce repérage permet de transformer un calcul complexe en un calcul simple avec un nombre rond.

Autres couples remarquables utiles en calcul mental :
• 25 × 4 = 100
• 50 × 2 = 100
• 125 × 8 = 1 000

Les programmes du cycle 3 insistent sur la connaissance de ces résultats intermédiaires pour enrichir le répertoire de calcul mental des élèves.',
  'Penser que l''on ne peut pas « casser » un facteur en produit de deux nombres, ou confondre associativité et distributivité.', 'valide',
  'Génération Claude — Terminologie Éduscol', 'free', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'b00f0000-0000-0000-0000-000000000003', 'Mathematiques', 'nombres_calcul', 'math_calcul_mental_strategies',
  'Calcul mental — Stratégies', 'Facile', 'reponse_courte',
  'Calculez mentalement 48 + 35 en utilisant la stratégie de compensation. Quel est le résultat ?', NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["83"]}'::jsonb,
  'Le résultat est 83.

La stratégie de compensation consiste à arrondir l''un des termes pour faciliter le calcul, puis à compenser l''ajustement effectué.

Méthode 1 — Arrondir le premier terme :
48 + 35 = (48 + 2) + (35 − 2) = 50 + 33 = 83.
On ajoute 2 à 48 pour obtenir 50 (nombre rond), et on retranche 2 à 35 pour compenser.

Méthode 2 — Arrondir le second terme :
48 + 35 = (48 − 5) + (35 + 5) = 43 + 40 = 83.

Le fondement mathématique est la conservation de la somme : si on ajoute une quantité à un terme et qu''on la retranche à l''autre, la somme reste identique. Formellement : a + b = (a + k) + (b − k).

En didactique du calcul mental, cette stratégie est appelée « compensation » ou « ajustement ». Elle fait partie des procédures expertes attendues au cycle 3 et est explicitement mentionnée dans les repères de progression Éduscol.',
  'Oublier de compenser : arrondir 48 à 50, calculer 50 + 35 = 85, mais ne pas retrancher les 2 ajoutés (résultat erroné : 85 au lieu de 83).', 'valide',
  'Génération Claude — Terminologie Éduscol', 'free', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'b00f0000-0000-0000-0000-000000000004', 'Mathematiques', 'nombres_calcul', 'math_calcul_mental_strategies',
  'Calcul mental — Stratégies', 'Facile', 'qcm',
  'Lucas calcule 156 − 98 en faisant : 156 − 100 + 2 = 58. Quelle propriété mathématique utilise-t-il ?', NULL,
  '[{"id":"a","label":"La commutativité de la soustraction"},{"id":"b","label":"La distributivité"},{"id":"c","label":"La conservation des écarts"},{"id":"d","label":"La compensation (ajustement du nombre soustrait puis correction)"}]'::jsonb,
  '{"mode":"single","value":"d"}'::jsonb,
  'Lucas utilise la stratégie de compensation (aussi appelée « ajustement »).

Son raisonnement :
156 − 98 = 156 − 100 + 2 = 56 + 2 = 58.

Il arrondit 98 à 100 (il soustrait 2 de trop), puis il compense en ajoutant 2 au résultat.

Formellement : a − b = a − (b + k) + k, ici avec k = 2.

Pourquoi les autres réponses sont incorrectes :
• a) La commutativité ne s''applique pas à la soustraction (a − b ≠ b − a en général).
• b) La distributivité concerne la multiplication par rapport à l''addition/soustraction.
• c) La conservation des écarts consisterait à ajouter (ou retrancher) la même quantité aux deux termes : (156 + 2) − (98 + 2) = 158 − 100 = 58. Le résultat est le même, mais la démarche de Lucas correspond à la compensation, pas à la conservation des écarts.

La distinction entre compensation et conservation des écarts est un point didactique important pour l''enseignant : les deux stratégies aboutissent au même résultat mais reposent sur des propriétés différentes.',
  'Confondre la compensation avec la conservation des écarts. Dans la conservation des écarts, on modifie les deux termes de la même quantité (156 − 98 → 158 − 100). Dans la compensation, on modifie un seul terme puis on corrige le résultat.', 'valide',
  'Génération Claude — Terminologie Éduscol', 'free', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'b00f0000-0000-0000-0000-000000000005', 'Mathematiques', 'nombres_calcul', 'math_calcul_mental_strategies',
  'Calcul mental — Stratégies', 'Facile', 'qcm',
  'Quelle décomposition permet de calculer le plus rapidement 35 × 12 ?', NULL,
  '[{"id":"a","label":"35 × 10 + 35 × 2 = 350 + 70 = 420"},{"id":"b","label":"30 × 12 + 5 × 12 = 360 + 60 = 420"},{"id":"c","label":"35 × 6 × 2 = 210 × 2 = 420"},{"id":"d","label":"Les trois sont correctes et donnent le même résultat"}]'::jsonb,
  '{"mode":"single","value":"d"}'::jsonb,
  'Les trois décompositions sont correctes et donnent toutes 420.

Analyse de chaque stratégie :

a) 35 × 12 = 35 × 10 + 35 × 2 = 350 + 70 = 420
→ Distributivité de la multiplication sur l''addition : a × (b + c) = a × b + a × c.
On décompose 12 = 10 + 2.

b) 35 × 12 = 30 × 12 + 5 × 12 = 360 + 60 = 420
→ Même propriété de distributivité, mais en décomposant l''autre facteur : 35 = 30 + 5.

c) 35 × 12 = 35 × 6 × 2 = 210 × 2 = 420
→ Associativité de la multiplication et décomposition multiplicative de 12 = 6 × 2.

L''enjeu didactique est fondamental : il n''existe pas une seule « bonne » méthode de calcul mental. La flexibilité calculatoire — c''est-à-dire la capacité à choisir et adapter sa stratégie en fonction des nombres en jeu — est un objectif central des programmes de cycle 3.

L''enseignant doit valoriser la diversité des procédures et amener les élèves à les comparer lors de moments de mise en commun.',
  'Croire qu''une seule décomposition est « la bonne » et rejeter les autres, alors que les trois reposent sur des propriétés mathématiques valides (distributivité et associativité).', 'valide',
  'Génération Claude — Terminologie Éduscol', 'free', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'b00f0000-0000-0000-0000-000000000006', 'Mathematiques', 'nombres_calcul', 'math_calcul_mental_strategies',
  'Calcul mental — Stratégies', 'Facile', 'reponse_courte',
  'Un enseignant demande à ses élèves de calculer 8 × 125. Léa dit : « 8 × 125 = 1 000 parce que 8 × 125 = 8 × (1 000 ÷ 8) = 1 000 ». Le résultat est juste, mais quel est le problème logique dans le raisonnement de Léa ?', NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["raisonnement circulaire","circulaire","cercle vicieux","circularité","raisonnement est circulaire"]}'::jsonb,
  'Le résultat de Léa (1 000) est correct, mais son raisonnement est circulaire.

Le problème logique : Léa écrit 125 = 1 000 ÷ 8, ce qui présuppose déjà que 8 × 125 = 1 000. Elle utilise le résultat qu''elle cherche à démontrer comme point de départ de sa démonstration. C''est un raisonnement circulaire (ou « cercle vicieux »).

Stratégies valides pour calculer 8 × 125 :

Stratégie 1 — Distributivité :
8 × 125 = 8 × 100 + 8 × 25 = 800 + 200 = 1 000.

Stratégie 2 — Décomposition multiplicative et associativité :
8 × 125 = (2 × 2 × 2) × 125 = 2 × (2 × (2 × 125)) = 2 × (2 × 250) = 2 × 500 = 1 000.
Ou encore : 125 × 8 = 125 × 2 × 2 × 2 = 250 × 2 × 2 = 500 × 2 = 1 000.

Stratégie 3 — Couple remarquable :
On sait que 125 × 8 = 1 000 fait partie des « produits remarquables » à connaître, au même titre que 25 × 4 = 100.

Ce type d''exercice développe la compétence « justifier » (domaine « Chercher / Raisonner » des programmes) et sensibilise à la rigueur de l''argumentation mathématique.',
  'Valider le raisonnement de Léa uniquement parce que le résultat est correct, sans repérer la circularité logique (le résultat est utilisé dans la preuve elle-même).', 'valide',
  'Génération Claude — Terminologie Éduscol', 'free', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'b00f0000-0000-0000-0000-000000000007', 'Mathematiques', 'nombres_calcul', 'math_calcul_mental_strategies',
  'Calcul mental — Stratégies', 'Facile', 'qcm',
  'Un élève de CM2 calcule 72 ÷ 4 en faisant : 72 ÷ 2 = 36, puis 36 ÷ 2 = 18. Cette stratégie est valide car…', NULL,
  '[{"id":"a","label":"Diviser par 4 revient à diviser deux fois par 2 (décomposition du diviseur)"},{"id":"b","label":"Il a appliqué la distributivité de la division"},{"id":"c","label":"Il a utilisé la commutativité de la division"},{"id":"d","label":"C''est un hasard, cette méthode ne fonctionne pas toujours"}]'::jsonb,
  '{"mode":"single","value":"a"}'::jsonb,
  'La stratégie est valide car diviser par 4 revient à diviser deux fois par 2.

Fondement mathématique :
4 = 2 × 2, donc a ÷ 4 = a ÷ (2 × 2) = (a ÷ 2) ÷ 2.

Application : 72 ÷ 4 = (72 ÷ 2) ÷ 2 = 36 ÷ 2 = 18.

Cette stratégie repose sur la décomposition multiplicative du diviseur et fonctionne toujours, pas seulement dans ce cas particulier. On peut la généraliser :
• Diviser par 8 = diviser trois fois par 2.
• Diviser par 6 = diviser par 2 puis par 3 (ou inversement).
• Diviser par 12 = diviser par 4 puis par 3, etc.

Pourquoi les autres réponses sont incorrectes :
• b) La distributivité de la division s''appliquerait sur une somme : (a + b) ÷ c = a ÷ c + b ÷ c. Ce n''est pas ce qui est fait ici.
• c) La division n''est pas commutative : a ÷ b ≠ b ÷ a en général.
• d) Ce n''est pas un hasard : la propriété est générale et découle de l''associativité de la multiplication (4 = 2 × 2).

En classe, cette stratégie est particulièrement efficace car les divisions par 2 sont parmi les premières maîtrisées par les élèves. Les programmes de cycle 3 encouragent le recours à ces décompositions pour développer le répertoire de calcul mental.',
  'Penser que cette méthode est un « truc » qui marche par hasard (réponse d), alors qu''elle repose sur une propriété mathématique générale : la décomposition multiplicative du diviseur.', 'valide',
  'Génération Claude — Terminologie Éduscol', 'free', true
) ON CONFLICT (id) DO NOTHING;

-- math_combinatoire_denombrement (organisation_donnees) : 3 -> 10 questions
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fb060000-0000-0000-0000-000000000001',
  'Mathematiques', 'organisation_donnees', 'math_combinatoire_denombrement',
  'Dénombrement et combinatoire — Principes fondamentaux', 'Difficile',
  'qcm',
  'Un élève possède 4 t-shirts différents et 3 pantalons différents. Combien de tenues différentes peut-il composer en choisissant un t-shirt et un pantalon ?',
  NULL,
  '[{"id":"a","label":"7 tenues"},{"id":"b","label":"12 tenues"},{"id":"c","label":"24 tenues"},{"id":"d","label":"4 tenues"}]'::jsonb,
  '{"mode":"single","value":"b"}'::jsonb,
  'On applique le principe multiplicatif (ou principe de multiplication) du dénombrement : lorsqu''on doit faire deux choix successifs indépendants, le nombre total de possibilités est le produit du nombre de choix pour chaque étape. Ici, l''élève choisit d''abord un t-shirt parmi 4 (4 possibilités), puis un pantalon parmi 3 (3 possibilités). Le nombre total de tenues est donc 4 × 3 = 12. Ce principe se généralise : si l''on doit faire k choix successifs avec n₁, n₂, ..., nₖ options, le nombre total de possibilités est n₁ × n₂ × ... × nₖ. C''est le principe fondamental du dénombrement.',
  'Additionner au lieu de multiplier : 4 + 3 = 7. L''addition ne s''applique que lorsque les choix sont disjoints (principe additif), pas lorsqu''on combine des choix indépendants.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fb060000-0000-0000-0000-000000000002',
  'Mathematiques', 'organisation_donnees', 'math_combinatoire_denombrement',
  'Dénombrement et combinatoire — Principes fondamentaux', 'Difficile',
  'vrai_faux',
  'Un restaurant propose en dessert soit une glace (5 parfums au choix) soit un gâteau (3 variétés au choix). Le nombre total de desserts possibles est 5 × 3 = 15.',
  NULL,
  NULL,
  '{"mode":"single","value":"faux"}'::jsonb,
  'C''est faux. Ici, le client choisit soit une glace, soit un gâteau : les deux choix sont disjoints (mutuellement exclusifs). On applique donc le principe additif : le nombre total de desserts est 5 + 3 = 8. Le principe multiplicatif s''appliquerait si le client devait choisir une glace ET un gâteau (par exemple un menu avec les deux). La distinction entre « ou » (addition) et « et » (multiplication) est fondamentale en dénombrement. Principe additif : si deux événements A et B sont disjoints, |A ∪ B| = |A| + |B|. Principe multiplicatif : si deux choix sont indépendants, le nombre de couples est |A| × |B|.',
  'Appliquer systématiquement le principe multiplicatif sans analyser si les choix sont combinés (« et ») ou alternatifs (« ou »). Ici, « soit... soit... » indique des choix disjoints → addition.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fb060000-0000-0000-0000-000000000003',
  'Mathematiques', 'organisation_donnees', 'math_combinatoire_denombrement',
  'Dénombrement et combinatoire — Principes fondamentaux', 'Difficile',
  'reponse_courte',
  'De combien de façons peut-on ranger 5 livres différents sur une étagère ?',
  NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["120","5! = 120","5!=120"]}'::jsonb,
  'Il s''agit de compter le nombre de permutations de 5 éléments distincts. Pour la 1ʳᵉ position, on a 5 choix ; pour la 2ᵉ position, il reste 4 livres ; pour la 3ᵉ, 3 livres ; pour la 4ᵉ, 2 livres ; pour la dernière, 1 seul livre. Par le principe multiplicatif : 5 × 4 × 3 × 2 × 1 = 5! = 120 arrangements possibles. De manière générale, le nombre de permutations de n objets distincts est n! (n factorielle). La factorielle croît très rapidement : 10! = 3 628 800. Ce concept est fondamental en combinatoire et intervient dans les calculs de probabilités.',
  'Confondre avec une puissance : répondre 5⁵ = 3125 (ce serait le cas si on pouvait remettre chaque livre avant de choisir le suivant, c''est-à-dire un tirage avec remise).',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fb060000-0000-0000-0000-000000000004',
  'Mathematiques', 'organisation_donnees', 'math_combinatoire_denombrement',
  'Dénombrement et combinatoire — Principes fondamentaux', 'Difficile',
  'qcm',
  'Un comité de 3 personnes doit être formé à partir d''un groupe de 7 personnes. Combien de comités différents peut-on former ?',
  NULL,
  '[{"id":"a","label":"21"},{"id":"b","label":"35"},{"id":"c","label":"210"},{"id":"d","label":"343"}]'::jsonb,
  '{"mode":"single","value":"b"}'::jsonb,
  'L''ordre dans lequel on choisit les membres du comité n''a pas d''importance : {Alice, Bob, Clara} est le même comité que {Bob, Clara, Alice}. Il s''agit donc d''une combinaison (et non d''un arrangement). Le nombre de combinaisons de 3 éléments parmi 7 est C(7,3) = 7! / (3! × 4!) = (7 × 6 × 5) / (3 × 2 × 1) = 210 / 6 = 35. La formule générale est C(n,k) = n! / (k! × (n−k)!). La clé pour distinguer combinaison et arrangement est de se demander : « L''ordre compte-t-il ? » Si oui → arrangement ; si non → combinaison. Former un comité = l''ordre ne compte pas → combinaison.',
  'Calculer un arrangement (7 × 6 × 5 = 210) au lieu d''une combinaison. L''arrangement compterait comme distincts les comités {A,B,C}, {A,C,B}, {B,A,C}, etc. Pour un comité, l''ordre ne compte pas, donc on divise par 3! = 6.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fb060000-0000-0000-0000-000000000005',
  'Mathematiques', 'organisation_donnees', 'math_combinatoire_denombrement',
  'Dénombrement et combinatoire — Principes fondamentaux', 'Difficile',
  'qcm',
  'Un glacier propose 4 parfums : vanille, chocolat, fraise, pistache. Un enfant veut choisir 2 boules de parfums différents. On utilise un arbre de dénombrement. Combien de branches terminales comporte l''arbre, et combien de choix distincts y a-t-il (l''ordre des boules ne comptant pas) ?',
  NULL,
  '[{"id":"a","label":"12 branches, 6 choix distincts"},{"id":"b","label":"8 branches, 4 choix distincts"},{"id":"c","label":"16 branches, 8 choix distincts"},{"id":"d","label":"12 branches, 12 choix distincts"}]'::jsonb,
  '{"mode":"single","value":"a"}'::jsonb,
  'L''arbre de dénombrement se construit en deux niveaux. Au premier niveau, on choisit le premier parfum (4 possibilités). Au second niveau, on choisit le second parfum parmi les 3 restants (parfums différents). L''arbre a donc 4 × 3 = 12 branches terminales. Mais comme l''ordre ne compte pas (une boule vanille-chocolat = une boule chocolat-vanille), chaque choix est compté deux fois dans l''arbre. Le nombre de choix distincts est 12 / 2 = 6. On retrouve C(4,2) = 4! / (2! × 2!) = 6. L''arbre de dénombrement est un outil visuel précieux en cycle 3 pour initier les élèves au dénombrement systématique.',
  'Oublier de diviser par 2 quand l''ordre ne compte pas, et répondre 12 choix distincts au lieu de 6.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fb060000-0000-0000-0000-000000000006',
  'Mathematiques', 'organisation_donnees', 'math_combinatoire_denombrement',
  'Dénombrement et combinatoire — Principes fondamentaux', 'Difficile',
  'reponse_courte',
  'Dans le triangle de Pascal, la 5ᵉ ligne (en commençant par la ligne 0) est : 1, 5, 10, 10, 5, 1. Que vaut C(5, 2) ?',
  NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["10","C(5,2) = 10","C(5,2)=10"]}'::jsonb,
  'Dans le triangle de Pascal, la ligne n contient les coefficients binomiaux C(n, 0), C(n, 1), ..., C(n, n). La 5ᵉ ligne est : C(5,0) = 1, C(5,1) = 5, C(5,2) = 10, C(5,3) = 10, C(5,4) = 5, C(5,5) = 1. Donc C(5,2) = 10, qui est le 3ᵉ nombre de la ligne (en comptant à partir de la position 0). On vérifie par la formule : C(5,2) = 5! / (2! × 3!) = 120 / (2 × 6) = 10. Le triangle de Pascal possède de nombreuses propriétés : symétrie (C(n,k) = C(n, n−k)), relation de Pascal (C(n,k) = C(n−1, k−1) + C(n−1, k)), et la somme de chaque ligne vaut 2ⁿ.',
  'Se tromper dans l''indexation : confondre la 5ᵉ ligne (qui commence à la ligne 0) avec la ligne qui commence par 1, 4, 6, 4, 1 (qui est la ligne 4). Bien repérer que la ligne n commence par C(n,0) = 1 et contient n + 1 termes.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fb060000-0000-0000-0000-000000000007',
  'Mathematiques', 'organisation_donnees', 'math_combinatoire_denombrement',
  'Dénombrement et combinatoire — Principes fondamentaux', 'Difficile',
  'qcm',
  'Un jeu de loterie demande de choisir 5 numéros parmi 49 (l''ordre ne compte pas et il n''y a pas de répétition). Combien de grilles différentes sont possibles ?',
  NULL,
  '[{"id":"a","label":"254 251 200"},{"id":"b","label":"1 906 884"},{"id":"c","label":"1 906 884 ou moins selon les doublons"},{"id":"d","label":"5 × 49 = 245"}]'::jsonb,
  '{"mode":"single","value":"b"}'::jsonb,
  'On choisit 5 numéros parmi 49 sans répétition et sans tenir compte de l''ordre : c''est une combinaison. Le nombre de grilles possibles est C(49,5) = 49! / (5! × 44!). Calculons étape par étape : C(49,5) = (49 × 48 × 47 × 46 × 45) / (5 × 4 × 3 × 2 × 1) = 228 826 080 / 120 = 1 906 884. Il y a donc 1 906 884 grilles possibles. Si l''on joue une seule grille, la probabilité de gagner le gros lot est de 1 / 1 906 884, soit environ 0,0000524 %. Ce type de calcul illustre concrètement l''utilité des combinaisons et permet de comprendre pourquoi les chances de gagner à la loterie sont si faibles.',
  'Calculer un arrangement (49 × 48 × 47 × 46 × 45 = 228 826 080) sans diviser par 5! = 120. L''arrangement compte l''ordre, mais dans une loterie, la grille {3, 12, 25, 38, 47} est la même que {47, 38, 25, 12, 3}.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

