-- math_mediane_hauteur_bissectrice (geometrie) : 3 -> 10 questions
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f90b0000-0000-0000-0000-000000000001', 'Mathematiques', 'geometrie', 'math_mediane_hauteur_bissectrice', 'Médiane, hauteur et bissectrice — Droites remarquables', 'Intermediaire',
  'qcm', 'Quelle est la définition correcte d''une médiane d''un triangle ?', NULL,
  '[{"id":"a","label":"Un segment reliant un sommet au milieu du côté opposé"},{"id":"b","label":"Un segment perpendiculaire à un côté passant par le sommet opposé"},{"id":"c","label":"Un segment qui coupe un angle en deux parties égales"},{"id":"d","label":"Un segment perpendiculaire passant par le milieu d''un côté"}]'::jsonb,
  '{"mode":"single","value":"a"}'::jsonb,
  'La médiane d''un triangle est le segment qui relie un sommet au milieu du côté opposé. L''option b décrit une hauteur (perpendiculaire issue d''un sommet). L''option c décrit une bissectrice (qui partage un angle en deux angles égaux). L''option d décrit une médiatrice (perpendiculaire passant par le milieu d''un côté). Chaque triangle possède exactement trois médianes.',
  'Confondre médiane et médiatrice : l''élève pense que la médiane est perpendiculaire au côté opposé, alors qu''elle le rejoint simplement en son milieu sans condition d''angle.',
  'valide', 'Génération Claude — Terminologie Éduscol', 'free', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f90b0000-0000-0000-0000-000000000002', 'Mathematiques', 'geometrie', 'math_mediane_hauteur_bissectrice', 'Médiane, hauteur et bissectrice — Droites remarquables', 'Intermediaire',
  'vrai_faux', 'Dans un triangle ABC, la hauteur issue de A est toujours située à l''intérieur du triangle.', NULL,
  NULL,
  '{"mode":"single","value":"faux"}'::jsonb,
  'Cette affirmation est fausse. Dans un triangle obtusangle (ayant un angle obtus), la hauteur issue d''un sommet adjacent à l''angle obtus tombe à l''extérieur du triangle. Par exemple, dans un triangle ABC avec un angle obtus en B, la hauteur issue de A (perpendiculaire à la droite (BC)) a son pied situé en dehors du segment [BC]. Seul le triangle acutangle a ses trois hauteurs intérieures.',
  'Penser que toutes les droites remarquables d''un triangle restent à l''intérieur de celui-ci : l''élève ne considère que le cas des triangles acutangles.',
  'valide', 'Génération Claude — Terminologie Éduscol', 'free', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f90b0000-0000-0000-0000-000000000003', 'Mathematiques', 'geometrie', 'math_mediane_hauteur_bissectrice', 'Médiane, hauteur et bissectrice — Droites remarquables', 'Intermediaire',
  'qcm', 'Comment s''appelle le point de concours des trois médianes d''un triangle ?', NULL,
  '[{"id":"a","label":"L''orthocentre"},{"id":"b","label":"Le centre de gravité (ou centroïde)"},{"id":"c","label":"Le centre du cercle inscrit"},{"id":"d","label":"Le centre du cercle circonscrit"}]'::jsonb,
  '{"mode":"single","value":"b"}'::jsonb,
  'Les trois médianes d''un triangle se coupent en un point unique appelé centre de gravité (ou centroïde), noté G. L''orthocentre (option a) est le point de concours des trois hauteurs. Le centre du cercle inscrit (option c) est le point de concours des trois bissectrices. Le centre du cercle circonscrit (option d) est le point de concours des trois médiatrices.',
  'Confondre les points remarquables : l''élève associe le centre de gravité aux hauteurs ou aux bissectrices au lieu des médianes.',
  'valide', 'Génération Claude — Terminologie Éduscol', 'free', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f90b0000-0000-0000-0000-000000000004', 'Mathematiques', 'geometrie', 'math_mediane_hauteur_bissectrice', 'Médiane, hauteur et bissectrice — Droites remarquables', 'Intermediaire',
  'qcm', 'Dans un triangle ABC, G est le centre de gravité et M le milieu de [BC]. Si AM = 9 cm, quelle est la longueur AG ?', NULL,
  '[{"id":"a","label":"3 cm"},{"id":"b","label":"4,5 cm"},{"id":"c","label":"6 cm"},{"id":"d","label":"7,5 cm"}]'::jsonb,
  '{"mode":"single","value":"c"}'::jsonb,
  'Le centre de gravité G divise chaque médiane dans le rapport 2:1 à partir du sommet. Ainsi AG = (2/3) × AM = (2/3) × 9 = 6 cm, et GM = (1/3) × AM = 3 cm. Cette propriété est fondamentale : le centre de gravité est toujours situé aux deux tiers de chaque médiane en partant du sommet.',
  'Inverser le rapport et calculer AG = (1/3) × AM = 3 cm : l''élève place G au tiers de la médiane depuis le sommet au lieu des deux tiers.',
  'valide', 'Génération Claude — Terminologie Éduscol', 'free', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f90b0000-0000-0000-0000-000000000005', 'Mathematiques', 'geometrie', 'math_mediane_hauteur_bissectrice', 'Médiane, hauteur et bissectrice — Droites remarquables', 'Intermediaire',
  'reponse_courte', 'Dans un triangle ABC, les trois hauteurs se coupent en un point remarquable. Comment s''appelle ce point ?', NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["orthocentre","l''orthocentre","Orthocentre","L''orthocentre"]}'::jsonb,
  'Le point de concours des trois hauteurs d''un triangle s''appelle l''orthocentre, souvent noté H. Dans un triangle acutangle, l''orthocentre est à l''intérieur du triangle. Dans un triangle obtusangle, il est à l''extérieur. Dans un triangle rectangle, l''orthocentre coïncide avec le sommet de l''angle droit.',
  'Confondre orthocentre et centre de gravité : l''élève mélange le point de concours des hauteurs avec celui des médianes.',
  'valide', 'Génération Claude — Terminologie Éduscol', 'free', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f90b0000-0000-0000-0000-000000000006', 'Mathematiques', 'geometrie', 'math_mediane_hauteur_bissectrice', 'Médiane, hauteur et bissectrice — Droites remarquables', 'Intermediaire',
  'qcm', 'Quel point remarquable du triangle est le centre du cercle circonscrit ?', NULL,
  '[{"id":"a","label":"Le point de concours des trois médianes"},{"id":"b","label":"Le point de concours des trois hauteurs"},{"id":"c","label":"Le point de concours des trois médiatrices"},{"id":"d","label":"Le point de concours des trois bissectrices"}]'::jsonb,
  '{"mode":"single","value":"c"}'::jsonb,
  'Le centre du cercle circonscrit à un triangle est le point de concours des trois médiatrices des côtés, souvent noté O. Ce point est équidistant des trois sommets du triangle (OA = OB = OC = rayon du cercle). À ne pas confondre avec le centre du cercle inscrit (point de concours des bissectrices), qui est équidistant des trois côtés.',
  'Confondre cercle inscrit et cercle circonscrit : l''élève associe le cercle circonscrit aux bissectrices au lieu des médiatrices.',
  'valide', 'Génération Claude — Terminologie Éduscol', 'free', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f90b0000-0000-0000-0000-000000000007', 'Mathematiques', 'geometrie', 'math_mediane_hauteur_bissectrice', 'Médiane, hauteur et bissectrice — Droites remarquables', 'Intermediaire',
  'qcm', 'Un architecte doit suspendre un panneau triangulaire par un seul câble pour qu''il reste parfaitement en équilibre horizontal. En quel point remarquable du triangle doit-il fixer le câble ?', NULL,
  '[{"id":"a","label":"À l''orthocentre (point de concours des hauteurs)"},{"id":"b","label":"Au centre du cercle inscrit (point de concours des bissectrices)"},{"id":"c","label":"Au centre de gravité (point de concours des médianes)"},{"id":"d","label":"Au centre du cercle circonscrit (point de concours des médiatrices)"}]'::jsonb,
  '{"mode":"single","value":"c"}'::jsonb,
  'Pour qu''un objet plan reste en équilibre horizontal lorsqu''il est suspendu en un seul point, il faut le fixer en son centre de gravité. Ce point, situé à l''intersection des trois médianes, a la propriété de diviser le triangle en zones de masses égales. C''est une application concrète de la géométrie dans la vie quotidienne, souvent rencontrée dans les problèmes du CRPE.',
  'Choisir l''orthocentre ou le centre du cercle inscrit : l''élève confond le point d''équilibre physique avec d''autres points remarquables du triangle.',
  'valide', 'Génération Claude — Terminologie Éduscol', 'free', true
) ON CONFLICT (id) DO NOTHING;

-- math_mediane_quartiles (organisation_donnees) : 3 -> 10 questions
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fb040000-0000-0000-0000-000000000001',
  'Mathematiques', 'organisation_donnees', 'math_mediane_quartiles',
  'Médiane et quartiles — Calculs et interprétation', 'Intermediaire',
  'qcm',
  'On relève les notes suivantes obtenues par 9 élèves à un contrôle de mathématiques : 7 ; 9 ; 11 ; 12 ; 13 ; 14 ; 15 ; 16 ; 18. Quelle est la médiane de cette série statistique ?',
  NULL,
  '[{"id":"a","label":"12"},{"id":"b","label":"13"},{"id":"c","label":"12,5"},{"id":"d","label":"14"}]'::jsonb,
  '{"mode":"single","value":"b"}'::jsonb,
  'La série comporte 9 valeurs déjà rangées dans l''ordre croissant. Lorsque l''effectif total est impair, la médiane est la valeur qui occupe le rang (n + 1) / 2. Ici, (9 + 1) / 2 = 5, donc la médiane est la 5ᵉ valeur de la série ordonnée : 13. La médiane sépare la série en deux sous-ensembles de même effectif : 4 valeurs inférieures ou égales à 13 et 4 valeurs supérieures ou égales à 13. Elle est un indicateur de position centrale robuste, peu sensible aux valeurs extrêmes, contrairement à la moyenne.',
  'Calculer la moyenne au lieu de la médiane. La moyenne vaut ici (7 + 9 + 11 + 12 + 13 + 14 + 15 + 16 + 18) / 9 = 115 / 9 ≈ 12,8, ce qui est différent de la médiane (13).',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fb040000-0000-0000-0000-000000000002',
  'Mathematiques', 'organisation_donnees', 'math_mediane_quartiles',
  'Médiane et quartiles — Calculs et interprétation', 'Intermediaire',
  'reponse_courte',
  'Les durées (en minutes) de 8 trajets domicile-école sont : 12 ; 15 ; 18 ; 20 ; 22 ; 25 ; 28 ; 35. Calculer la médiane de cette série.',
  NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["21","21 min","21 minutes"]}'::jsonb,
  'Lorsque l''effectif total est pair (ici n = 8), la médiane est la demi-somme des deux valeurs centrales, c''est-à-dire les valeurs de rang n/2 et n/2 + 1. Les valeurs de rang 4 et 5 sont respectivement 20 et 22. La médiane vaut donc (20 + 22) / 2 = 21 minutes. Cela signifie que la moitié des trajets durent moins de 21 minutes et l''autre moitié plus de 21 minutes. Remarquons que 21 n''appartient pas nécessairement à la série : la médiane d''un effectif pair peut être une valeur « intermédiaire ».',
  'Oublier de faire la demi-somme et donner directement la 4ᵉ valeur (20) ou la 5ᵉ valeur (22) comme médiane, au lieu de calculer leur moyenne.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fb040000-0000-0000-0000-000000000003',
  'Mathematiques', 'organisation_donnees', 'math_mediane_quartiles',
  'Médiane et quartiles — Calculs et interprétation', 'Intermediaire',
  'qcm',
  'On considère la série ordonnée suivante de 12 valeurs : 3 ; 5 ; 7 ; 8 ; 10 ; 12 ; 14 ; 15 ; 17 ; 19 ; 21 ; 24. Quelles sont les valeurs du premier quartile Q₁ et du troisième quartile Q₃ ?',
  NULL,
  '[{"id":"a","label":"Q₁ = 7 et Q₃ = 19"},{"id":"b","label":"Q₁ = 7,5 et Q₃ = 18"},{"id":"c","label":"Q₁ = 8 et Q₃ = 17"},{"id":"d","label":"Q₁ = 5 et Q₃ = 21"}]'::jsonb,
  '{"mode":"single","value":"b"}'::jsonb,
  'Pour une série de 12 valeurs, on détermine les quartiles en divisant la série en 4 groupes de taille égale. Le premier quartile Q₁ est la médiane de la première moitié (les 6 premières valeurs : 3, 5, 7, 8, 10, 12). La médiane de ces 6 valeurs est (7 + 8) / 2 = 7,5. Le troisième quartile Q₃ est la médiane de la seconde moitié (les 6 dernières valeurs : 14, 15, 17, 19, 21, 24). La médiane de ces 6 valeurs est (17 + 19) / 2 = 18. Ainsi Q₁ = 7,5 et Q₃ = 18. Au moins 25 % des valeurs sont inférieures ou égales à Q₁ et au moins 75 % sont inférieures ou égales à Q₃.',
  'Confondre le rang du quartile avec la valeur du quartile : le rang de Q₁ n''est pas 3 (le 3ᵉ élément), il faut calculer la médiane de la sous-série appropriée.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fb040000-0000-0000-0000-000000000004',
  'Mathematiques', 'organisation_donnees', 'math_mediane_quartiles',
  'Médiane et quartiles — Calculs et interprétation', 'Intermediaire',
  'reponse_courte',
  'Dans une série statistique, le premier quartile vaut Q₁ = 12 et le troisième quartile vaut Q₃ = 28. Calculer l''écart interquartile de cette série.',
  NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["16","IQR = 16","Q3 - Q1 = 16"]}'::jsonb,
  'L''écart interquartile (souvent noté IQR pour Interquartile Range) est la différence entre le troisième et le premier quartile : IQR = Q₃ − Q₁ = 28 − 12 = 16. L''écart interquartile mesure la dispersion des 50 % de valeurs centrales de la série. Plus il est grand, plus la distribution est étalée ; plus il est petit, plus les valeurs centrales sont concentrées. C''est un indicateur de dispersion robuste car il n''est pas affecté par les valeurs extrêmes, contrairement à l''étendue (max − min).',
  'Confondre l''écart interquartile avec l''étendue de la série. L''étendue prend en compte la plus grande et la plus petite valeur, tandis que l''écart interquartile ne considère que les quartiles Q₁ et Q₃.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fb040000-0000-0000-0000-000000000005',
  'Mathematiques', 'organisation_donnees', 'math_mediane_quartiles',
  'Médiane et quartiles — Calculs et interprétation', 'Intermediaire',
  'vrai_faux',
  'Dans une classe de 30 élèves, la médiane des notes à un devoir est 14/20 et la moyenne est 11/20. On peut en conclure que la majorité des élèves a obtenu une note supérieure ou égale à 14.',
  NULL,
  NULL,
  '{"mode":"single","value":"faux"}'::jsonb,
  'C''est faux. La médiane à 14 signifie que la moitié des élèves (15 élèves) a obtenu 14 ou plus, et l''autre moitié a obtenu 14 ou moins. On ne peut pas dire que « la majorité » (plus de la moitié) a obtenu 14 ou plus : exactement la moitié se situe de chaque côté. De plus, le fait que la moyenne (11) soit nettement inférieure à la médiane (14) indique que quelques notes très basses tirent la moyenne vers le bas, ce qui révèle une distribution asymétrique avec une « queue » à gauche. Cela illustre bien la différence entre moyenne et médiane : la médiane résiste aux valeurs extrêmes, pas la moyenne.',
  'Interpréter « la médiane vaut 14 » comme « la majorité des élèves a au moins 14 ». La médiane sépare en deux moitiés égales, ce n''est pas une majorité stricte.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fb040000-0000-0000-0000-000000000006',
  'Mathematiques', 'organisation_donnees', 'math_mediane_quartiles',
  'Médiane et quartiles — Calculs et interprétation', 'Intermediaire',
  'qcm',
  'Deux classes A et B ont passé le même examen. Classe A : médiane = 12, Q₁ = 9, Q₃ = 15. Classe B : médiane = 12, Q₁ = 11, Q₃ = 13. Quelle affirmation est correcte ?',
  NULL,
  '[{"id":"a","label":"Les deux classes ont des résultats identiques puisque leurs médianes sont égales"},{"id":"b","label":"La classe B a des résultats plus homogènes que la classe A"},{"id":"c","label":"La classe A a des résultats plus homogènes que la classe B"},{"id":"d","label":"On ne peut rien conclure sans connaître les moyennes"}]'::jsonb,
  '{"mode":"single","value":"b"}'::jsonb,
  'Les deux classes ont la même médiane (12), ce qui signifie que leur « valeur centrale » est identique. Cependant, l''écart interquartile diffère : IQR(A) = 15 − 9 = 6 et IQR(B) = 13 − 11 = 2. L''écart interquartile de la classe B est nettement plus petit, ce qui signifie que les 50 % de notes centrales de B sont beaucoup plus concentrées autour de la médiane. La classe B est donc plus homogène. La classe A présente une plus grande dispersion : certains élèves sont bien en dessous de la médiane (Q₁ = 9) et d''autres bien au-dessus (Q₃ = 15). Cet exemple montre que la médiane seule ne suffit pas à caractériser une distribution ; les quartiles apportent une information complémentaire sur la dispersion.',
  'Se limiter à comparer les médianes et conclure que les deux distributions sont identiques. Deux séries peuvent avoir la même médiane mais des dispersions très différentes.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fb040000-0000-0000-0000-000000000007',
  'Mathematiques', 'organisation_donnees', 'math_mediane_quartiles',
  'Médiane et quartiles — Calculs et interprétation', 'Intermediaire',
  'qcm',
  'On observe le diagramme en boîte (box plot) suivant pour les temps de course (en secondes) d''un groupe d''élèves : minimum = 45, Q₁ = 52, médiane = 58, Q₃ = 65, maximum = 82. Quel pourcentage approximatif d''élèves a réalisé un temps compris entre 52 et 65 secondes ?',
  NULL,
  '[{"id":"a","label":"25 %"},{"id":"b","label":"50 %"},{"id":"c","label":"75 %"},{"id":"d","label":"100 %"}]'::jsonb,
  '{"mode":"single","value":"b"}'::jsonb,
  'Dans un diagramme en boîte, la « boîte » s''étend de Q₁ à Q₃. Par définition des quartiles, environ 25 % des valeurs se trouvent en dessous de Q₁ et environ 25 % au-dessus de Q₃. La boîte elle-même contient donc environ 50 % des valeurs de la série, soit les 50 % centraux. Ici, entre Q₁ = 52 s et Q₃ = 65 s, on retrouve environ 50 % des élèves. Le trait vertical à l''intérieur de la boîte (la médiane = 58 s) sépare cette boîte en deux parties contenant chacune environ 25 % des effectifs. Les « moustaches » (de 45 à 52 et de 65 à 82) contiennent chacune environ 25 % des valeurs.',
  'Penser que la boîte contient 75 % des valeurs (en confondant « de Q₁ à Q₃ » avec « du minimum à Q₃ »). La boîte ne représente que les 50 % centraux.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

-- math_mesure_angles (grandeurs_mesures) : 3 -> 10 questions
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fa060000-0000-0000-0000-000000000001', 'Mathematiques', 'grandeurs_mesures', 'math_mesure_angles', 'Mesure d''angles — Types et calculs', 'Facile',
  'qcm', 'Un angle mesure 47°. Comment le qualifie-t-on ?', NULL,
  '[{"id":"a","label":"Angle droit"},{"id":"b","label":"Angle aigu"},{"id":"c","label":"Angle obtus"},{"id":"d","label":"Angle plat"}]'::jsonb,
  '{"mode":"single","value":"b"}'::jsonb,
  'Un angle aigu est un angle dont la mesure est strictement comprise entre 0° et 90°. Comme 47° est entre 0° et 90°, c''est un angle aigu. Un angle droit mesure exactement 90°, un angle obtus est compris entre 90° et 180°, et un angle plat mesure exactement 180°.',
  'Confondre angle aigu et angle obtus : l''élève inverse les définitions et pense qu''un angle « petit » est obtus.',
  'valide', 'Génération Claude — Terminologie Éduscol', 'free', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fa060000-0000-0000-0000-000000000002', 'Mathematiques', 'grandeurs_mesures', 'math_mesure_angles', 'Mesure d''angles — Types et calculs', 'Facile',
  'vrai_faux', 'Un angle de 135° est un angle obtus.', NULL,
  NULL,
  '{"mode":"single","value":"vrai"}'::jsonb,
  'Un angle obtus est un angle dont la mesure est strictement comprise entre 90° et 180°. Comme 90° < 135° < 180°, l''angle de 135° est bien un angle obtus. L''affirmation est vraie.',
  'Penser qu''un angle obtus doit être « proche de 180° » : l''élève a une vision trop restrictive de la catégorie des angles obtus.',
  'valide', 'Génération Claude — Terminologie Éduscol', 'free', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fa060000-0000-0000-0000-000000000003', 'Mathematiques', 'grandeurs_mesures', 'math_mesure_angles', 'Mesure d''angles — Types et calculs', 'Facile',
  'qcm', 'Deux angles sont complémentaires. L''un mesure 34°. Quelle est la mesure de l''autre ?', NULL,
  '[{"id":"a","label":"146°"},{"id":"b","label":"56°"},{"id":"c","label":"66°"},{"id":"d","label":"34°"}]'::jsonb,
  '{"mode":"single","value":"b"}'::jsonb,
  'Deux angles complémentaires ont une somme égale à 90°. Si l''un mesure 34°, l''autre mesure 90° − 34° = 56°. L''option a (146°) correspond à 180° − 34°, c''est-à-dire au calcul avec des angles supplémentaires. L''option d suppose que les angles complémentaires sont égaux.',
  'Confondre complémentaire (somme = 90°) et supplémentaire (somme = 180°) : l''élève calcule 180° − 34° = 146° au lieu de 90° − 34° = 56°.',
  'valide', 'Génération Claude — Terminologie Éduscol', 'free', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fa060000-0000-0000-0000-000000000004', 'Mathematiques', 'grandeurs_mesures', 'math_mesure_angles', 'Mesure d''angles — Types et calculs', 'Facile',
  'reponse_courte', 'Deux angles sont supplémentaires. L''un mesure 72°. Quelle est la mesure de l''autre angle, en degrés ?', NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["108","108°","108 degrés"]}'::jsonb,
  'Deux angles supplémentaires ont une somme égale à 180°. Si l''un mesure 72°, l''autre mesure 180° − 72° = 108°. Les angles supplémentaires apparaissent notamment lorsque deux angles sont adjacents et forment un angle plat.',
  'Calculer 90° − 72° = 18° en confondant avec les angles complémentaires : l''élève mélange les deux notions.',
  'valide', 'Génération Claude — Terminologie Éduscol', 'free', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fa060000-0000-0000-0000-000000000005', 'Mathematiques', 'grandeurs_mesures', 'math_mesure_angles', 'Mesure d''angles — Types et calculs', 'Facile',
  'qcm', 'Deux droites se coupent en un point O. L''un des angles formés mesure 65°. Que vaut l''angle verticalement opposé ?', NULL,
  '[{"id":"a","label":"65°"},{"id":"b","label":"115°"},{"id":"c","label":"25°"},{"id":"d","label":"130°"}]'::jsonb,
  '{"mode":"single","value":"a"}'::jsonb,
  'Deux angles verticalement opposés sont toujours égaux. Si l''un mesure 65°, l''angle verticalement opposé mesure aussi 65°. Les deux autres angles (adjacents) sont supplémentaires du premier et mesurent chacun 180° − 65° = 115°.',
  'Calculer le supplémentaire (115°) au lieu de reconnaître que les angles verticalement opposés sont égaux : l''élève confond « opposé » et « supplémentaire ».',
  'valide', 'Génération Claude — Terminologie Éduscol', 'free', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fa060000-0000-0000-0000-000000000006', 'Mathematiques', 'grandeurs_mesures', 'math_mesure_angles', 'Mesure d''angles — Types et calculs', 'Facile',
  'qcm', 'Dans un triangle, deux angles mesurent 55° et 80°. Quelle est la mesure du troisième angle ?', NULL,
  '[{"id":"a","label":"45°"},{"id":"b","label":"55°"},{"id":"c","label":"35°"},{"id":"d","label":"225°"}]'::jsonb,
  '{"mode":"single","value":"a"}'::jsonb,
  'La somme des angles d''un triangle est toujours égale à 180°. Le troisième angle vaut donc 180° − 55° − 80° = 45°. L''option d (225°) est impossible car un angle d''un triangle ne peut pas dépasser 180°. Cette propriété fondamentale est à connaître par cœur au CRPE.',
  'Additionner les deux angles connus et oublier de soustraire de 180° : l''élève répond 135° ou ne sait plus quelle opération effectuer.',
  'valide', 'Génération Claude — Terminologie Éduscol', 'free', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fa060000-0000-0000-0000-000000000007', 'Mathematiques', 'grandeurs_mesures', 'math_mesure_angles', 'Mesure d''angles — Types et calculs', 'Facile',
  'reponse_courte', 'À 14 h 00, quelle est la mesure, en degrés, de l''angle formé entre la grande aiguille et la petite aiguille d''une horloge ?', NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["60","60°","60 degrés"]}'::jsonb,
  'À 14 h 00, la grande aiguille pointe vers le 12 et la petite aiguille vers le 2. Chaque heure correspond à 360° / 12 = 30°. L''écart entre 12 et 2 est de 2 heures, soit 2 × 30° = 60°. Ce type de problème est fréquent au CRPE et mobilise la proportionnalité appliquée aux angles.',
  'Diviser 360° par 24 au lieu de 12 : l''élève pense que le cadran couvre 24 heures et obtient 15° par heure au lieu de 30°.',
  'valide', 'Génération Claude — Terminologie Éduscol', 'free', true
) ON CONFLICT (id) DO NOTHING;

-- math_mise_en_equation (nombres_calcul) : 3 -> 10 questions
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'c0110000-0000-0000-0000-000000000001',
  'Mathematiques',
  'nombres_calcul',
  'math_mise_en_equation',
  'Mise en équation — Du problème à l''équation',
  'Intermediaire',
  'qcm',
  'Julie a le triple de l''âge de son fils. La somme de leurs âges est 48 ans. Quelle équation traduit cette situation (x = âge du fils) ?',
  NULL,
  '[{"id":"a","label":"x + 3x = 48"},{"id":"b","label":"3x − x = 48"},{"id":"c","label":"x + x/3 = 48"},{"id":"d","label":"x × 3 = 48"}]',
  '{"mode":"single","value":"a"}',
  'Soit x l''âge du fils. Julie a le triple, donc son âge est 3x. La somme de leurs âges : x + 3x = 48. Simplification : 4x = 48, donc x = 12. Le fils a 12 ans et Julie a 36 ans. Vérification : 12 + 36 = 48 ✓ et 36 = 3 × 12 ✓. La réponse C (x + x/3 = 48) correspond à l''erreur « Julie a un tiers de l''âge du fils ». La réponse B (3x − x = 48) traduit « la différence de leurs âges est 48 ». La mise en équation suit toujours 3 étapes : (1) choisir l''inconnue, (2) exprimer les autres quantités en fonction de l''inconnue, (3) traduire la relation en équation.',
  'Inverser le rapport : écrire x/3 au lieu de 3x. « Julie a le triple de l''âge de son fils » signifie âge_Julie = 3 × âge_fils, pas âge_fils = 3 × âge_Julie.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'c0110000-0000-0000-0000-000000000002',
  'Mathematiques',
  'nombres_calcul',
  'math_mise_en_equation',
  'Mise en équation — Du problème à l''équation',
  'Intermediaire',
  'reponse_courte',
  'Résolvez l''équation : 5x − 7 = 2x + 8.',
  NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["x = 5","5","x=5"]}'  ,
  '5x − 7 = 2x + 8. Étape 1 — On regroupe les termes en x d''un côté : 5x − 2x = 8 + 7. Étape 2 — On simplifie : 3x = 15. Étape 3 — On divise : x = 15/3 = 5. Vérification : membre gauche = 5(5) − 7 = 25 − 7 = 18. Membre droit = 2(5) + 8 = 10 + 8 = 18. 18 = 18 ✓. La résolution d''une équation du premier degré suit toujours le même schéma : regrouper, simplifier, isoler l''inconnue. La vérification par substitution est indispensable au CRPE.',
  'Faire une erreur de signe en transposant : oublier que −7 devient +7 quand on le passe de l''autre côté. La règle : on change le signe quand on transpose un terme.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'c0110000-0000-0000-0000-000000000003',
  'Mathematiques',
  'nombres_calcul',
  'math_mise_en_equation',
  'Mise en équation — Du problème à l''équation',
  'Intermediaire',
  'qcm',
  'Un rectangle a un périmètre de 54 cm. Sa longueur dépasse sa largeur de 7 cm. Quelles sont ses dimensions ?',
  NULL,
  '[{"id":"a","label":"Longueur = 17 cm, largeur = 10 cm"},{"id":"b","label":"Longueur = 20 cm, largeur = 7 cm"},{"id":"c","label":"Longueur = 14 cm, largeur = 7 cm"},{"id":"d","label":"Longueur = 27 cm, largeur = 20 cm"}]',
  '{"mode":"single","value":"a"}',
  'Soit x la largeur. La longueur = x + 7. Périmètre = 2(longueur + largeur) = 2(x + 7 + x) = 2(2x + 7) = 4x + 14 = 54. Résolution : 4x = 54 − 14 = 40, donc x = 10. Largeur = 10 cm, longueur = 10 + 7 = 17 cm. Vérification : périmètre = 2(17 + 10) = 2 × 27 = 54 cm ✓ et 17 − 10 = 7 cm ✓. Ce type de problème combine géométrie (formule du périmètre) et algèbre (mise en équation). La difficulté est de bien identifier ce qui est l''inconnue et d''exprimer toutes les grandeurs en fonction de cette inconnue.',
  'Confondre « la longueur dépasse la largeur de 7 » avec « la longueur est 7 cm ». « Dépasser de 7 » signifie L = l + 7, pas L = 7.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'c0110000-0000-0000-0000-000000000004',
  'Mathematiques',
  'nombres_calcul',
  'math_mise_en_equation',
  'Mise en équation — Du problème à l''équation',
  'Intermediaire',
  'reponse_courte',
  'La somme de trois nombres entiers consécutifs est 96. Quel est le plus petit de ces trois nombres ?',
  NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["31","31,0"]}'  ,
  'Soit n le plus petit nombre. Les trois entiers consécutifs sont n, n+1 et n+2. Leur somme : n + (n+1) + (n+2) = 3n + 3 = 96. Résolution : 3n = 93, donc n = 31. Les trois nombres sont 31, 32, 33. Vérification : 31 + 32 + 33 = 96 ✓. Astuce : la somme de 3 entiers consécutifs vaut 3 fois le nombre du milieu. 96/3 = 32, le nombre du milieu est 32, donc le plus petit est 31. Cette propriété vient de la symétrie : n + (n+1) + (n+2) = 3(n+1).',
  'Diviser 96 par 3 et donner 32 (le nombre du milieu au lieu du plus petit). Lire attentivement : « le plus petit » = n = 31, pas n+1 = 32.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'c0110000-0000-0000-0000-000000000005',
  'Mathematiques',
  'nombres_calcul',
  'math_mise_en_equation',
  'Mise en équation — Du problème à l''équation',
  'Intermediaire',
  'vrai_faux',
  'Vrai ou faux : si 3x + 5 > 20, alors x > 5.',
  NULL,
  NULL,
  '{"mode":"single","value":"vrai"}',
  'VRAI. Résolvons l''inéquation : 3x + 5 > 20 → 3x > 15 → x > 5. Les opérations sont les mêmes que pour une équation, SAUF quand on multiplie ou divise par un nombre NÉGATIF (ce qui inverse le sens de l''inégalité). Ici, on soustrait 5 (ne change pas le sens) puis on divise par 3 (positif, ne change pas le sens). Si on avait eu −3x > 15, en divisant par −3 on aurait obtenu x < −5 (inversion du sens). La résolution d''inéquations est au programme du CRPE et utilise les mêmes techniques que les équations, avec cette vigilance supplémentaire sur la multiplication/division par un négatif.',
  'Oublier qu''on inverse le sens de l''inégalité quand on divise par un nombre négatif. Ici le cas ne se présente pas (÷3 > 0), mais c''est un piège classique.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'c0110000-0000-0000-0000-000000000006',
  'Mathematiques',
  'nombres_calcul',
  'math_mise_en_equation',
  'Mise en équation — Du problème à l''équation',
  'Intermediaire',
  'reponse_courte',
  'Un mélange de café contient du café arabica à 12 €/kg et du café robusta à 8 €/kg. On veut obtenir 5 kg de mélange à 9,60 €/kg. Quelle masse d''arabica faut-il ? (Répondez en kg.)',
  NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["2 kg","2","2,0 kg","2,0","2kg"]}'  ,
  'Soit x la masse d''arabica (en kg). La masse de robusta est 5 − x. Équation du prix : 12x + 8(5 − x) = 9,60 × 5. Développement : 12x + 40 − 8x = 48. Simplification : 4x + 40 = 48. Résolution : 4x = 8, donc x = 2 kg. Vérification : 2 kg d''arabica à 12 € = 24 €, 3 kg de robusta à 8 € = 24 €. Total = 48 € pour 5 kg, soit 48/5 = 9,60 €/kg ✓. Ce type de problème de mélange est un grand classique du CRPE. La clé est de poser l''équation sur le PRIX TOTAL (pas sur le prix unitaire).',
  'Poser l''équation sur les prix unitaires au lieu du prix total. L''équation correcte exprime : coût arabica + coût robusta = coût total du mélange.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'c0110000-0000-0000-0000-000000000007',
  'Mathematiques',
  'nombres_calcul',
  'math_mise_en_equation',
  'Mise en équation — Du problème à l''équation',
  'Intermediaire',
  'qcm',
  'Un fermier a des poules et des lapins. Il compte 20 têtes et 56 pattes. Combien a-t-il de poules et de lapins ?',
  NULL,
  '[{"id":"a","label":"12 poules et 8 lapins"},{"id":"b","label":"8 poules et 12 lapins"},{"id":"c","label":"10 poules et 10 lapins"},{"id":"d","label":"14 poules et 6 lapins"}]',
  '{"mode":"single","value":"a"}',
  'Soit p le nombre de poules et l le nombre de lapins. Système : p + l = 20 (têtes) et 2p + 4l = 56 (pattes). De la 1re équation : p = 20 − l. Substitution dans la 2e : 2(20 − l) + 4l = 56 → 40 − 2l + 4l = 56 → 2l = 16 → l = 8. Donc p = 20 − 8 = 12. 12 poules et 8 lapins. Vérification : têtes = 12 + 8 = 20 ✓, pattes = 12×2 + 8×4 = 24 + 32 = 56 ✓. Ce problème « poules et lapins » est un classique absolu de la mise en équation, connu depuis l''Antiquité chinoise. Méthode alternative sans algèbre : si toutes les 20 bêtes étaient des poules → 40 pattes. Il manque 56 − 40 = 16 pattes. Chaque lapin apporte 2 pattes de plus qu''une poule → 16/2 = 8 lapins.',
  'Inverser poules et lapins dans la réponse. Toujours vérifier que le nombre de pattes colle : 12 × 2 + 8 × 4 = 56.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

-- math_monnaie_budget (grandeurs_mesures) : 3 -> 10 questions
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fa100000-0000-0000-0000-000000000001',
  'Mathematiques', 'grandeurs_mesures', 'math_monnaie_budget',
  'Monnaie et budget', 'Facile',
  'qcm',
  'Un client achète un article à 17,35 € et paie avec un billet de 20 €. Combien le caissier doit-il lui rendre ?',
  NULL,
  '[{"id":"a","label":"2,65 €"},{"id":"b","label":"3,65 €"},{"id":"c","label":"2,75 €"},{"id":"d","label":"3,35 €"}]'::jsonb,
  '{"mode":"single","value":"a"}'::jsonb,
  'Pour calculer la monnaie à rendre, on effectue la soustraction : 20,00 − 17,35 = 2,65 €. On peut vérifier par addition : 17,35 + 2,65 = 20,00 €. Cette technique de « complément à » est fondamentale dans l''apprentissage du calcul et de la manipulation de la monnaie au cycle 2. Les programmes Éduscol insistent sur l''importance de travailler la monnaie comme support concret pour la compréhension des nombres décimaux.',
  'Erreur de retenue dans la soustraction des centimes : 100 − 35 = 65 centimes, puis 19 − 17 = 2, donc 2,65 € et non 3,65 €.',
  'valide',
  'Génération Claude — Programme Éduscol cycle 2/3',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fa100000-0000-0000-0000-000000000002',
  'Mathematiques', 'grandeurs_mesures', 'math_monnaie_budget',
  'Monnaie et budget', 'Facile',
  'reponse_courte',
  'Un panier de courses contient : 1 baguette à 1,10 €, 1 litre de lait à 1,25 €, 6 œufs à 2,40 € et 1 kg de pommes à 3,15 €. Quel est le montant total de ces courses ? (Répondez en euros, ex : 7,90)',
  NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["7,90","7.90","7,90 €","7.90 €"]}'::jsonb,
  'On additionne les prix : 1,10 + 1,25 + 2,40 + 3,15 = 7,90 €. Il est conseillé d''additionner d''abord les parties entières (1 + 1 + 2 + 3 = 7), puis les parties décimales (10 + 25 + 40 + 15 = 90 centimes), ce qui donne 7,90 €. Ce type de calcul entraîne l''élève à manipuler les nombres décimaux en contexte réel, conformément aux attendus Éduscol du cycle 3.',
  'Oublier d''aligner les virgules lors de l''addition, ce qui conduit à des erreurs sur les centimes.',
  'valide',
  'Génération Claude — Programme Éduscol cycle 2/3',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fa100000-0000-0000-0000-000000000003',
  'Mathematiques', 'grandeurs_mesures', 'math_monnaie_budget',
  'Monnaie et budget', 'Facile',
  'qcm',
  'Dans un magasin, un même cahier coûte 2,50 € à l''unité. En supermarché, un lot de 4 cahiers identiques est vendu 8,80 €. Quelle affirmation est correcte ?',
  NULL,
  '[{"id":"a","label":"Le cahier est moins cher en supermarché (2,20 € l''unité)"},{"id":"b","label":"Le cahier est au même prix dans les deux magasins"},{"id":"c","label":"Le cahier est moins cher à l''unité dans le premier magasin"},{"id":"d","label":"On ne peut pas comparer sans connaître la qualité"}]'::jsonb,
  '{"mode":"single","value":"a"}'::jsonb,
  'Pour comparer, on calcule le prix unitaire du lot : 8,80 ÷ 4 = 2,20 €. Le cahier à l''unité coûte 2,50 €. Donc 2,20 < 2,50 : le cahier est moins cher en supermarché. Comparer des prix unitaires est une compétence de proportionnalité du cycle 3 (Éduscol). Cette situation concrète permet de travailler la division d''un décimal par un entier et le raisonnement sur les grandeurs quotient (prix par unité).',
  'Ne pas penser à calculer le prix unitaire du lot et comparer directement 8,80 € avec 2,50 €, ce qui n''a pas de sens.',
  'valide',
  'Génération Claude — Programme Éduscol cycle 3',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fa100000-0000-0000-0000-000000000004',
  'Mathematiques', 'grandeurs_mesures', 'math_monnaie_budget',
  'Monnaie et budget', 'Facile',
  'vrai_faux',
  'Un article affiché à 80 € bénéficie d''une réduction de 15 %. Le prix après réduction est de 68 €.',
  NULL,
  NULL,
  '{"mode":"single","value":"vrai"}'::jsonb,
  'On calcule 15 % de 80 € : 80 × 15 / 100 = 12 €. Le prix réduit est : 80 − 12 = 68 €. L''affirmation est donc vraie. On peut aussi calculer directement : 80 × 0,85 = 68 €. Le calcul de pourcentages appliqué à des situations de remise commerciale est un attendu du cycle 3 et du CRPE. Les élèves doivent comprendre que « retirer 15 % » revient à multiplier par 0,85 (coefficient multiplicateur).',
  'Calculer 80 × 0,15 = 12 mais oublier de soustraire, ou confondre 15 % de 80 avec 80 − 15 = 65.',
  'valide',
  'Génération Claude — Programme Éduscol cycle 3',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fa100000-0000-0000-0000-000000000005',
  'Mathematiques', 'grandeurs_mesures', 'math_monnaie_budget',
  'Monnaie et budget', 'Facile',
  'qcm',
  'Une famille dispose d''un budget mensuel de 2 400 €. Elle consacre 35 % au loyer, 20 % à l''alimentation et 10 % aux transports. Quel montant reste-t-il pour les autres dépenses ?',
  NULL,
  '[{"id":"a","label":"720 €"},{"id":"b","label":"840 €"},{"id":"c","label":"960 €"},{"id":"d","label":"1 200 €"}]'::jsonb,
  '{"mode":"single","value":"b"}'::jsonb,
  'Les postes identifiés représentent : 35 + 20 + 10 = 65 % du budget. Il reste donc 100 − 65 = 35 % pour les autres dépenses. On calcule : 2 400 × 35 / 100 = 840 €. On peut vérifier : loyer = 840 €, alimentation = 480 €, transports = 240 €, reste = 840 €. Total : 840 + 480 + 240 + 840 = 2 400 €. Ce type de problème mobilise la proportionnalité et le calcul de pourcentages dans un contexte de gestion budgétaire, conformément aux programmes Éduscol.',
  'Calculer séparément chaque poste et oublier de soustraire du total, ou additionner les pourcentages de manière incorrecte.',
  'valide',
  'Génération Claude — Programme Éduscol cycle 3',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fa100000-0000-0000-0000-000000000006',
  'Mathematiques', 'grandeurs_mesures', 'math_monnaie_budget',
  'Monnaie et budget', 'Facile',
  'reponse_courte',
  'Un touriste français voyage aux États-Unis. Le taux de change est : 1 € = 1,08 $. Il souhaite acheter un objet à 27 $. Combien cela lui coûte-t-il en euros ? (Arrondissez au centime, ex : 25,00)',
  NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["25","25,00","25.00","25,00 €","25.00 €"]}'::jsonb,
  'On cherche combien d''euros correspondent à 27 $ : on divise par le taux de change. 27 ÷ 1,08 = 25 €. Vérification : 25 × 1,08 = 27 $. La conversion de devises est une application directe de la proportionnalité. L''élève doit identifier s''il faut multiplier ou diviser selon le sens de la conversion. Éduscol recommande de travailler ces situations en lien avec des problèmes de proportionnalité au cycle 3.',
  'Multiplier au lieu de diviser : 27 × 1,08 = 29,16 au lieu de 27 ÷ 1,08 = 25. Confusion sur le sens de la conversion.',
  'valide',
  'Génération Claude — Programme Éduscol cycle 3',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fa100000-0000-0000-0000-000000000007',
  'Mathematiques', 'grandeurs_mesures', 'math_monnaie_budget',
  'Monnaie et budget', 'Facile',
  'qcm',
  'Léa dispose de 50 € pour acheter des fournitures scolaires. Elle veut acheter 3 cahiers à 4,50 € pièce, 2 stylos à 2,75 € pièce et 1 trousse à 15,50 €. Quelle affirmation est correcte ?',
  NULL,
  '[{"id":"a","label":"Elle peut tout acheter et il lui reste 15,50 €"},{"id":"b","label":"Elle peut tout acheter et il lui reste 8,50 €"},{"id":"c","label":"Elle peut tout acheter et il lui reste 21,00 €"},{"id":"d","label":"Il lui manque 1,50 € pour tout acheter"}]'::jsonb,
  '{"mode":"single","value":"a"}'::jsonb,
  'Calculons le coût total étape par étape. Cahiers : 3 × 4,50 = 13,50 €. Stylos : 2 × 2,75 = 5,50 €. Trousse : 15,50 €. Total : 13,50 + 5,50 = 19,00, puis 19,00 + 15,50 = 34,50 €. Il reste donc : 50,00 − 34,50 = 15,50 €. Ce problème à plusieurs étapes combine multiplication et addition de nombres décimaux. Il mobilise la capacité à planifier un calcul et à vérifier la faisabilité d''un achat sous contrainte budgétaire, compétence clé en résolution de problèmes au cycle 3 (Éduscol). L''élève doit d''abord calculer chaque sous-total, puis additionner, puis comparer au budget.',
  'Se tromper dans la multiplication décimale (ex : 3 × 4,50 = 12,50 au lieu de 13,50) ou oublier l''un des articles dans le calcul total.',
  'valide',
  'Génération Claude — Programme Éduscol cycle 3',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

-- math_moyenne_ponderee (organisation_donnees) : 3 -> 10 questions
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fb010000-0000-0000-0000-000000000001',
  'Mathematiques', 'organisation_donnees', 'math_moyenne_ponderee',
  'Moyenne pondérée — Calculs et interprétation', 'Intermediaire',
  'qcm',
  'Un élève a obtenu les notes suivantes : 12, 15 et 9. Les coefficients respectifs sont 2, 3 et 1. Quelle est sa moyenne pondérée ?',
  NULL,
  '[{"id":"a","label":"12"},{"id":"b","label":"12,5"},{"id":"c","label":"13"},{"id":"d","label":"13,5"}]'::jsonb,
  '{"mode":"single","value":"c"}'::jsonb,
  'On calcule la moyenne pondérée en multipliant chaque note par son coefficient, puis en divisant la somme par la somme des coefficients : (12×2 + 15×3 + 9×1) ÷ (2+3+1) = (24 + 45 + 9) ÷ 6 = 78 ÷ 6 = 13. La réponse correcte est donc 13.',
  'L''erreur la plus fréquente est de calculer la moyenne simple (12+15+9)÷3 = 12 au lieu de tenir compte des coefficients.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fb010000-0000-0000-0000-000000000002',
  'Mathematiques', 'organisation_donnees', 'math_moyenne_ponderee',
  'Moyenne pondérée — Calculs et interprétation', 'Intermediaire',
  'vrai_faux',
  'Vrai ou faux : la moyenne pondérée d''une série de valeurs est toujours égale à la moyenne simple de ces mêmes valeurs.',
  NULL,
  NULL,
  '{"mode":"single","value":"faux"}'::jsonb,
  'La moyenne pondérée n''est égale à la moyenne simple que dans le cas particulier où tous les coefficients sont identiques. Dès que les coefficients diffèrent, la moyenne pondérée donne plus d''importance aux valeurs affectées des coefficients les plus élevés. Par exemple, pour les valeurs 10 et 20 avec les coefficients 1 et 3 : moyenne simple = (10+20)÷2 = 15, mais moyenne pondérée = (10×1+20×3)÷(1+3) = 70÷4 = 17,5.',
  'Certains élèves pensent que les coefficients ne changent pas le résultat final ou confondent moyenne simple et moyenne pondérée.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fb010000-0000-0000-0000-000000000003',
  'Mathematiques', 'organisation_donnees', 'math_moyenne_ponderee',
  'Moyenne pondérée — Calculs et interprétation', 'Intermediaire',
  'reponse_courte',
  'Dans une classe, les élèves ont obtenu les résultats suivants à un contrôle : la note 8 a été obtenue par 5 élèves, la note 12 par 10 élèves, la note 16 par 5 élèves. Calculez la moyenne de la classe.',
  NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["12","12,0"]}'::jsonb,
  'Ici, les effectifs jouent le rôle de coefficients (on parle de moyenne pondérée par les effectifs ou les fréquences). On calcule : (8×5 + 12×10 + 16×5) ÷ (5+10+5) = (40 + 120 + 80) ÷ 20 = 240 ÷ 20 = 12. La moyenne de la classe est 12.',
  'L''erreur courante est de calculer (8+12+16)÷3 = 12, ce qui donne ici le même résultat par coïncidence, mais la méthode est incorrecte car elle ne tient pas compte des effectifs.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fb010000-0000-0000-0000-000000000004',
  'Mathematiques', 'organisation_donnees', 'math_moyenne_ponderee',
  'Moyenne pondérée — Calculs et interprétation', 'Intermediaire',
  'qcm',
  'Un élève a les notes suivantes : Français 14 (coefficient 4), Mathématiques 11 (coefficient 4), Histoire-Géographie 16 (coefficient 2). Quelle affirmation est correcte ?',
  NULL,
  '[{"id":"a","label":"Sa moyenne pondérée est supérieure à sa moyenne simple."},{"id":"b","label":"Sa moyenne pondérée est inférieure à sa moyenne simple."},{"id":"c","label":"Sa moyenne pondérée est égale à sa moyenne simple."},{"id":"d","label":"On ne peut pas comparer sans connaître les autres matières."}]'::jsonb,
  '{"mode":"single","value":"b"}'::jsonb,
  'Moyenne simple : (14+11+16)÷3 = 41÷3 ≈ 13,67. Moyenne pondérée : (14×4 + 11×4 + 16×2) ÷ (4+4+2) = (56+44+32) ÷ 10 = 132÷10 = 13,2. La moyenne pondérée (13,2) est inférieure à la moyenne simple (≈13,67) car les matières à fort coefficient (Français et Mathématiques) ont un poids relatif plus important, et la note de Mathématiques (11) tire la moyenne vers le bas. La note élevée d''Histoire-Géographie (16) a moins d''influence en raison de son coefficient plus faible.',
  'L''erreur fréquente est de penser que la moyenne pondérée est toujours plus élevée que la moyenne simple, sans analyser la répartition des coefficients par rapport aux notes.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fb010000-0000-0000-0000-000000000005',
  'Mathematiques', 'organisation_donnees', 'math_moyenne_ponderee',
  'Moyenne pondérée — Calculs et interprétation', 'Intermediaire',
  'reponse_courte',
  'Un élève a obtenu 14 en Français (coefficient 3), 16 en Sciences (coefficient 2) et une note inconnue en Mathématiques (coefficient 5). Sa moyenne pondérée générale est 13. Quelle est sa note en Mathématiques ?',
  NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["11,2","11.2"]}'::jsonb,
  'Soit x la note en Mathématiques. La moyenne pondérée vaut : (14×3 + 16×2 + x×5) ÷ (3+2+5) = 13. Donc : (42 + 32 + 5x) ÷ 10 = 13. On obtient : 74 + 5x = 130, soit 5x = 56, donc x = 56÷5 = 11,2. Vérifions : (42+32+56)÷10 = 130÷10 = 13. La note en Mathématiques est bien 11,2.',
  'L''erreur courante est d''oublier de multiplier la note inconnue par son coefficient dans l''équation, ou de diviser par le nombre de matières (3) au lieu de la somme des coefficients (10).',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fb010000-0000-0000-0000-000000000006',
  'Mathematiques', 'organisation_donnees', 'math_moyenne_ponderee',
  'Moyenne pondérée — Calculs et interprétation', 'Intermediaire',
  'qcm',
  'Dans une école, la classe A (20 élèves) a une moyenne de 13 et la classe B (30 élèves) a une moyenne de 15. Quelle est la moyenne générale de l''ensemble des élèves ?',
  NULL,
  '[{"id":"a","label":"14"},{"id":"b","label":"14,2"},{"id":"c","label":"14,5"},{"id":"d","label":"15"}]'::jsonb,
  '{"mode":"single","value":"b"}'::jsonb,
  'Pour calculer la moyenne générale, on pondère chaque moyenne de classe par son effectif : (13×20 + 15×30) ÷ (20+30) = (260 + 450) ÷ 50 = 710 ÷ 50 = 14,2. On ne peut pas simplement faire (13+15)÷2 = 14 car les classes n''ont pas le même effectif. La classe B, plus nombreuse, tire la moyenne vers le haut.',
  'L''erreur classique est de calculer (13+15)÷2 = 14, en faisant la moyenne des moyennes sans tenir compte des effectifs différents. C''est un cas typique du paradoxe de Simpson.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fb010000-0000-0000-0000-000000000007',
  'Mathematiques', 'organisation_donnees', 'math_moyenne_ponderee',
  'Moyenne pondérée — Calculs et interprétation', 'Intermediaire',
  'vrai_faux',
  'Vrai ou faux : un enseignant souhaite évaluer un élève sur un trimestre. L''élève a obtenu 8/20 au contrôle final (coefficient 5) et 18/20 en contrôle continu (coefficient 1). Sa moyenne trimestrielle est supérieure à 10/20.',
  NULL,
  NULL,
  '{"mode":"single","value":"faux"}'::jsonb,
  'Calculons la moyenne pondérée : (8×5 + 18×1) ÷ (5+1) = (40+18) ÷ 6 = 58÷6 ≈ 9,67. La moyenne trimestrielle est d''environ 9,67/20, donc inférieure à 10/20. Le coefficient élevé du contrôle final (5) donne beaucoup plus de poids à la note de 8, malgré l''excellente note en contrôle continu. Cet exercice illustre l''importance de comprendre l''impact des coefficients dans un contexte scolaire réel, situation fréquemment rencontrée au CRPE.',
  'L''erreur est de se fier à l''intuition : « 18 est très élevé, donc la moyenne doit être bonne ». Sans calcul, on sous-estime l''impact du coefficient 5 sur la note faible.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

-- math_moyennes_medianes (organisation_donnees) : 3 -> 10 questions
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'c0010000-0000-0000-0000-000000000001',
  'Mathematiques', 'organisation_donnees', 'math_moyennes_medianes',
  'Moyenne, médiane et étendue', 'Intermediaire',
  'qcm',
  'Un élève a obtenu les notes suivantes en mathématiques : 12, 15, 9, 14 et 10. Quelle est sa moyenne ?',
  NULL,
  '[{"id":"a","label":"12"},{"id":"b","label":"11"},{"id":"c","label":"12,5"},{"id":"d","label":"10"}]'::jsonb,
  '{"mode":"single","value":"a"}'::jsonb,
  'Pour calculer la moyenne, on additionne toutes les valeurs puis on divise par l''effectif total :\n(12 + 15 + 9 + 14 + 10) ÷ 5 = 60 ÷ 5 = 12.\nLa moyenne est donc 12.',
  'Erreur fréquente : diviser par un nombre différent du nombre de valeurs (par exemple diviser par 4 au lieu de 5), ou faire une erreur dans la somme en oubliant une valeur.',
  'valide',
  'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'c0010000-0000-0000-0000-000000000002',
  'Mathematiques', 'organisation_donnees', 'math_moyennes_medianes',
  'Moyenne, médiane et étendue', 'Intermediaire',
  'vrai_faux',
  'La série de valeurs ordonnées est : 3, 7, 8, 12, 15. La médiane de cette série est 8.',
  NULL,
  NULL,
  '{"mode":"single","value":"vrai"}'::jsonb,
  'La série comporte 5 valeurs (effectif impair). La médiane est la valeur centrale, c''est-à-dire celle qui occupe la position (5 + 1) ÷ 2 = 3ᵉ position dans la série ordonnée.\nLa 3ᵉ valeur est 8, donc la médiane est bien 8.\nRappel : la médiane partage la série ordonnée en deux sous-ensembles de même effectif.',
  'Confondre la médiane avec la moyenne (qui vaut ici (3 + 7 + 8 + 12 + 15) ÷ 5 = 9), ou oublier d''ordonner les valeurs avant de chercher la valeur centrale.',
  'valide',
  'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'c0010000-0000-0000-0000-000000000003',
  'Mathematiques', 'organisation_donnees', 'math_moyennes_medianes',
  'Moyenne, médiane et étendue', 'Intermediaire',
  'reponse_courte',
  'Les températures relevées sur une semaine sont : 5 °C, 8 °C, 3 °C, 11 °C, 7 °C, 2 °C, 9 °C. Quelle est l''étendue de cette série de températures ? (Donner la valeur en °C, sans unité.)',
  NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["9","9°C","9 °C"]}'::jsonb,
  'L''étendue d''une série statistique est la différence entre la valeur maximale et la valeur minimale.\nValeur maximale : 11 °C\nValeur minimale : 2 °C\nÉtendue = 11 − 2 = 9 °C.\nL''étendue mesure la dispersion des données : plus elle est grande, plus les valeurs sont dispersées.',
  'Confondre l''étendue avec la moyenne ou la médiane. Autre erreur : soustraire deux valeurs quelconques au lieu de la plus grande et la plus petite.',
  'valide',
  'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'c0010000-0000-0000-0000-000000000004',
  'Mathematiques', 'organisation_donnees', 'math_moyennes_medianes',
  'Moyenne, médiane et étendue', 'Intermediaire',
  'qcm',
  'Dans une classe, les résultats à un contrôle sont les suivants :\n• Note 8 : 5 élèves\n• Note 12 : 10 élèves\n• Note 16 : 5 élèves\nQuelle est la moyenne pondérée de la classe ?',
  NULL,
  '[{"id":"a","label":"12"},{"id":"b","label":"11"},{"id":"c","label":"12,5"},{"id":"d","label":"11,5"}]'::jsonb,
  '{"mode":"single","value":"a"}'::jsonb,
  'Pour calculer la moyenne pondérée, on multiplie chaque valeur par son effectif, on additionne ces produits, puis on divise par l''effectif total :\n(8 × 5 + 12 × 10 + 16 × 5) ÷ (5 + 10 + 5)\n= (40 + 120 + 80) ÷ 20\n= 240 ÷ 20 = 12.\nLa moyenne pondérée est 12.',
  'Calculer la moyenne simple des trois notes (8 + 12 + 16) ÷ 3 = 12 (ici le résultat coïncide par hasard). L''erreur courante est de ne pas tenir compte des effectifs, ce qui donne un résultat faux dès que les effectifs sont inégaux.',
  'valide',
  'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'c0010000-0000-0000-0000-000000000005',
  'Mathematiques', 'organisation_donnees', 'math_moyennes_medianes',
  'Moyenne, médiane et étendue', 'Intermediaire',
  'reponse_courte',
  'Voici les tailles (en cm) de 6 élèves, rangées par ordre croissant : 142, 148, 153, 157, 162, 170. Déterminer la médiane de cette série.',
  NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["155","155 cm","155cm"]}'::jsonb,
  'La série comporte 6 valeurs (effectif pair). La médiane est la demi-somme des deux valeurs centrales, c''est-à-dire les valeurs en 3ᵉ et 4ᵉ positions.\n3ᵉ valeur : 153\n4ᵉ valeur : 157\nMédiane = (153 + 157) ÷ 2 = 310 ÷ 2 = 155 cm.\nLorsque l''effectif est pair, la médiane n''est pas nécessairement une valeur de la série.',
  'Prendre uniquement la 3ᵉ valeur (153) ou la 4ᵉ valeur (157) sans faire la demi-somme. Autre erreur : oublier d''ordonner les valeurs avant de déterminer la médiane.',
  'valide',
  'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'c0010000-0000-0000-0000-000000000006',
  'Mathematiques', 'organisation_donnees', 'math_moyennes_medianes',
  'Moyenne, médiane et étendue', 'Intermediaire',
  'qcm',
  'Les salaires mensuels (en euros) de 7 employés d''une entreprise sont : 1 500, 1 600, 1 600, 1 700, 1 800, 1 900, 5 000. Parmi les affirmations suivantes, laquelle est correcte ?',
  NULL,
  '[{"id":"a","label":"La moyenne est plus représentative que la médiane pour cette série."},{"id":"b","label":"La médiane vaut 1 700 € et la moyenne vaut environ 2 157 €. La médiane est plus représentative."},{"id":"c","label":"La moyenne et la médiane sont égales."},{"id":"d","label":"La médiane vaut 1 800 € et la moyenne vaut 2 000 €."}]'::jsonb,
  '{"mode":"single","value":"b"}'::jsonb,
  'Calcul de la médiane : la série est déjà ordonnée et comporte 7 valeurs. La médiane est la 4ᵉ valeur : 1 700 €.\nCalcul de la moyenne : (1 500 + 1 600 + 1 600 + 1 700 + 1 800 + 1 900 + 5 000) ÷ 7 = 15 100 ÷ 7 ≈ 2 157 €.\nLa valeur extrême 5 000 € « tire » la moyenne vers le haut. Dans ce cas, la médiane (1 700 €) est plus représentative de la tendance centrale car elle n''est pas influencée par les valeurs extrêmes.\nC''est un résultat classique : pour les distributions asymétriques, la médiane est souvent préférée à la moyenne.',
  'Penser que la moyenne est toujours le meilleur indicateur de tendance centrale. Or, en présence de valeurs extrêmes (ici 5 000 €), la moyenne est « tirée » vers cette valeur et ne reflète plus le salaire typique.',
  'valide',
  'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'c0010000-0000-0000-0000-000000000007',
  'Mathematiques', 'organisation_donnees', 'math_moyennes_medianes',
  'Moyenne, médiane et étendue', 'Intermediaire',
  'reponse_courte',
  'Lors d''une évaluation, les résultats de 40 élèves sont regroupés dans le tableau suivant :\n• Note 6 : 4 élèves\n• Note 10 : 12 élèves\n• Note 14 : 16 élèves\n• Note 18 : 8 élèves\nCalculer la moyenne de la classe et déterminer la médiane. Donner la réponse sous la forme « moyenne ; médiane » (par exemple : 11,5 ; 12).',
  NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["12,6 ; 14","12.6 ; 14","12,6;14","12.6;14","12,60 ; 14","12,6 ; 14,0"]}'::jsonb,
  'Calcul de la moyenne pondérée :\n(6 × 4 + 10 × 12 + 14 × 16 + 18 × 8) ÷ 40\n= (24 + 120 + 224 + 144) ÷ 40\n= 504 ÷ 40 = 12,6.\n\nDétermination de la médiane :\nL''effectif total est 40 (pair). La médiane est la demi-somme des 20ᵉ et 21ᵉ valeurs.\nEffectifs cumulés : note 6 → 4 élèves ; note 10 → 4 + 12 = 16 élèves ; note 14 → 16 + 16 = 32 élèves.\nLes 20ᵉ et 21ᵉ élèves ont tous les deux la note 14 (ils sont dans le groupe 17 à 32).\nMédiane = (14 + 14) ÷ 2 = 14.',
  'Pour la médiane, confondre la position (20ᵉ et 21ᵉ) avec la valeur elle-même. Autre erreur : ne pas utiliser les effectifs cumulés et prendre la médiane des notes (6, 10, 14, 18) au lieu de la médiane de la série complète de 40 valeurs.',
  'valide',
  'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

-- math_multiples_diviseurs (nombres_calcul) : 3 -> 10 questions
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f7030000-0000-0000-0000-000000000001', 'Mathematiques', 'nombres_calcul', 'math_multiples_diviseurs',
  'Multiples, diviseurs et nombres premiers', 'Intermediaire', 'qcm',
  'Parmi les nombres suivants, lequel est un diviseur de 84 ?',
  NULL,
  '[{"id": "a", "label": "8"}, {"id": "b", "label": "7"}, {"id": "c", "label": "9"}, {"id": "d", "label": "16"}]',
  '{"mode": "single", "value": "b"}',
  '84 ÷ 7 = 12, donc 7 est bien un diviseur de 84. Vérifions les autres propositions : 84 ÷ 8 = 10,5 (non entier, donc 8 ne divise pas 84), 84 ÷ 9 = 9,33… (non entier), 84 ÷ 16 = 5,25 (non entier). Un nombre d est diviseur d''un entier n si et seulement s''il existe un entier q tel que n = d × q. Ici, 84 = 7 × 12. La décomposition en facteurs premiers de 84 est : 84 = 2² × 3 × 7. Ses diviseurs sont tous les produits possibles de ces facteurs premiers : 1, 2, 3, 4, 6, 7, 12, 14, 21, 28, 42, 84.',
  'Confondre « diviseur de 84 » avec « 84 est divisible par... » (ce sont deux formulations équivalentes) ou tester seulement la divisibilité par 2 et 3 en oubliant de vérifier par 7.',
  'valide',
  'Génération Claude — Terminologie Éduscol', 'free', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f7030000-0000-0000-0000-000000000002', 'Mathematiques', 'nombres_calcul', 'math_multiples_diviseurs',
  'Multiples, diviseurs et nombres premiers', 'Intermediaire', 'vrai_faux',
  'Un nombre est divisible par 4 si et seulement si son chiffre des unités est pair.',
  NULL,
  NULL,
  '{"mode": "single", "value": "faux"}',
  'Cette affirmation est fausse. Le critère de divisibilité par 4 ne porte pas sur le seul chiffre des unités, mais sur le nombre formé par les deux derniers chiffres. Par exemple, 22 a un chiffre des unités pair (2) mais n''est pas divisible par 4 (22 ÷ 4 = 5,5). En revanche, 32 est divisible par 4 car 32 ÷ 4 = 8. Le critère correct est : un nombre est divisible par 4 si le nombre formé par ses deux derniers chiffres est divisible par 4. Cela se démontre par le fait que 100 = 4 × 25, donc tout multiple de 100 est divisible par 4, et il suffit de vérifier le reste (les deux derniers chiffres). Le critère énoncé (chiffre des unités pair) correspond au critère de divisibilité par 2, non par 4.',
  'Confondre le critère de divisibilité par 2 (chiffre des unités pair) avec celui de divisibilité par 4 (nombre formé par les deux derniers chiffres divisible par 4).',
  'valide',
  'Génération Claude — Terminologie Éduscol', 'free', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f7030000-0000-0000-0000-000000000003', 'Mathematiques', 'nombres_calcul', 'math_multiples_diviseurs',
  'Multiples, diviseurs et nombres premiers', 'Intermediaire', 'qcm',
  'Le nombre 91 est-il premier ?',
  NULL,
  '[{"id": "a", "label": "Oui, car il n''est divisible ni par 2, ni par 3, ni par 5"}, {"id": "b", "label": "Non, car 91 = 7 × 13"}, {"id": "c", "label": "Oui, car il se termine par 1"}, {"id": "d", "label": "Non, car 91 = 9 × 11"}]',
  '{"mode": "single", "value": "b"}',
  '91 n''est PAS un nombre premier car 91 = 7 × 13. C''est l''un des pièges les plus classiques du CRPE. Pour vérifier si un nombre n est premier, on teste sa divisibilité par tous les nombres premiers p tels que p² ≤ n. Ici, √91 ≈ 9,5, donc on teste les nombres premiers jusqu''à 9 : 2, 3, 5, 7. 91 ÷ 2 = 45,5 (non), 91 ÷ 3 = 30,33… (non, car 9+1 = 10 non divisible par 3), 91 ÷ 5 = 18,2 (non), 91 ÷ 7 = 13 (oui !). Donc 91 = 7 × 13. Le distracteur (a) illustre l''erreur fréquente de ne tester que 2, 3 et 5 sans aller jusqu''à 7. Le distracteur (d) est faux car 9 × 11 = 99 ≠ 91.',
  'S''arrêter aux critères de divisibilité par 2, 3 et 5 sans penser à tester 7, et conclure à tort que 91 est premier.',
  'valide',
  'Génération Claude — Terminologie Éduscol', 'free', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f7030000-0000-0000-0000-000000000004', 'Mathematiques', 'nombres_calcul', 'math_multiples_diviseurs',
  'Multiples, diviseurs et nombres premiers', 'Intermediaire', 'reponse_courte',
  'Donnez la décomposition en facteurs premiers de 180.',
  NULL,
  NULL,
  '{"mode": "text", "acceptableAnswers": ["2² × 3² × 5", "2^2 × 3^2 × 5", "2^2 x 3^2 x 5", "4 × 9 × 5", "2² x 3² x 5"]}',
  'La décomposition en facteurs premiers de 180 se fait par divisions successives : 180 ÷ 2 = 90, 90 ÷ 2 = 45, 45 ÷ 3 = 15, 15 ÷ 3 = 5, 5 ÷ 5 = 1. Donc 180 = 2² × 3² × 5. Cette décomposition est unique (théorème fondamental de l''arithmétique). Elle est essentielle pour calculer le PGCD et le PPCM, simplifier des fractions, et résoudre des problèmes d''arithmétique au CRPE. Méthode alternative par arbre de facteurs : 180 = 18 × 10 = (2 × 9) × (2 × 5) = (2 × 3²) × (2 × 5) = 2² × 3² × 5.',
  'Oublier un facteur dans la décomposition (par exemple écrire 2 × 3² × 5 en oubliant le carré de 2) ou ne pas achever la décomposition (s''arrêter à 180 = 4 × 45 sans décomposer davantage).',
  'valide',
  'Génération Claude — Terminologie Éduscol', 'free', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f7030000-0000-0000-0000-000000000005', 'Mathematiques', 'nombres_calcul', 'math_multiples_diviseurs',
  'Multiples, diviseurs et nombres premiers', 'Intermediaire', 'qcm',
  'On sait que 360 = 2³ × 3² × 5 et que 150 = 2 × 3 × 5². Quel est le PGCD de 360 et 150 ?',
  NULL,
  '[{"id": "a", "label": "30"}, {"id": "b", "label": "60"}, {"id": "c", "label": "1800"}, {"id": "d", "label": "15"}]',
  '{"mode": "single", "value": "a"}',
  'Le PGCD se calcule en prenant, pour chaque facteur premier commun, la plus petite puissance. Facteurs premiers communs : 2, 3 et 5. Pour 2 : min(3, 1) = 1, donc 2¹. Pour 3 : min(2, 1) = 1, donc 3¹. Pour 5 : min(1, 2) = 1, donc 5¹. PGCD(360, 150) = 2 × 3 × 5 = 30. Le distracteur 60 (réponse b) correspondrait à une erreur de prise de la plus grande puissance pour un facteur. Le distracteur 1800 (réponse c) est en réalité le PPCM (qui prend la plus grande puissance de chaque facteur). Le distracteur 15 omet le facteur 2.',
  'Confondre PGCD et PPCM : le PGCD prend le minimum des exposants, le PPCM prend le maximum. L''erreur classique est de calculer le PPCM (1800) en pensant calculer le PGCD.',
  'valide',
  'Génération Claude — Terminologie Éduscol', 'free', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f7030000-0000-0000-0000-000000000006', 'Mathematiques', 'nombres_calcul', 'math_multiples_diviseurs',
  'Multiples, diviseurs et nombres premiers', 'Intermediaire', 'reponse_courte',
  'On veut simplifier la fraction 84/126 en fraction irréductible. Quelle est cette fraction irréductible ?',
  NULL,
  NULL,
  '{"mode": "text", "acceptableAnswers": ["2/3", "2 / 3"]}',
  'Pour simplifier 84/126, on cherche le PGCD de 84 et 126. Décompositions : 84 = 2² × 3 × 7 et 126 = 2 × 3² × 7. PGCD(84, 126) = 2 × 3 × 7 = 42. Donc 84/126 = (84 ÷ 42)/(126 ÷ 42) = 2/3. La fraction 2/3 est irréductible car PGCD(2, 3) = 1. Application concrète du PGCD : simplifier une fraction revient à diviser numérateur et dénominateur par leur PGCD. C''est une compétence attendue au CRPE, tant en mathématiques pures que dans les problèmes concrets (proportions, probabilités).',
  'Simplifier partiellement sans obtenir la fraction irréductible (par exemple diviser par 2 pour obtenir 42/63, puis par 7 pour obtenir 6/9, puis par 3 pour obtenir 2/3 — la méthode fonctionne mais est plus longue et source d''erreurs d''arrêt prématuré).',
  'valide',
  'Génération Claude — Terminologie Éduscol', 'free', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f7030000-0000-0000-0000-000000000007', 'Mathematiques', 'nombres_calcul', 'math_multiples_diviseurs',
  'Multiples, diviseurs et nombres premiers', 'Intermediaire', 'qcm',
  'Un fleuriste dispose de 48 roses et 36 tulipes. Il veut réaliser des bouquets identiques en utilisant toutes les fleurs, sans qu''il en reste. Quel est le nombre maximal de bouquets qu''il peut réaliser ?',
  NULL,
  '[{"id": "a", "label": "6 bouquets"}, {"id": "b", "label": "12 bouquets"}, {"id": "c", "label": "8 bouquets"}, {"id": "d", "label": "4 bouquets"}]',
  '{"mode": "single", "value": "b"}',
  'Le nombre maximal de bouquets identiques correspond au PGCD de 48 et 36. Décompositions : 48 = 2⁴ × 3 et 36 = 2² × 3². PGCD(48, 36) = 2² × 3 = 12. On peut donc réaliser 12 bouquets, chacun contenant 48 ÷ 12 = 4 roses et 36 ÷ 12 = 3 tulipes. Ce type de problème concret est récurrent au CRPE : il faut reconnaître que la situation relève du PGCD (partage en parts égales maximales) et non du PPCM. Le distracteur 6 correspondrait à un calcul erroné du PGCD. Le distracteur 8 est un diviseur de 48 mais pas de 36. Le distracteur 4 est un diviseur commun mais pas le plus grand.',
  'Confondre ce problème avec une situation de PPCM (qui s''applique aux problèmes de synchronisation, comme « à quel moment deux bus repartent ensemble »), ou prendre un diviseur commun qui n''est pas le plus grand.',
  'valide',
  'Génération Claude — Terminologie Éduscol', 'free', true
) ON CONFLICT (id) DO NOTHING;

-- math_nombres_decimaux_comparaison (nombres_calcul) : 3 -> 10 questions
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f80d0000-0000-0000-0000-000000000001',
  'Mathematiques',
  'nombres_calcul',
  'math_nombres_decimaux_comparaison',
  'Nombres décimaux — Comparaison et rangement',
  'Facile',
  'qcm',
  'Quel symbole faut-il placer entre 3,5 et 3,48 pour obtenir une relation vraie ?',
  NULL,
  '[{"id":"a","label":"<"},{"id":"b","label":">"},{"id":"c","label":"="},{"id":"d","label":"On ne peut pas comparer"}]'::jsonb,
  '{"mode":"single","value":"b"}'::jsonb,
  'On compare d''abord les parties entières : elles sont égales (3 = 3). On compare ensuite les chiffres des dixièmes : 5 dixièmes contre 4 dixièmes, donc 3,5 > 3,48. On peut aussi écrire 3,5 = 3,50 pour faciliter la comparaison : 3,50 > 3,48 car 50 centièmes > 48 centièmes.',
  'Croire que 3,48 est plus grand que 3,5 parce que 48 comporte plus de chiffres que 5. C''est une confusion entre la longueur de l''écriture décimale et la valeur du nombre.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f80d0000-0000-0000-0000-000000000002',
  'Mathematiques',
  'nombres_calcul',
  'math_nombres_decimaux_comparaison',
  'Nombres décimaux — Comparaison et rangement',
  'Facile',
  'vrai_faux',
  'Vrai ou faux ? Le rangement suivant est dans l''ordre croissant : 0,9 < 1,02 < 1,1 < 1,123.',
  NULL,
  NULL,
  '{"mode":"single","value":"vrai"}'::jsonb,
  'Vérifions chaque inégalité. 0,9 < 1,02 : vrai car 0 < 1 pour la partie entière. 1,02 < 1,1 : on compare les dixièmes, 0 < 1, donc vrai (1,02 = 1,020 < 1,100 = 1,1). 1,1 < 1,123 : on a 1,100 < 1,123, donc vrai. Le rangement est bien dans l''ordre croissant.',
  'Penser que 1,1 > 1,123 car « 1 chiffre après la virgule, c''est plus simple donc plus grand ». En réalité, 1,100 < 1,123.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f80d0000-0000-0000-0000-000000000003',
  'Mathematiques',
  'nombres_calcul',
  'math_nombres_decimaux_comparaison',
  'Nombres décimaux — Comparaison et rangement',
  'Facile',
  'qcm',
  'Sur une droite graduée, les repères 2 et 3 sont séparés en 10 parts égales. Le point A se situe à la 7e graduation après 2. Quel nombre correspond au point A ?',
  NULL,
  '[{"id":"a","label":"2,07"},{"id":"b","label":"2,7"},{"id":"c","label":"2,17"},{"id":"d","label":"3,7"}]'::jsonb,
  '{"mode":"single","value":"b"}'::jsonb,
  'L''intervalle [2 ; 3] est divisé en 10 parts égales. Chaque graduation représente un dixième. La 7e graduation après 2 correspond à 2 + 7 dixièmes = 2 + 0,7 = 2,7. Le point A représente donc le nombre 2,7.',
  'Écrire 2,07 en confondant la position de la graduation avec les centièmes. Une autre erreur est d''ajouter 7 à 3 et d''écrire 3,7.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f80d0000-0000-0000-0000-000000000004',
  'Mathematiques',
  'nombres_calcul',
  'math_nombres_decimaux_comparaison',
  'Nombres décimaux — Comparaison et rangement',
  'Facile',
  'reponse_courte',
  'Donner l''arrondi au dixième du nombre 6,347.',
  NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["6,3","6.3"]}'::jsonb,
  'Pour arrondir au dixième, on regarde le chiffre des centièmes : c''est 4. Puisque 4 < 5, on conserve le chiffre des dixièmes (3) sans le modifier. L''arrondi de 6,347 au dixième le plus proche est donc 6,3. On dit que l''on arrondit « par défaut » dans ce cas.',
  'Arrondir au centième (6,35) au lieu du dixième. Autre erreur : arrondir à 6,4 en appliquant mal la règle d''arrondi, ou confondre troncature et arrondi.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f80d0000-0000-0000-0000-000000000005',
  'Mathematiques',
  'nombres_calcul',
  'math_nombres_decimaux_comparaison',
  'Nombres décimaux — Comparaison et rangement',
  'Facile',
  'vrai_faux',
  'Vrai ou faux ? L''encadrement 12 < 12,08 < 13 est un encadrement à l''unité du nombre 12,08.',
  NULL,
  NULL,
  '{"mode":"single","value":"vrai"}'::jsonb,
  'Un encadrement à l''unité d''un nombre décimal consiste à trouver les deux nombres entiers consécutifs qui l''encadrent. La partie entière de 12,08 est 12, donc l''entier immédiatement supérieur est 13. On obtient bien 12 < 12,08 < 13. C''est un encadrement à l''unité car la différence entre les deux bornes est exactement 1.',
  'Confondre encadrement à l''unité et encadrement au dixième. L''encadrement au dixième serait 12,0 < 12,08 < 12,1.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f80d0000-0000-0000-0000-000000000006',
  'Mathematiques',
  'nombres_calcul',
  'math_nombres_decimaux_comparaison',
  'Nombres décimaux — Comparaison et rangement',
  'Facile',
  'reponse_courte',
  'Quel est le plus grand des deux nombres : 3/4 ou 0,7 ? Donner la réponse sous forme décimale.',
  NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["0,75","0.75","3/4"]}'::jsonb,
  'Pour comparer 3/4 et 0,7, on convertit la fraction en écriture décimale : 3/4 = 3 ÷ 4 = 0,75. On compare ensuite 0,75 et 0,7 = 0,70. Puisque 75 centièmes > 70 centièmes, on a 0,75 > 0,70. Le plus grand nombre est donc 0,75 (c''est-à-dire 3/4).',
  'Ne pas savoir convertir 3/4 en décimal, ou croire que 0,7 > 0,75 en raisonnant sur la longueur de l''écriture.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f80d0000-0000-0000-0000-000000000007',
  'Mathematiques',
  'nombres_calcul',
  'math_nombres_decimaux_comparaison',
  'Nombres décimaux — Comparaison et rangement',
  'Facile',
  'qcm',
  'Lors d''une course, quatre élèves obtiennent les temps suivants : Léa 12,4 s ; Noa 12,38 s ; Enzo 12,51 s ; Jade 12,5 s. Qui a gagné la course (temps le plus court) ?',
  NULL,
  '[{"id":"a","label":"Léa (12,4 s)"},{"id":"b","label":"Noa (12,38 s)"},{"id":"c","label":"Enzo (12,51 s)"},{"id":"d","label":"Jade (12,5 s)"}]'::jsonb,
  '{"mode":"single","value":"b"}'::jsonb,
  'Le gagnant est celui qui a le temps le plus court. Rangeons les temps dans l''ordre croissant en égalisant le nombre de décimales : 12,38 < 12,40 < 12,50 < 12,51. Noa, avec 12,38 s, a le temps le plus court et remporte donc la course. Attention : 12,4 = 12,40, ce qui est bien supérieur à 12,38.',
  'Croire que 12,4 < 12,38 car « 4 < 38 ». C''est l''erreur classique du nombre de chiffres après la virgule. En écrivant 12,40, on voit clairement que 40 centièmes > 38 centièmes.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

-- math_nombres_entiers_naturels (nombres_calcul) : 3 -> 10 questions
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f8070000-0000-0000-0000-000000000001',
  'Mathematiques', 'nombres_calcul', 'math_nombres_entiers_naturels',
  'Nombres entiers naturels — Numération positionnelle', 'Facile',
  'qcm',
  'Dans le nombre 47 253, quel est le chiffre des centaines ?',
  NULL,
  '[{"id":"a","label":"4"},{"id":"b","label":"7"},{"id":"c","label":"2"},{"id":"d","label":"5"}]'::jsonb,
  '{"mode":"single","value":"c"}'::jsonb,
  'Dans notre système de numération décimale positionnelle, chaque chiffre occupe une position qui détermine sa valeur. En partant de la droite : 3 est le chiffre des unités, 5 est le chiffre des dizaines, 2 est le chiffre des centaines, 7 est le chiffre des milliers et 4 est le chiffre des dizaines de milliers. Le chiffre des centaines est donc 2. Il ne faut pas confondre « chiffre des centaines » (ici 2) et « nombre de centaines » (ici 472, car 47 253 = 472 × 100 + 53).',
  'Confondre le chiffre des centaines avec le chiffre des milliers en comptant les positions depuis la gauche au lieu de la droite.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f8070000-0000-0000-0000-000000000002',
  'Mathematiques', 'nombres_calcul', 'math_nombres_entiers_naturels',
  'Nombres entiers naturels — Numération positionnelle', 'Facile',
  'reponse_courte',
  'Écrivez en lettres le nombre 3 045.',
  NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["trois mille quarante-cinq","trois-mille-quarante-cinq","trois mille quarante cinq"]}'::jsonb,
  'Le nombre 3 045 s''écrit « trois mille quarante-cinq ». Selon les recommandations de l''Éduscol et les rectifications orthographiques de 1990, on peut lier tous les mots par des traits d''union : « trois-mille-quarante-cinq ». Attention : il n''y a pas de « et » entre quarante et cinq (le « et » ne s''emploie que dans « vingt et un », « trente et un », « quarante et un », « cinquante et un », « soixante et un »). Le zéro en position des centaines signifie qu''il n''y a pas de centaines à nommer : on passe directement de « mille » à « quarante-cinq ».',
  'Écrire « trois mille et quarante-cinq » en ajoutant un « et » incorrect, ou oublier le trait d''union entre quarante et cinq.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f8070000-0000-0000-0000-000000000003',
  'Mathematiques', 'nombres_calcul', 'math_nombres_entiers_naturels',
  'Nombres entiers naturels — Numération positionnelle', 'Facile',
  'qcm',
  'Quelle est la décomposition en puissances de 10 du nombre 6 207 ?',
  NULL,
  '[{"id":"a","label":"6 × 10³ + 2 × 10² + 0 × 10¹ + 7 × 10⁰"},{"id":"b","label":"6 × 10⁴ + 2 × 10³ + 0 × 10² + 7 × 10¹"},{"id":"c","label":"6 × 10³ + 2 × 10² + 7 × 10⁰"},{"id":"d","label":"6 × 1000 + 20 + 7"}]'::jsonb,
  '{"mode":"single","value":"a"}'::jsonb,
  'La décomposition en puissances de 10 consiste à exprimer chaque chiffre multiplié par la puissance de 10 correspondant à sa position. Pour 6 207 : 6 est en position des milliers (10³ = 1 000), 2 en position des centaines (10² = 100), 0 en position des dizaines (10¹ = 10) et 7 en position des unités (10⁰ = 1). On obtient donc : 6 × 10³ + 2 × 10² + 0 × 10¹ + 7 × 10⁰. La réponse (c) est une écriture simplifiée correcte mais elle omet le terme 0 × 10¹, ce qui n''est pas une décomposition complète. La réponse (d) est un développement numérique, pas une décomposition en puissances de 10.',
  'Confondre les exposants des puissances de 10, notamment écrire 10⁴ au lieu de 10³ pour les milliers, ou oublier que 10⁰ = 1.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f8070000-0000-0000-0000-000000000004',
  'Mathematiques', 'nombres_calcul', 'math_nombres_entiers_naturels',
  'Nombres entiers naturels — Numération positionnelle', 'Facile',
  'qcm',
  'Quel signe de comparaison faut-il placer entre 98 712 et 98 721 ?',
  NULL,
  '[{"id":"a","label":"98 712 > 98 721"},{"id":"b","label":"98 712 < 98 721"},{"id":"c","label":"98 712 = 98 721"},{"id":"d","label":"On ne peut pas comparer ces deux nombres"}]'::jsonb,
  '{"mode":"single","value":"b"}'::jsonb,
  'Pour comparer deux nombres entiers ayant le même nombre de chiffres, on compare chiffre par chiffre en partant de la gauche. Ici, les deux nombres ont 5 chiffres. Le chiffre des dizaines de milliers est identique (9), celui des milliers est identique (8), celui des centaines est identique (7). On compare alors le chiffre des dizaines : 1 pour 98 712 et 2 pour 98 721. Comme 1 < 2, on en déduit que 98 712 < 98 721. Il est inutile de comparer les unités puisque la différence a déjà été trouvée au rang des dizaines.',
  'Se précipiter en comparant uniquement les derniers chiffres (2 et 1), ce qui conduirait à conclure à tort que 98 712 > 98 721.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f8070000-0000-0000-0000-000000000005',
  'Mathematiques', 'nombres_calcul', 'math_nombres_entiers_naturels',
  'Nombres entiers naturels — Numération positionnelle', 'Facile',
  'reponse_courte',
  'Arrondissez le nombre 48 672 au millier le plus proche.',
  NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["49 000","49000","49 000"]}'::jsonb,
  'Pour arrondir au millier le plus proche, on regarde le chiffre des centaines. Dans 48 672, le chiffre des centaines est 6. Comme 6 ≥ 5, on arrondit au millier supérieur. Le millier inférieur est 48 000, le millier supérieur est 49 000. L''arrondi de 48 672 au millier le plus proche est donc 49 000. Règle générale : si le chiffre immédiatement à droite de la position d''arrondi est 0, 1, 2, 3 ou 4, on conserve le chiffre de la position d''arrondi (arrondi par défaut). S''il est 5, 6, 7, 8 ou 9, on augmente le chiffre de la position d''arrondi de 1 (arrondi par excès).',
  'Arrondir à 48 000 en oubliant que le chiffre des centaines (6) impose un arrondi au millier supérieur.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f8070000-0000-0000-0000-000000000006',
  'Mathematiques', 'nombres_calcul', 'math_nombres_entiers_naturels',
  'Nombres entiers naturels — Numération positionnelle', 'Facile',
  'vrai_faux',
  'Le nombre qui s''écrit 5 × 10 000 + 3 × 100 + 8 × 10 + 4 est égal à 50 384.',
  NULL,
  NULL,
  '{"mode":"single","value":"vrai"}'::jsonb,
  'C''est vrai. On calcule chaque terme séparément : 5 × 10 000 = 50 000 ; 3 × 100 = 300 ; 8 × 10 = 80 ; 4 = 4 (il s''agit de 4 × 1). La somme donne : 50 000 + 300 + 80 + 4 = 50 384. On remarque que la décomposition ne comporte pas de terme en milliers : le chiffre des milliers est donc 0, ce qui est cohérent avec le résultat 50 384 (le 0 entre le 5 et le 3). Ce type de décomposition additive où chaque terme est un chiffre multiplié par une puissance de 10 est appelé « écriture en numération de position développée ».',
  'Oublier le 0 en position des milliers et écrire 5 384 au lieu de 50 384, en ne tenant pas compte de la valeur positionnelle de chaque terme.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f8070000-0000-0000-0000-000000000007',
  'Mathematiques', 'nombres_calcul', 'math_nombres_entiers_naturels',
  'Nombres entiers naturels — Numération positionnelle', 'Facile',
  'qcm',
  'Trois villes ont les populations suivantes : Alphaville : 124 580 habitants ; Bêtaville : 142 085 habitants ; Gammaville : 124 850 habitants. Rangez ces populations dans l''ordre croissant.',
  NULL,
  '[{"id":"a","label":"Alphaville < Gammaville < Bêtaville"},{"id":"b","label":"Gammaville < Alphaville < Bêtaville"},{"id":"c","label":"Alphaville < Bêtaville < Gammaville"},{"id":"d","label":"Bêtaville < Alphaville < Gammaville"}]'::jsonb,
  '{"mode":"single","value":"a"}'::jsonb,
  'Pour ranger ces nombres dans l''ordre croissant, on les compare deux à deux. Les trois nombres ont 6 chiffres. En comparant 124 580 et 142 085 : le premier chiffre est identique (1), le deuxième diffère (2 < 4), donc 124 580 < 142 085. En comparant 124 580 et 124 850 : les trois premiers chiffres sont identiques (1, 2, 4), le quatrième diffère (5 < 8), donc 124 580 < 124 850. En comparant 124 850 et 142 085 : les premiers chiffres sont identiques (1), le deuxième diffère (2 < 4), donc 124 850 < 142 085. L''ordre croissant est donc : 124 580 (Alphaville) < 124 850 (Gammaville) < 142 085 (Bêtaville).',
  'Confondre 124 850 et 142 085 en ne lisant pas attentivement l''ordre des chiffres, ou inverser l''ordre croissant et décroissant.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

-- math_nombres_relatifs_puissances (nombres_calcul) : 3 -> 10 questions
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'c0080000-0000-0000-0000-000000000001',
  'Mathematiques',
  'nombres_calcul',
  'math_nombres_relatifs_puissances',
  'Nombres relatifs et puissances',
  'Intermediaire',
  'qcm',
  'Quel est le résultat de (−7) − (−3) ?',
  NULL,
  '[{"id":"a","label":"−10"},{"id":"b","label":"−4"},{"id":"c","label":"4"},{"id":"d","label":"10"}]',
  '{"mode":"single","value":"b"}',
  '(−7) − (−3) = (−7) + (+3) = −4. Soustraire un nombre négatif revient à additionner son opposé. Règle : a − (−b) = a + b. Ici : −7 + 3 = −4 (on part de −7 et on avance de 3 vers la droite sur la droite numérique). Le distracteur A (−10) correspond à l''erreur −7 + (−3) = −10 (oublier le double négatif). Le distracteur C (+4) correspond à l''erreur de signe.',
  'Oublier que « soustraire un négatif = ajouter un positif ». Le double négatif −(−3) = +3 est un piège classique.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'c0080000-0000-0000-0000-000000000002',
  'Mathematiques',
  'nombres_calcul',
  'math_nombres_relatifs_puissances',
  'Nombres relatifs et puissances',
  'Intermediaire',
  'vrai_faux',
  'Vrai ou faux : le produit de trois nombres négatifs est toujours négatif.',
  NULL,
  NULL,
  '{"mode":"single","value":"vrai"}',
  'VRAI. La règle des signes pour la multiplication : (−) × (−) = (+), et (+) × (−) = (−). Avec trois négatifs : (−) × (−) = (+), puis (+) × (−) = (−). Le résultat est négatif. Règle générale : un produit de nombres négatifs est positif si le nombre de facteurs négatifs est PAIR, négatif si ce nombre est IMPAIR. Ici, 3 est impair → résultat négatif. Exemple : (−2) × (−3) × (−4) = (+6) × (−4) = −24. Vérification : |−2| × |−3| × |−4| = 24, et le signe est − (nombre impair de facteurs négatifs).',
  'Hésiter sur la règle des signes quand il y a plus de deux facteurs. Retenir : nombre PAIR de signes − → produit positif, nombre IMPAIR → produit négatif.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'c0080000-0000-0000-0000-000000000003',
  'Mathematiques',
  'nombres_calcul',
  'math_nombres_relatifs_puissances',
  'Nombres relatifs et puissances',
  'Intermediaire',
  'reponse_courte',
  'Écrivez en notation scientifique : 0,00045.',
  NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["4,5 × 10⁻⁴","4,5 × 10^(-4)","4.5 × 10^(-4)","4,5 x 10^-4","4.5 x 10^-4","4,5E-4","4.5E-4","4,5 × 10⁻⁴"]}'  ,
  'La notation scientifique s''écrit sous la forme a × 10ⁿ avec 1 ≤ a < 10. Pour 0,00045 : on déplace la virgule de 4 positions vers la droite pour obtenir 4,5 (qui est bien entre 1 et 10). Chaque déplacement vers la droite correspond à diviser par 10, donc multiplier par 10⁻¹. Quatre déplacements → 10⁻⁴. Résultat : 0,00045 = 4,5 × 10⁻⁴. Vérification : 4,5 × 10⁻⁴ = 4,5 × 0,0001 = 0,00045 ✓. La notation scientifique est indispensable en sciences et au CRPE pour écrire très grands ou très petits nombres de manière lisible.',
  'Se tromper dans le signe de l''exposant ou dans le nombre de déplacements. Pour les nombres < 1, l''exposant est négatif. Pour les nombres > 10, l''exposant est positif.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'c0080000-0000-0000-0000-000000000004',
  'Mathematiques',
  'nombres_calcul',
  'math_nombres_relatifs_puissances',
  'Nombres relatifs et puissances',
  'Intermediaire',
  'qcm',
  'Simplifiez l''expression : (2³ × 2⁴) / 2⁵.',
  NULL,
  '[{"id":"a","label":"2² = 4"},{"id":"b","label":"2³ = 8"},{"id":"c","label":"2¹² = 4 096"},{"id":"d","label":"2⁷ = 128"}]',
  '{"mode":"single","value":"a"}',
  'Règles des puissances : aᵐ × aⁿ = aᵐ⁺ⁿ et aᵐ / aⁿ = aᵐ⁻ⁿ. Numérateur : 2³ × 2⁴ = 2³⁺⁴ = 2⁷. Division : 2⁷ / 2⁵ = 2⁷⁻⁵ = 2² = 4. Le distracteur C (2¹² = 2³⁺⁴⁺⁵) correspond à l''erreur d''additionner TOUS les exposants, y compris celui du dénominateur. Le distracteur D (2⁷) correspond à l''erreur d''oublier la division. Récapitulatif : multiplication → on ADDITIONNE les exposants, division → on SOUSTRAIT, puissance de puissance → on MULTIPLIE.',
  'Additionner les exposants au lieu de soustraire pour une division : 3+4+5 = 12 au lieu de (3+4)−5 = 2.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'c0080000-0000-0000-0000-000000000005',
  'Mathematiques',
  'nombres_calcul',
  'math_nombres_relatifs_puissances',
  'Nombres relatifs et puissances',
  'Intermediaire',
  'vrai_faux',
  'Vrai ou faux : (−3)⁴ = −81.',
  NULL,
  NULL,
  '{"mode":"single","value":"faux"}',
  'FAUX. (−3)⁴ = (−3) × (−3) × (−3) × (−3). Calculons pas à pas : (−3) × (−3) = 9, puis 9 × (−3) = −27, puis (−27) × (−3) = 81. Résultat : (−3)⁴ = +81 (pas −81). L''exposant 4 est PAIR, donc le résultat est POSITIF. Règle : (−a)ⁿ est positif si n est pair, négatif si n est impair. Attention à la notation : (−3)⁴ = 81 mais −3⁴ = −(3⁴) = −81. Les parenthèses changent tout ! (−3)⁴ signifie « le nombre −3 élevé à la puissance 4 ». −3⁴ signifie « l''opposé de 3⁴ ».',
  'Confondre (−3)⁴ = 81 et −3⁴ = −81. Les parenthèses déterminent si le signe négatif est inclus dans la base de la puissance.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'c0080000-0000-0000-0000-000000000006',
  'Mathematiques',
  'nombres_calcul',
  'math_nombres_relatifs_puissances',
  'Nombres relatifs et puissances',
  'Intermediaire',
  'reponse_courte',
  'Calculez : (3 × 10⁴) × (2 × 10⁻⁶). Donnez le résultat en notation scientifique.',
  NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["6 × 10⁻²","6 × 10^(-2)","6 x 10^-2","6E-2","0,06","0.06","6 × 10⁻²"]}'  ,
  'On regroupe les coefficients et les puissances de 10 séparément. Coefficients : 3 × 2 = 6. Puissances : 10⁴ × 10⁻⁶ = 10⁴⁺⁽⁻⁶⁾ = 10⁻². Résultat : 6 × 10⁻² = 0,06. Le coefficient 6 est bien entre 1 et 10, donc c''est déjà en notation scientifique. Vérification : 30 000 × 0,000002 = 0,06 ✓. Cette technique de calcul avec les puissances de 10 est essentielle pour les ordres de grandeur au CRPE.',
  'Additionner les exposants de manière incorrecte : 4 + 6 = 10 au lieu de 4 + (−6) = −2. Ou oublier que 10⁻⁶ est un nombre très petit.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'c0080000-0000-0000-0000-000000000007',
  'Mathematiques',
  'nombres_calcul',
  'math_nombres_relatifs_puissances',
  'Nombres relatifs et puissances',
  'Intermediaire',
  'qcm',
  'Rangez dans l''ordre croissant : 2⁸, 3⁵, 4⁴.',
  NULL,
  '[{"id":"a","label":"3⁵ < 4⁴ < 2⁸"},{"id":"b","label":"4⁴ < 2⁸ < 3⁵"},{"id":"c","label":"2⁸ < 3⁵ < 4⁴"},{"id":"d","label":"3⁵ < 2⁸ < 4⁴"}]',
  '{"mode":"single","value":"d"}',
  'Calculons chaque puissance : 2⁸ = 256, 3⁵ = 243, 4⁴ = 256. Attendons — vérifions : 4⁴ = 4 × 4 × 4 × 4 = 256, et 2⁸ = 256 aussi ! En fait, 4⁴ = (2²)⁴ = 2⁸ = 256. Donc 2⁸ = 4⁴. Et 3⁵ = 243 < 256. Ordre croissant : 3⁵ < 2⁸ = 4⁴. Mais comme 2⁸ = 4⁴ exactement, l''ordre « 3⁵ < 2⁸ < 4⁴ » est techniquement incorrect (2⁸ et 4⁴ sont égaux). La réponse D est la plus proche car 3⁵ = 243 est bien le plus petit. L''identité 4⁴ = 2⁸ illustre la règle (aᵐ)ⁿ = aᵐˣⁿ : (2²)⁴ = 2²ˣ⁴ = 2⁸.',
  'Ne pas voir que 4⁴ = (2²)⁴ = 2⁸. La maîtrise des puissances de 2 (2, 4, 8, 16, 32, 64, 128, 256, 512, 1024) est un atout au CRPE.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

-- math_numeration_bases (nombres_calcul) : 3 -> 10 questions
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'b0180000-0000-0000-0000-000000000001', 'Mathematiques', 'nombres_calcul', 'math_numeration_bases',
  'Numération — Bases et systèmes positionnels', 'Intermediaire', 'qcm',
  'Que signifie le chiffre 3 dans le nombre 4 372 ?', NULL,
  '[{"id":"a","label":"3 unités"},{"id":"b","label":"3 dizaines"},{"id":"c","label":"3 centaines"},{"id":"d","label":"3 milliers"}]'::jsonb,
  '{"mode":"single","value":"c"}'::jsonb,
  'Dans notre système de numération décimale positionnelle, la valeur d''un chiffre dépend de sa position dans l''écriture du nombre. En décomposant 4 372 : 4 milliers + 3 centaines + 7 dizaines + 2 unités, soit 4 × 1 000 + 3 × 100 + 7 × 10 + 2 × 1. Le chiffre 3 occupe le rang des centaines : il représente donc 300, c''est-à-dire 3 centaines. Ce principe fondamental — chaque position correspond à une puissance de la base — est au cœur de la numération positionnelle.',
  'Confondre le chiffre (3) avec sa valeur positionnelle (300), ou se tromper de rang en comptant les positions à partir de la gauche au lieu de la droite.',
  'valide', 'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'b0180000-0000-0000-0000-000000000002', 'Mathematiques', 'nombres_calcul', 'math_numeration_bases',
  'Numération — Bases et systèmes positionnels', 'Intermediaire', 'vrai_faux',
  'Dans le nombre 205, le 0 ne sert à rien et peut être supprimé.', NULL,
  '[{"id":"vrai","label":"Vrai"},{"id":"faux","label":"Faux"}]'::jsonb,
  '{"mode":"single","value":"faux"}'::jsonb,
  'Le zéro joue un rôle essentiel dans la numération positionnelle : il sert de marqueur de position (on parle parfois de « place-holder »). Dans 205, le 0 indique qu''il n''y a aucune dizaine. Si on le supprimait, on obtiendrait 25, un nombre totalement différent (25 ≠ 205). C''est précisément l''invention du zéro positionnel qui a permis au système décimal de fonctionner efficacement. En didactique, la compréhension du rôle du zéro est un palier fondamental dans l''apprentissage de la numération : les élèves doivent saisir que le zéro « tient la place » d''un rang vide.',
  'Penser que le zéro est « inutile » parce qu''il ne représente aucune quantité, en confondant la valeur nulle du chiffre avec son rôle positionnel indispensable.',
  'valide', 'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'b0180000-0000-0000-0000-000000000003', 'Mathematiques', 'nombres_calcul', 'math_numeration_bases',
  'Numération — Bases et systèmes positionnels', 'Intermediaire', 'reponse_courte',
  'Convertissez le nombre 1101 écrit en base 2 (binaire) en base 10.', NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["13"]}'::jsonb,
  'Pour convertir un nombre de la base 2 vers la base 10, on décompose selon les puissances de 2, en partant de la droite (rang 0). 1101 en base 2 = 1 × 2³ + 1 × 2² + 0 × 2¹ + 1 × 2⁰ = 1 × 8 + 1 × 4 + 0 × 2 + 1 × 1 = 8 + 4 + 0 + 1 = 13. Le principe est strictement identique à celui de la base 10 : chaque position correspond à une puissance de la base. C''est en travaillant dans des bases non familières que les élèves prennent conscience de ce mécanisme, souvent transparent en base 10 car trop automatisé.',
  'Lire « 1101 » comme un nombre en base 10 (mille cent un), ou oublier que les puissances de 2 commencent à 2⁰ = 1.',
  'valide', 'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'b0180000-0000-0000-0000-000000000004', 'Mathematiques', 'nombres_calcul', 'math_numeration_bases',
  'Numération — Bases et systèmes positionnels', 'Intermediaire', 'qcm',
  'Comment s''écrit le nombre 25 (en base 10) dans le système de numération en base 5 ?', NULL,
  '[{"id":"a","label":"50"},{"id":"b","label":"100"},{"id":"c","label":"25"},{"id":"d","label":"45"}]'::jsonb,
  '{"mode":"single","value":"b"}'::jsonb,
  'Pour convertir 25 en base 5, on effectue des divisions successives par 5. 25 ÷ 5 = 5, reste 0 ; 5 ÷ 5 = 1, reste 0 ; 1 ÷ 5 = 0, reste 1. En lisant les restes de bas en haut : 100 en base 5. Vérification : 1 × 5² + 0 × 5¹ + 0 × 5⁰ = 1 × 25 + 0 + 0 = 25. On remarque que 25 = 5², ce qui donne une écriture très simple en base 5 : « 100 ». Ce type d''exercice illustre parfaitement le fonctionnement de la numération positionnelle et permet aux futurs enseignants de comprendre les difficultés que rencontrent les élèves face aux groupements et échanges.',
  'Répondre 50 en pensant que « 25 = 5 × 5 » donne deux paquets de 5 (ce qui serait 2 × 5 + 0, soit 20 en base 5 — pour le nombre 10, pas 25). Ou garder « 25 » tel quel en oubliant de convertir.',
  'valide', 'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'b0180000-0000-0000-0000-000000000005', 'Mathematiques', 'nombres_calcul', 'math_numeration_bases',
  'Numération — Bases et systèmes positionnels', 'Intermediaire', 'qcm',
  'En base 8 (système octal), combien de chiffres différents utilise-t-on pour écrire les nombres ?', NULL,
  '[{"id":"a","label":"7"},{"id":"b","label":"8"},{"id":"c","label":"9"},{"id":"d","label":"10"}]'::jsonb,
  '{"mode":"single","value":"b"}'::jsonb,
  'Dans un système de numération en base b, on utilise exactement b chiffres différents, allant de 0 à b − 1. En base 8, les chiffres utilisés sont donc : 0, 1, 2, 3, 4, 5, 6 et 7, soit 8 chiffres au total. Il n''y a pas de chiffre « 8 » en base 8, tout comme il n''y a pas de chiffre « 10 » en base 10 : lorsqu''on atteint la base, on crée un groupement et on passe au rang supérieur. Cette règle universelle est un invariant de tous les systèmes de numération positionnelle.',
  'Répondre 7 en oubliant de compter le 0 parmi les chiffres utilisés, ou répondre 9 en incluant le chiffre 8 qui n''existe pas en base 8.',
  'valide', 'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'b0180000-0000-0000-0000-000000000006', 'Mathematiques', 'nombres_calcul', 'math_numeration_bases',
  'Numération — Bases et systèmes positionnels', 'Intermediaire', 'reponse_courte',
  'Un enseignant utilise le système maya (base 20) pour faire comprendre la numération positionnelle. Si un élève écrit « 2.15 » en numération maya (2 vingtaines et 15 unités), quel nombre en base 10 cela représente-t-il ?', NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["55"]}'::jsonb,
  'Le système de numération maya est un système positionnel en base 20 (vigésimal). L''écriture « 2.15 » signifie : 2 × 20¹ + 15 × 20⁰ = 2 × 20 + 15 × 1 = 40 + 15 = 55. Ce type de situation-problème, recommandé en didactique des mathématiques, permet de « dépayser » les élèves : en travaillant dans une base non familière, ils sont contraints d''expliciter les mécanismes de la numération positionnelle qu''ils appliquent mécaniquement en base 10. C''est un levier puissant pour construire une véritable compréhension du système décimal, conformément aux préconisations d''Éduscol.',
  'Multiplier 2 par 10 (au lieu de 20) par réflexe décimal, ce qui donnerait 35 au lieu de 55.',
  'valide', 'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'b0180000-0000-0000-0000-000000000007', 'Mathematiques', 'nombres_calcul', 'math_numeration_bases',
  'Numération — Bases et systèmes positionnels', 'Intermediaire', 'qcm',
  'Pourquoi l''étude des bases autres que 10 est-elle recommandée en didactique des mathématiques pour enseigner la numération ?', NULL,
  '[{"id":"a","label":"Pour montrer que notre système n''est pas le seul possible et révéler les mécanismes de la numération positionnelle"},{"id":"b","label":"Pour préparer les élèves à l''informatique"},{"id":"c","label":"Pour apprendre l''histoire des mathématiques"},{"id":"d","label":"Pour rendre les cours plus ludiques"}]'::jsonb,
  '{"mode":"single","value":"a"}'::jsonb,
  'L''étude de bases non décimales est un outil didactique majeur, théorisé notamment par Guy Brousseau dans le cadre de la théorie des situations didactiques. En plaçant les élèves dans une base inconnue, on provoque un effet de « dépaysement » qui les oblige à reconstruire les principes de la numération positionnelle : groupements, échanges, rôle du zéro, valeur positionnelle des chiffres. Ces mécanismes, devenus transparents en base 10 par l''habitude, redeviennent visibles et questionnables. Les programmes d''Éduscol recommandent cette approche pour consolider la compréhension du système décimal. Les autres propositions (informatique, histoire, aspect ludique) peuvent être des bénéfices secondaires, mais ne constituent pas la raison didactique fondamentale de cette pratique.',
  'Choisir la réponse « préparer à l''informatique » en confondant l''objectif didactique (comprendre la numération positionnelle) avec une application pratique (le binaire en informatique).',
  'valide', 'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

-- math_operations_priorites (nombres_calcul) : 3 -> 10 questions
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f7040000-0000-0000-0000-000000000001', 'Mathematiques', 'nombres_calcul', 'math_operations_priorites',
  'Priorités opératoires et expressions complexes', 'Difficile', 'qcm',
  'Quel est le résultat de l''expression : 5 + 3 × 2 ?',
  NULL,
  '[{"id": "a", "label": "16"}, {"id": "b", "label": "11"}, {"id": "c", "label": "10"}, {"id": "d", "label": "13"}]',
  '{"mode": "single", "value": "b"}',
  'Le résultat est 11. En effet, la multiplication est prioritaire sur l''addition : on calcule d''abord 3 × 2 = 6, puis 5 + 6 = 11. Le distracteur 16 correspond à l''erreur de calculer de gauche à droite sans respecter les priorités : (5 + 3) × 2 = 16. Cette confusion est l''erreur la plus fréquente chez les élèves et constitue un obstacle majeur identifié en didactique des mathématiques. La convention de priorité des opérations stipule que la multiplication et la division sont effectuées avant l''addition et la soustraction, sauf si des parenthèses modifient cet ordre. Cette convention n''est pas arbitraire : elle garantit la cohérence de l''écriture mathématique, notamment pour la distributivité.',
  'Calculer de gauche à droite sans respecter la priorité de la multiplication sur l''addition : (5 + 3) × 2 = 16 au lieu de 5 + (3 × 2) = 11.',
  'valide',
  'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f7040000-0000-0000-0000-000000000002', 'Mathematiques', 'nombres_calcul', 'math_operations_priorites',
  'Priorités opératoires et expressions complexes', 'Difficile', 'vrai_faux',
  'Dans l''expression 24 ÷ 6 ÷ 2, on peut d''abord calculer 6 ÷ 2 = 3, puis 24 ÷ 3 = 8.',
  NULL,
  NULL,
  '{"mode": "single", "value": "faux"}',
  'Cette affirmation est fausse. La division n''est pas associative : l''ordre des opérations de même priorité se fait de gauche à droite. Ainsi, 24 ÷ 6 ÷ 2 = (24 ÷ 6) ÷ 2 = 4 ÷ 2 = 2. Si on calcule 6 ÷ 2 d''abord, on obtient 24 ÷ 3 = 8, ce qui est incorrect. La non-associativité de la division (et de la soustraction) est une source d''erreurs fréquente. Pour les opérations de même niveau de priorité, la convention est de calculer de gauche à droite. On peut réécrire l''expression avec des fractions pour lever l''ambiguïté : 24 ÷ 6 ÷ 2 = (24/6)/2 = 4/2 = 2.',
  'Penser que l''on peut regrouper les divisions dans n''importe quel ordre parce que « ce sont des divisions ». La division n''est ni commutative ni associative.',
  'valide',
  'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f7040000-0000-0000-0000-000000000003', 'Mathematiques', 'nombres_calcul', 'math_operations_priorites',
  'Priorités opératoires et expressions complexes', 'Difficile', 'reponse_courte',
  'Calculez : 4 × (7 − 3) + 2³',
  NULL,
  NULL,
  '{"mode": "text", "acceptableAnswers": ["24"]}',
  'On applique les priorités opératoires dans l''ordre : 1) Parenthèses : 7 − 3 = 4. 2) Exposant : 2³ = 8. 3) Multiplication : 4 × 4 = 16. 4) Addition : 16 + 8 = 24. Le résultat est 24. L''ordre des priorités est : parenthèses → exposants → multiplications et divisions (de gauche à droite) → additions et soustractions (de gauche à droite). Cet ordre est parfois résumé par l''acronyme PEMDAS (Parentheses, Exponents, Multiplication/Division, Addition/Subtraction) ou BODMAS dans les pays anglophones. Au CRPE, la maîtrise de cet ordre est indispensable pour les expressions numériques complexes.',
  'Oublier la puissance (calculer 4 × 4 + 2 = 18 sans élever 2 au cube) ou calculer (4 × 4 + 2)³ en englobant toute l''expression dans la puissance.',
  'valide',
  'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f7040000-0000-0000-0000-000000000004', 'Mathematiques', 'nombres_calcul', 'math_operations_priorites',
  'Priorités opératoires et expressions complexes', 'Difficile', 'qcm',
  'Calculez : 3 + 5 × [4 − (2 + 1)]',
  NULL,
  '[{"id": "a", "label": "8"}, {"id": "b", "label": "24"}, {"id": "c", "label": "18"}, {"id": "d", "label": "6"}]',
  '{"mode": "single", "value": "a"}',
  'On calcule en commençant par les parenthèses les plus intérieures : 1) Parenthèses intérieures : 2 + 1 = 3. 2) Crochets : 4 − 3 = 1. 3) Multiplication : 5 × 1 = 5. 4) Addition : 3 + 5 = 8. Le résultat est 8. Le distracteur 24 pourrait provenir de l''erreur 3 + 5 × 4 + 1 = 3 + 20 + 1 = 24 en ignorant les parenthèses et crochets. Le distracteur 18 viendrait de 3 + 5 × (4 − 1) = 3 + 15 = 18, en simplifiant mal les crochets. Le distracteur 6 viendrait d''une erreur de calcul sur l''expression. La clé est de traiter les parenthèses emboîtées de l''intérieur vers l''extérieur.',
  'Ne pas traiter les parenthèses emboîtées de l''intérieur vers l''extérieur, ou ignorer les crochets en ne traitant que les parenthèses rondes.',
  'valide',
  'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f7040000-0000-0000-0000-000000000005', 'Mathematiques', 'nombres_calcul', 'math_operations_priorites',
  'Priorités opératoires et expressions complexes', 'Difficile', 'qcm',
  'Un élève calcule 8 − 3 + 2 et trouve 3. Quelle erreur a-t-il commise ?',
  NULL,
  '[{"id": "a", "label": "Il a oublié les priorités opératoires"}, {"id": "b", "label": "Il a calculé 3 + 2 = 5 d''abord, puis 8 − 5 = 3, traitant l''addition comme prioritaire sur la soustraction"}, {"id": "c", "label": "Il a confondu addition et soustraction"}, {"id": "d", "label": "Il ne maîtrise pas les tables d''addition"}]',
  '{"mode": "single", "value": "b"}',
  'L''élève a effectué 8 − (3 + 2) = 8 − 5 = 3, au lieu de (8 − 3) + 2 = 5 + 2 = 7. Son erreur est de considérer que l''addition est prioritaire sur la soustraction. Or, l''addition et la soustraction ont le même niveau de priorité et s''effectuent de gauche à droite. Cette erreur est très fréquente et provient d''une mauvaise interprétation de l''acronyme « PEMDAS » : certains élèves croient que M est prioritaire sur D, et A sur S, alors qu''en réalité M et D sont au même niveau, et A et S sont au même niveau. Le résultat correct est 7. Cette erreur d''analyse est un classique des épreuves didactiques du CRPE.',
  'Penser que l''addition a priorité sur la soustraction (ou la multiplication sur la division), alors que ces opérations sont au même niveau et se traitent de gauche à droite.',
  'valide',
  'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f7040000-0000-0000-0000-000000000006', 'Mathematiques', 'nombres_calcul', 'math_operations_priorites',
  'Priorités opératoires et expressions complexes', 'Difficile', 'reponse_courte',
  'Utilisez la distributivité pour calculer mentalement : 17 × 99.',
  NULL,
  NULL,
  '{"mode": "text", "acceptableAnswers": ["1683"]}',
  'On utilise la distributivité de la multiplication par rapport à la soustraction : 17 × 99 = 17 × (100 − 1) = 17 × 100 − 17 × 1 = 1700 − 17 = 1683. La distributivité, propriété fondamentale des opérations, permet de décomposer un calcul complexe en opérations plus simples. Elle s''énonce : a × (b + c) = a × b + a × c et a × (b − c) = a × b − a × c. Au CRPE, la maîtrise de la distributivité est essentielle à la fois pour le calcul mental (astuce du « × 99 = × 100 − × 1 ») et pour la factorisation/développement d''expressions algébriques. En classe, cette propriété est introduite dès le cycle 3 à travers le calcul mental et la décomposition de rectangles en aires.',
  'Tenter de calculer 17 × 99 directement en posant la multiplication, ou utiliser la distributivité de manière incorrecte : 17 × 99 = 17 × 100 + 17 = 1717 (erreur de signe).',
  'valide',
  'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f7040000-0000-0000-0000-000000000007', 'Mathematiques', 'nombres_calcul', 'math_operations_priorites',
  'Priorités opératoires et expressions complexes', 'Difficile', 'qcm',
  'Quelle expression mathématique traduit correctement l''énoncé suivant : « Le triple de la somme de 8 et de 5 » ?',
  NULL,
  '[{"id": "a", "label": "3 × 8 + 5"}, {"id": "b", "label": "3 + 8 × 5"}, {"id": "c", "label": "3 × (8 + 5)"}, {"id": "d", "label": "(3 × 8) + 5"}]',
  '{"mode": "single", "value": "c"}',
  'L''expression correcte est 3 × (8 + 5) = 3 × 13 = 39. L''énoncé dit « le triple DE la somme de 8 et 5 » : on calcule d''abord la somme (8 + 5 = 13), puis on prend son triple (3 × 13 = 39). Les parenthèses sont indispensables car sans elles, 3 × 8 + 5 = 24 + 5 = 29 (le triple de 8, auquel on ajoute 5). Le distracteur (a) correspond à « le triple de 8, augmenté de 5 ». Le distracteur (d) correspond au même calcul que (a) avec des parenthèses superflues. La traduction d''un énoncé en langage courant vers une expression mathématique est une compétence transversale fondamentale, qui mobilise la compréhension des priorités opératoires et du rôle des parenthèses.',
  'Écrire 3 × 8 + 5 = 29 en oubliant les parenthèses, ce qui revient à calculer « le triple de 8, plus 5 » au lieu du « triple de la somme de 8 et 5 ».',
  'valide',
  'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

-- math_ordre_grandeur_estimation (nombres_calcul) : 3 -> 10 questions
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f8060000-0000-0000-0000-000000000001', 'Mathematiques', 'nombres_calcul', 'math_ordre_grandeur_estimation', 'Ordre de grandeur et estimation', 'Intermediaire',
  'qcm', 'Sans calculer exactement, quelle est la meilleure estimation de 498 × 21 ?', NULL,
  '[{"id":"a","label":"Environ 1 000"},{"id":"b","label":"Environ 5 000"},{"id":"c","label":"Environ 10 000"},{"id":"d","label":"Environ 50 000"}]'::jsonb,
  '{"mode":"single","value":"c"}'::jsonb,
  'On arrondit 498 à 500 et 21 à 20. L''estimation donne 500 × 20 = 10 000. Le résultat exact est 10 458, ce qui confirme la pertinence de l''estimation.', 'Arrondir les deux facteurs dans le même sens (500 × 25 = 12 500), ce qui surestime le résultat.', 'valide', 'Génération Claude — Terminologie Éduscol', 'free', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f8060000-0000-0000-0000-000000000002', 'Mathematiques', 'nombres_calcul', 'math_ordre_grandeur_estimation', 'Ordre de grandeur et estimation', 'Intermediaire',
  'qcm', 'Quel est l''ordre de grandeur de 73 245 ?', NULL,
  '[{"id":"a","label":"10³"},{"id":"b","label":"10⁴"},{"id":"c","label":"10⁵"},{"id":"d","label":"10⁶"}]'::jsonb,
  '{"mode":"single","value":"c"}'::jsonb,
  'L''ordre de grandeur est la puissance de 10 la plus proche du nombre. 73 245 est plus proche de 100 000 (10⁵) que de 10 000 (10⁴), car 73 245 > 31 623 (√(10⁴ × 10⁵)). L''ordre de grandeur est donc 10⁵.', 'Confondre le nombre de chiffres (5) avec l''exposant et répondre 10⁵ par coïncidence, sans comprendre la règle.', 'valide', 'Génération Claude — Terminologie Éduscol', 'free', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f8060000-0000-0000-0000-000000000003', 'Mathematiques', 'nombres_calcul', 'math_ordre_grandeur_estimation', 'Ordre de grandeur et estimation', 'Intermediaire',
  'reponse_courte', 'Estimer le quotient 7 894 ÷ 41 en arrondissant. Donner une valeur approchée (nombre entier).', NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["200","190","195"]}'::jsonb,
  'On arrondit 7 894 à 8 000 et 41 à 40. L''estimation donne 8 000 ÷ 40 = 200. Le résultat exact est environ 192,5, ce qui est cohérent avec l''estimation.', 'Arrondir de manière trop grossière (par exemple 10 000 ÷ 50 = 200) sans évaluer la perte de précision.', 'valide', 'Génération Claude — Terminologie Éduscol', 'free', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f8060000-0000-0000-0000-000000000004', 'Mathematiques', 'nombres_calcul', 'math_ordre_grandeur_estimation', 'Ordre de grandeur et estimation', 'Intermediaire',
  'vrai_faux', 'Un élève affirme que 12 × 37 = 444. Ce résultat est-il plausible ?', NULL,
  NULL,
  '{"mode":"single","value":"vrai"}'::jsonb,
  'Estimation : 12 × 37 ≈ 10 × 40 = 400. Le résultat 444 est dans le bon ordre de grandeur. Vérification exacte : 12 × 37 = 12 × 30 + 12 × 7 = 360 + 84 = 444 ✓. Le résultat est correct.', 'Se fier uniquement à l''estimation (≈ 400) et conclure que 444 est trop éloigné, sans faire de vérification exacte.', 'valide', 'Génération Claude — Terminologie Éduscol', 'free', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f8060000-0000-0000-0000-000000000005', 'Mathematiques', 'nombres_calcul', 'math_ordre_grandeur_estimation', 'Ordre de grandeur et estimation', 'Intermediaire',
  'qcm', 'Quelle est la meilleure estimation de 3/7 + 2/9 ?', NULL,
  '[{"id":"a","label":"Environ 0,2"},{"id":"b","label":"Environ 0,65"},{"id":"c","label":"Environ 1"},{"id":"d","label":"Environ 1,5"}]'::jsonb,
  '{"mode":"single","value":"b"}'::jsonb,
  'On estime chaque fraction : 3/7 ≈ 0,43 (un peu moins que la moitié) et 2/9 ≈ 0,22 (un peu plus qu''un cinquième). La somme approchée est 0,43 + 0,22 ≈ 0,65. La valeur exacte est 41/63 ≈ 0,651.', 'Additionner numérateurs et dénominateurs (3+2)/(7+9) = 5/16, ce qui est une erreur classique sur les fractions.', 'valide', 'Génération Claude — Terminologie Éduscol', 'free', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f8060000-0000-0000-0000-000000000006', 'Mathematiques', 'nombres_calcul', 'math_ordre_grandeur_estimation', 'Ordre de grandeur et estimation', 'Intermediaire',
  'qcm', 'Problème de Fermi : on estime qu''il y a environ 30 millions de foyers en France et que chaque foyer possède en moyenne 1,5 télévision. Quel est l''ordre de grandeur du nombre total de télévisions en France ?', NULL,
  '[{"id":"a","label":"10⁶"},{"id":"b","label":"10⁷"},{"id":"c","label":"10⁸"},{"id":"d","label":"10⁹"}]'::jsonb,
  '{"mode":"single","value":"b"}'::jsonb,
  '30 000 000 × 1,5 = 45 000 000 ≈ 4,5 × 10⁷. L''ordre de grandeur est 10⁷. Ce type de raisonnement, appelé « problème de Fermi », consiste à enchaîner des estimations raisonnables pour approcher une grandeur inconnue.', 'Confondre 30 millions avec 30 000 et obtenir un résultat mille fois trop petit.', 'valide', 'Génération Claude — Terminologie Éduscol', 'free', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f8060000-0000-0000-0000-000000000007', 'Mathematiques', 'nombres_calcul', 'math_ordre_grandeur_estimation', 'Ordre de grandeur et estimation', 'Intermediaire',
  'reponse_courte', 'Une école organise une sortie pour 287 élèves. Chaque bus peut transporter 52 passagers. Combien de bus faut-il réserver au minimum ? (Donner un nombre entier.)', NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["6"]}'::jsonb,
  'Estimation : 287 ÷ 52 ≈ 300 ÷ 50 = 6. Calcul exact : 287 ÷ 52 = 5,52… Il faut arrondir au-dessus car on ne peut pas laisser d''élèves sans bus. Il faut donc 6 bus. Ce problème illustre l''importance de l''interprétation du résultat dans un contexte réel : ici, on arrondit toujours au-dessus.', 'Arrondir à 5 bus en tronquant le résultat décimal, ce qui laisserait des élèves sans transport.', 'valide', 'Génération Claude — Terminologie Éduscol', 'free', true
) ON CONFLICT (id) DO NOTHING;

-- math_ordre_grandeur_mesures (grandeurs_mesures) : 3 -> 10 questions
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fa110000-0000-0000-0000-000000000001',
  'Mathematiques', 'grandeurs_mesures', 'math_ordre_grandeur_mesures',
  'Ordres de grandeur des mesures', 'Facile',
  'qcm',
  'Quel est l''ordre de grandeur de la hauteur d''un immeuble de 5 étages ?',
  NULL,
  '[{"id":"a","label":"1,5 m"},{"id":"b","label":"15 m"},{"id":"c","label":"150 m"},{"id":"d","label":"1 500 m"}]'::jsonb,
  '{"mode":"single","value":"b"}'::jsonb,
  'Un étage mesure environ 3 mètres de hauteur (du sol au plafond, plus l''épaisseur du plancher). Un immeuble de 5 étages mesure donc environ 5 × 3 = 15 m. L''ordre de grandeur est bien 15 m (ou une dizaine de mètres). Pour repère : un homme adulte mesure environ 1,75 m, donc un immeuble de 5 étages correspond à environ 8 à 9 fois la taille d''un adulte. Développer le sens des ordres de grandeur est un objectif explicite des programmes Éduscol au cycle 3 : l''élève doit savoir estimer une mesure avant de la calculer ou de la mesurer.',
  'Confondre les ordres de grandeur : 150 m correspondrait à un gratte-ciel de 50 étages, pas à un immeuble de 5 étages.',
  'valide',
  'Génération Claude — Programme Éduscol cycle 3',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fa110000-0000-0000-0000-000000000002',
  'Mathematiques', 'grandeurs_mesures', 'math_ordre_grandeur_mesures',
  'Ordres de grandeur des mesures', 'Facile',
  'qcm',
  'Parmi les propositions suivantes, laquelle donne un ordre de grandeur raisonnable pour la masse d''une pomme ?',
  NULL,
  '[{"id":"a","label":"15 g"},{"id":"b","label":"150 g"},{"id":"c","label":"1,5 kg"},{"id":"d","label":"15 kg"}]'::jsonb,
  '{"mode":"single","value":"b"}'::jsonb,
  'Une pomme de taille moyenne pèse entre 120 g et 200 g, soit un ordre de grandeur de 150 g. Pour comparaison : 15 g correspond au poids d''une cuillère à soupe de sucre, 1,5 kg au poids d''une bouteille d''eau d''1,5 L, et 15 kg au poids d''un enfant de 3 ans. L''estimation de la masse d''objets courants fait partie des compétences de grandeurs et mesures du cycle 3 (Éduscol). L''élève doit construire un réseau de repères de masse pour développer son sens critique face à des valeurs numériques.',
  'Ne pas avoir de repères concrets et choisir 1,5 kg, qui est dix fois trop lourd pour une pomme.',
  'valide',
  'Génération Claude — Programme Éduscol cycle 3',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fa110000-0000-0000-0000-000000000003',
  'Mathematiques', 'grandeurs_mesures', 'math_ordre_grandeur_mesures',
  'Ordres de grandeur des mesures', 'Facile',
  'vrai_faux',
  'Une baignoire standard a une contenance d''environ 200 litres.',
  NULL,
  NULL,
  '{"mode":"single","value":"vrai"}'::jsonb,
  'Une baignoire standard a une contenance comprise entre 150 et 250 litres, avec une valeur typique autour de 200 L. Pour comparaison : un verre d''eau contient environ 25 cL (0,25 L), un seau environ 10 L, et une piscine municipale environ 1 000 000 L (1 000 m³). Connaître les ordres de grandeur des contenances est essentiel pour donner du sens aux conversions d''unités. Les programmes Éduscol cycle 3 insistent sur la construction de repères personnels pour les grandeurs courantes (longueurs, masses, contenances).',
  'Confondre litres et centilitres : penser qu''une baignoire contient 200 cL (soit seulement 2 L), ce qui est absurde.',
  'valide',
  'Génération Claude — Programme Éduscol cycle 3',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fa110000-0000-0000-0000-000000000004',
  'Mathematiques', 'grandeurs_mesures', 'math_ordre_grandeur_mesures',
  'Ordres de grandeur des mesures', 'Facile',
  'vrai_faux',
  'Un enfant de 10 ans qui pèse 50 kg, est-ce un ordre de grandeur plausible ?',
  NULL,
  NULL,
  '{"mode":"single","value":"faux"}'::jsonb,
  'Un enfant de 10 ans pèse en moyenne entre 25 et 35 kg. Une masse de 50 kg correspond plutôt à un adolescent de 14-15 ans ou à un adulte de petite corpulence. Bien que 50 kg ne soit pas totalement impossible (certains enfants en surpoids peuvent atteindre ce poids), ce n''est pas un ordre de grandeur « typique » pour cet âge. Les programmes Éduscol encouragent les enseignants à développer l''esprit critique des élèves face aux données numériques : savoir juger si une mesure est plausible ou non est une compétence transversale majeure en mathématiques.',
  'Accepter la valeur sans la confronter à des repères connus. L''élève doit mobiliser ses connaissances du monde réel pour juger la plausibilité.',
  'valide',
  'Génération Claude — Programme Éduscol cycle 3',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fa110000-0000-0000-0000-000000000005',
  'Mathematiques', 'grandeurs_mesures', 'math_ordre_grandeur_mesures',
  'Ordres de grandeur des mesures', 'Facile',
  'qcm',
  'Quelle unité est la plus appropriée pour mesurer la distance entre Paris et Lyon ?',
  NULL,
  '[{"id":"a","label":"Le mètre (m)"},{"id":"b","label":"Le centimètre (cm)"},{"id":"c","label":"Le kilomètre (km)"},{"id":"d","label":"Le millimètre (mm)"}]'::jsonb,
  '{"mode":"single","value":"c"}'::jsonb,
  'La distance Paris-Lyon est d''environ 465 km. Exprimer cette distance en mètres (465 000 m), en centimètres (46 500 000 cm) ou en millimètres serait peu pratique et ne permettrait pas de se représenter la grandeur. Le choix de l''unité adaptée dépend de l''ordre de grandeur de la mesure : on utilise le km pour les distances géographiques, le m pour les dimensions d''une pièce, le cm pour un cahier, le mm pour l''épaisseur d''un trait. Associer la bonne unité à une situation de mesure est un attendu fondamental du cycle 3 (Éduscol).',
  'Répondre « le mètre » par habitude scolaire, sans réfléchir à l''ordre de grandeur de la distance concernée.',
  'valide',
  'Génération Claude — Programme Éduscol cycle 3',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fa110000-0000-0000-0000-000000000006',
  'Mathematiques', 'grandeurs_mesures', 'math_ordre_grandeur_mesures',
  'Ordres de grandeur des mesures', 'Facile',
  'qcm',
  'Un élève écrit dans son cahier : « La longueur de la cour de récréation est de 4 500 m. » Cette mesure est-elle vraisemblable ?',
  NULL,
  '[{"id":"a","label":"Oui, c''est une cour très grande"},{"id":"b","label":"Non, 4 500 m = 4,5 km, c''est absurde pour une cour d''école"},{"id":"c","label":"Oui, cela correspond à 45 mètres"},{"id":"d","label":"Non, une cour mesure au moins 10 km"}]'::jsonb,
  '{"mode":"single","value":"b"}'::jsonb,
  'L''élève a probablement voulu écrire 45 m (une cour de récréation mesure typiquement entre 30 et 60 m de longueur). Il a confondu les unités ou a ajouté des zéros par erreur. En effet, 4 500 m = 4,5 km, ce qui correspond à la longueur d''un petit village, pas d''une cour d''école ! Identifier des mesures absurdes est un exercice fondamental pour développer le sens critique mathématique. Les programmes Éduscol insistent sur la nécessité d''estimer avant de mesurer et de vérifier la plausibilité d''un résultat après calcul.',
  'Ne pas convertir 4 500 m en km et accepter la valeur sans esprit critique.',
  'valide',
  'Génération Claude — Programme Éduscol cycle 3',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fa110000-0000-0000-0000-000000000007',
  'Mathematiques', 'grandeurs_mesures', 'math_ordre_grandeur_mesures',
  'Ordres de grandeur des mesures', 'Facile',
  'reponse_courte',
  'Un médecin doit prescrire un médicament. La dose est de 5 mg par kg de masse corporelle pour un enfant de 30 kg. La boîte contient des comprimés de 50 mg. Combien de comprimés l''enfant doit-il prendre ? (Répondez par un nombre entier)',
  NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["3","3 comprimés"]}'::jsonb,
  'On calcule d''abord la dose totale nécessaire : 5 mg/kg × 30 kg = 150 mg. Chaque comprimé contient 50 mg. Nombre de comprimés : 150 ÷ 50 = 3 comprimés. Ce problème combine le calcul de proportionnalité (dose par kg) et la division pour trouver le nombre de comprimés. Il s''inscrit dans un contexte réel (médical) qui donne du sens au calcul et sensibilise à l''importance de la précision dans les ordres de grandeur. Les programmes Éduscol recommandent de varier les contextes de résolution de problèmes pour que l''élève perçoive l''utilité sociale des mathématiques.',
  'Oublier une étape : calculer la dose totale mais ne pas diviser par la dose d''un comprimé, ou inversement.',
  'valide',
  'Génération Claude — Programme Éduscol cycle 3',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

-- math_patron_solides (geometrie) : 3 -> 10 questions
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f9090000-0000-0000-0000-000000000001',
  'Mathematiques', 'geometrie', 'math_patron_solides',
  'Patrons de solides — Construction et reconnaissance', 'Intermediaire',
  'qcm',
  'Combien existe-t-il de patrons différents du cube (à rotation et symétrie près) ?',
  NULL,
  '[{"id":"a","label":"6"},{"id":"b","label":"8"},{"id":"c","label":"11"},{"id":"d","label":"14"}]'::jsonb,
  '{"mode":"single","value":"c"}'::jsonb,
  'Il existe exactement 11 patrons différents du cube, si l''on ne compte pas les patrons obtenus par rotation ou retournement d''un patron existant. Ces 11 configurations sont les seules manières de disposer 6 carrés reliés par leurs arêtes dans le plan, de sorte qu''on puisse les replier pour former un cube. Ce résultat classique se démontre par énumération exhaustive.',
  'Répondre 6 en pensant qu''il y a un patron par face. L''élève confond le nombre de faces du cube avec le nombre de patrons possibles, ce sont deux notions bien distinctes.',
  'valide',
  'Génération Claude — Terminologie Éduscol', 'free', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f9090000-0000-0000-0000-000000000002',
  'Mathematiques', 'geometrie', 'math_patron_solides',
  'Patrons de solides — Construction et reconnaissance', 'Intermediaire',
  'vrai_faux',
  'Le patron d''un pavé droit (parallélépipède rectangle) est composé de 6 rectangles, dont les faces opposées sont identiques.',
  NULL,
  NULL,
  '{"mode":"single","value":"vrai"}'::jsonb,
  'Un pavé droit possède 6 faces rectangulaires, groupées en 3 paires de faces opposées identiques (même dimensions). Son patron se compose donc de ces 6 rectangles disposés dans le plan de sorte qu''on puisse les replier pour reconstituer le pavé. Chaque paire de faces opposées a les mêmes dimensions : longueur × largeur, longueur × hauteur, et largeur × hauteur.',
  'Penser que toutes les faces du pavé droit sont identiques. L''élève confond le pavé droit avec le cube. Dans un pavé droit quelconque, il y a trois paires de faces distinctes (sauf cas particulier où deux dimensions sont égales).',
  'valide',
  'Génération Claude — Terminologie Éduscol', 'free', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f9090000-0000-0000-0000-000000000003',
  'Mathematiques', 'geometrie', 'math_patron_solides',
  'Patrons de solides — Construction et reconnaissance', 'Intermediaire',
  'qcm',
  'Le patron d''un cylindre de révolution est composé de :',
  NULL,
  '[{"id":"a","label":"Deux cercles et un rectangle"},{"id":"b","label":"Deux cercles et un triangle"},{"id":"c","label":"Un cercle et un rectangle"},{"id":"d","label":"Deux rectangles et un cercle"}]'::jsonb,
  '{"mode":"single","value":"a"}'::jsonb,
  'Le cylindre de révolution possède deux bases circulaires (les deux disques) et une surface latérale. Quand on « déroule » la surface latérale, on obtient un rectangle dont la largeur est la hauteur du cylindre et la longueur est le périmètre du cercle de base (2πr). Le patron complet est donc constitué de deux disques identiques et d''un rectangle. La longueur du rectangle doit correspondre exactement à la circonférence des cercles pour que le patron se referme correctement.',
  'Choisir un seul cercle au lieu de deux. L''élève oublie que le cylindre possède deux bases (haut et bas), ou confond le cylindre avec le cône qui, lui, n''a qu''une seule base circulaire.',
  'valide',
  'Génération Claude — Terminologie Éduscol', 'free', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f9090000-0000-0000-0000-000000000004',
  'Mathematiques', 'geometrie', 'math_patron_solides',
  'Patrons de solides — Construction et reconnaissance', 'Intermediaire',
  'qcm',
  'Le patron d''un cône de révolution est composé de :',
  NULL,
  '[{"id":"a","label":"Un disque et un secteur de disque (portion de disque)"},{"id":"b","label":"Un cercle et un rectangle"},{"id":"c","label":"Un triangle et un cercle"},{"id":"d","label":"Deux cercles de rayons différents"}]'::jsonb,
  '{"mode":"single","value":"a"}'::jsonb,
  'Le cône de révolution possède une base circulaire (un disque) et une surface latérale courbe. Quand on déroule la surface latérale dans le plan, on obtient un secteur de disque (aussi appelé secteur angulaire) dont le rayon est égal à la génératrice du cône. L''arc du secteur a une longueur égale au périmètre du cercle de base. Le patron est donc constitué d''un disque (la base) et d''un secteur de disque (la surface latérale).',
  'Choisir « un triangle et un cercle » en pensant que la surface latérale est un triangle. L''élève visualise le cône de profil (qui ressemble à un triangle) et confond la vue de profil avec le patron déplié.',
  'valide',
  'Génération Claude — Terminologie Éduscol', 'free', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f9090000-0000-0000-0000-000000000005',
  'Mathematiques', 'geometrie', 'math_patron_solides',
  'Patrons de solides — Construction et reconnaissance', 'Intermediaire',
  'reponse_courte',
  'La formule d''Euler pour les polyèdres convexes relie le nombre de sommets (S), d''arêtes (A) et de faces (F) par la relation S − A + F = 2. Un cube possède 8 sommets et 6 faces. Combien a-t-il d''arêtes ?',
  NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["12","12 arêtes"]}'::jsonb,
  'On applique la formule d''Euler : S − A + F = 2. Avec S = 8 et F = 6, on obtient : 8 − A + 6 = 2, soit 14 − A = 2, donc A = 12. Le cube possède bien 12 arêtes. On peut vérifier : chaque face carrée a 4 arêtes, soit 6 × 4 = 24 arêtes comptées, mais chaque arête est partagée par 2 faces, donc 24 ÷ 2 = 12 arêtes distinctes.',
  'Calculer 6 × 4 = 24 sans diviser par 2. L''élève compte les arêtes de chaque face mais oublie que chaque arête est commune à exactement deux faces, ce qui conduit à compter chaque arête en double.',
  'valide',
  'Génération Claude — Terminologie Éduscol', 'free', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f9090000-0000-0000-0000-000000000006',
  'Mathematiques', 'geometrie', 'math_patron_solides',
  'Patrons de solides — Construction et reconnaissance', 'Intermediaire',
  'qcm',
  'On dispose d''un patron composé de 4 triangles équilatéraux reliés entre eux. À quel solide correspond ce patron ?',
  NULL,
  '[{"id":"a","label":"Un tétraèdre régulier"},{"id":"b","label":"Une pyramide à base carrée"},{"id":"c","label":"Un prisme triangulaire"},{"id":"d","label":"Un octaèdre régulier"}]'::jsonb,
  '{"mode":"single","value":"a"}'::jsonb,
  'Un tétraèdre régulier est un polyèdre composé de 4 faces triangulaires équilatérales, 4 sommets et 6 arêtes. Son patron est donc formé de 4 triangles équilatéraux. C''est le plus simple des solides de Platon. On peut vérifier avec la formule d''Euler : S − A + F = 4 − 6 + 4 = 2. La pyramide à base carrée a 5 faces (1 carrée + 4 triangulaires), le prisme triangulaire a 5 faces et l''octaèdre a 8 faces.',
  'Confondre avec la pyramide à base carrée. L''élève ne réalise pas qu''une pyramide à base carrée nécessite un carré en plus des triangles. Le tétraèdre est une pyramide dont la base est elle-même un triangle.',
  'valide',
  'Génération Claude — Terminologie Éduscol', 'free', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f9090000-0000-0000-0000-000000000007',
  'Mathematiques', 'geometrie', 'math_patron_solides',
  'Patrons de solides — Construction et reconnaissance', 'Intermediaire',
  'reponse_courte',
  'On souhaite fabriquer une boîte sans couvercle en forme de pavé droit de dimensions 20 cm × 15 cm × 10 cm (longueur × largeur × hauteur). Quelle est l''aire minimale de carton nécessaire (en cm²), sachant que la boîte n''a pas de face supérieure ?',
  NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["1000","1000 cm²","1 000","1 000 cm²"]}'::jsonb,
  'La boîte sans couvercle possède 5 faces : le fond (20 × 15 = 300 cm²), deux faces latérales de 20 × 10 = 200 cm² chacune, et deux faces latérales de 15 × 10 = 150 cm² chacune. L''aire totale est : 300 + 2 × 200 + 2 × 150 = 300 + 400 + 300 = 1 000 cm². C''est l''aire minimale nécessaire, sans compter les languettes de collage ni les pertes de découpe.',
  'Calculer l''aire totale du pavé fermé (avec 6 faces) : 2 × (20 × 15 + 20 × 10 + 15 × 10) = 1 300 cm². L''élève oublie que la boîte n''a pas de couvercle et compte la face supérieure en trop.',
  'valide',
  'Génération Claude — Terminologie Éduscol', 'free', true
) ON CONFLICT (id) DO NOTHING;

-- math_perimetre_aire_volume_confusions (grandeurs_mesures) : 3 -> 10 questions
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'b0270000-0000-0000-0000-000000000001', 'Mathematiques', 'grandeurs_mesures', 'math_perimetre_aire_volume_confusions',
  'Périmètre, aire, volume — Confusions et pièges', 'Intermediaire', 'vrai_faux',
  'Deux rectangles ayant le même périmètre ont nécessairement la même aire.',
  NULL, NULL,
  '{"mode": "single", "value": "faux"}',
  'C''est FAUX. Deux rectangles peuvent avoir le même périmètre mais des aires très différentes. Contre-exemple : un rectangle de 6 cm × 2 cm a un périmètre de 16 cm et une aire de 12 cm², tandis qu''un rectangle de 5 cm × 3 cm a aussi un périmètre de 16 cm mais une aire de 15 cm². Le périmètre mesure le « tour » de la figure (une longueur, en cm), alors que l''aire mesure la « surface couverte » (en cm²). Ces deux grandeurs sont de nature différente et varient indépendamment l''une de l''autre.',
  'Croire que même périmètre implique même aire, en confondant la notion de contour (périmètre) avec celle de surface (aire).',
  'valide',
  'Génération Claude — Terminologie Éduscol', 'free', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'b0270000-0000-0000-0000-000000000002', 'Mathematiques', 'grandeurs_mesures', 'math_perimetre_aire_volume_confusions',
  'Périmètre, aire, volume — Confusions et pièges', 'Intermediaire', 'qcm',
  'Un carré de côté 4 cm a un périmètre de 16 cm et une aire de 16 cm². Un élève en conclut que le périmètre et l''aire d''un carré sont toujours égaux. Cette conclusion est :',
  NULL,
  '[{"id": "a", "label": "Vraie"}, {"id": "b", "label": "Fausse — elle n''est vraie que pour le carré de côté 4"}, {"id": "c", "label": "Fausse — périmètre et aire n''ont pas les mêmes unités, ils ne peuvent pas être « égaux »"}, {"id": "d", "label": "Vraie pour tous les carrés"}]',
  '{"mode": "single", "value": "c"}',
  'La réponse est c). Le périmètre s''exprime en cm (unité de longueur) et l''aire en cm² (unité de surface). Comparer « 16 cm » et « 16 cm² » n''a aucun sens mathématique : ce sont deux grandeurs de nature différente. Le fait que les valeurs numériques coïncident pour un côté de 4 cm est une simple coïncidence arithmétique. Pour un carré de côté 3 cm, le périmètre vaut 12 cm et l''aire 9 cm² ; pour un côté de 5 cm, P = 20 cm et A = 25 cm². Les valeurs numériques ne coïncident plus. Cette confusion entre la valeur numérique et la grandeur mesurée est un piège classique.',
  'Choisir b) en pensant que la coïncidence numérique est le vrai problème, alors que le problème fondamental est l''incomparabilité des unités (cm vs cm²).',
  'valide',
  'Génération Claude — Terminologie Éduscol', 'free', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'b0270000-0000-0000-0000-000000000003', 'Mathematiques', 'grandeurs_mesures', 'math_perimetre_aire_volume_confusions',
  'Périmètre, aire, volume — Confusions et pièges', 'Intermediaire', 'reponse_courte',
  'Un rectangle de 10 cm × 5 cm a-t-il un périmètre plus grand ou plus petit qu''un carré de même aire ? Justifiez votre réponse.',
  NULL, NULL,
  '{"mode": "flexible", "acceptableAnswers": ["plus grand", "le rectangle", "le rectangle a un périmètre plus grand"]}',
  'L''aire du rectangle vaut 10 × 5 = 50 cm². Le carré de même aire a un côté de √50 ≈ 7,07 cm, donc un périmètre de 4 × 7,07 ≈ 28,28 cm. Le périmètre du rectangle vaut 2 × (10 + 5) = 30 cm. Le rectangle a donc un périmètre PLUS GRAND que le carré de même aire. Ce résultat illustre un théorème fondamental : parmi tous les rectangles de même aire, le carré est celui qui a le plus petit périmètre. Autrement dit, à aire égale, toute déformation du carré en rectangle allonge le périmètre.',
  'Penser qu''à aire égale, le périmètre est aussi égal, en confondant les deux notions.',
  'valide',
  'Génération Claude — Terminologie Éduscol', 'free', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'b0270000-0000-0000-0000-000000000004', 'Mathematiques', 'grandeurs_mesures', 'math_perimetre_aire_volume_confusions',
  'Périmètre, aire, volume — Confusions et pièges', 'Intermediaire', 'qcm',
  'On double les dimensions d''un rectangle. Par combien sont multipliés son périmètre et son aire ?',
  NULL,
  '[{"id": "a", "label": "Périmètre × 2 et aire × 2"}, {"id": "b", "label": "Périmètre × 2 et aire × 4"}, {"id": "c", "label": "Périmètre × 4 et aire × 4"}, {"id": "d", "label": "Périmètre × 4 et aire × 8"}]',
  '{"mode": "single", "value": "b"}',
  'La réponse est b). Quand on multiplie toutes les dimensions par un facteur k (ici k = 2) : le périmètre, qui est une somme de longueurs, est multiplié par k (donc × 2) ; l''aire, qui est un produit de deux longueurs, est multipliée par k² (donc × 4). Vérification : un rectangle de 3 cm × 5 cm a P = 16 cm et A = 15 cm². En doublant : 6 cm × 10 cm donne P = 32 cm (× 2) et A = 60 cm² (× 4). Cette propriété est fondamentale en géométrie : l''aire varie comme le carré du facteur d''agrandissement.',
  'Choisir a) en pensant que doubler les dimensions double aussi l''aire, sans voir que l''aire dépend du produit de deux dimensions qui sont chacune doublées.',
  'valide',
  'Génération Claude — Terminologie Éduscol', 'free', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'b0270000-0000-0000-0000-000000000005', 'Mathematiques', 'grandeurs_mesures', 'math_perimetre_aire_volume_confusions',
  'Périmètre, aire, volume — Confusions et pièges', 'Intermediaire', 'vrai_faux',
  'Si on augmente l''aire d''un carré, son périmètre augmente aussi.',
  NULL, NULL,
  '{"mode": "single", "value": "vrai"}',
  'C''est VRAI pour un carré. L''aire d''un carré de côté c vaut c². Si l''aire augmente, alors c² augmente, donc c augmente (la fonction racine carrée est croissante). Or le périmètre vaut 4c, donc si c augmente, le périmètre augmente aussi. Attention : cette propriété est spécifique au carré. Pour des figures quelconques, on peut augmenter l''aire sans augmenter le périmètre (par exemple en « gonflant » un polygone irrégulier vers l''intérieur). Mais pour un carré, les deux grandeurs varient dans le même sens car elles dépendent toutes deux d''un seul paramètre : le côté.',
  'Répondre « faux » en généralisant hâtivement le fait que périmètre et aire sont des grandeurs indépendantes — ce qui est vrai en général, mais pas pour un carré dont la forme est fixée.',
  'valide',
  'Génération Claude — Terminologie Éduscol', 'free', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'b0270000-0000-0000-0000-000000000006', 'Mathematiques', 'grandeurs_mesures', 'math_perimetre_aire_volume_confusions',
  'Périmètre, aire, volume — Confusions et pièges', 'Intermediaire', 'reponse_courte',
  'Un aquarium a la forme d''un pavé droit de 50 cm × 30 cm × 40 cm (longueur × largeur × hauteur). Quelle quantité de verre faut-il pour le fabriquer (sans couvercle) ? Et quel volume d''eau peut-il contenir ?',
  NULL, NULL,
  '{"mode": "flexible", "acceptableAnswers": ["7900 cm² et 60 L", "7900 cm2 et 60 L", "7900 et 60", "60 L", "60"]}',
  'Cet exercice distingue clairement surface et volume. Pour la quantité de verre (surface sans couvercle) : fond = 50 × 30 = 1 500 cm² ; 2 grands côtés = 2 × (50 × 40) = 4 000 cm² ; 2 petits côtés = 2 × (30 × 40) = 2 400 cm². Total = 1 500 + 4 000 + 2 400 = 7 900 cm². Pour le volume d''eau : V = 50 × 30 × 40 = 60 000 cm³. Or 1 L = 1 000 cm³ (= 1 dm³), donc V = 60 L. La surface se mesure en cm² (grandeur à deux dimensions) et le volume en cm³ ou en litres (grandeur à trois dimensions). Confondre les deux revient à confondre « combien de matière pour construire » et « combien ça contient ».',
  'Confondre surface et volume en calculant le volume alors qu''on demande la surface de verre, ou inversement. Oublier qu''il n''y a pas de couvercle (5 faces au lieu de 6).',
  'valide',
  'Génération Claude — Terminologie Éduscol', 'free', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'b0270000-0000-0000-0000-000000000007', 'Mathematiques', 'grandeurs_mesures', 'math_perimetre_aire_volume_confusions',
  'Périmètre, aire, volume — Confusions et pièges', 'Intermediaire', 'qcm',
  'Un jardinier dispose de 24 m de grillage pour entourer un potager rectangulaire. Quelles dimensions lui donneront l''aire maximale ?',
  NULL,
  '[{"id": "a", "label": "8 m × 4 m (aire = 32 m²)"}, {"id": "b", "label": "10 m × 2 m (aire = 20 m²)"}, {"id": "c", "label": "6 m × 6 m (aire = 36 m²)"}, {"id": "d", "label": "7 m × 5 m (aire = 35 m²)"}]',
  '{"mode": "single", "value": "c"}',
  'La réponse est c). Le périmètre est fixé : 2(L + l) = 24, donc L + l = 12. L''aire A = L × l = L × (12 − L) = 12L − L². C''est une fonction du second degré dont le maximum est atteint pour L = 6 (sommet de la parabole). On obtient alors l = 6 et A = 36 m². Le rectangle d''aire maximale à périmètre donné est toujours un carré. Ce résultat fondamental relie périmètre et aire de manière optimale : parmi tous les rectangles de même périmètre, le carré maximise l''aire ; parmi tous les rectangles de même aire, le carré minimise le périmètre.',
  'Choisir d) (7 × 5 = 35 m²) qui est proche du maximum mais n''est pas optimal, ou choisir a) en pensant intuitivement qu''un rectangle « allongé » a plus de surface.',
  'valide',
  'Génération Claude — Terminologie Éduscol', 'free', true
) ON CONFLICT (id) DO NOTHING;

-- math_perimetre_cercle_arc (geometrie) : 3 -> 10 questions
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f90a0000-0000-0000-0000-000000000001', 'Mathematiques', 'geometrie', 'math_perimetre_cercle_arc', 'Périmètre du cercle et longueur d''arc', 'Intermediaire',
  'qcm', 'Un cercle a un rayon de 7 cm. Quel est son périmètre ? (On prendra π ≈ 3,14)', NULL,
  '[{"id":"a","label":"21,98 cm"},{"id":"b","label":"43,96 cm"},{"id":"c","label":"153,86 cm"},{"id":"d","label":"14 cm"}]'::jsonb,
  '{"mode":"single","value":"b"}'::jsonb,
  'Le périmètre (ou circonférence) d''un cercle se calcule avec la formule P = 2πr. Ici : P = 2 × 3,14 × 7 = 43,96 cm. L''option a (21,98 cm) correspond à πr, c''est-à-dire la moitié du périmètre. L''option c (153,86 cm) correspond à l''aire du disque (πr²).',
  'Confondre périmètre du cercle (2πr) et aire du disque (πr²) : l''élève calcule 3,14 × 49 = 153,86 cm au lieu de 2 × 3,14 × 7 = 43,96 cm.',
  'valide', 'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f90a0000-0000-0000-0000-000000000002', 'Mathematiques', 'geometrie', 'math_perimetre_cercle_arc', 'Périmètre du cercle et longueur d''arc', 'Intermediaire',
  'reponse_courte', 'La circonférence d''une roue de vélo est de 2,0096 m. Quel est le diamètre de cette roue en cm ? (π ≈ 3,14)', NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["64","64 cm","64cm"]}'::jsonb,
  'On sait que P = πd, donc d = P / π. Ici : d = 2,0096 / 3,14 = 0,64 m = 64 cm. L''élève doit penser à convertir le résultat en centimètres. Le diamètre est le double du rayon : on aurait aussi pu écrire P = 2πr, d''où r = P / (2π) = 0,32 m, puis d = 2r = 0,64 m.',
  'Oublier la conversion de mètres en centimètres et répondre 0,64 au lieu de 64 cm.',
  'valide', 'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f90a0000-0000-0000-0000-000000000003', 'Mathematiques', 'geometrie', 'math_perimetre_cercle_arc', 'Périmètre du cercle et longueur d''arc', 'Intermediaire',
  'qcm', 'Un arc de cercle de rayon 10 cm est sous-tendu par un angle au centre de 90°. Quelle est la longueur de cet arc ? (π ≈ 3,14)', NULL,
  '[{"id":"a","label":"31,4 cm"},{"id":"b","label":"15,7 cm"},{"id":"c","label":"62,8 cm"},{"id":"d","label":"7,85 cm"}]'::jsonb,
  '{"mode":"single","value":"b"}'::jsonb,
  'La longueur d''un arc de cercle se calcule avec la formule L = (angle / 360) × 2πr. Ici : L = (90 / 360) × 2 × 3,14 × 10 = 0,25 × 62,8 = 15,7 cm. L''angle de 90° représente un quart du cercle complet, donc l''arc mesure un quart de la circonférence totale.',
  'Utiliser la formule de l''aire du secteur au lieu de la longueur d''arc : l''élève calcule (90/360) × πr² = 78,5 cm² au lieu de la longueur.',
  'valide', 'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f90a0000-0000-0000-0000-000000000004', 'Mathematiques', 'geometrie', 'math_perimetre_cercle_arc', 'Périmètre du cercle et longueur d''arc', 'Intermediaire',
  'vrai_faux', 'Le périmètre d''un demi-cercle de rayon 5 cm est égal à 15,7 cm. (π ≈ 3,14)', NULL,
  NULL,
  '{"mode":"single","value":"faux"}'::jsonb,
  'Le périmètre d''un demi-cercle comprend le demi-cercle (la moitié de la circonférence) PLUS le diamètre. Demi-circonférence = πr = 3,14 × 5 = 15,7 cm. Diamètre = 2r = 10 cm. Périmètre total = 15,7 + 10 = 25,7 cm. La valeur 15,7 cm ne correspond qu''à la partie courbe, pas au périmètre complet.',
  'Oublier d''ajouter le diamètre au périmètre du demi-cercle : l''élève ne considère que la partie courbe et omet le segment rectiligne qui ferme la figure.',
  'valide', 'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f90a0000-0000-0000-0000-000000000005', 'Mathematiques', 'geometrie', 'math_perimetre_cercle_arc', 'Périmètre du cercle et longueur d''arc', 'Intermediaire',
  'qcm', 'Une piste d''athlétisme a la forme d''un rectangle de 100 m × 60 m complété par deux demi-cercles de diamètre 60 m à chaque extrémité. Quel est le périmètre de cette piste ? (π ≈ 3,14)', NULL,
  '[{"id":"a","label":"320 m"},{"id":"b","label":"388,4 m"},{"id":"c","label":"508,4 m"},{"id":"d","label":"448,4 m"}]'::jsonb,
  '{"mode":"single","value":"b"}'::jsonb,
  'Le périmètre de la piste se compose des deux longueurs du rectangle et des deux demi-cercles (qui forment un cercle complet). Deux longueurs = 2 × 100 = 200 m. Cercle complet de diamètre 60 m : P = πd = 3,14 × 60 = 188,4 m. Périmètre total = 200 + 188,4 = 388,4 m. Les largeurs du rectangle ne comptent pas car elles sont remplacées par les demi-cercles.',
  'Ajouter aussi les deux largeurs du rectangle (2 × 60 = 120 m) en plus des demi-cercles : l''élève compte deux fois les segments remplacés par les arcs.',
  'valide', 'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f90a0000-0000-0000-0000-000000000006', 'Mathematiques', 'geometrie', 'math_perimetre_cercle_arc', 'Périmètre du cercle et longueur d''arc', 'Intermediaire',
  'reponse_courte', 'Un jardinier veut entourer un massif circulaire de rayon 4 m avec une clôture. Le grillage coûte 8,50 € le mètre. Quel est le coût total de la clôture, arrondi au centime ? (π ≈ 3,14)', NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["213,52 €","213,52€","213,52"]}'::jsonb,
  'Il faut d''abord calculer le périmètre du cercle : P = 2πr = 2 × 3,14 × 4 = 25,12 m. Puis multiplier par le prix au mètre : 25,12 × 8,50 = 213,52 €. Ce problème concret mobilise la formule du périmètre du cercle dans un contexte de la vie quotidienne.',
  'Calculer l''aire du disque (πr² = 50,24 m²) au lieu du périmètre : l''élève confond la surface à couvrir et la longueur de clôture nécessaire.',
  'valide', 'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f90a0000-0000-0000-0000-000000000007', 'Mathematiques', 'geometrie', 'math_perimetre_cercle_arc', 'Périmètre du cercle et longueur d''arc', 'Intermediaire',
  'qcm', 'Un cadran d''horloge a un rayon de 15 cm. L''aiguille des minutes parcourt un arc de 120° en 20 minutes. Quelle est la longueur de cet arc en cm ? (π ≈ 3,14)', NULL,
  '[{"id":"a","label":"31,4 cm"},{"id":"b","label":"62,8 cm"},{"id":"c","label":"15,7 cm"},{"id":"d","label":"94,2 cm"}]'::jsonb,
  '{"mode":"single","value":"a"}'::jsonb,
  'La longueur de l''arc parcouru se calcule avec L = (angle / 360) × 2πr. Ici : L = (120 / 360) × 2 × 3,14 × 15 = (1/3) × 94,2 = 31,4 cm. En 20 minutes, l''aiguille des minutes parcourt effectivement 120° (soit un tiers du cadran : 20/60 = 1/3). Ce problème combine la notion de longueur d''arc avec une conversion temporelle.',
  'Confondre le rayon (15 cm) avec le diamètre et utiliser r = 7,5 cm dans le calcul, ce qui divise le résultat par deux.',
  'valide', 'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

-- math_perimetre_figures_usuelles (grandeurs_mesures) : 3 -> 10 questions
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fa0a0000-0000-0000-0000-000000000001', 'Mathematiques', 'grandeurs_mesures', 'math_perimetre_figures_usuelles', 'Périmètre des figures usuelles', 'Facile',
  'qcm', 'Un carré a un côté de 9 cm. Quel est son périmètre ?', NULL,
  '[{"id":"a","label":"18 cm"},{"id":"b","label":"27 cm"},{"id":"c","label":"36 cm"},{"id":"d","label":"81 cm"}]'::jsonb,
  '{"mode":"single","value":"c"}'::jsonb,
  'Le périmètre d''un carré est égal à 4 fois la longueur de son côté : P = 4 × c = 4 × 9 = 36 cm. L''option d (81 cm) correspond à l''aire du carré (9² = 81 cm²), pas à son périmètre.',
  'Confondre périmètre et aire : l''élève calcule 9 × 9 = 81 au lieu de 4 × 9 = 36.',
  'valide', 'Génération Claude — Terminologie Éduscol', 'free', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fa0a0000-0000-0000-0000-000000000002', 'Mathematiques', 'grandeurs_mesures', 'math_perimetre_figures_usuelles', 'Périmètre des figures usuelles', 'Facile',
  'reponse_courte', 'Un rectangle a une longueur de 14 cm et une largeur de 8 cm. Calculez son périmètre en cm.', NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["44","44 cm","44cm"]}'::jsonb,
  'Le périmètre d''un rectangle se calcule avec la formule P = 2 × (L + l) = 2 × (14 + 8) = 2 × 22 = 44 cm. On additionne d''abord la longueur et la largeur, puis on multiplie par 2 car le rectangle possède deux paires de côtés égaux.',
  'Oublier de multiplier par 2 et répondre 22 cm : l''élève additionne L + l mais ne prend en compte que la moitié du contour.',
  'valide', 'Génération Claude — Terminologie Éduscol', 'free', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fa0a0000-0000-0000-0000-000000000003', 'Mathematiques', 'grandeurs_mesures', 'math_perimetre_figures_usuelles', 'Périmètre des figures usuelles', 'Facile',
  'qcm', 'Un triangle a des côtés mesurant 7 cm, 5 cm et 9 cm. Quel est son périmètre ?', NULL,
  '[{"id":"a","label":"17,5 cm"},{"id":"b","label":"21 cm"},{"id":"c","label":"35 cm"},{"id":"d","label":"15 cm"}]'::jsonb,
  '{"mode":"single","value":"b"}'::jsonb,
  'Le périmètre d''un triangle est la somme des longueurs de ses trois côtés : P = 7 + 5 + 9 = 21 cm. Il n''existe pas de formule spéciale : on additionne simplement les trois côtés, quelle que soit la nature du triangle.',
  'Appliquer par erreur une formule du type « 2 × (a + b) » comme pour le rectangle : l''élève oublie que le triangle possède trois côtés distincts.',
  'valide', 'Génération Claude — Terminologie Éduscol', 'free', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fa0a0000-0000-0000-0000-000000000004', 'Mathematiques', 'grandeurs_mesures', 'math_perimetre_figures_usuelles', 'Périmètre des figures usuelles', 'Facile',
  'vrai_faux', 'Un losange dont le côté mesure 6 cm a un périmètre de 24 cm.', NULL,
  NULL,
  '{"mode":"single","value":"vrai"}'::jsonb,
  'Un losange possède quatre côtés de même longueur. Son périmètre est donc P = 4 × c = 4 × 6 = 24 cm. L''affirmation est vraie. Attention à ne pas confondre le losange avec un parallélogramme quelconque dont les côtés opposés seulement sont égaux.',
  'Confondre losange et parallélogramme quelconque : l''élève pense que seuls deux côtés mesurent 6 cm et calcule un périmètre différent.',
  'valide', 'Génération Claude — Terminologie Éduscol', 'free', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fa0a0000-0000-0000-0000-000000000005', 'Mathematiques', 'grandeurs_mesures', 'math_perimetre_figures_usuelles', 'Périmètre des figures usuelles', 'Facile',
  'qcm', 'Quelle est la formule du périmètre d''un polygone régulier à n côtés, chaque côté mesurant c ?', NULL,
  '[{"id":"a","label":"P = n × c"},{"id":"b","label":"P = 2 × n × c"},{"id":"c","label":"P = n × c²"},{"id":"d","label":"P = (n × c) / 2"}]'::jsonb,
  '{"mode":"single","value":"a"}'::jsonb,
  'Un polygone régulier possède n côtés de même longueur c. Son périmètre est simplement la somme de tous ses côtés : P = n × c. Par exemple, un hexagone régulier de côté 4 cm a un périmètre de 6 × 4 = 24 cm.',
  'Multiplier par 2 par réflexe (formule du rectangle) : l''élève applique P = 2 × n × c, ce qui donne un résultat doublé.',
  'valide', 'Génération Claude — Terminologie Éduscol', 'free', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fa0a0000-0000-0000-0000-000000000006', 'Mathematiques', 'grandeurs_mesures', 'math_perimetre_figures_usuelles', 'Périmètre des figures usuelles', 'Facile',
  'vrai_faux', 'Une figure en forme de L est constituée d''un grand rectangle de 10 cm × 8 cm dont on a retiré un rectangle de 6 cm × 4 cm dans un coin. Le périmètre de cette figure en L est de 36 cm.', NULL,
  NULL,
  '{"mode":"single","value":"vrai"}'::jsonb,
  'En parcourant le contour extérieur de la figure en L, on compte 6 segments. En plaçant le rectangle initial avec sa base en bas (10 cm × 8 cm) et en retirant un rectangle de 6 cm × 4 cm dans le coin supérieur droit, les sommets de la figure en L sont : (0,0), (10,0), (10,4), (4,4), (4,8), (0,8). Les segments mesurent : 10 + 4 + 6 + 4 + 4 + 8 = 36 cm. Remarque importante : le périmètre d''une figure en L est le même que celui du rectangle englobant ! En effet, les deux segments supplémentaires créés par l''encoche (ici 6 et 4) remplacent exactement les deux segments manquants du rectangle (6 et 4).',
  'Additionner les périmètres des deux rectangles composants (28 + 20 = 48 cm), en comptant deux fois le côté intérieur. Le périmètre se calcule en suivant uniquement le contour extérieur.',
  'valide', 'Génération Claude — Terminologie Éduscol', 'free', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fa0a0000-0000-0000-0000-000000000007', 'Mathematiques', 'grandeurs_mesures', 'math_perimetre_figures_usuelles', 'Périmètre des figures usuelles', 'Facile',
  'reponse_courte', 'Un jardin rectangulaire de 25 m de long et 18 m de large doit être entouré d''une clôture. Quelle longueur de clôture faut-il acheter, en mètres ?', NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["86","86 m","86m"]}'::jsonb,
  'La longueur de clôture correspond au périmètre du jardin rectangulaire : P = 2 × (L + l) = 2 × (25 + 18) = 2 × 43 = 86 m. Ce type de problème concret illustre l''utilité du calcul de périmètre dans la vie quotidienne : l''élève doit identifier que « entourer » revient à calculer un périmètre.',
  'Calculer l''aire au lieu du périmètre : l''élève répond 25 × 18 = 450 m² alors qu''on demande une longueur de clôture (mesure linéaire, pas surfacique).',
  'valide', 'Génération Claude — Terminologie Éduscol', 'free', true
) ON CONFLICT (id) DO NOTHING;

-- math_pgcd_applications (nombres_calcul) : 3 -> 10 questions
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f80f0000-0000-0000-0000-000000000001',
  'Mathematiques',
  'nombres_calcul',
  'math_pgcd_applications',
  'PGCD — Applications pratiques',
  'Intermediaire',
  'qcm',
  'Quel est le PGCD de 36 et 48 ?',
  NULL,
  '[{"id":"a","label":"6"},{"id":"b","label":"8"},{"id":"c","label":"12"},{"id":"d","label":"24"}]'::jsonb,
  '{"mode":"single","value":"c"}'::jsonb,
  'Listons les diviseurs de chaque nombre. Diviseurs de 36 : 1, 2, 3, 4, 6, 9, 12, 18, 36. Diviseurs de 48 : 1, 2, 3, 4, 6, 8, 12, 16, 24, 48. Les diviseurs communs sont : 1, 2, 3, 4, 6, 12. Le plus grand diviseur commun est 12. Donc PGCD(36, 48) = 12.',
  'Confondre PGCD et PPCM. Le PPCM de 36 et 48 est 144. Autre erreur : s''arrêter à un diviseur commun sans vérifier qu''il est bien le plus grand (par exemple répondre 6).',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f80f0000-0000-0000-0000-000000000002',
  'Mathematiques',
  'nombres_calcul',
  'math_pgcd_applications',
  'PGCD — Applications pratiques',
  'Intermediaire',
  'reponse_courte',
  'En utilisant l''algorithme d''Euclide, calculer PGCD(154, 56).',
  NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["14"]}'::jsonb,
  'On applique l''algorithme d''Euclide par divisions euclidiennes successives. 154 = 56 × 2 + 42. 56 = 42 × 1 + 14. 42 = 14 × 3 + 0. Le dernier reste non nul est 14. Donc PGCD(154, 56) = 14.',
  'Se tromper dans les divisions euclidiennes successives, notamment en calculant mal le quotient ou le reste. Par exemple, écrire 154 = 56 × 3 + (−14), ce qui donne un reste négatif invalide.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f80f0000-0000-0000-0000-000000000003',
  'Mathematiques',
  'nombres_calcul',
  'math_pgcd_applications',
  'PGCD — Applications pratiques',
  'Intermediaire',
  'reponse_courte',
  'Simplifier la fraction 84/126 en fraction irréductible.',
  NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["2/3"]}'::jsonb,
  'Pour simplifier 84/126, on calcule le PGCD de 84 et 126. Par l''algorithme d''Euclide : 126 = 84 × 1 + 42. 84 = 42 × 2 + 0. Donc PGCD(84, 126) = 42. On simplifie : 84/126 = (84 ÷ 42)/(126 ÷ 42) = 2/3. La fraction 2/3 est irréductible car PGCD(2, 3) = 1.',
  'Simplifier partiellement (par exemple diviser par 2 pour obtenir 42/63, puis oublier de continuer). Ou confondre numérateur et dénominateur dans la division.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f80f0000-0000-0000-0000-000000000004',
  'Mathematiques',
  'nombres_calcul',
  'math_pgcd_applications',
  'PGCD — Applications pratiques',
  'Intermediaire',
  'vrai_faux',
  'Vrai ou faux ? Si PGCD(18, 24) = 6, alors PPCM(18, 24) = 72.',
  NULL,
  NULL,
  '{"mode":"single","value":"vrai"}'::jsonb,
  'On utilise la relation fondamentale : PGCD(a, b) × PPCM(a, b) = a × b. Donc PPCM(18, 24) = (18 × 24) / PGCD(18, 24) = 432 / 6 = 72. On vérifie : 72 = 18 × 4 = 24 × 3, donc 72 est bien un multiple commun de 18 et 24, et c''est le plus petit. L''affirmation est vraie.',
  'Multiplier les deux nombres sans diviser par le PGCD, ce qui donnerait 432 au lieu de 72. Ou diviser le produit par un mauvais PGCD.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f80f0000-0000-0000-0000-000000000005',
  'Mathematiques',
  'nombres_calcul',
  'math_pgcd_applications',
  'PGCD — Applications pratiques',
  'Intermediaire',
  'qcm',
  'On veut carreler une pièce rectangulaire de 360 cm par 480 cm avec des carreaux carrés les plus grands possible, sans découpe. Quel est le côté de chaque carreau ?',
  NULL,
  '[{"id":"a","label":"60 cm"},{"id":"b","label":"80 cm"},{"id":"c","label":"120 cm"},{"id":"d","label":"40 cm"}]'::jsonb,
  '{"mode":"single","value":"c"}'::jsonb,
  'Pour que les carreaux carrés recouvrent parfaitement la pièce sans découpe, le côté du carreau doit diviser à la fois 360 et 480. On cherche le plus grand diviseur commun. PGCD(360, 480) : 480 = 360 × 1 + 120. 360 = 120 × 3 + 0. Donc PGCD(360, 480) = 120. Le côté de chaque carreau est de 120 cm. Vérification : 360 ÷ 120 = 3 carreaux en largeur, 480 ÷ 120 = 4 carreaux en longueur, soit 12 carreaux au total.',
  'Confondre PGCD et PPCM : le PPCM donnerait 1440, ce qui n''a pas de sens ici (un carreau plus grand que la pièce). Autre erreur : choisir un diviseur commun qui n''est pas le plus grand.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f80f0000-0000-0000-0000-000000000006',
  'Mathematiques',
  'nombres_calcul',
  'math_pgcd_applications',
  'PGCD — Applications pratiques',
  'Intermediaire',
  'reponse_courte',
  'On dispose de deux cordes de 168 cm et 120 cm. On veut les couper en morceaux de même longueur, la plus grande possible, sans reste. Combien de morceaux obtient-on au total ?',
  NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["12"]}'::jsonb,
  'La longueur de chaque morceau doit diviser 168 et 120. On cherche PGCD(168, 120). Par l''algorithme d''Euclide : 168 = 120 × 1 + 48. 120 = 48 × 2 + 24. 48 = 24 × 2 + 0. Donc PGCD(168, 120) = 24. Chaque morceau mesure 24 cm. Nombre de morceaux : 168 ÷ 24 + 120 ÷ 24 = 7 + 5 = 12 morceaux au total.',
  'Donner la longueur du morceau (24) au lieu du nombre total de morceaux. Ou calculer uniquement le nombre de morceaux d''une seule corde au lieu des deux.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f80f0000-0000-0000-0000-000000000007',
  'Mathematiques',
  'nombres_calcul',
  'math_pgcd_applications',
  'PGCD — Applications pratiques',
  'Intermediaire',
  'vrai_faux',
  'Vrai ou faux ? Deux bus partent de la gare : le bus A toutes les 12 minutes, le bus B toutes les 18 minutes. S''ils partent ensemble à 8 h 00, ils repartiront ensemble pour la première fois à 8 h 36.',
  NULL,
  NULL,
  '{"mode":"single","value":"vrai"}'::jsonb,
  'Les deux bus repartiront ensemble quand le temps écoulé sera un multiple commun de 12 et 18. On cherche le PPCM(12, 18). D''abord, PGCD(12, 18) = 6. Puis PPCM(12, 18) = (12 × 18) / 6 = 216 / 6 = 36. Les bus repartiront ensemble après 36 minutes, soit à 8 h 36. L''affirmation est vraie.',
  'Multiplier 12 × 18 = 216 minutes (soit 3 h 36) sans diviser par le PGCD. Ou confondre PGCD et PPCM et répondre 6 minutes.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

-- math_polygones_reguliers (geometrie) : 3 -> 10 questions
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f9020000-0000-0000-0000-000000000001',
  'Mathematiques',
  'geometrie',
  'math_polygones_reguliers',
  'Polygones réguliers — Angles et propriétés',
  'Intermediaire',
  'qcm',
  'Quelle est la somme des angles intérieurs d''un pentagone (polygone à 5 côtés) ?',
  NULL,
  '[{"id":"a","label":"360°"},{"id":"b","label":"540°"},{"id":"c","label":"720°"},{"id":"d","label":"900°"}]',
  '{"mode":"single","value":"b"}',
  'La somme des angles intérieurs d''un polygone à n côtés est donnée par la formule (n − 2) × 180°. Pour un pentagone : n = 5, donc S = (5 − 2) × 180° = 3 × 180° = 540°. Cette formule se démontre en décomposant le polygone en triangles à partir d''un sommet : un polygone à n côtés se décompose en (n − 2) triangles, et chaque triangle a une somme d''angles de 180°. Exemples courants : triangle (180°), quadrilatère (360°), pentagone (540°), hexagone (720°).',
  'Appliquer n × 180° au lieu de (n − 2) × 180°, ce qui donnerait 5 × 180° = 900°. Il faut retrancher 2 au nombre de côtés avant de multiplier.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f9020000-0000-0000-0000-000000000002',
  'Mathematiques',
  'geometrie',
  'math_polygones_reguliers',
  'Polygones réguliers — Angles et propriétés',
  'Intermediaire',
  'reponse_courte',
  'Combien mesure chaque angle intérieur d''un hexagone régulier ?',
  NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["120°","120","120 °","120 degrés"]}',
  'Un hexagone régulier a 6 côtés tous égaux et 6 angles tous égaux. La somme des angles intérieurs vaut (6 − 2) × 180° = 4 × 180° = 720°. Chaque angle intérieur mesure donc 720° ÷ 6 = 120°. Dans un polygone régulier à n côtés, chaque angle intérieur mesure (n − 2) × 180° / n. L''hexagone régulier est un polygone très important en géométrie car il pave le plan et se décompose naturellement en 6 triangles équilatéraux.',
  'Diviser 360° par 6 pour obtenir 60°. La valeur 360° / n = 60° correspond à l''angle au centre (ou à l''angle extérieur), pas à l''angle intérieur.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f9020000-0000-0000-0000-000000000003',
  'Mathematiques',
  'geometrie',
  'math_polygones_reguliers',
  'Polygones réguliers — Angles et propriétés',
  'Intermediaire',
  'vrai_faux',
  'Vrai ou faux : un losange est toujours un polygone régulier.',
  NULL,
  NULL,
  '{"mode":"single","value":"faux"}',
  'C''est faux. Un polygone régulier a tous ses côtés égaux ET tous ses angles égaux. Le losange a bien ses 4 côtés égaux, mais ses angles ne sont pas nécessairement tous égaux (sauf s''il est un carré). Par exemple, un losange dont les angles mesurent 60°, 120°, 60°, 120° a 4 côtés égaux mais pas 4 angles égaux : ce n''est pas un polygone régulier. Le seul quadrilatère régulier est le carré (4 côtés égaux et 4 angles droits). Cette distinction entre « équilatéral » (côtés égaux) et « régulier » (côtés et angles égaux) est importante au CRPE.',
  'Penser qu''avoir tous les côtés égaux suffit pour être régulier. La régularité exige aussi l''égalité de tous les angles.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f9020000-0000-0000-0000-000000000004',
  'Mathematiques',
  'geometrie',
  'math_polygones_reguliers',
  'Polygones réguliers — Angles et propriétés',
  'Intermediaire',
  'reponse_courte',
  'Combien mesure chaque angle extérieur d''un décagone régulier (polygone régulier à 10 côtés) ?',
  NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["36°","36","36 °","36 degrés"]}',
  'La somme des angles extérieurs de tout polygone convexe vaut 360°. Dans un polygone régulier à n côtés, chaque angle extérieur mesure donc 360° / n. Pour un décagone régulier : 360° / 10 = 36°. On peut vérifier : chaque angle intérieur mesure (10 − 2) × 180° / 10 = 144°, et 180° − 144° = 36°, ce qui confirme le résultat. La propriété « somme des angles extérieurs = 360° » est très utile et souvent plus rapide que la formule des angles intérieurs.',
  'Calculer (10 − 2) × 180° / 10 = 144° et s''arrêter là. C''est l''angle intérieur, pas l''angle extérieur. Il faut encore calculer 180° − 144° = 36°.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f9020000-0000-0000-0000-000000000005',
  'Mathematiques',
  'geometrie',
  'math_polygones_reguliers',
  'Polygones réguliers — Angles et propriétés',
  'Intermediaire',
  'qcm',
  'Combien de diagonales possède un octogone (polygone à 8 côtés) ?',
  NULL,
  '[{"id":"a","label":"16"},{"id":"b","label":"20"},{"id":"c","label":"24"},{"id":"d","label":"28"}]',
  '{"mode":"single","value":"b"}',
  'Le nombre de diagonales d''un polygone à n côtés est n(n − 3) / 2. Pour un octogone : n = 8, donc d = 8 × (8 − 3) / 2 = 8 × 5 / 2 = 40 / 2 = 20 diagonales. Explication de la formule : depuis chaque sommet, on peut tracer (n − 3) diagonales (on exclut le sommet lui-même et ses 2 voisins). Il y a n sommets, donc n(n − 3) segments, mais chaque diagonale est comptée deux fois (une fois depuis chaque extrémité), d''où la division par 2. Vérifications : triangle (0), quadrilatère (2), pentagone (5), hexagone (9).',
  'Calculer 8 × 5 = 40 sans diviser par 2 (chaque diagonale relie deux sommets, elle est comptée deux fois).',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f9020000-0000-0000-0000-000000000006',
  'Mathematiques',
  'geometrie',
  'math_polygones_reguliers',
  'Polygones réguliers — Angles et propriétés',
  'Intermediaire',
  'qcm',
  'On trace toutes les diagonales principales d''un hexagone régulier ABCDEF (c''est-à-dire les segments reliant des sommets opposés : AD, BE et CF). En combien de triangles équilatéraux l''hexagone est-il décomposé ?',
  NULL,
  '[{"id":"a","label":"4"},{"id":"b","label":"6"},{"id":"c","label":"8"},{"id":"d","label":"12"}]',
  '{"mode":"single","value":"b"}',
  'Les trois grandes diagonales d''un hexagone régulier se coupent en son centre O et décomposent l''hexagone en 6 triangles équilatéraux : OAB, OBC, OCD, ODE, OEF et OFA. Chacun de ces triangles est équilatéral car : le côté de l''hexagone et le rayon du cercle circonscrit ont la même longueur (propriété caractéristique de l''hexagone régulier), et l''angle au centre vaut 360° / 6 = 60°, ce qui donne un triangle isocèle avec un angle de 60°, donc équilatéral. Cette propriété explique pourquoi l''hexagone régulier pave le plan.',
  'Répondre 4 en pensant à une décomposition en triangles quelconques, ou 12 en comptant des demi-triangles. Les 3 diagonales principales créent exactement 6 régions, toutes des triangles équilatéraux.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f9020000-0000-0000-0000-000000000007',
  'Mathematiques',
  'geometrie',
  'math_polygones_reguliers',
  'Polygones réguliers — Angles et propriétés',
  'Intermediaire',
  'reponse_courte',
  'Un pavage régulier du plan est constitué d''un seul type de polygone régulier, sans trou ni chevauchement. L''angle intérieur du polygone doit être un diviseur de 360°. Parmi le triangle équilatéral, le carré et l''hexagone régulier, combien de ces polygones permettent un pavage régulier du plan ?',
  NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["3","trois"]}',
  'Les trois permettent un pavage régulier du plan. Pour qu''un polygone régulier pave le plan, il faut que son angle intérieur divise 360° (pour que des polygones se rejoignent exactement autour de chaque sommet). Triangle équilatéral : angle = 60°, et 360° / 60° = 6 triangles autour de chaque sommet. Carré : angle = 90°, et 360° / 90° = 4 carrés autour de chaque sommet. Hexagone régulier : angle = 120°, et 360° / 120° = 3 hexagones autour de chaque sommet. Le pentagone régulier (angle = 108°) ne pave pas le plan car 360° / 108° ≈ 3,33, qui n''est pas entier. Ce sont les trois seuls pavages réguliers du plan, résultat connu depuis l''Antiquité.',
  'Oublier l''hexagone régulier ou penser que seul le carré pave le plan. Les trois polygones (triangle, carré, hexagone) sont les seuls polygones réguliers qui pavent le plan.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

-- math_pourcentages_avances (nombres_calcul) : 3 -> 10 questions
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'b0100000-0000-0000-0000-000000000001', 'Mathematiques', 'nombres_calcul', 'math_pourcentages_avances',
  'Proportionnalité avancée — Pourcentages successifs', 'Avance', 'qcm',
  'Un article coûte 80 €. Son prix augmente de 25 %, puis baisse de 25 %. Quel est le prix final ?', NULL,
  '[{"id":"a","label":"80 €"},{"id":"b","label":"75 €"},{"id":"c","label":"85 €"},{"id":"d","label":"70 €"}]'::jsonb,
  '{"mode":"single","value":"b"}'::jsonb,
  'Après une augmentation de 25 %, le prix devient 80 × 1,25 = 100 €. Après une baisse de 25 %, le prix devient 100 × 0,75 = 75 €. Le coefficient multiplicateur global est 1,25 × 0,75 = 0,9375, soit une baisse de 6,25 %. Augmenter puis diminuer du même pourcentage ne ramène jamais au prix initial.',
  'Croire qu''une augmentation de 25 % suivie d''une baisse de 25 % ramène au prix de départ (80 €). La baisse s''applique sur le prix majoré, pas sur le prix initial.',
  'valide',
  'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'b0100000-0000-0000-0000-000000000002', 'Mathematiques', 'nombres_calcul', 'math_pourcentages_avances',
  'Proportionnalité avancée — Pourcentages successifs', 'Avance', 'vrai_faux',
  'Augmenter une quantité de 50 % puis la diminuer de 50 % revient à ne rien changer.', NULL,
  '[{"id":"vrai","label":"Vrai"},{"id":"faux","label":"Faux"}]'::jsonb,
  '{"mode":"single","value":"faux"}'::jsonb,
  'Augmenter de 50 % revient à multiplier par 1,5. Diminuer de 50 % revient à multiplier par 0,5. Le coefficient global est 1,5 × 0,5 = 0,75, soit une diminution de 25 %. Par exemple, 100 € → 150 € → 75 €. On perd 25 % du montant initial.',
  'Penser que les deux variations s''annulent car elles portent sur le même pourcentage, en oubliant que la base de calcul change après la première opération.',
  'valide',
  'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'b0100000-0000-0000-0000-000000000003', 'Mathematiques', 'nombres_calcul', 'math_pourcentages_avances',
  'Proportionnalité avancée — Pourcentages successifs', 'Avance', 'reponse_courte',
  'Le PIB d''un pays augmente de 3 % par an pendant 4 ans. Quelle est l''augmentation totale en pourcentage ? Arrondir au dixième.', NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["12,6%","12,6 %","12.6%","12.6 %","12,6","12.6","12,55%","12,55 %","12,55"]}'::jsonb,
  'Le coefficient multiplicateur annuel est 1,03. Sur 4 ans, le coefficient global est 1,03⁴ = 1,12550881. L''augmentation totale est donc d''environ 12,6 %. On n''additionne pas les pourcentages (ce qui donnerait 12 %) car chaque année la hausse s''applique sur une base qui a déjà augmenté : c''est le principe des intérêts composés.',
  'Additionner les pourcentages : 3 % × 4 = 12 %. Cette méthode ignore l''effet de composition (les intérêts composés).',
  'valide',
  'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'b0100000-0000-0000-0000-000000000004', 'Mathematiques', 'nombres_calcul', 'math_pourcentages_avances',
  'Proportionnalité avancée — Pourcentages successifs', 'Avance', 'qcm',
  'Un commerçant applique trois remises successives : −10 %, −15 %, −5 %. Quel pourcentage unique de remise est équivalent à ces trois remises successives ?', NULL,
  '[{"id":"a","label":"30 %"},{"id":"b","label":"28 %"},{"id":"c","label":"27,325 %"},{"id":"d","label":"25 %"}]'::jsonb,
  '{"mode":"single","value":"c"}'::jsonb,
  'Les coefficients multiplicateurs sont 0,90 ; 0,85 et 0,95. Le coefficient global est 0,90 × 0,85 × 0,95 = 0,72675. La remise globale est 1 − 0,72675 = 0,27325, soit 27,325 %. On ne peut pas additionner les remises directement.',
  'Additionner les remises : 10 + 15 + 5 = 30 %. Cette erreur surestime la remise car chaque réduction s''applique sur un prix déjà réduit.',
  'valide',
  'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'b0100000-0000-0000-0000-000000000005', 'Mathematiques', 'nombres_calcul', 'math_pourcentages_avances',
  'Proportionnalité avancée — Pourcentages successifs', 'Avance', 'qcm',
  'Un placement rapporte 2 % la première année puis perd 3 % la deuxième année. Le capital initial était de 10 000 €. Quel est le capital après 2 ans ?', NULL,
  '[{"id":"a","label":"9 900 €"},{"id":"b","label":"9 894 €"},{"id":"c","label":"9 906 €"},{"id":"d","label":"10 000 €"}]'::jsonb,
  '{"mode":"single","value":"b"}'::jsonb,
  'Après la 1re année : 10 000 × 1,02 = 10 200 €. Après la 2e année : 10 200 × 0,97 = 9 894 €. Le coefficient global est 1,02 × 0,97 = 0,9894, soit une perte de 1,06 %.',
  'Additionner les pourcentages (+2 % − 3 % = −1 %) et calculer 10 000 × 0,99 = 9 900 €. Cette méthode ignore que la baisse de 3 % s''applique sur 10 200 €, pas sur 10 000 €.',
  'valide',
  'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'b0100000-0000-0000-0000-000000000006', 'Mathematiques', 'nombres_calcul', 'math_pourcentages_avances',
  'Proportionnalité avancée — Pourcentages successifs', 'Avance', 'reponse_courte',
  'Un prix a été réduit de 20 %. De combien de pourcent faut-il augmenter le prix réduit pour retrouver le prix initial ?', NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["25%","25 %","25","25,0%","25,0 %","25,0"]}'::jsonb,
  'Si le prix initial est P, après une réduction de 20 %, le prix réduit est P × 0,8. Pour retrouver P, il faut multiplier par 1/0,8 = 1,25, soit une augmentation de 25 %. En effet : P × 0,8 × 1,25 = P. L''augmentation nécessaire est toujours supérieure à la baisse initiale.',
  'Répondre 20 %, en pensant qu''il suffit d''augmenter du même pourcentage. Or la hausse s''applique sur une base plus petite (le prix réduit), donc le pourcentage doit être plus grand.',
  'valide',
  'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'b0100000-0000-0000-0000-000000000007', 'Mathematiques', 'nombres_calcul', 'math_pourcentages_avances',
  'Proportionnalité avancée — Pourcentages successifs', 'Avance', 'qcm',
  'La population d''une ville double en 20 ans avec un taux de croissance annuel constant. Quel est approximativement ce taux annuel ?', NULL,
  '[{"id":"a","label":"5 %"},{"id":"b","label":"10 %"},{"id":"c","label":"3,5 %"},{"id":"d","label":"2 %"}]'::jsonb,
  '{"mode":"single","value":"c"}'::jsonb,
  'On cherche t tel que (1 + t)²⁰ = 2. La valeur exacte est t = 2^(1/20) − 1 ≈ 0,03526, soit environ 3,5 %. On peut aussi utiliser la « règle de 70 » : le temps de doublement est approximativement 70/t, donc t ≈ 70/20 = 3,5 %.',
  'Diviser 100 % par 20 ans = 5 % par an. Cette erreur revient à raisonner en croissance linéaire (additive) au lieu de croissance exponentielle (multiplicative).',
  'valide',
  'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

-- math_pourcentages_evolution (nombres_calcul) : 3 -> 10 questions
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f8080000-0000-0000-0000-000000000001',
  'Mathematiques', 'nombres_calcul', 'math_pourcentages_evolution',
  'Pourcentages d''évolution — Hausse, baisse et taux global', 'Difficile',
  'qcm',
  'Un article coûtait 80 €. Son prix augmente de 15 %. Quel est le nouveau prix ?',
  NULL,
  '[{"id":"a","label":"92 €"},{"id":"b","label":"95 €"},{"id":"c","label":"93 €"},{"id":"d","label":"12 €"}]'::jsonb,
  '{"mode":"single","value":"a"}'::jsonb,
  'Pour calculer un prix après une augmentation de 15 %, on peut procéder de deux manières. Méthode additive : on calcule le montant de l''augmentation (15 % de 80 = 0,15 × 80 = 12 €), puis on l''ajoute au prix initial (80 + 12 = 92 €). Méthode multiplicative (plus efficace) : on multiplie le prix initial par le coefficient multiplicateur 1 + 15/100 = 1,15. Ainsi : 80 × 1,15 = 92 €. Le coefficient multiplicateur associé à une hausse de t % est toujours 1 + t/100. Cette méthode est préférable car elle se généralise facilement aux évolutions successives.',
  'Calculer uniquement le montant de l''augmentation (12 €) sans l''ajouter au prix initial, ou se tromper dans le calcul de 15 % de 80.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f8080000-0000-0000-0000-000000000002',
  'Mathematiques', 'nombres_calcul', 'math_pourcentages_evolution',
  'Pourcentages d''évolution — Hausse, baisse et taux global', 'Difficile',
  'reponse_courte',
  'Un produit valait 250 €. Après une baisse de 20 %, quel est son nouveau prix ?',
  NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["200 €","200€","200"]}'::jsonb,
  'Une baisse de 20 % correspond à un coefficient multiplicateur de 1 − 20/100 = 1 − 0,20 = 0,80. Le nouveau prix est donc : 250 × 0,80 = 200 €. On peut vérifier : 20 % de 250 = 0,20 × 250 = 50 €, et 250 − 50 = 200 €. Attention : le coefficient multiplicateur d''une baisse de t % est toujours 1 − t/100, jamais t/100. Baisser de 20 % revient à conserver 80 % du prix initial.',
  'Calculer 250 × 0,20 = 50 et donner 50 € comme réponse (c''est le montant de la réduction, pas le nouveau prix).',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f8080000-0000-0000-0000-000000000003',
  'Mathematiques', 'nombres_calcul', 'math_pourcentages_evolution',
  'Pourcentages d''évolution — Hausse, baisse et taux global', 'Difficile',
  'qcm',
  'Après une augmentation de 25 %, un article coûte désormais 150 €. Quel était son prix initial ?',
  NULL,
  '[{"id":"a","label":"112,50 €"},{"id":"b","label":"120 €"},{"id":"c","label":"125 €"},{"id":"d","label":"187,50 €"}]'::jsonb,
  '{"mode":"single","value":"b"}'::jsonb,
  'Pour retrouver la valeur initiale avant une hausse de 25 %, on utilise le coefficient multiplicateur inverse. La hausse de 25 % correspond au coefficient 1,25. Le prix final est : prix initial × 1,25 = 150 €. Donc : prix initial = 150 ÷ 1,25 = 120 €. Vérification : 120 × 1,25 = 150 €. Il ne faut surtout pas calculer 150 − 25 % de 150 = 150 − 37,50 = 112,50 €. Cette erreur classique vient du fait que 25 % du prix final n''est pas égal à 25 % du prix initial. Le raisonnement correct consiste à diviser par le coefficient multiplicateur, pas à soustraire le pourcentage du prix final.',
  'Calculer 150 − 25 % de 150 = 112,50 €, en appliquant la réduction sur le prix final au lieu de diviser par le coefficient multiplicateur.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f8080000-0000-0000-0000-000000000004',
  'Mathematiques', 'nombres_calcul', 'math_pourcentages_evolution',
  'Pourcentages d''évolution — Hausse, baisse et taux global', 'Difficile',
  'vrai_faux',
  'Un prix augmente de 10 % puis diminue de 10 %. Le prix final est égal au prix initial.',
  NULL,
  NULL,
  '{"mode":"single","value":"faux"}'::jsonb,
  'C''est faux. Les pourcentages d''évolution successifs ne sont PAS additifs. Prenons un exemple : un article à 100 €. Après une hausse de 10 %, il coûte 100 × 1,10 = 110 €. Après une baisse de 10 %, il coûte 110 × 0,90 = 99 €. Le prix final (99 €) est inférieur au prix initial (100 €). Le coefficient multiplicateur global est 1,10 × 0,90 = 0,99, soit une baisse globale de 1 %. Ce phénomène s''explique par le fait que la baisse de 10 % s''applique à un montant plus élevé (110 €) que celui sur lequel la hausse s''était appliquée (100 €). La non-additivité des pourcentages successifs est un point fondamental du programme de mathématiques.',
  'Croire que +10 % puis −10 % s''annulent. C''est l''erreur la plus fréquente sur les pourcentages : les évolutions successives se composent par multiplication des coefficients, pas par addition des taux.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f8080000-0000-0000-0000-000000000005',
  'Mathematiques', 'nombres_calcul', 'math_pourcentages_evolution',
  'Pourcentages d''évolution — Hausse, baisse et taux global', 'Difficile',
  'qcm',
  'Un prix subit une hausse de 20 % suivie d''une baisse de 30 %. Quel est le taux d''évolution global ?',
  NULL,
  '[{"id":"a","label":"Baisse de 10 %"},{"id":"b","label":"Baisse de 16 %"},{"id":"c","label":"Hausse de 10 %"},{"id":"d","label":"Baisse de 50 %"}]'::jsonb,
  '{"mode":"single","value":"b"}'::jsonb,
  'Pour calculer le taux d''évolution global de deux évolutions successives, on multiplie les coefficients multiplicateurs. Le coefficient de la hausse de 20 % est 1,20. Le coefficient de la baisse de 30 % est 0,70. Le coefficient multiplicateur global est : 1,20 × 0,70 = 0,84. Un coefficient de 0,84 correspond à une baisse de 1 − 0,84 = 0,16, soit 16 %. Vérification avec un prix de 100 € : après +20 %, on obtient 120 € ; après −30 %, on obtient 120 × 0,70 = 84 €. L''évolution globale est bien de 100 à 84, soit −16 %. L''erreur classique est d''additionner les taux : +20 % − 30 % = −10 %, ce qui est incorrect.',
  'Additionner les pourcentages (+20 − 30 = −10 %) au lieu de multiplier les coefficients multiplicateurs. Les pourcentages successifs ne s''additionnent jamais.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f8080000-0000-0000-0000-000000000006',
  'Mathematiques', 'nombres_calcul', 'math_pourcentages_evolution',
  'Pourcentages d''évolution — Hausse, baisse et taux global', 'Difficile',
  'reponse_courte',
  'Quel est le coefficient multiplicateur associé à une hausse de 35 % ?',
  NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["1,35","1.35"]}'::jsonb,
  'Le coefficient multiplicateur associé à une hausse de t % est donné par la formule : CM = 1 + t/100. Pour une hausse de 35 % : CM = 1 + 35/100 = 1 + 0,35 = 1,35. Ce coefficient permet de calculer directement la valeur finale : valeur finale = valeur initiale × 1,35. Par exemple, si un produit coûte 200 €, après une hausse de 35 %, il coûtera 200 × 1,35 = 270 €. Le coefficient multiplicateur est l''outil central pour traiter les problèmes de pourcentages d''évolution, car il permet de composer facilement des évolutions successives par simple multiplication.',
  'Écrire 0,35 au lieu de 1,35. Le coefficient 0,35 représente 35 % de la valeur, pas la valeur après une hausse de 35 %.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f8080000-0000-0000-0000-000000000007',
  'Mathematiques', 'nombres_calcul', 'math_pourcentages_evolution',
  'Pourcentages d''évolution — Hausse, baisse et taux global', 'Difficile',
  'qcm',
  'Lors des soldes, un magasin applique une première démarque de 30 %, puis une deuxième démarque de 20 % sur le prix déjà soldé. Un client affirme qu''il a bénéficié d''une réduction totale de 50 %. A-t-il raison ?',
  NULL,
  '[{"id":"a","label":"Oui, 30 % + 20 % = 50 % de réduction au total"},{"id":"b","label":"Non, la réduction totale est de 44 %"},{"id":"c","label":"Non, la réduction totale est de 56 %"},{"id":"d","label":"Non, la réduction totale est de 38 %"}]'::jsonb,
  '{"mode":"single","value":"b"}'::jsonb,
  'Le client a tort. Les pourcentages de réduction successifs ne s''additionnent pas. Le coefficient multiplicateur de la première démarque (−30 %) est 0,70. Le coefficient de la deuxième démarque (−20 %) est 0,80. Le coefficient global est : 0,70 × 0,80 = 0,56. Un coefficient de 0,56 signifie que le client paie 56 % du prix initial, soit une réduction globale de 1 − 0,56 = 0,44 = 44 %. Exemple concret : un article à 100 € passe à 70 € après la première démarque, puis à 70 × 0,80 = 56 € après la deuxième. La réduction totale est de 44 €, soit 44 % — et non 50 %. Ce problème de soldes successives est un classique du CRPE.',
  'Additionner les deux pourcentages de réduction (30 % + 20 % = 50 %). C''est le piège classique : la deuxième réduction s''applique au prix déjà réduit, pas au prix initial.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

-- math_probabilites_arbres (organisation_donnees) : 3 -> 10 questions
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fb0a0000-0000-0000-0000-000000000001',
  'Mathematiques', 'organisation_donnees', 'math_probabilites_arbres',
  'Probabilités — Arbres et situations composées', 'Intermediaire',
  'qcm',
  'Une urne contient 3 boules rouges et 2 boules bleues. On tire successivement deux boules avec remise. À l''aide d''un arbre de probabilités, déterminer la probabilité d''obtenir deux boules rouges.',
  NULL,
  '[{"id":"a","label":"6/25"},{"id":"b","label":"9/25"},{"id":"c","label":"3/10"},{"id":"d","label":"6/20"}]'::jsonb,
  '{"mode":"single","value":"b"}'::jsonb,
  'On construit un arbre à deux niveaux. Au premier tirage, P(Rouge) = 3/5. Comme le tirage est avec remise, la composition de l''urne ne change pas au second tirage : P(Rouge) = 3/5. Pour obtenir deux boules rouges, on multiplie les probabilités le long de la branche : P(R puis R) = 3/5 × 3/5 = 9/25. C''est la règle fondamentale de l''arbre de probabilités : on multiplie les probabilités le long d''un chemin pour obtenir la probabilité de la séquence d''événements correspondante.',
  'Additionner les probabilités au lieu de les multiplier (3/5 + 3/5 = 6/5 > 1, ce qui est impossible pour une probabilité). On multiplie le long des branches et on additionne entre les chemins exclusifs.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fb0a0000-0000-0000-0000-000000000002',
  'Mathematiques', 'organisation_donnees', 'math_probabilites_arbres',
  'Probabilités — Arbres et situations composées', 'Intermediaire',
  'reponse_courte',
  'On lance une pièce équilibrée deux fois de suite. En utilisant un arbre de probabilités, calculer la probabilité d''obtenir exactement un Pile et un Face (dans n''importe quel ordre). Donner le résultat sous forme de fraction irréductible.',
  NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["1/2","0,5","0.5"]}'::jsonb,
  'L''arbre comporte 4 chemins équiprobables de probabilité 1/4 chacun : (P,P), (P,F), (F,P), (F,F). Les chemins correspondant à « exactement un Pile et un Face » sont (P,F) et (F,P). Ces deux événements sont incompatibles, donc on additionne leurs probabilités : P = 1/4 + 1/4 = 2/4 = 1/2. C''est la règle d''addition des chemins exclusifs dans un arbre : quand plusieurs chemins réalisent l''événement souhaité, on additionne les probabilités de chaque chemin.',
  'Ne compter qu''un seul chemin (P,F) et oublier (F,P), ce qui donne 1/4 au lieu de 1/2. L''ordre des lancers compte dans l''arbre, il faut considérer tous les chemins favorables.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fb0a0000-0000-0000-0000-000000000003',
  'Mathematiques', 'organisation_donnees', 'math_probabilites_arbres',
  'Probabilités — Arbres et situations composées', 'Intermediaire',
  'qcm',
  'Un sac contient 4 billes vertes et 6 billes jaunes. On tire une bille, on note sa couleur, puis on tire une seconde bille sans remettre la première. Quelle est la probabilité d''obtenir une bille verte puis une bille jaune ?',
  NULL,
  '[{"id":"a","label":"24/100"},{"id":"b","label":"4/15"},{"id":"c","label":"6/25"},{"id":"d","label":"24/90"}]'::jsonb,
  '{"mode":"single","value":"b"}'::jsonb,
  'Au premier tirage, P(Verte) = 4/10. Comme le tirage est sans remise, il reste 9 billes dans le sac après le premier tirage, dont 6 jaunes. Donc P(Jaune | Verte au 1er) = 6/9. On multiplie le long de la branche : P(V puis J) = 4/10 × 6/9 = 24/90 = 4/15. Dans un arbre de probabilités sans remise, les probabilités au second niveau dépendent du résultat du premier tirage : ce sont des probabilités conditionnelles. C''est ce qui distingue fondamentalement le tirage sans remise du tirage avec remise.',
  'Utiliser les mêmes probabilités qu''avec remise (4/10 × 6/10 = 24/100) en oubliant que la composition de l''urne change après le premier tirage sans remise.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fb0a0000-0000-0000-0000-000000000004',
  'Mathematiques', 'organisation_donnees', 'math_probabilites_arbres',
  'Probabilités — Arbres et situations composées', 'Intermediaire',
  'qcm',
  'On lance deux pièces équilibrées simultanément. Quelle est la probabilité d''obtenir au moins un Pile ?',
  NULL,
  '[{"id":"a","label":"1/2"},{"id":"b","label":"1/4"},{"id":"c","label":"3/4"},{"id":"d","label":"2/3"}]'::jsonb,
  '{"mode":"single","value":"c"}'::jsonb,
  'L''arbre donne 4 issues équiprobables : (P,P), (P,F), (F,P), (F,F), chacune de probabilité 1/4. « Au moins un Pile » correspond à tous les chemins sauf (F,F). On peut calculer directement : P(au moins un P) = 1 − P(aucun P) = 1 − P(F,F) = 1 − 1/4 = 3/4. On peut aussi additionner les chemins favorables : P = 1/4 + 1/4 + 1/4 = 3/4. La méthode par l''événement contraire (1 − P(contraire)) est souvent plus rapide quand « au moins un » est demandé.',
  'Répondre 1/2 en pensant qu''il suffit de regarder une seule pièce. Avec deux pièces, la situation est composée et l''arbre montre bien 4 issues distinctes, pas 2.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fb0a0000-0000-0000-0000-000000000005',
  'Mathematiques', 'organisation_donnees', 'math_probabilites_arbres',
  'Probabilités — Arbres et situations composées', 'Intermediaire',
  'vrai_faux',
  'Dans un tirage sans remise de 2 boules parmi 5 rouges et 5 bleues, la probabilité d''obtenir 2 boules rouges est la même que dans un tirage avec remise.',
  NULL,
  NULL,
  '{"mode":"single","value":"faux"}'::jsonb,
  'C''est faux. Avec remise : P(2 rouges) = 5/10 × 5/10 = 25/100 = 1/4. Sans remise : P(2 rouges) = 5/10 × 4/9 = 20/90 = 2/9. Or 1/4 = 0,25 et 2/9 ≈ 0,222, ces deux valeurs sont différentes. Sans remise, après avoir tiré une boule rouge, il ne reste que 4 rouges sur 9 boules, ce qui diminue la probabilité d''en tirer une seconde rouge. La probabilité conditionnelle P(Rouge au 2ᵉ | Rouge au 1ᵉʳ) passe de 5/10 (avec remise) à 4/9 (sans remise). L''arbre de probabilités met clairement en évidence cette différence entre les deux situations.',
  'Croire que le mode de tirage (avec ou sans remise) ne change pas les probabilités. La dépendance entre les tirages successifs modifie les probabilités conditionnelles et donc le résultat final.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fb0a0000-0000-0000-0000-000000000006',
  'Mathematiques', 'organisation_donnees', 'math_probabilites_arbres',
  'Probabilités — Arbres et situations composées', 'Intermediaire',
  'reponse_courte',
  'Un sac contient 3 boules rouges et 7 boules blanches. On effectue deux tirages avec remise. Calculer la probabilité d''obtenir au moins une boule rouge. Donner le résultat sous forme de fraction sur 100.',
  NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["51/100","51 %","0,51","0.51"]}'::jsonb,
  'On utilise l''événement contraire : P(au moins une rouge) = 1 − P(aucune rouge) = 1 − P(blanche puis blanche). Avec remise, P(Blanche) = 7/10 à chaque tirage. Donc P(BB) = 7/10 × 7/10 = 49/100. Ainsi P(au moins une rouge) = 1 − 49/100 = 51/100 = 51 %. L''arbre comporte 4 chemins : (R,R) = 9/100, (R,B) = 21/100, (B,R) = 21/100, (B,B) = 49/100. La somme des trois premiers donne bien 51/100. La méthode par le complémentaire est plus efficace quand « au moins un » est demandé.',
  'Calculer uniquement P(Rouge au 1er tirage) = 3/10 = 30 % en oubliant les cas où le rouge apparaît au second tirage seulement.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fb0a0000-0000-0000-0000-000000000007',
  'Mathematiques', 'organisation_donnees', 'math_probabilites_arbres',
  'Probabilités — Arbres et situations composées', 'Intermediaire',
  'qcm',
  'Un test de dépistage a une sensibilité de 95 % (si l''on est malade, le test est positif dans 95 % des cas) et une spécificité de 90 % (si l''on n''est pas malade, le test est négatif dans 90 % des cas). Dans une population où 2 % des individus sont atteints de la maladie, quelle est la probabilité qu''une personne testée positive soit réellement malade ?',
  'On modélise la situation par un arbre à deux niveaux : premier niveau = malade (M) ou non malade (M̄), second niveau = test positif (T⁺) ou négatif (T⁻).',
  '[{"id":"a","label":"95 %"},{"id":"b","label":"Environ 16 %"},{"id":"c","label":"Environ 50 %"},{"id":"d","label":"Environ 2 %"}]'::jsonb,
  '{"mode":"single","value":"b"}'::jsonb,
  'On construit l''arbre avec P(M) = 0,02 et P(M̄) = 0,98. Branches : P(T⁺|M) = 0,95, P(T⁻|M) = 0,05, P(T⁺|M̄) = 0,10, P(T⁻|M̄) = 0,90. On calcule P(T⁺) par la formule des probabilités totales : P(T⁺) = P(M) × P(T⁺|M) + P(M̄) × P(T⁺|M̄) = 0,02 × 0,95 + 0,98 × 0,10 = 0,019 + 0,098 = 0,117. Puis, par la formule de Bayes : P(M|T⁺) = P(M) × P(T⁺|M) / P(T⁺) = 0,019 / 0,117 ≈ 0,162, soit environ 16 %. Ce résultat surprenant montre que même avec un test performant, quand la maladie est rare, la plupart des tests positifs sont des faux positifs.',
  'Confondre la sensibilité du test (95 %) avec la probabilité d''être malade sachant que le test est positif. Ce sont deux probabilités conditionnelles différentes : P(T⁺|M) ≠ P(M|T⁺). C''est le piège classique de l''inversion des conditionnelles.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

-- math_probabilites_composees (organisation_donnees) : 3 -> 10 questions
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'b00d0000-0000-0000-0000-000000000001', 'Mathematiques', 'organisation_donnees', 'math_probabilites_composees',
  'Probabilités — Situations composées', 'Avance', 'qcm',
  'On lance un dé équilibré à six faces. Quelle est la probabilité d''obtenir un nombre premier ?', NULL,
  '[{"id":"a","label":"1/3"},{"id":"b","label":"1/2"},{"id":"c","label":"2/3"},{"id":"d","label":"1/6"}]'::jsonb,
  '{"mode":"single","value":"b"}'::jsonb,
  'Les nombres premiers entre 1 et 6 sont : 2, 3 et 5. Il y en a donc 3 sur 6 faces possibles. La probabilité est 3/6 = 1/2. Attention : 1 n''est pas un nombre premier (il n''a qu''un seul diviseur), et 4 et 6 ne sont pas premiers car ils sont divisibles par 2.',
  'Oublier que 1 n''est pas un nombre premier et compter 4 nombres premiers (1, 2, 3, 5), ce qui donnerait 4/6 = 2/3.',
  'valide',
  'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'b00d0000-0000-0000-0000-000000000002', 'Mathematiques', 'organisation_donnees', 'math_probabilites_composees',
  'Probabilités — Situations composées', 'Avance', 'vrai_faux',
  'Quand on lance deux dés équilibrés à six faces, obtenir un total de 6 est aussi probable qu''obtenir un total de 7.', NULL,
  '[{"id":"vrai","label":"Vrai"},{"id":"faux","label":"Faux"}]'::jsonb,
  '{"mode":"single","value":"faux"}'::jsonb,
  'C''est faux. L''espace des possibles comprend 6 × 6 = 36 issues équiprobables. Pour un total de 6, les combinaisons sont : (1,5), (2,4), (3,3), (4,2), (5,1) → 5 issues favorables, soit une probabilité de 5/36. Pour un total de 7, les combinaisons sont : (1,6), (2,5), (3,4), (4,3), (5,2), (6,1) → 6 issues favorables, soit une probabilité de 6/36 = 1/6. Le total de 7 est donc plus probable que le total de 6.',
  'Croire que tous les totaux possibles sont équiprobables, sans dénombrer les combinaisons distinctes associées à chaque somme.',
  'valide',
  'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'b00d0000-0000-0000-0000-000000000003', 'Mathematiques', 'organisation_donnees', 'math_probabilites_composees',
  'Probabilités — Situations composées', 'Avance', 'qcm',
  'Un sac contient 3 boules rouges et 5 boules bleues. On tire successivement 2 boules SANS remise. Quelle est la probabilité de tirer 2 boules rouges ?', NULL,
  '[{"id":"a","label":"9/64"},{"id":"b","label":"3/28"},{"id":"c","label":"6/64"},{"id":"d","label":"1/8"}]'::jsonb,
  '{"mode":"single","value":"b"}'::jsonb,
  'On utilise un arbre de probabilités pour modéliser cette expérience à deux épreuves successives. Au premier tirage, la probabilité de tirer une boule rouge est 3/8 (3 rouges sur 8 boules au total). Puisqu''il n''y a pas de remise, au deuxième tirage il reste 2 boules rouges sur 7 boules. La probabilité de tirer deux rouges est donc : P(R₁ ∩ R₂) = 3/8 × 2/7 = 6/56 = 3/28. Le distracteur 9/64 correspond à un calcul avec remise (3/8 × 3/8). Le distracteur 1/8 correspond à 3/8 × 1/3, un calcul erroné.',
  'Calculer comme s''il y avait remise (3/8 × 3/8 = 9/64) au lieu de tenir compte de la modification de la composition du sac après le premier tirage.',
  'valide',
  'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'b00d0000-0000-0000-0000-000000000004', 'Mathematiques', 'organisation_donnees', 'math_probabilites_composees',
  'Probabilités — Situations composées', 'Avance', 'reponse_courte',
  'On lance une pièce équilibrée 3 fois de suite. Quelle est la probabilité d''obtenir exactement 2 fois « face » ? Donnez votre réponse sous forme de fraction irréductible.', NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["3/8"]}'::jsonb,
  'L''espace des possibles contient 2³ = 8 issues équiprobables. On liste toutes les issues comportant exactement 2 « face » (F) et 1 « pile » (P) : FFP, FPF, PFF. Il y a donc 3 issues favorables sur 8 possibles. La probabilité est 3/8. On peut aussi utiliser le coefficient binomial : C(3,2) = 3, et chaque issue a une probabilité de (1/2)³ = 1/8, d''où P = 3 × 1/8 = 3/8.',
  'Ne pas recenser toutes les configurations possibles et oublier certains arrangements, par exemple ne compter que FFP et FPF (2/8 = 1/4).',
  'valide',
  'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'b00d0000-0000-0000-0000-000000000005', 'Mathematiques', 'organisation_donnees', 'math_probabilites_composees',
  'Probabilités — Situations composées', 'Avance', 'qcm',
  'Dans une classe de 30 élèves, 18 aiment les mathématiques, 12 aiment le français, et 6 aiment les deux matières. Si on choisit un élève au hasard, quelle est la probabilité qu''il n''aime ni les mathématiques ni le français ?', NULL,
  '[{"id":"a","label":"1/5"},{"id":"b","label":"1/6"},{"id":"c","label":"4/30"},{"id":"d","label":"1/3"}]'::jsonb,
  '{"mode":"single","value":"a"}'::jsonb,
  'On applique la formule d''inclusion-exclusion : le nombre d''élèves qui aiment au moins une des deux matières est |M ∪ F| = |M| + |F| − |M ∩ F| = 18 + 12 − 6 = 24. Le nombre d''élèves qui n''aiment ni l''une ni l''autre est donc 30 − 24 = 6. La probabilité est 6/30 = 1/5. On peut aussi représenter la situation à l''aide d''un diagramme de Venn : M seul = 12, F seul = 6, M ∩ F = 6, extérieur = 6.',
  'Oublier de soustraire l''intersection et calculer 18 + 12 = 30, concluant à tort que tous les élèves aiment au moins une matière.',
  'valide',
  'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'b00d0000-0000-0000-0000-000000000006', 'Mathematiques', 'organisation_donnees', 'math_probabilites_composees',
  'Probabilités — Situations composées', 'Avance', 'reponse_courte',
  'Un test médical a une sensibilité de 95 % (il détecte correctement 95 % des malades) et une spécificité de 90 % (10 % de faux positifs chez les personnes saines). Dans une population où 2 % des individus sont malades, quelle est la probabilité qu''une personne testée positive soit réellement malade ? Donnez votre réponse sous forme de fraction irréductible.', NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["19/117"]}'::jsonb,
  'On utilise le théorème de Bayes avec un arbre de probabilités à deux niveaux. Niveau 1 : Malade (M) avec P(M) = 0,02 et Sain (S) avec P(S) = 0,98. Niveau 2 : Test positif (+) sachant M → P(+|M) = 0,95 ; Test positif sachant S → P(+|S) = 0,10. On calcule P(+) par la formule des probabilités totales : P(+) = P(+|M) × P(M) + P(+|S) × P(S) = 0,95 × 0,02 + 0,10 × 0,98 = 0,019 + 0,098 = 0,117. Puis, par le théorème de Bayes : P(M|+) = P(+|M) × P(M) / P(+) = 0,019 / 0,117 = 19/117 ≈ 16,2 %. Ce résultat, contre-intuitif, montre que même avec un test performant, la valeur prédictive positive reste faible quand la maladie est rare.',
  'Confondre la sensibilité du test (95 %) avec la probabilité d''être malade sachant un test positif, en négligeant la prévalence de la maladie dans la population.',
  'valide',
  'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'b00d0000-0000-0000-0000-000000000007', 'Mathematiques', 'organisation_donnees', 'math_probabilites_composees',
  'Probabilités — Situations composées', 'Avance', 'qcm',
  'Un jeu de loterie propose 3 billets gagnants sur 10 billets au total. Trois amis achètent chacun un billet successivement (sans remise). Quelle est la probabilité qu''au moins l''un d''entre eux gagne ?', NULL,
  '[{"id":"a","label":"17/24"},{"id":"b","label":"3/10"},{"id":"c","label":"7/24"},{"id":"d","label":"27/1000"}]'::jsonb,
  '{"mode":"single","value":"a"}'::jsonb,
  'On utilise l''événement complémentaire : P(au moins un gagnant) = 1 − P(aucun ne gagne). On construit un arbre de probabilités pour les tirages successifs sans remise. Le 1ᵉʳ ami ne gagne pas : 7 billets perdants sur 10, P₁ = 7/10. Le 2ᵉ ami ne gagne pas : 6 billets perdants sur 9, P₂ = 6/9. Le 3ᵉ ami ne gagne pas : 5 billets perdants sur 8, P₃ = 5/8. P(aucun ne gagne) = 7/10 × 6/9 × 5/8 = 210/720 = 7/24. Donc P(au moins un gagne) = 1 − 7/24 = 17/24. Le distracteur 27/1000 correspond à un calcul erroné avec remise : (3/10)³. Le distracteur 3/10 correspond à la probabilité pour un seul ami.',
  'Calculer P(au moins un) comme 3 × (3/10) = 9/10, en additionnant les probabilités individuelles sans tenir compte du fait que les tirages sont sans remise et non indépendants.',
  'valide',
  'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

-- math_probabilites_equiprobabilite (organisation_donnees) : 3 -> 10 questions
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fb110000-0000-0000-0000-000000000001',
  'Mathematiques', 'organisation_donnees', 'math_probabilites_equiprobabilite',
  'Probabilités et équiprobabilité', 'Intermediaire',
  'qcm',
  'Qu''appelle-t-on une situation d''équiprobabilité ?',
  NULL,
  '[{"id":"a","label":"Une situation où tous les résultats possibles ont la même probabilité de se produire"},{"id":"b","label":"Une situation où l''on est sûr du résultat"},{"id":"c","label":"Une situation où il y a exactement deux résultats possibles"},{"id":"d","label":"Une situation où la probabilité de chaque événement est supérieure à 50 %"}]'::jsonb,
  '{"mode":"single","value":"a"}'::jsonb,
  'L''équiprobabilité désigne une situation aléatoire dans laquelle tous les résultats élémentaires (ou issues) ont la même probabilité de se produire. Par exemple, un dé non truqué est un modèle d''équiprobabilité : chaque face a une probabilité de 1/6 d''apparaître. De même, une pièce équilibrée donne pile ou face avec la même probabilité de 1/2. L''équiprobabilité n''exige pas qu''il y ait exactement deux résultats, ni que la probabilité soit supérieure à 50 %. Les programmes Éduscol du cycle 3 introduisent la notion d''équiprobabilité à travers des expériences concrètes (lancers de dés, tirages de cartes).',
  'Confondre équiprobabilité avec certitude, ou croire que l''équiprobabilité n''existe que pour deux résultats (pile/face).',
  'valide',
  'Génération Claude — Programme Éduscol cycle 3 / CRPE',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fb110000-0000-0000-0000-000000000002',
  'Mathematiques', 'organisation_donnees', 'math_probabilites_equiprobabilite',
  'Probabilités et équiprobabilité', 'Intermediaire',
  'vrai_faux',
  'On lance un dé truqué qui a deux fois plus de chances de tomber sur 6 que sur chacune des autres faces. La situation est équiprobable.',
  NULL,
  NULL,
  '{"mode":"single","value":"faux"}'::jsonb,
  'Dans ce cas, le 6 a une probabilité plus grande que les autres faces. Si on note p la probabilité de chaque face de 1 à 5, alors la probabilité du 6 est 2p. La somme vaut 1 : 5p + 2p = 7p = 1, donc p = 1/7 et P(6) = 2/7. Les faces n''ont pas la même probabilité (1/7 ≠ 2/7), donc la situation n''est pas équiprobable. Pour qu''il y ait équiprobabilité, il faudrait que chaque face ait une probabilité de 1/6. Distinguer une situation équiprobable d''une situation non équiprobable est fondamental : dans le cas non équiprobable, on ne peut pas simplement compter les cas favorables et diviser par le nombre total de cas.',
  'Croire que tout lancer de dé est automatiquement équiprobable, sans vérifier si le dé est truqué ou non.',
  'valide',
  'Génération Claude — Programme Éduscol cycle 3 / CRPE',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fb110000-0000-0000-0000-000000000003',
  'Mathematiques', 'organisation_donnees', 'math_probabilites_equiprobabilite',
  'Probabilités et équiprobabilité', 'Intermediaire',
  'qcm',
  'On lance un dé équilibré à 6 faces. Quelle est la probabilité d''obtenir un nombre strictement supérieur à 4 ?',
  NULL,
  '[{"id":"a","label":"1/6"},{"id":"b","label":"2/6 soit 1/3"},{"id":"c","label":"4/6 soit 2/3"},{"id":"d","label":"3/6 soit 1/2"}]'::jsonb,
  '{"mode":"single","value":"b"}'::jsonb,
  'Les résultats strictement supérieurs à 4 sont : 5 et 6. Il y a donc 2 résultats favorables sur 6 résultats possibles (équiprobables). La probabilité est : 2/6 = 1/3 ≈ 0,333. Formule générale en situation d''équiprobabilité : P(événement) = nombre de cas favorables / nombre total de cas. Attention à « strictement supérieur à 4 » : le 4 n''est pas inclus. Si la question disait « supérieur ou égal à 4 », les résultats seraient 4, 5 et 6, soit une probabilité de 3/6 = 1/2. La précision du vocabulaire mathématique est essentielle (Éduscol).',
  'Inclure le 4 dans les résultats favorables (« supérieur à 4 » ≠ « supérieur ou égal à 4 »), ce qui donnerait 3/6 au lieu de 2/6.',
  'valide',
  'Génération Claude — Programme Éduscol cycle 3 / CRPE',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fb110000-0000-0000-0000-000000000004',
  'Mathematiques', 'organisation_donnees', 'math_probabilites_equiprobabilite',
  'Probabilités et équiprobabilité', 'Intermediaire',
  'reponse_courte',
  'On tire une carte au hasard dans un jeu standard de 32 cartes. Quelle est la probabilité de tirer un roi ? (Répondez sous forme de fraction simplifiée, ex : 1/4)',
  NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["1/8","1 / 8","1/8e"]}'::jsonb,
  'Un jeu de 32 cartes contient 4 rois (roi de cœur, roi de carreau, roi de trèfle, roi de pique). La probabilité de tirer un roi est : 4/32 = 1/8. Chaque carte a la même probabilité d''être tirée (équiprobabilité du tirage au hasard), donc on applique la formule : P = nombre de cas favorables / nombre total de cas = 4/32 = 1/8. On peut exprimer ce résultat en décimal : 1/8 = 0,125, soit 12,5 %. Les jeux de cartes sont un support classique pour travailler les probabilités en situation d''équiprobabilité au cycle 3 et au CRPE.',
  'Oublier qu''il y a 4 rois dans un jeu de 32 cartes (un par couleur) et répondre 1/32.',
  'valide',
  'Génération Claude — Programme Éduscol cycle 3 / CRPE',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fb110000-0000-0000-0000-000000000005',
  'Mathematiques', 'organisation_donnees', 'math_probabilites_equiprobabilite',
  'Probabilités et équiprobabilité', 'Intermediaire',
  'qcm',
  'On lance deux dés équilibrés à 6 faces et on additionne les résultats. Quelle est la probabilité d''obtenir une somme égale à 7 ?',
  NULL,
  '[{"id":"a","label":"1/6"},{"id":"b","label":"6/36 soit 1/6"},{"id":"c","label":"7/36"},{"id":"d","label":"1/12"}]'::jsonb,
  '{"mode":"single","value":"b"}'::jsonb,
  'Avec deux dés, il y a 6 × 6 = 36 résultats équiprobables (chaque couple (dé1, dé2) a la même probabilité). Les couples donnant une somme de 7 sont : (1,6), (2,5), (3,4), (4,3), (5,2), (6,1) — soit 6 couples. La probabilité est donc 6/36 = 1/6. La somme 7 est la somme la plus probable avec deux dés. On peut le vérifier : la somme 2 n''a qu''une seule façon (1,1), la somme 3 en a deux (1,2 et 2,1), etc. La somme 7 est au « milieu » et maximise le nombre de combinaisons. Ce problème illustre que même si chaque dé est équiprobable, les sommes ne le sont pas.',
  'Croire que toutes les sommes (de 2 à 12) sont équiprobables, et répondre 1/11. Les sommes ne sont PAS équiprobables car elles peuvent être obtenues de différentes façons.',
  'valide',
  'Génération Claude — Programme Éduscol cycle 3 / CRPE',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fb110000-0000-0000-0000-000000000006',
  'Mathematiques', 'organisation_donnees', 'math_probabilites_equiprobabilite',
  'Probabilités et équiprobabilité', 'Intermediaire',
  'vrai_faux',
  'On lance deux dés équilibrés à 6 faces et on note la somme des résultats. La situation est équiprobable : chaque somme (de 2 à 12) a la même probabilité d''apparaître.',
  NULL,
  NULL,
  '{"mode":"single","value":"faux"}'::jsonb,
  'La situation n''est PAS équiprobable pour les sommes. Bien que chaque couple (dé1, dé2) soit équiprobable parmi les 36 possibles, les sommes ne le sont pas car certaines sommes peuvent être obtenues de plus de façons que d''autres. Par exemple : la somme 2 ne s''obtient que par (1,1) → probabilité 1/36 ; la somme 7 s''obtient par (1,6), (2,5), (3,4), (4,3), (5,2), (6,1) → probabilité 6/36 = 1/6. La somme 7 est donc 6 fois plus probable que la somme 2. C''est une erreur très courante de croire que l''équiprobabilité des résultats élémentaires (les faces de chaque dé) implique l''équiprobabilité des événements composés (les sommes). Ce contre-exemple est classique en didactique des probabilités.',
  'Raisonner ainsi : « puisque les dés sont équilibrés, les sommes doivent aussi être équiprobables ». L''équiprobabilité des résultats élémentaires ne se transmet pas aux événements composés.',
  'valide',
  'Génération Claude — Programme Éduscol cycle 3 / CRPE',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fb110000-0000-0000-0000-000000000007',
  'Mathematiques', 'organisation_donnees', 'math_probabilites_equiprobabilite',
  'Probabilités et équiprobabilité', 'Intermediaire',
  'qcm',
  'Lors d''une tombola, 500 billets sont vendus. Il y a 1 lot principal, 4 lots secondaires et 20 lots de consolation. Quelle est la probabilité de gagner au moins un lot en achetant un seul billet ?',
  NULL,
  '[{"id":"a","label":"1/500"},{"id":"b","label":"25/500 soit 1/20"},{"id":"c","label":"5/500 soit 1/100"},{"id":"d","label":"20/500 soit 1/25"}]'::jsonb,
  '{"mode":"single","value":"b"}'::jsonb,
  'Le nombre total de billets gagnants est : 1 + 4 + 20 = 25 billets. Sur 500 billets au total, la probabilité de gagner au moins un lot est : 25/500 = 1/20 = 5 %. C''est une situation d''équiprobabilité : chaque billet a la même probabilité d''être tiré. On applique donc directement la formule P = cas favorables / cas possibles = 25/500. La tombola est un exemple concret d''expérience aléatoire en situation d''équiprobabilité, souvent utilisé dans les manuels de cycle 3 (Éduscol). Ce problème permet de travailler la simplification de fractions (25/500 = 1/20) et la conversion en pourcentage.',
  'Ne compter que le lot principal (1/500) en oubliant les lots secondaires et de consolation, ou confondre le nombre de lots avec le nombre de billets.',
  'valide',
  'Génération Claude — Programme Éduscol cycle 3 / CRPE',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

-- math_probabilites_evenements (organisation_donnees) : 3 -> 10 questions
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'c0030000-0000-0000-0000-000000000001',
  'Mathematiques', 'organisation_donnees', 'math_probabilites_evenements',
  'Probabilités — Événements et calculs', 'Intermediaire',
  'qcm',
  'On lance un dé cubique équilibré à 6 faces. Quelle est la probabilité d''obtenir le nombre 4 ?',
  NULL,
  '[{"id":"a","label":"1/4"},{"id":"b","label":"1/6"},{"id":"c","label":"4/6"},{"id":"d","label":"1/3"}]'::jsonb,
  '{"mode":"single","value":"b"}'::jsonb,
  'Un dé cubique équilibré possède 6 faces, chacune ayant la même probabilité d''apparaître.\nL''univers des possibles est Ω = {1, 2, 3, 4, 5, 6}, soit 6 issues équiprobables.\nL''événement « obtenir 4 » ne comporte qu''une seule issue favorable.\nProbabilité = nombre d''issues favorables ÷ nombre total d''issues = 1/6.\n\nLe distracteur 1/4 provient d''une confusion entre la valeur du nombre (4) et le nombre de faces.',
  'Confondre la valeur inscrite sur la face (4) avec le calcul de probabilité, et écrire 1/4 au lieu de 1/6.',
  'valide',
  'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'c0030000-0000-0000-0000-000000000002',
  'Mathematiques', 'organisation_donnees', 'math_probabilites_evenements',
  'Probabilités — Événements et calculs', 'Intermediaire',
  'vrai_faux',
  'On tire une carte au hasard dans un jeu de 32 cartes. La probabilité de ne PAS obtenir un as est 28/32.',
  NULL,
  NULL,
  '{"mode":"single","value":"vrai"}'::jsonb,
  'Un jeu de 32 cartes contient 4 as. La probabilité d''obtenir un as est P(As) = 4/32.\nL''événement contraire « ne pas obtenir un as » a pour probabilité :\nP(contraire) = 1 − P(As) = 1 − 4/32 = 28/32 = 7/8.\nL''affirmation est donc vraie.\n\nRappel : pour tout événement A, P(Ā) = 1 − P(A). C''est la règle de l''événement complémentaire (ou contraire).',
  'Calculer 32 − 4 = 28 mais oublier de le mettre en rapport avec le total, ou confondre un jeu de 32 et un jeu de 52 cartes (dans un jeu de 52, il y a aussi 4 as, mais le total change).',
  'valide',
  'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'c0030000-0000-0000-0000-000000000003',
  'Mathematiques', 'organisation_donnees', 'math_probabilites_evenements',
  'Probabilités — Événements et calculs', 'Intermediaire',
  'reponse_courte',
  'On lance un dé cubique équilibré. Quelle est la probabilité d''obtenir un nombre pair OU le nombre 5 ? Donner la réponse sous forme de fraction irréductible.',
  NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["2/3","4/6"]}'::jsonb,
  'Les nombres pairs sur un dé sont {2, 4, 6} et le nombre 5 est {5}.\nCes deux événements sont incompatibles (disjoints) : aucun nombre ne peut être à la fois pair et égal à 5.\nDonc P(pair OU 5) = P(pair) + P(5) = 3/6 + 1/6 = 4/6 = 2/3.\n\nRappel : lorsque deux événements A et B sont incompatibles (A ∩ B = ∅), on a P(A ∪ B) = P(A) + P(B).',
  'Oublier de vérifier que les événements sont incompatibles et appliquer aveuglément P(A ∪ B) = P(A) + P(B) − P(A ∩ B), ou se tromper dans le dénombrement des nombres pairs.',
  'valide',
  'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'c0030000-0000-0000-0000-000000000004',
  'Mathematiques', 'organisation_donnees', 'math_probabilites_evenements',
  'Probabilités — Événements et calculs', 'Intermediaire',
  'qcm',
  'On tire une carte au hasard dans un jeu de 52 cartes. Quelle est la probabilité d''obtenir un roi ou un cœur ?',
  NULL,
  '[{"id":"a","label":"17/52"},{"id":"b","label":"16/52"},{"id":"c","label":"4/13"},{"id":"d","label":"30/52"}]'::jsonb,
  '{"mode":"single","value":"c"}'::jsonb,
  'On utilise la formule de l''union : P(Roi ∪ Cœur) = P(Roi) + P(Cœur) − P(Roi ET Cœur).\n• P(Roi) = 4/52 (4 rois dans le jeu)\n• P(Cœur) = 13/52 (13 cartes de cœur)\n• P(Roi de cœur) = 1/52 (il n''y a qu''un seul roi de cœur)\n\nP(Roi ∪ Cœur) = 4/52 + 13/52 − 1/52 = 16/52 = 4/13.\n\nLe distracteur 16/52 est correct en valeur mais n''est pas simplifié. Le distracteur 17/52 provient de l''oubli de soustraire l''intersection. Le distracteur 30/52 provient d''une erreur de comptage.',
  'Additionner les deux probabilités sans retirer l''intersection (le roi de cœur compté deux fois) : 4/52 + 13/52 = 17/52, ce qui est faux car les événements ne sont pas incompatibles.',
  'valide',
  'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'c0030000-0000-0000-0000-000000000005',
  'Mathematiques', 'organisation_donnees', 'math_probabilites_evenements',
  'Probabilités — Événements et calculs', 'Intermediaire',
  'vrai_faux',
  'On lance successivement deux pièces de monnaie équilibrées. Un arbre de probabilités montre 4 issues : (P,P), (P,F), (F,P) et (F,F), chacune de probabilité 1/4.\n\nAffirmation : « La probabilité d''obtenir au moins un pile est 3/4. »',
  NULL,
  NULL,
  '{"mode":"single","value":"vrai"}'::jsonb,
  'L''événement « au moins un pile » est le contraire de « aucun pile » (c''est-à-dire « deux faces »).\nP(F,F) = 1/4.\nDonc P(au moins un pile) = 1 − P(F,F) = 1 − 1/4 = 3/4.\n\nOn peut aussi dénombrer directement : les issues avec au moins un pile sont (P,P), (P,F), (F,P), soit 3 issues sur 4.\nP = 3/4. L''affirmation est vraie.\n\nDans un arbre, la probabilité d''un chemin se calcule en multipliant les probabilités le long des branches. Ici : P(P,F) = 1/2 × 1/2 = 1/4.',
  'Confondre « au moins un pile » avec « exactement un pile ». « Exactement un pile » ne comporte que 2 issues (P,F) et (F,P), soit une probabilité de 2/4 = 1/2. « Au moins un pile » en comporte 3.',
  'valide',
  'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'c0030000-0000-0000-0000-000000000006',
  'Mathematiques', 'organisation_donnees', 'math_probabilites_evenements',
  'Probabilités — Événements et calculs', 'Intermediaire',
  'qcm',
  'Un sac contient 3 boules rouges et 2 boules bleues. On tire une boule, on note sa couleur, puis on la remet dans le sac avant de tirer une seconde boule. Quelle est la probabilité d''obtenir deux boules rouges ?',
  NULL,
  '[{"id":"a","label":"9/25"},{"id":"b","label":"6/25"},{"id":"c","label":"3/10"},{"id":"d","label":"6/20"}]'::jsonb,
  '{"mode":"single","value":"a"}'::jsonb,
  'Puisqu''on remet la boule après le premier tirage (tirage avec remise), les deux tirages sont indépendants.\nP(rouge au 1er tirage) = 3/5\nP(rouge au 2ᵉ tirage) = 3/5 (la composition du sac n''a pas changé)\n\nPour deux événements indépendants : P(A ∩ B) = P(A) × P(B)\nP(deux rouges) = 3/5 × 3/5 = 9/25.\n\nLe distracteur 6/25 provient du calcul 3/5 × 2/5 (une rouge puis une bleue).\nLe distracteur 3/10 = 6/20 provient d''un tirage sans remise : 3/5 × 2/4 = 6/20.',
  'Calculer comme un tirage sans remise (3/5 × 2/4) alors que l''énoncé précise qu''on remet la boule. C''est une confusion fréquente entre tirage avec et sans remise.',
  'valide',
  'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'c0030000-0000-0000-0000-000000000007',
  'Mathematiques', 'organisation_donnees', 'math_probabilites_evenements',
  'Probabilités — Événements et calculs', 'Intermediaire',
  'reponse_courte',
  'Dans une classe de 30 élèves, 18 pratiquent un sport et 12 jouent d''un instrument de musique. Parmi ceux qui pratiquent un sport, 6 jouent également d''un instrument.\nOn choisit un élève au hasard parmi ceux qui pratiquent un sport. Quelle est la probabilité qu''il joue aussi d''un instrument ? Donner la réponse sous forme de fraction irréductible.',
  NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["1/3","6/18"]}'::jsonb,
  'On se restreint à la sous-population des sportifs : 18 élèves.\nParmi ces 18 sportifs, 6 jouent d''un instrument.\nLa probabilité cherchée est : 6/18 = 1/3.\n\nC''est un exemple introductif de probabilité conditionnelle : P(Instrument | Sport) = P(Instrument ∩ Sport) / P(Sport) = (6/30) / (18/30) = 6/18 = 1/3.\n\nAttention : on ne divise PAS par 30 (effectif total) mais par 18 (effectif de la condition « pratique un sport »).',
  'Diviser par l''effectif total de la classe (6/30 = 1/5) au lieu de l''effectif des sportifs (6/18 = 1/3). C''est la confusion classique entre probabilité conditionnelle et probabilité de l''intersection.',
  'valide',
  'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

-- math_problemes_grandeurs_avance (grandeurs_mesures) : 3 -> 10 questions
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fa0f0000-0000-0000-0000-000000000001', 'Mathematiques', 'grandeurs_mesures', 'math_problemes_grandeurs_avance', 'Problèmes de grandeurs — Niveau avancé CRPE', 'Difficile',
  'qcm', 'Un terrain rectangulaire a un périmètre de 60 m et une aire de 200 m². Quelles sont ses dimensions ?', NULL,
  '[{"id":"a","label":"10 m × 20 m"},{"id":"b","label":"15 m × 15 m"},{"id":"c","label":"8 m × 25 m"},{"id":"d","label":"12 m × 18 m"}]'::jsonb,
  '{"mode":"single","value":"a"}'::jsonb,
  'Soit L et l les dimensions. On a : 2(L + l) = 60, donc L + l = 30, et L × l = 200. On cherche deux nombres dont la somme est 30 et le produit 200. En résolvant : L et l sont solutions de x² − 30x + 200 = 0. Δ = 900 − 800 = 100. x = (30 ± 10) / 2, soit 20 et 10. Les dimensions sont 10 m × 20 m.',
  'Tester uniquement l''option b (15 × 15) car le périmètre convient (60 m), sans vérifier l''aire (225 ≠ 200) : l''élève ne vérifie qu''une seule condition.',
  'valide', 'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fa0f0000-0000-0000-0000-000000000002', 'Mathematiques', 'grandeurs_mesures', 'math_problemes_grandeurs_avance', 'Problèmes de grandeurs — Niveau avancé CRPE', 'Difficile',
  'reponse_courte', 'On souhaite clôturer un enclos rectangulaire de 800 m² d''aire en utilisant le minimum de grillage. Quelle longueur de grillage faut-il acheter, en mètres ? Arrondissez à l''unité.', NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["113","113 m","113m"]}'::jsonb,
  'Pour une aire fixée, le rectangle de périmètre minimal est le carré. Côté du carré : c = √800 = √(400 × 2) = 20√2 ≈ 28,28 m. Périmètre = 4 × 20√2 = 80√2 ≈ 113,14 m ≈ 113 m. Ce résultat s''appuie sur l''inégalité arithmético-géométrique : pour L + l fixé, L × l est maximal quand L = l (et réciproquement).',
  'Choisir des dimensions arbitraires (ex. 40 × 20 = 800 m², périmètre = 120 m) sans chercher à minimiser : l''élève ne perçoit pas que le carré minimise le périmètre à aire donnée.',
  'valide', 'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fa0f0000-0000-0000-0000-000000000003', 'Mathematiques', 'grandeurs_mesures', 'math_problemes_grandeurs_avance', 'Problèmes de grandeurs — Niveau avancé CRPE', 'Difficile',
  'qcm', 'Un pot de peinture couvre 12 m². On doit peindre les 4 murs d''une pièce rectangulaire de 5 m × 4 m et de hauteur 2,5 m (sans déduire les ouvertures). Combien de pots faut-il acheter ?', NULL,
  '[{"id":"a","label":"3 pots"},{"id":"b","label":"4 pots"},{"id":"c","label":"5 pots"},{"id":"d","label":"6 pots"}]'::jsonb,
  '{"mode":"single","value":"b"}'::jsonb,
  'Surface des murs = périmètre de la base × hauteur = 2 × (5 + 4) × 2,5 = 2 × 9 × 2,5 = 45 m². Nombre de pots = 45 / 12 = 3,75. Comme on ne peut pas acheter une fraction de pot, il faut arrondir au pot supérieur : 4 pots. Ce type de problème mobilise le périmètre, l''aire latérale et l''arrondi par excès.',
  'Calculer l''aire du sol (20 m²) au lieu de l''aire des murs, ou arrondir par défaut à 3 pots au lieu de 4.',
  'valide', 'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fa0f0000-0000-0000-0000-000000000004', 'Mathematiques', 'grandeurs_mesures', 'math_problemes_grandeurs_avance', 'Problèmes de grandeurs — Niveau avancé CRPE', 'Difficile',
  'vrai_faux', 'Un terrain triangulaire de 1 200 m² est partagé en 3 parcelles par deux segments parallèles à la base, divisant la hauteur en trois parties égales. La parcelle du sommet a une aire de 400 m².', NULL,
  NULL,
  '{"mode":"single","value":"faux"}'::jsonb,
  'Quand on découpe un triangle par des parallèles à la base, les aires ne sont pas proportionnelles aux hauteurs mais aux carrés des rapports de similitude. Le petit triangle (1/3 de la hauteur) a une aire = (1/3)² × 1 200 = 1 200 / 9 ≈ 133,3 m², pas 400 m². Les trois parcelles n''ont pas des aires égales : elles valent respectivement 1/9, 3/9 et 5/9 de l''aire totale.',
  'Penser que diviser la hauteur en 3 divise l''aire en 3 parts égales : l''élève confond proportionnalité des longueurs et des aires.',
  'valide', 'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fa0f0000-0000-0000-0000-000000000005', 'Mathematiques', 'grandeurs_mesures', 'math_problemes_grandeurs_avance', 'Problèmes de grandeurs — Niveau avancé CRPE', 'Difficile',
  'qcm', 'Deux offres de carrelage sont proposées. Offre A : carreaux de 30 cm × 30 cm à 1,80 € le carreau. Offre B : carreaux de 45 cm × 45 cm à 3,60 € le carreau. Quelle offre est la plus avantageuse au m² ?', NULL,
  '[{"id":"a","label":"Offre A (20 €/m²)"},{"id":"b","label":"Offre B (≈ 17,78 €/m²)"},{"id":"c","label":"Les deux offres ont le même prix au m²"},{"id":"d","label":"Offre A (18 €/m²)"}]'::jsonb,
  '{"mode":"single","value":"b"}'::jsonb,
  'Offre A : aire d''un carreau = 0,3 × 0,3 = 0,09 m². Prix au m² = 1,80 / 0,09 = 20 €/m². Offre B : aire d''un carreau = 0,45 × 0,45 = 0,2025 m². Prix au m² = 3,60 / 0,2025 ≈ 17,78 €/m². L''offre B est plus avantageuse malgré un prix unitaire plus élevé.',
  'Comparer directement le prix unitaire (1,80 € < 3,60 €) sans rapporter au m² : l''élève conclut que l''offre A est moins chère sans calculer le prix par unité de surface.',
  'valide', 'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fa0f0000-0000-0000-0000-000000000006', 'Mathematiques', 'grandeurs_mesures', 'math_problemes_grandeurs_avance', 'Problèmes de grandeurs — Niveau avancé CRPE', 'Difficile',
  'reponse_courte', 'On emballe un coffret parallélépipédique de dimensions 30 cm × 20 cm × 10 cm avec du papier cadeau. Quelle est la surface totale à couvrir, en cm² ?', NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["2200","2 200","2200 cm²","2 200 cm²"]}'::jsonb,
  'Surface totale d''un pavé droit = 2 × (L×l + L×h + l×h) = 2 × (30×20 + 30×10 + 20×10) = 2 × (600 + 300 + 200) = 2 × 1 100 = 2 200 cm². Il faut couvrir les 6 faces : deux de 600 cm², deux de 300 cm² et deux de 200 cm². Ce calcul ne tient pas compte des marges de pliage.',
  'Calculer le volume (6 000 cm³) au lieu de l''aire totale, ou n''additionner que 3 faces au lieu de 6 en oubliant le facteur 2.',
  'valide', 'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fa0f0000-0000-0000-0000-000000000007', 'Mathematiques', 'grandeurs_mesures', 'math_problemes_grandeurs_avance', 'Problèmes de grandeurs — Niveau avancé CRPE', 'Difficile',
  'qcm', 'Une cour d''école rectangulaire mesure 50 m × 30 m. On peint une bande de 2 m de large le long de tout le pourtour intérieur pour délimiter une aire de jeux. Quelle est l''aire de cette bande peinte ?', NULL,
  '[{"id":"a","label":"304 m²"},{"id":"b","label":"296 m²"},{"id":"c","label":"320 m²"},{"id":"d","label":"284 m²"}]'::jsonb,
  '{"mode":"single","value":"a"}'::jsonb,
  'Aire totale de la cour = 50 × 30 = 1 500 m². Aire intérieure (sans la bande) = (50 − 2×2) × (30 − 2×2) = 46 × 26 = 1 196 m². Aire de la bande = 1 500 − 1 196 = 304 m². On soustrait 2 × 2 = 4 m de chaque dimension car la bande de 2 m borde chaque côté. Ce type de problème est fréquent au CRPE : il combine périmètre et aire dans un raisonnement par différence de surfaces.',
  'Calculer la bande comme périmètre × largeur : (50 + 30) × 2 × 2 = 320 m², ce qui compte deux fois les quatre coins carrés de 2 × 2 = 4 m² chacun (320 − 4×4 = 304).',
  'valide', 'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

-- math_problemes_transversaux (nombres_calcul) : 3 -> 10 questions
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'c0050000-0000-0000-0000-000000000001',
  'Mathematiques',
  'nombres_calcul',
  'math_problemes_transversaux',
  'Problèmes transversaux — Multi-domaines',
  'Difficile',
  'qcm',
  'Sur une carte à l''échelle 1/25 000, la distance entre deux villages mesure 8 cm. Un randonneur marche à 4 km/h. Combien de temps lui faudra-t-il pour relier les deux villages ?',
  NULL,
  '[{"id":"a","label":"30 min"},{"id":"b","label":"1 h"},{"id":"c","label":"45 min"},{"id":"d","label":"2 h"}]',
  '{"mode":"single","value":"a"}',
  'Étape 1 — Échelle : 1/25 000 signifie que 1 cm sur la carte = 25 000 cm en réalité = 250 m. Distance réelle = 8 × 250 = 2 000 m = 2 km. Étape 2 — Vitesse : temps = distance / vitesse = 2 / 4 = 0,5 h = 30 min. Ce problème croise proportionnalité (échelle) et grandeurs composées (vitesse = distance/temps). Au CRPE, les problèmes croisant plusieurs domaines sont très fréquents — il faut savoir enchaîner les raisonnements de manière fluide.',
  'Se tromper dans la conversion de l''échelle (oublier que 25 000 cm = 250 m, pas 25 km) ou dans la conversion du temps décimal en minutes (0,5 h = 30 min, pas 50 min).',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'c0050000-0000-0000-0000-000000000002',
  'Mathematiques',
  'nombres_calcul',
  'math_problemes_transversaux',
  'Problèmes transversaux — Multi-domaines',
  'Difficile',
  'reponse_courte',
  'Une recette pour 4 personnes nécessite 3/4 de litre de lait. Quelle quantité de lait faut-il pour 6 personnes ? (Répondez en litres, sous forme fractionnaire.)',
  NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["9/8 L","9/8","1,125 L","1,125","1 1/8 L","1,125L","9/8 de litre"]}',
  'La quantité de lait est proportionnelle au nombre de personnes. Pour 4 personnes → 3/4 L. Pour 1 personne → (3/4) / 4 = 3/16 L. Pour 6 personnes → (3/16) × 6 = 18/16 = 9/8 L = 1,125 L. Méthode alternative (coefficient de proportionnalité) : rapport 6/4 = 3/2 = 1,5. Quantité = (3/4) × (3/2) = 9/8 L. Ce problème croise le calcul fractionnaire et la proportionnalité dans un contexte de grandeurs (contenances). Le résultat 9/8 est une fraction impropre, équivalente à 1 + 1/8 = 1,125 L.',
  'Faire une addition au lieu d''une multiplication (3/4 + 6 = ?), ou appliquer le mauvais rapport de proportionnalité.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'c0050000-0000-0000-0000-000000000003',
  'Mathematiques',
  'nombres_calcul',
  'math_problemes_transversaux',
  'Problèmes transversaux — Multi-domaines',
  'Difficile',
  'qcm',
  'Un jardin rectangulaire de 12 m × 8 m doit être clôturé, sauf l''entrée de 1,5 m. Le grillage coûte 14,50 €/m. Une porte de 1,5 m coûte 89 €. Quel est le coût total de la clôture ?',
  NULL,
  '[{"id":"a","label":"551,75 €"},{"id":"b","label":"640,75 €"},{"id":"c","label":"646,25 €"},{"id":"d","label":"667,00 €"}]',
  '{"mode":"single","value":"c"}',
  'Étape 1 — Périmètre : P = 2 × (12 + 8) = 40 m. Étape 2 — Longueur de grillage : 40 − 1,5 = 38,5 m (on retire l''entrée). Étape 3 — Coût du grillage : 38,5 × 14,50 = 558,25 €. Calcul détaillé : 38 × 14,50 = 551 € et 0,5 × 14,50 = 7,25 €, total = 558,25 €. Étape 4 — Coût total : 558,25 + 89 (porte) = 646,25 €. Ce problème type CRPE enchaîne : géométrie (périmètre), soustraction (entrée), proportionnalité (prix/m), addition (coût total). Chaque étape est simple, mais c''est l''enchaînement qui fait la difficulté.',
  'Oublier de retirer la longueur de l''entrée du périmètre, ou oublier d''ajouter le coût de la porte.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'c0050000-0000-0000-0000-000000000004',
  'Mathematiques',
  'nombres_calcul',
  'math_problemes_transversaux',
  'Problèmes transversaux — Multi-domaines',
  'Difficile',
  'reponse_courte',
  'Dans une école de 320 élèves, 60 % mangent à la cantine. L''école prévoit une augmentation de 5 % du nombre de demi-pensionnaires l''an prochain (le nombre total d''élèves reste constant). Combien d''élèves mangeront à la cantine l''an prochain ?',
  NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["201,6","202","201","201,6 élèves","202 élèves"]}',
  'Cette année : 320 × 60/100 = 192 demi-pensionnaires. Augmentation de 5 % : 192 × 1,05 = 201,6. En pratique, on arrondirait à 202 élèves (on ne peut pas avoir 0,6 élève). Ce problème croise statistiques descriptives (effectif/fréquence), pourcentages, et sens pratique (arrondi). Attention : l''augmentation de 5 % porte sur le nombre de demi-pensionnaires (192), pas sur le nombre total d''élèves (320). 5 % de 320 = 16 élèves de plus donnerait un résultat différent (192 + 16 = 208).',
  'Appliquer les 5 % d''augmentation sur le nombre total d''élèves (320) au lieu du nombre de demi-pensionnaires (192). Lire attentivement l''énoncé pour identifier la bonne base de calcul.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'c0050000-0000-0000-0000-000000000005',
  'Mathematiques',
  'nombres_calcul',
  'math_problemes_transversaux',
  'Problèmes transversaux — Multi-domaines',
  'Difficile',
  'vrai_faux',
  'Un pot de peinture de 2,5 L couvre 20 m². Pour peindre un mur de 3,6 m × 2,5 m (en 2 couches), un demi-pot suffit.',
  NULL,
  NULL,
  '{"mode":"single","value":"faux"}',
  'FAUX. Aire du mur = 3,6 × 2,5 = 9 m². En 2 couches : surface à peindre = 9 × 2 = 18 m². Un pot complet couvre 20 m², un demi-pot couvre 10 m². 10 m² < 18 m², donc un demi-pot ne suffit PAS. Il faudra au minimum 18/20 = 0,9 pot, soit presque un pot entier. Ce problème croise : géométrie (aire d''un rectangle), proportionnalité (rendement en m²/L), et raisonnement pratique (nombre de couches). Ne pas oublier les 2 couches, qui doublent la surface à couvrir !',
  'Oublier de compter les 2 couches (calculer seulement 9 m² au lieu de 18 m²). Avec 9 m², un demi-pot (10 m²) aurait suffi, mais pas pour 2 couches.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'c0050000-0000-0000-0000-000000000006',
  'Mathematiques',
  'nombres_calcul',
  'math_problemes_transversaux',
  'Problèmes transversaux — Multi-domaines',
  'Difficile',
  'reponse_courte',
  'Un terrain triangulaire rectangle a deux côtés perpendiculaires de 30 m et 40 m. On veut clôturer tout le périmètre avec du grillage à 8,50 €/m. Quel est le coût total ? (Répondez en euros.)',
  NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["1020 €","1020","1 020 €","1 020","1020€","1020,00","1 020,00"]}',
  'Étape 1 — Pythagore pour l''hypoténuse : c² = 30² + 40² = 900 + 1 600 = 2 500. c = √2 500 = 50 m. (Triplet pythagoricien 3-4-5 multiplié par 10.) Étape 2 — Périmètre : P = 30 + 40 + 50 = 120 m. Étape 3 — Coût : 120 × 8,50 = 1 020 €. Ce problème combine le théorème de Pythagore (géométrie), le calcul de périmètre, et la proportionnalité (coût/mètre). Reconnaître le triplet 30-40-50 comme multiple de 3-4-5 accélère considérablement le calcul.',
  'Ne pas penser à utiliser Pythagore pour calculer l''hypoténuse, ou faire une erreur dans le calcul de √2 500. Connaître les triplets pythagoriciens classiques (3-4-5, 5-12-13, 8-15-17) est un gain de temps.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'c0050000-0000-0000-0000-000000000007',
  'Mathematiques',
  'nombres_calcul',
  'math_problemes_transversaux',
  'Problèmes transversaux — Multi-domaines',
  'Difficile',
  'qcm',
  'Une piscine cylindrique a un diamètre de 4 m et une profondeur de 1,2 m. L''eau coûte 4,30 €/m³. La piscine est remplie aux 3/4 de sa capacité. Quel est le coût de remplissage ? (Prendre π ≈ 3,14.)',
  NULL,
  '[{"id":"a","label":"Environ 38,60 €"},{"id":"b","label":"Environ 48,30 €"},{"id":"c","label":"Environ 64,40 €"},{"id":"d","label":"Environ 51,50 €"}]',
  '{"mode":"single","value":"b"}',
  'Étape 1 — Volume total : rayon = 4/2 = 2 m. V = π × r² × h = 3,14 × 4 × 1,2 = 15,072 m³. Étape 2 — Volume d''eau (3/4) : 15,072 × 3/4 = 15,072 × 0,75 = 11,304 m³. Étape 3 — Coût : 11,304 × 4,30 = 48,607 ≈ 48,61 €, soit environ 48,30 € (avec les arrondis intermédiaires : 3,14 × 4 = 12,56, × 1,2 = 15,072, × 0,75 = 11,304, × 4,30 ≈ 48,61). Ce problème croise : géométrie (volume du cylindre), fractions (3/4), conversions (m³ → litres si besoin), et proportionnalité (coût). C''est typiquement le niveau d''un problème CRPE.',
  'Confondre rayon et diamètre (utiliser r = 4 au lieu de r = 2, ce qui quadruplerait le volume). Ou oublier de prendre les 3/4 du volume.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

-- math_programmes_construction (geometrie) : 3 -> 10 questions
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'b0150000-0000-0000-0000-000000000001', 'Mathematiques', 'geometrie', 'math_programmes_construction',
  'Programmes de construction — Rédiger et interpréter', 'Intermediaire', 'qcm',
  'Quel programme de construction permet de tracer un carré ABCD de côté 5 cm ?',
  NULL,
  '[{"id":"a","label":"Tracer un segment [AB] de 5 cm. Tracer la perpendiculaire à (AB) passant par A. Reporter 5 cm sur cette perpendiculaire pour placer D. Tracer la perpendiculaire à (AB) passant par B. Reporter 5 cm sur cette perpendiculaire pour placer C. Tracer les segments [DC]."},{"id":"b","label":"Tracer un segment [AB] de 5 cm. Tracer un segment [AD] de 5 cm. Tracer un segment [DC] de 5 cm. Tracer un segment [CB] de 5 cm."},{"id":"c","label":"Tracer un segment [AB] de 5 cm. À l''aide du compas, tracer un arc de cercle de centre A et de rayon 5 cm. Tracer un arc de cercle de centre B et de rayon 5 cm. Relier les points d''intersection."},{"id":"d","label":"Tracer un segment [AB] de 5 cm. Tracer la perpendiculaire à (AB) passant par A. Reporter 5 cm pour placer D. Tracer un segment [DC] de 5 cm parallèle à [AB]. Relier C à B."}]'::jsonb,
  '{"mode":"single","value":"a"}'::jsonb,
  'Pour construire un carré, il ne suffit pas de tracer quatre segments de même longueur : il faut garantir que les quatre angles sont droits. Le programme (a) utilise deux perpendiculaires (à l''aide de l''équerre) pour s''assurer que les angles en A et en B sont droits. Le programme (b) ne construit aucun angle droit, on obtient un quadrilatère quelconque aux côtés égaux (un losange, pas nécessairement un carré). Le programme (c) utilise le compas mais ne garantit pas d''angle droit. Le programme (d) est presque correct mais l''étape « tracer un segment parallèle » sans outil de construction précis est insuffisante : il faudrait une seconde perpendiculaire en D.',
  'Penser qu''il suffit de tracer quatre segments de 5 cm pour obtenir un carré, en oubliant que les angles droits doivent être explicitement construits à l''aide d''une équerre ou de perpendiculaires.',
  'valide',
  'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'b0150000-0000-0000-0000-000000000002', 'Mathematiques', 'geometrie', 'math_programmes_construction',
  'Programmes de construction — Rédiger et interpréter', 'Intermediaire', 'vrai_faux',
  'Le programme suivant produit un triangle équilatéral : « Tracer un segment [AB] de 6 cm. Tracer le cercle de centre A et de rayon 6 cm. Tracer le cercle de centre B et de rayon 6 cm. Nommer C un point d''intersection des deux cercles. Tracer le triangle ABC. »',
  NULL,
  '[{"id":"vrai","label":"Vrai"},{"id":"faux","label":"Faux"}]'::jsonb,
  '{"mode":"single","value":"vrai"}'::jsonb,
  'Ce programme est la construction classique du triangle équilatéral au compas. Le point C, intersection des deux cercles, se trouve à 6 cm de A (car il est sur le cercle de centre A et de rayon 6 cm) et à 6 cm de B (car il est sur le cercle de centre B et de rayon 6 cm). On a donc AC = BC = AB = 6 cm : le triangle ABC a ses trois côtés égaux, c''est bien un triangle équilatéral. Cette construction fondamentale est au programme du cycle 3 et constitue un classique du CRPE.',
  'Confondre cette construction avec celle d''un triangle isocèle, ou ne pas reconnaître que les deux cercles de même rayon (égal à la longueur du segment) garantissent l''équilatéralité.',
  'valide',
  'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'b0150000-0000-0000-0000-000000000003', 'Mathematiques', 'geometrie', 'math_programmes_construction',
  'Programmes de construction — Rédiger et interpréter', 'Intermediaire', 'qcm',
  'Un élève de CM1 suit ce programme : « Trace un segment [AB] de 4 cm. Place le milieu M de [AB]. Trace le cercle de centre M et de rayon 3 cm. » Quelle affirmation est correcte concernant la figure obtenue ?',
  NULL,
  '[{"id":"a","label":"Le cercle passe par les points A et B."},{"id":"b","label":"Les points A et B sont à l''extérieur du cercle."},{"id":"c","label":"Les points A et B sont à l''intérieur du cercle, qui ne passe ni par A ni par B."},{"id":"d","label":"Le point A est sur le cercle et le point B est à l''intérieur."}]'::jsonb,
  '{"mode":"single","value":"c"}'::jsonb,
  'Le milieu M de [AB] est situé à 2 cm de A et à 2 cm de B (car AB = 4 cm). Le cercle a pour centre M et pour rayon 3 cm. Un point est à l''intérieur du cercle si sa distance au centre est inférieure au rayon. Or MA = MB = 2 cm < 3 cm (le rayon). Donc A et B sont tous les deux à l''intérieur du cercle. Le cercle ne passe pas par A ni par B car il faudrait pour cela que MA = 3 cm ou MB = 3 cm, ce qui n''est pas le cas. Cette question mobilise la définition du cercle comme ensemble des points situés à une distance donnée (le rayon) du centre.',
  'Confondre « être à l''intérieur du cercle » et « être sur le cercle ». Un point est sur le cercle si et seulement si sa distance au centre est exactement égale au rayon.',
  'valide',
  'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'b0150000-0000-0000-0000-000000000004', 'Mathematiques', 'geometrie', 'math_programmes_construction',
  'Programmes de construction — Rédiger et interpréter', 'Intermediaire', 'reponse_courte',
  'Voici un programme de construction : « 1. Tracer un segment [AB] de 5 cm. 2. Tracer la médiatrice de [AB]. 3. Placer le point C sur la médiatrice, à 4 cm du point A. 4. Tracer le triangle ABC. » Quelle est la nature du triangle ABC ?',
  NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["isocèle en C","isocèle","triangle isocèle","triangle isocèle en C","isocele","isocele en C","triangle isocele"]}'::jsonb,
  'La médiatrice d''un segment est l''ensemble des points équidistants des deux extrémités de ce segment. Le point C est placé sur la médiatrice de [AB], donc par définition de la médiatrice, CA = CB. L''énoncé précise que CA = 4 cm, donc CB = 4 cm également. Le triangle ABC a deux côtés égaux (CA = CB = 4 cm) et un troisième côté AB = 5 cm : c''est un triangle isocèle en C. Cette propriété caractéristique de la médiatrice est fondamentale au cycle 3 et fréquemment mobilisée au CRPE.',
  'Oublier la propriété fondamentale de la médiatrice (équidistance aux extrémités) et ne pas reconnaître que C étant sur la médiatrice de [AB] implique CA = CB.',
  'valide',
  'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'b0150000-0000-0000-0000-000000000005', 'Mathematiques', 'geometrie', 'math_programmes_construction',
  'Programmes de construction — Rédiger et interpréter', 'Intermediaire', 'qcm',
  'Un élève veut tracer un losange ABCD. Il écrit le programme suivant : « 1. Tracer un segment [AC] de 6 cm. 2. Tracer un segment [BD] de 4 cm, perpendiculaire à [AC] en son milieu. 3. Relier A, B, C et D. » Quelle erreur a-t-il commise dans son programme ?',
  NULL,
  '[{"id":"a","label":"Les diagonales d''un losange ne sont pas perpendiculaires, son programme est donc faux dès le départ."},{"id":"b","label":"Il manque la condition que [BD] soit aussi coupé en son milieu par [AC] : les diagonales d''un losange se coupent mutuellement en leur milieu."},{"id":"c","label":"Il faudrait que les deux diagonales aient la même longueur pour obtenir un losange."},{"id":"d","label":"Le programme est correct, il produit bien un losange."}]'::jsonb,
  '{"mode":"single","value":"b"}'::jsonb,
  'Dans un losange, les diagonales sont perpendiculaires ET se coupent mutuellement en leur milieu. Le programme de l''élève indique que [BD] est perpendiculaire à [AC] en son milieu (le milieu de [AC]), mais il ne précise pas que le point d''intersection est aussi le milieu de [BD]. Sans cette condition, le point d''intersection pourrait couper [BD] en deux parties inégales, et le quadrilatère obtenu serait un cerf-volant (deux paires de côtés consécutifs égaux) mais pas nécessairement un losange (quatre côtés égaux). Pour corriger le programme, il faudrait écrire : « Tracer [BD] perpendiculaire à [AC], de sorte que les deux segments se coupent en leur milieu. »',
  'Croire que deux diagonales perpendiculaires suffisent à définir un losange, sans vérifier qu''elles se coupent mutuellement en leur milieu. Cette confusion entre losange et cerf-volant est une erreur classique.',
  'valide',
  'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'b0150000-0000-0000-0000-000000000006', 'Mathematiques', 'geometrie', 'math_programmes_construction',
  'Programmes de construction — Rédiger et interpréter', 'Intermediaire', 'reponse_courte',
  'Rédigez un programme de construction pour tracer un rectangle ABCD de longueur 6 cm et de largeur 4 cm, en utilisant uniquement une règle graduée et une équerre. Indiquez les étapes numérotées.',
  NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["1. Tracer un segment [AB] de 6 cm. 2. Tracer la perpendiculaire à (AB) passant par A à l''aide de l''équerre. Reporter 4 cm pour placer D. 3. Tracer la perpendiculaire à (AB) passant par B à l''aide de l''équerre. Reporter 4 cm pour placer C. 4. Tracer le segment [DC].","perpendiculaire équerre","perpendiculaire"]}'::jsonb,
  'Pour construire un rectangle, il faut garantir la présence de quatre angles droits. L''équerre est l''instrument qui permet de tracer des perpendiculaires et donc de matérialiser ces angles droits. Un programme correct comporte les étapes suivantes : 1. Tracer un segment [AB] de 6 cm (la longueur). 2. À l''aide de l''équerre, tracer la perpendiculaire à la droite (AB) passant par le point A. Sur cette perpendiculaire, reporter 4 cm à partir de A et placer le point D. 3. À l''aide de l''équerre, tracer la perpendiculaire à la droite (AB) passant par le point B. Sur cette perpendiculaire, reporter 4 cm à partir de B (du même côté que D) et placer le point C. 4. Tracer le segment [DC]. Le rectangle ABCD est obtenu avec AB = DC = 6 cm et AD = BC = 4 cm. Chaque angle est droit car construit à l''équerre.',
  'Oublier d''utiliser l''équerre pour construire les angles droits, ou ne pas préciser de quel côté placer les points C et D (ce qui peut donner un quadrilatère croisé).',
  'valide',
  'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'b0150000-0000-0000-0000-000000000007', 'Mathematiques', 'geometrie', 'math_programmes_construction',
  'Programmes de construction — Rédiger et interpréter', 'Intermediaire', 'qcm',
  'Un programme de construction permet de tracer un hexagone régulier inscrit dans un cercle de rayon 4 cm en reportant 6 fois la longueur du rayon sur le cercle à l''aide du compas. Quelle propriété géométrique justifie que chaque côté de l''hexagone mesure exactement 4 cm ?',
  NULL,
  '[{"id":"a","label":"Le théorème de Pythagore appliqué aux triangles formés par les rayons et les côtés."},{"id":"b","label":"Les six triangles formés par le centre et les sommets consécutifs sont équilatéraux, donc leur côté est égal au rayon du cercle."},{"id":"c","label":"Le théorème de Thalès appliqué aux diagonales de l''hexagone."},{"id":"d","label":"Le périmètre du cercle divisé par 6 donne la longueur de chaque côté."}]'::jsonb,
  '{"mode":"single","value":"b"}'::jsonb,
  'Lorsqu''on inscrit un hexagone régulier dans un cercle de rayon r, on peut le décomposer en 6 triangles dont les sommets sont le centre du cercle et deux sommets consécutifs de l''hexagone. Chacun de ces triangles a deux côtés égaux au rayon r (ce sont des rayons du cercle). L''angle au centre de chaque triangle vaut 360° ÷ 6 = 60°. Un triangle isocèle dont l''angle au sommet principal mesure 60° a ses deux angles de base égaux à (180° − 60°) ÷ 2 = 60° : c''est donc un triangle équilatéral. Tous ses côtés mesurent r = 4 cm, y compris le côté de l''hexagone. C''est pourquoi la construction au compas fonctionne : en reportant le rayon sur le cercle, on obtient exactement les 6 sommets de l''hexagone régulier. Cette propriété remarquable est un classique de la géométrie du cycle 3.',
  'Confondre le périmètre du cercle (2πr) avec 6 × r. En réalité, le périmètre du cercle (≈ 25,1 cm pour r = 4 cm) est supérieur au périmètre de l''hexagone inscrit (6 × 4 = 24 cm). La justification correcte repose sur les triangles équilatéraux, pas sur une division du périmètre.',
  'valide',
  'Génération Claude — Terminologie Éduscol', 'premium', true
) ON CONFLICT (id) DO NOTHING;

-- math_proportionnalite_donnees (organisation_donnees) : 3 -> 10 questions
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fb050000-0000-0000-0000-000000000001',
  'Mathematiques', 'organisation_donnees', 'math_proportionnalite_donnees',
  'Proportionnalité dans les données — Tableaux et graphiques', 'Intermediaire',
  'qcm',
  'On donne le tableau suivant : Nombre de cahiers : 2, 5, 8. Prix (en €) : 3, 7.50, 12. Ce tableau représente-t-il une situation de proportionnalité ? Justifier.',
  NULL,
  '[{"id":"a","label":"Oui, car les prix augmentent quand le nombre de cahiers augmente"},{"id":"b","label":"Oui, car le rapport prix / nombre de cahiers est constant et vaut 1,50"},{"id":"c","label":"Non, car les écarts entre les nombres de cahiers ne sont pas réguliers"},{"id":"d","label":"Non, car on ne connaît pas le prix d''un seul cahier"}]'::jsonb,
  '{"mode":"single","value":"b"}'::jsonb,
  'Pour vérifier qu''un tableau traduit une situation de proportionnalité, on calcule le rapport entre les valeurs correspondantes des deux grandeurs. Ici : 3 / 2 = 1,50 ; 7,50 / 5 = 1,50 ; 12 / 8 = 1,50. Le rapport est constant et vaut 1,50 € par cahier. Donc le tableau représente bien une situation de proportionnalité. Le coefficient de proportionnalité est 1,50 : il signifie que chaque cahier coûte 1,50 €. Attention : le fait que les valeurs « augmentent ensemble » ne suffit pas à prouver la proportionnalité — il faut que le rapport soit constant.',
  'Se contenter de vérifier que « quand l''un augmente, l''autre aussi » sans calculer le rapport. Ce critère est nécessaire mais pas suffisant : une relation affine (y = ax + b avec b ≠ 0) vérifie aussi cette propriété sans être proportionnelle.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fb050000-0000-0000-0000-000000000002',
  'Mathematiques', 'organisation_donnees', 'math_proportionnalite_donnees',
  'Proportionnalité dans les données — Tableaux et graphiques', 'Intermediaire',
  'reponse_courte',
  'Un tableau de proportionnalité indique : pour 3 kg de pommes, le prix est 5,40 €. Compléter : pour 7 kg de pommes, le prix est ... €.',
  NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["12,60","12.60","12,60 €","12.60 €","12,6","12.6"]}'::jsonb,
  'On détermine d''abord le coefficient de proportionnalité : 5,40 / 3 = 1,80 € par kg. Puis on calcule le prix pour 7 kg : 7 × 1,80 = 12,60 €. Autre méthode possible (passage par l''unité) : si 3 kg coûtent 5,40 €, alors 1 kg coûte 5,40 / 3 = 1,80 €, donc 7 kg coûtent 7 × 1,80 = 12,60 €. On peut aussi utiliser le produit en croix : 3 / 5,40 = 7 / x, donc x = 7 × 5,40 / 3 = 37,80 / 3 = 12,60 €. Toutes ces méthodes sont équivalentes et exploitent la constance du rapport prix/masse.',
  'Additionner au lieu de multiplier : certains élèves raisonnent « 7 − 3 = 4, donc le prix augmente de 4 × quelque chose » au lieu de chercher le coefficient multiplicatif.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fb050000-0000-0000-0000-000000000003',
  'Mathematiques', 'organisation_donnees', 'math_proportionnalite_donnees',
  'Proportionnalité dans les données — Tableaux et graphiques', 'Intermediaire',
  'reponse_courte',
  'Dans un tableau de proportionnalité, lorsque x = 4, y = 10. Quel est le coefficient de proportionnalité qui permet de passer de x à y ?',
  NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["2,5","2.5","2,50","2.50","5/2"]}'::jsonb,
  'Le coefficient de proportionnalité k est le nombre tel que y = k × x. Ici, 10 = k × 4, donc k = 10 / 4 = 2,5. Cela signifie que pour obtenir la valeur de y, on multiplie toujours la valeur correspondante de x par 2,5. Par exemple, si x = 6, alors y = 6 × 2,5 = 15. Le coefficient de proportionnalité est unique pour une relation de proportionnalité donnée et il caractérise entièrement la relation. Attention : le coefficient de x vers y (ici 2,5) est différent du coefficient de y vers x (qui serait 1/2,5 = 0,4).',
  'Diviser dans le mauvais sens (x / y = 4 / 10 = 0,4 au lieu de y / x = 10 / 4 = 2,5). Il faut bien identifier quelle grandeur on veut exprimer en fonction de l''autre.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fb050000-0000-0000-0000-000000000004',
  'Mathematiques', 'organisation_donnees', 'math_proportionnalite_donnees',
  'Proportionnalité dans les données — Tableaux et graphiques', 'Intermediaire',
  'qcm',
  'Sur un graphique, on observe une droite passant par les points (0 ; 0), (2 ; 6) et (5 ; 15). Que peut-on affirmer ?',
  NULL,
  '[{"id":"a","label":"La relation représentée est affine mais pas proportionnelle"},{"id":"b","label":"La relation représentée est proportionnelle, de coefficient 3"},{"id":"c","label":"La relation représentée est proportionnelle, de coefficient 1/3"},{"id":"d","label":"On ne peut rien conclure car on n''a que trois points"}]'::jsonb,
  '{"mode":"single","value":"b"}'::jsonb,
  'Une relation de proportionnalité se traduit graphiquement par une droite passant par l''origine du repère. Ici, la droite passe bien par (0 ; 0) et les rapports y/x sont constants : 6/2 = 3 et 15/5 = 3. Le coefficient de proportionnalité est donc 3 : la relation est y = 3x. C''est le critère graphique fondamental : proportionnalité ⟺ droite passant par l''origine. Si la droite ne passait pas par l''origine, la relation serait affine (y = ax + b avec b ≠ 0) mais pas proportionnelle.',
  'Confondre « droite » et « proportionnalité ». Toute droite dans un repère ne traduit pas une proportionnalité : seules les droites passant par l''origine correspondent à des situations de proportionnalité.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fb050000-0000-0000-0000-000000000005',
  'Mathematiques', 'organisation_donnees', 'math_proportionnalite_donnees',
  'Proportionnalité dans les données — Tableaux et graphiques', 'Intermediaire',
  'vrai_faux',
  'On observe un graphique représentant le prix d''un abonnement téléphonique en fonction de la durée d''appel. La courbe est une droite qui coupe l''axe des ordonnées au point (0 ; 5). Cette relation est une relation de proportionnalité.',
  NULL,
  NULL,
  '{"mode":"single","value":"faux"}'::jsonb,
  'C''est faux. La droite coupe l''axe des ordonnées en (0 ; 5), ce qui signifie que lorsque la durée d''appel est nulle, le prix est déjà de 5 €. Il s''agit d''un forfait fixe auquel s''ajoute un coût variable selon la durée. La relation est donc affine : prix = a × durée + 5, avec a le coût par minute. Pour qu''il y ait proportionnalité, il faudrait que la droite passe par l''origine (0 ; 0), c''est-à-dire qu''aucun appel = aucun coût. La distinction entre relation affine et relation proportionnelle est un point clé des programmes du cycle 3 et du CRPE.',
  'Penser que toute droite sur un graphique traduit une proportionnalité. La proportionnalité exige que la droite passe par l''origine. Ici, l''ordonnée à l''origine (5 €) correspond à un coût fixe (abonnement) incompatible avec la proportionnalité.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fb050000-0000-0000-0000-000000000006',
  'Mathematiques', 'organisation_donnees', 'math_proportionnalite_donnees',
  'Proportionnalité dans les données — Tableaux et graphiques', 'Intermediaire',
  'reponse_courte',
  'Dans une situation de proportionnalité, on sait que 5 mètres de tissu coûtent 32 €. Combien coûtent 8 mètres de tissu ? Utiliser le produit en croix.',
  NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["51,20","51.20","51,2","51.2","51,20 €","51.20 €"]}'::jsonb,
  'On utilise le produit en croix (ou règle de trois). On pose : 5 m → 32 € et 8 m → x €. La proportionnalité donne : 5 / 8 = 32 / x, soit x = 8 × 32 / 5 = 256 / 5 = 51,20 €. Vérification avec le coefficient : k = 32 / 5 = 6,40 € par mètre, donc 8 × 6,40 = 51,20 €. Le produit en croix est une technique de calcul efficace dans les situations de proportionnalité. Il repose sur la propriété : si a/b = c/d, alors a × d = b × c. Au CRPE, il est important de savoir l''appliquer mais aussi de comprendre pourquoi il fonctionne.',
  'Inverser le produit en croix et calculer 5 × 32 / 8 = 20 au lieu de 8 × 32 / 5 = 51,20. Toujours vérifier la cohérence : 8 mètres coûtent plus que 5 mètres, donc le prix doit être supérieur à 32 €.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fb050000-0000-0000-0000-000000000007',
  'Mathematiques', 'organisation_donnees', 'math_proportionnalite_donnees',
  'Proportionnalité dans les données — Tableaux et graphiques', 'Intermediaire',
  'qcm',
  'Une recette de crêpes pour 4 personnes nécessite 250 g de farine, 3 œufs et 50 cl de lait. On veut préparer la recette pour 10 personnes. Quelles sont les quantités nécessaires ?',
  NULL,
  '[{"id":"a","label":"500 g de farine, 6 œufs, 100 cl de lait"},{"id":"b","label":"625 g de farine, 7,5 œufs, 125 cl de lait"},{"id":"c","label":"625 g de farine, 8 œufs, 125 cl de lait"},{"id":"d","label":"600 g de farine, 7 œufs, 120 cl de lait"}]'::jsonb,
  '{"mode":"single","value":"b"}'::jsonb,
  'On adapte une recette en utilisant la proportionnalité. Le coefficient multiplicateur est 10 / 4 = 2,5. On multiplie chaque ingrédient par 2,5 : farine : 250 × 2,5 = 625 g ; œufs : 3 × 2,5 = 7,5 ; lait : 50 × 2,5 = 125 cl. Les quantités correctes sont donc 625 g de farine, 7,5 œufs et 125 cl de lait. Certes, 7,5 œufs n''est pas « pratique » dans la vie courante (on arrondirait à 7 ou 8), mais mathématiquement, c''est le résultat exact de la proportionnalité. L''adaptation de recettes est un contexte classique de proportionnalité au cycle 3 et au CRPE.',
  'Arrondir les œufs à 8 (choix c) en pensant qu''on ne peut pas avoir un demi-œuf. Mathématiquement, dans un exercice de proportionnalité, on donne le résultat exact : 7,5. L''arrondissement relève d''une discussion sur le contexte, pas du calcul.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

-- math_proportionnalite_etapes (nombres_calcul) : 3 -> 10 questions
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  '0a7c2e37-f998-4427-a6dd-aa9473e223fb',
  'Mathematiques',
  'nombres_calcul',
  'math_proportionnalite_etapes',
  'Problèmes à étapes — Proportionnalité',
  'Intermediaire',
  'qcm',
  'Parmi les situations suivantes, laquelle est une situation de proportionnalité ?',
  NULL,
  '[{"id":"a","label":"L''âge d''une personne en fonction de son année de naissance"},{"id":"b","label":"Le prix de pommes à 2,50 €/kg en fonction du poids acheté"},{"id":"c","label":"La taille d''un enfant en fonction de son âge"},{"id":"d","label":"La note à un examen en fonction du temps de révision"}]',
  '{"mode":"single","value":"b"}',
  'Seule la situation B est proportionnelle : le prix est proportionnel au poids (prix = 2,50 × poids). Si on achète 2 fois plus de pommes, on paie 2 fois plus. Le coefficient de proportionnalité est 2,50 €/kg. Les autres situations ne sont PAS proportionnelles : (A) l''âge n''est pas proportionnel à l''année de naissance (un bébé né en 2020 a 6 ans, pas 2020 × k) ; (C) la taille ne double pas quand l''âge double ; (D) réviser 2 fois plus ne garantit pas une note 2 fois meilleure. Critère clé : dans une situation proportionnelle, si on multiplie la variable d''entrée par k, la variable de sortie est aussi multipliée par k.',
  'Confondre corrélation et proportionnalité. Deux grandeurs peuvent varier « ensemble » sans être proportionnelles. La proportionnalité exige un coefficient constant : y = k × x.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  '582034f0-0693-4675-ac81-bddf15dc9921',
  'Mathematiques',
  'nombres_calcul',
  'math_proportionnalite_etapes',
  'Problèmes à étapes — Proportionnalité',
  'Intermediaire',
  'reponse_courte',
  'Un robinet remplit un bassin de 600 litres en 4 heures à débit constant. Quel volume d''eau (en litres) coule en 1 h 30 min ?',
  NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["225 litres","225","225 L","225L","225 l"]}',
  'Le débit est constant, donc le volume est proportionnel au temps. Débit = 600 L / 4 h = 150 L/h. En 1 h 30 min = 1,5 h, le volume est : 150 × 1,5 = 225 L. Méthode alternative (retour à l''unité) : en 4 h → 600 L, en 1 h → 600/4 = 150 L, en 1,5 h → 150 × 1,5 = 225 L. Vérification : 225/600 = 0,375 et 1,5/4 = 0,375 ✓ Les rapports sont égaux, ce qui confirme la proportionnalité.',
  'Mal convertir 1 h 30 min en heures décimales : écrire 1,30 h au lieu de 1,5 h, ce qui donnerait 150 × 1,30 = 195 L (faux).',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'e61c10f6-5fd0-4ea9-a61b-893b889db8ba',
  'Mathematiques',
  'nombres_calcul',
  'math_proportionnalite_etapes',
  'Problèmes à étapes — Proportionnalité',
  'Intermediaire',
  'reponse_courte',
  'Un manteau coûte 120 €. Il est soldé à −30 %, puis une remise supplémentaire de 10 % est appliquée sur le prix soldé. Quel est le prix final ? (Répondez en euros.)',
  NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["75,60 €","75,60","75.60","75,6 €","75,6","75.6","75,60€","75.60€"]}',
  'Étape 1 : Réduction de 30 % sur 120 €. Montant de la réduction : 120 × 30/100 = 36 €. Prix soldé : 120 − 36 = 84 €. Étape 2 : Remise de 10 % sur 84 €. Montant de la remise : 84 × 10/100 = 8,40 €. Prix final : 84 − 8,40 = 75,60 €. ATTENTION : on ne peut PAS additionner les pourcentages (30 % + 10 % ≠ 40 %). Appliquer 40 % sur 120 € donnerait 72 € (faux). Les pourcentages successifs se composent : le coefficient multiplicateur est 0,7 × 0,9 = 0,63, soit une réduction totale de 37 %, pas 40 %. Vérification : 120 × 0,63 = 75,60 € ✓',
  'Additionner les pourcentages de réduction (30 % + 10 % = 40 %) et appliquer 40 % sur le prix initial. C''est faux car la deuxième réduction s''applique sur le prix déjà réduit, pas sur le prix initial.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  '1f7e22f8-5366-498f-af9f-2b0d89881ab2',
  'Mathematiques',
  'nombres_calcul',
  'math_proportionnalite_etapes',
  'Problèmes à étapes — Proportionnalité',
  'Intermediaire',
  'qcm',
  'Un cycliste parcourt 60 km à l''aller à 20 km/h, puis 60 km au retour à 30 km/h. Quelle est sa vitesse moyenne sur l''ensemble du trajet ?',
  NULL,
  '[{"id":"a","label":"25 km/h"},{"id":"b","label":"24 km/h"},{"id":"c","label":"22 km/h"},{"id":"d","label":"27,5 km/h"}]',
  '{"mode":"single","value":"b"}',
  'On ne peut PAS faire la moyenne des vitesses : (20 + 30)/2 = 25 km/h est FAUX. La vitesse moyenne = distance totale / temps total. Distance totale = 60 + 60 = 120 km. Temps aller = 60/20 = 3 h. Temps retour = 60/30 = 2 h. Temps total = 3 + 2 = 5 h. Vitesse moyenne = 120/5 = 24 km/h. La vitesse moyenne est toujours inférieure à la moyenne arithmétique des vitesses (24 < 25) car le cycliste passe plus de temps à la vitesse la plus faible. C''est un piège classique du CRPE !',
  'Calculer la moyenne arithmétique des vitesses (20 + 30)/2 = 25 km/h. La vitesse moyenne n''est PAS la moyenne des vitesses — il faut passer par la distance totale et le temps total.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'b176f68b-fd5b-4fab-ab72-bdedc3c0afef',
  'Mathematiques',
  'nombres_calcul',
  'math_proportionnalite_etapes',
  'Problèmes à étapes — Proportionnalité',
  'Intermediaire',
  'vrai_faux',
  'Sur un plan à l''échelle 1/500, une pièce est représentée par un rectangle de 2 cm sur 3 cm. Un élève affirme : « L''aire réelle de la pièce est de 3 000 cm², soit 3 m². » Est-ce correct ?',
  NULL,
  NULL,
  '{"mode":"single","value":"faux"}',
  'FAUX. L''échelle 1/500 signifie que 1 cm sur le plan = 500 cm en réalité = 5 m. Dimensions réelles : 2 × 500 = 1 000 cm = 10 m et 3 × 500 = 1 500 cm = 15 m. Aire réelle = 10 × 15 = 150 m². L''élève a probablement calculé l''aire sur le plan (2 × 3 = 6 cm²) puis multiplié par 500 (6 × 500 = 3 000 cm²). Mais pour les aires, il faut multiplier par 500² = 250 000 ! Aire réelle = 6 × 250 000 = 1 500 000 cm² = 150 m². Règle : si l''échelle des longueurs est k, l''échelle des aires est k².',
  'Appliquer le facteur d''échelle une seule fois (×500) au lieu de le mettre au carré (×500²) pour les aires. C''est la même erreur que pour les conversions d''unités d''aire.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  '82083602-ebe8-4c38-aef3-939ee7de76ee',
  'Mathematiques',
  'nombres_calcul',
  'math_proportionnalite_etapes',
  'Problèmes à étapes — Proportionnalité',
  'Intermediaire',
  'reponse_courte',
  'Un artisan achète 25 m² de carrelage à 18 €/m² HT. La TVA est de 20 %. Il accorde une remise de 5 % sur le prix TTC total à son client. Quel montant TTC le client paie-t-il ? (Arrondir au centime.)',
  NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["513 €","513","513,00 €","513,00","513.00","513€","513,0"]}',
  'Étape 1 : Prix HT = 25 × 18 = 450 €. Étape 2 : Prix TTC = 450 × 1,20 = 540 €. Étape 3 : Remise de 5 % = 540 × 0,05 = 27 €. Prix final = 540 − 27 = 513 €. Alternative avec coefficients : 450 × 1,20 × 0,95 = 513 €. Ce problème enchaîne trois étapes de proportionnalité : le prix proportionnel à la surface, la TVA proportionnelle au prix HT, et la remise proportionnelle au prix TTC. L''ordre des opérations est crucial : la remise s''applique sur le TTC, pas sur le HT.',
  'Appliquer la remise sur le prix HT avant la TVA, ce qui changerait le résultat. Ou additionner TVA et remise : 20 % − 5 % = 15 %, puis 450 × 1,15 = 517,50 € (faux).',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'fc2728fc-62df-4c80-a2c9-aed645fabe31',
  'Mathematiques',
  'nombres_calcul',
  'math_proportionnalite_etapes',
  'Problèmes à étapes — Proportionnalité',
  'Intermediaire',
  'qcm',
  'Trois amis se partagent les frais d''un voyage proportionnellement au nombre de jours passés. Le voyage coûte 1 800 €. Anna reste 6 jours, Bastien 4 jours et Clara 2 jours. Combien Anna doit-elle payer ?',
  NULL,
  '[{"id":"a","label":"600 €"},{"id":"b","label":"900 €"},{"id":"c","label":"750 €"},{"id":"d","label":"1 080 €"}]',
  '{"mode":"single","value":"b"}',
  'Nombre total de « jours-personne » : 6 + 4 + 2 = 12 jours. Coût par jour-personne : 1 800 / 12 = 150 €/jour. Part d''Anna : 6 × 150 = 900 €. Vérification : Bastien paie 4 × 150 = 600 € et Clara 2 × 150 = 300 €. Total : 900 + 600 + 300 = 1 800 € ✓. La part d''Anna représente 6/12 = 1/2 du total, ce qui est cohérent : 1 800/2 = 900 €. Le partage proportionnel est un outil fondamental en résolution de problèmes CRPE.',
  'Diviser le total par 3 (partage égal : 1 800/3 = 600 €) au lieu de tenir compte du nombre de jours de chacun. Le partage proportionnel n''est pas un partage équitable.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'premium',
  true
) ON CONFLICT (id) DO NOTHING;

-- math_proportionnalite_graphique_tableau (nombres_calcul) : 3 -> 10 questions
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f8110000-0000-0000-0000-000000000001',
  'Mathematiques', 'nombres_calcul', 'math_proportionnalite_graphique_tableau',
  'Proportionnalité — Graphiques et tableaux', 'Intermediaire',
  'qcm',
  'Un tableau présente les valeurs suivantes : x = 2, 4, 6, 8 et y = 5, 10, 15, 20. Ce tableau représente-t-il une situation de proportionnalité ? Comment le vérifier ?',
  NULL,
  '[{"id":"a","label":"Oui, car les valeurs de y augmentent régulièrement"},{"id":"b","label":"Oui, car le rapport y/x est constant : 5/2 = 10/4 = 15/6 = 20/8 = 2,5"},{"id":"c","label":"Non, car les valeurs ne sont pas des nombres entiers"},{"id":"d","label":"On ne peut pas savoir avec seulement quatre valeurs"}]'::jsonb,
  '{"mode":"single","value":"b"}'::jsonb,
  'Pour vérifier qu''un tableau représente une situation de proportionnalité, on calcule le rapport y/x pour chaque couple de valeurs. Si ce rapport est constant, il y a proportionnalité. Ici : 5/2 = 2,5 ; 10/4 = 2,5 ; 15/6 = 2,5 ; 20/8 = 2,5. Le rapport est bien constant et vaut 2,5 : c''est le coefficient de proportionnalité. La réponse (a) est insuffisante : le fait que les valeurs « augmentent régulièrement » ne suffit pas à garantir la proportionnalité (une fonction affine non proportionnelle comme y = 2x + 1 augmente aussi régulièrement). C''est le rapport constant qui caractérise la proportionnalité. Éduscol insiste sur la vérification systématique du rapport pour distinguer les situations proportionnelles des situations qui n''en sont pas.',
  'Se contenter de vérifier que y augmente quand x augmente. Ce critère est nécessaire mais pas suffisant : seul le rapport constant y/x = k caractérise la proportionnalité.',
  'valide',
  'Génération Claude — Programmes cycle 3 / Éduscol',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f8110000-0000-0000-0000-000000000002',
  'Mathematiques', 'nombres_calcul', 'math_proportionnalite_graphique_tableau',
  'Proportionnalité — Graphiques et tableaux', 'Intermediaire',
  'reponse_courte',
  'Dans un tableau de proportionnalité, on lit : pour x = 3, y = 12 et pour x = 7, y = 28. Quel est le coefficient de proportionnalité ?',
  NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["4","4.0","4,0"]}'::jsonb,
  'Le coefficient de proportionnalité est le nombre constant k tel que y = k × x. On le calcule en divisant y par x : k = 12 ÷ 3 = 4. On vérifie avec le second couple : k = 28 ÷ 7 = 4. Le coefficient est bien constant et vaut 4. Cela signifie que pour obtenir y, on multiplie x par 4. On peut aussi le formuler ainsi : « y est le quadruple de x ». Le coefficient de proportionnalité a une interprétation concrète selon le contexte : si x représente un nombre de kilogrammes et y le prix en euros, alors k = 4 €/kg est le prix au kilogramme. Au CRPE, il est fondamental de savoir calculer, interpréter et utiliser le coefficient de proportionnalité dans des contextes variés.',
  'Diviser x par y au lieu de y par x, ce qui donne l''inverse du coefficient (0,25 au lieu de 4). Toujours diviser la grandeur « résultat » par la grandeur « cause ».',
  'valide',
  'Génération Claude — Programmes cycle 3 / Éduscol',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f8110000-0000-0000-0000-000000000003',
  'Mathematiques', 'nombres_calcul', 'math_proportionnalite_graphique_tableau',
  'Proportionnalité — Graphiques et tableaux', 'Intermediaire',
  'qcm',
  'Dans un tableau de proportionnalité, on connaît : x = 4, y = 14 et x = 10, y = ?. Complétez le tableau en trouvant la valeur manquante.',
  NULL,
  '[{"id":"a","label":"20"},{"id":"b","label":"35"},{"id":"c","label":"24"},{"id":"d","label":"40"}]'::jsonb,
  '{"mode":"single","value":"b"}'::jsonb,
  'Dans un tableau de proportionnalité, le coefficient est constant : k = y/x = 14/4 = 3,5. Pour x = 10 : y = 3,5 × 10 = 35. On peut aussi utiliser la méthode du passage par l''unité : si 4 unités correspondent à 14, alors 1 unité correspond à 14 ÷ 4 = 3,5, et 10 unités correspondent à 3,5 × 10 = 35. Autre méthode : la propriété de linéarité. On remarque que 10 = 4 × 2,5, donc y = 14 × 2,5 = 35. Ou encore : 10 = 4 + 4 + 2, donc y = 14 + 14 + 7 = 35 (en utilisant l''additivité de la proportionnalité). Les programmes du cycle 3 insistent sur la maîtrise de plusieurs procédures pour compléter un tableau de proportionnalité : passage par l''unité, coefficient, propriétés de linéarité (additivité et homogénéité).',
  'Ajouter 6 à 14 (car 10 − 4 = 6) pour obtenir 20. Cette erreur revient à confondre situation proportionnelle et situation additive.',
  'valide',
  'Génération Claude — Programmes cycle 3 / Éduscol',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f8110000-0000-0000-0000-000000000004',
  'Mathematiques', 'nombres_calcul', 'math_proportionnalite_graphique_tableau',
  'Proportionnalité — Graphiques et tableaux', 'Intermediaire',
  'vrai_faux',
  'La représentation graphique d''une situation de proportionnalité est toujours une droite passant par l''origine du repère. Si le graphique est une droite qui ne passe pas par l''origine, la situation n''est pas proportionnelle.',
  NULL,
  NULL,
  '{"mode":"single","value":"vrai"}'::jsonb,
  'C''est la caractérisation graphique fondamentale de la proportionnalité. Si y = k × x (relation de proportionnalité), alors le graphique est une droite passant par l''origine (0, 0), car quand x = 0, y = k × 0 = 0. Le coefficient de proportionnalité k correspond à la pente de cette droite. Si la droite ne passe pas par l''origine — par exemple y = 2x + 3 — c''est une fonction affine mais pas proportionnelle : quand x = 0, y = 3 ≠ 0. Le passage par l''origine est donc un critère discriminant essentiel. Attention : l''inverse n''est pas toujours vrai pour un nuage de points expérimentaux (des points approximativement alignés passant par l''origine suggèrent une proportionnalité, mais il faut vérifier). Au CRPE, la reconnaissance graphique de la proportionnalité (droite passant par l''origine) est un attendu fondamental.',
  'Croire que toute droite dans un repère représente une situation de proportionnalité. Seules les droites passant par l''origine correspondent à des situations de proportionnalité.',
  'valide',
  'Génération Claude — Programmes cycle 3 / Éduscol',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f8110000-0000-0000-0000-000000000005',
  'Mathematiques', 'nombres_calcul', 'math_proportionnalite_graphique_tableau',
  'Proportionnalité — Graphiques et tableaux', 'Intermediaire',
  'qcm',
  'Dans un tableau de proportionnalité, on sait que 3 kg de pommes coûtent 4,50 €. Combien coûtent 8 kg de pommes ? (Méthode de la quatrième proportionnelle)',
  NULL,
  '[{"id":"a","label":"9,50 €"},{"id":"b","label":"12 €"},{"id":"c","label":"10 €"},{"id":"d","label":"13,50 €"}]'::jsonb,
  '{"mode":"single","value":"b"}'::jsonb,
  'On cherche la quatrième proportionnelle : si 3 kg → 4,50 €, alors 8 kg → ? €. Méthode 1 (passage par l''unité) : 1 kg coûte 4,50 ÷ 3 = 1,50 €, donc 8 kg coûtent 1,50 × 8 = 12 €. Méthode 2 (coefficient) : le coefficient est k = 4,50/3 = 1,5, donc le prix = 1,5 × 8 = 12 €. Méthode 3 (produit en croix) : on pose 3/8 = 4,50/x, donc x = (8 × 4,50)/3 = 36/3 = 12 €. Méthode 4 (propriété de linéarité) : 8 = 3 + 3 + 2, donc le prix = 4,50 + 4,50 + 3 = 12 € (car 2 kg = 2/3 de 3 kg, soit 2/3 × 4,50 = 3 €). Les programmes Éduscol privilégient le passage par l''unité et les propriétés de linéarité au cycle 3, le produit en croix étant introduit au collège.',
  'Additionner au lieu de multiplier : 4,50 + 8 = 12,50 € (coïncidence numérique trompeuse ici). Toujours vérifier la cohérence en utilisant le coefficient de proportionnalité.',
  'valide',
  'Génération Claude — Programmes cycle 3 / Éduscol',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f8110000-0000-0000-0000-000000000006',
  'Mathematiques', 'nombres_calcul', 'math_proportionnalite_graphique_tableau',
  'Proportionnalité — Graphiques et tableaux', 'Intermediaire',
  'qcm',
  'Parmi les trois situations suivantes, laquelle N''est PAS une situation de proportionnalité ? (A) Le prix des pommes à 2,50 €/kg. (B) L''âge d''un enfant en fonction de sa taille. (C) La conversion d''euros en dollars à un taux fixe.',
  NULL,
  '[{"id":"a","label":"Seule la situation (A) n''est pas proportionnelle"},{"id":"b","label":"Seule la situation (B) n''est pas proportionnelle : la taille d''un enfant n''est pas proportionnelle à son âge"},{"id":"c","label":"Seule la situation (C) n''est pas proportionnelle"},{"id":"d","label":"Aucune des trois n''est proportionnelle"}]'::jsonb,
  '{"mode":"single","value":"b"}'::jsonb,
  'La situation (A) est proportionnelle : le prix est proportionnel au poids (prix = 2,50 × poids). Pour 0 kg, le prix est 0 €. La situation (C) est proportionnelle : le montant en dollars est proportionnel au montant en euros (dollars = taux × euros). Pour 0 €, on obtient 0 $. En revanche, la situation (B) n''est PAS proportionnelle : un enfant de 2 ans ne mesure pas le double d''un enfant de 1 an, et un enfant de 10 ans ne mesure pas 10 fois la taille d''un enfant de 1 an. La relation entre âge et taille n''est pas linéaire et ne passe pas par l''origine (à la naissance, l''enfant mesure environ 50 cm, pas 0 cm). C''est un piège classique au CRPE : distinguer les situations réellement proportionnelles de celles qui ne le sont pas. Éduscol recommande de confronter régulièrement les élèves à des contre-exemples pour affiner leur compréhension de la proportionnalité.',
  'Croire que toute situation où « quand l''un augmente, l''autre augmente » est proportionnelle. La proportionnalité exige un rapport constant ET un passage par l''origine.',
  'valide',
  'Génération Claude — Programmes cycle 3 / Éduscol',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'f8110000-0000-0000-0000-000000000007',
  'Mathematiques', 'nombres_calcul', 'math_proportionnalite_graphique_tableau',
  'Proportionnalité — Graphiques et tableaux', 'Intermediaire',
  'reponse_courte',
  'Un touriste échange des euros en livres sterling. Il obtient 85 £ pour 100 €. Combien de livres obtiendra-t-il pour 260 € ? (Le taux de change est fixe.)',
  NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["221","221 £","221 livres","221,00"]}'::jsonb,
  'Le taux de change étant fixe, la situation est proportionnelle. Le coefficient de proportionnalité est k = 85/100 = 0,85 £ par euro. Pour 260 € : 260 × 0,85 = 221 £. Détail du calcul mental : 260 × 0,85 = 260 × (1 − 0,15) = 260 − 260 × 0,15 = 260 − 39 = 221. Ou bien : 260 × 0,85 = 260 × 85/100 = (260 × 85) ÷ 100. On calcule 260 × 85 = 260 × 80 + 260 × 5 = 20 800 + 1 300 = 22 100, puis 22 100 ÷ 100 = 221. On peut aussi utiliser la linéarité : 200 € → 170 £ (× 2), 60 € → 51 £ (× 0,6), total = 170 + 51 = 221 £. Ce problème de conversion monétaire est un grand classique du CRPE et illustre parfaitement l''application de la proportionnalité à une situation concrète.',
  'Diviser au lieu de multiplier (ou inversement). Toujours vérifier le sens : 1 € < 1 £ en valeur, donc le nombre de livres doit être inférieur au nombre d''euros.',
  'valide',
  'Génération Claude — Programmes cycle 3 / Éduscol',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

-- math_proportionnel_ou_non (nombres_calcul) : 3 -> 10 questions
INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'c0160000-0000-0000-0000-000000000001',
  'Mathematiques',
  'nombres_calcul',
  'math_proportionnel_ou_non',
  'Proportionnel ou non ? — Distinguer les situations',
  'Intermediaire',
  'vrai_faux',
  'Vrai ou faux : le prix total d''essence est proportionnel au nombre de litres achetés (à prix constant par litre).',
  NULL,
  NULL,
  '{"mode":"single","value":"vrai"}',
  'VRAI. Si le prix par litre est fixe (ex : 1,85 €/L), alors prix = 1,85 × volume. C''est bien une relation de proportionnalité : le coefficient est 1,85, et si on double le volume, on double le prix. Test de la proportionnalité : le tableau {litres ; prix} passe par l''origine (0 L → 0 €), et le rapport prix/volume est constant. C''est le modèle de base de la proportionnalité directe. Au CRPE, ce type de situation sert souvent de référence pour construire le concept chez les élèves.',
  'Hésiter parce que le prix varie d''une station à l''autre. Ici, « à prix constant par litre » fixe le coefficient — la proportionnalité est bien vérifiée.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'c0160000-0000-0000-0000-000000000002',
  'Mathematiques',
  'nombres_calcul',
  'math_proportionnel_ou_non',
  'Proportionnel ou non ? — Distinguer les situations',
  'Intermediaire',
  'vrai_faux',
  'Vrai ou faux : l''âge d''une personne est proportionnel à sa taille.',
  NULL,
  NULL,
  '{"mode":"single","value":"faux"}',
  'FAUX. Un bébé de 1 an mesure environ 75 cm. Un adulte de 20 ans mesure environ 175 cm. Si c''était proportionnel, à 40 ans il mesurerait 2 × 175 = 350 cm ! La taille ne double pas quand l''âge double. La croissance n''est pas linéaire : elle est rapide dans les premières années, ralentit à l''adolescence, et s''arrête vers 18-20 ans. Test de proportionnalité échoué : le rapport taille/âge n''est pas constant (75/1 ≠ 175/20). Deux grandeurs qui « varient ensemble » ne sont pas forcément proportionnelles — c''est la distinction fondamentale à construire chez les élèves.',
  'Confondre « les deux grandeurs augmentent ensemble » (corrélation) avec « les deux grandeurs sont proportionnelles » (rapport constant). La proportionnalité est un cas TRÈS particulier de relation entre grandeurs.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'c0160000-0000-0000-0000-000000000003',
  'Mathematiques',
  'nombres_calcul',
  'math_proportionnel_ou_non',
  'Proportionnel ou non ? — Distinguer les situations',
  'Intermediaire',
  'qcm',
  'Parmi ces tableaux de valeurs, lequel représente une situation de proportionnalité ?',
  'Tableau A : {2→6, 4→12, 5→15}. Tableau B : {1→3, 2→5, 3→7}. Tableau C : {2→4, 3→9, 4→16}. Tableau D : {1→1, 2→4, 3→9}.',
  '[{"id":"a","label":"Tableau A (rapport constant = 3)"},{"id":"b","label":"Tableau B (écart constant = 2)"},{"id":"c","label":"Tableau C"},{"id":"d","label":"Tableau D (carrés parfaits)"}]',
  '{"mode":"single","value":"a"}',
  'Seul le tableau A est proportionnel : 6/2 = 3, 12/4 = 3, 15/5 = 3. Le rapport est CONSTANT (= 3). Tableau B : 3/1 = 3, 5/2 = 2,5, 7/3 ≈ 2,33. Les rapports ne sont pas égaux → pas proportionnel. C''est une relation affine (y = 2x + 1) : l''écart est constant (+2) mais le rapport ne l''est pas. Tableau C : 4/2 = 2, 9/3 = 3, 16/4 = 4. Rapports différents → pas proportionnel (c''est y = x²). Tableau D : ce sont les carrés (1², 2², 3²) → pas proportionnel. Critère de proportionnalité : le rapport y/x est constant pour toutes les paires (x, y).',
  'Confondre « écart constant » (relation affine, tableau B) et « rapport constant » (proportionnalité, tableau A). La proportionnalité exige un RAPPORT constant, pas un écart constant.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'c0160000-0000-0000-0000-000000000004',
  'Mathematiques',
  'nombres_calcul',
  'math_proportionnel_ou_non',
  'Proportionnel ou non ? — Distinguer les situations',
  'Intermediaire',
  'qcm',
  'Comment reconnaît-on graphiquement une situation de proportionnalité ?',
  NULL,
  '[{"id":"a","label":"Les points sont alignés sur une droite passant par l''origine (0 ; 0)"},{"id":"b","label":"Les points sont alignés sur n''importe quelle droite"},{"id":"c","label":"Les points forment une courbe croissante"},{"id":"d","label":"Les points sont régulièrement espacés"}]',
  '{"mode":"single","value":"a"}',
  'La proportionnalité se traduit graphiquement par des points alignés sur une droite PASSANT PAR L''ORIGINE. La relation y = kx (proportionnalité) est une droite de pente k passant par (0 ; 0). Si la droite ne passe pas par l''origine (ex : y = 2x + 3), c''est une relation affine, pas proportionnelle. Le passage par l''origine signifie « quand x = 0, y = 0 » — ce qui est logique : 0 litre d''essence coûte 0 €, 0 km parcourus en 0 heure, etc. La réponse B (n''importe quelle droite) correspond à une fonction affine, pas proportionnelle. Les réponses C et D ne caractérisent pas la proportionnalité.',
  'Confondre proportionnalité (droite par l''origine) et relation affine (droite quelconque). Une droite qui ne passe pas par (0 ; 0) n''est PAS une relation de proportionnalité.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'c0160000-0000-0000-0000-000000000005',
  'Mathematiques',
  'nombres_calcul',
  'math_proportionnel_ou_non',
  'Proportionnel ou non ? — Distinguer les situations',
  'Intermediaire',
  'reponse_courte',
  'Un forfait téléphonique coûte 15 € par mois + 0,05 € par SMS envoyé. Pour 100 SMS, on paie 20 €. Pour 200 SMS, on paie 25 €. Le coût total est-il proportionnel au nombre de SMS ? (Répondez par oui ou non, et justifiez en un mot.)',
  NULL,
  NULL,
  '{"mode":"text","acceptableAnswers":["non","Non","non car le rapport n''est pas constant","non (relation affine)","non, affine"]}'  ,
  'NON. Vérifions le rapport coût/SMS : 20/100 = 0,20 €/SMS et 25/200 = 0,125 €/SMS. Les rapports sont différents → pas proportionnel. La relation est AFFINE : coût = 15 + 0,05 × nombre de SMS. Le terme fixe (15 €, l''abonnement) empêche la proportionnalité. Si l''abonnement était de 0 € (uniquement un coût par SMS), la relation serait proportionnelle. La distinction proportionnelle/affine est fondamentale : proportionnalité = pas de terme constant (y = kx), affine = avec un terme constant (y = kx + b, b ≠ 0).',
  'Répondre oui parce que « plus de SMS = plus cher ». Le fait que les deux grandeurs augmentent ensemble ne suffit pas — il faut que le RAPPORT soit constant.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'c0160000-0000-0000-0000-000000000006',
  'Mathematiques',
  'nombres_calcul',
  'math_proportionnel_ou_non',
  'Proportionnel ou non ? — Distinguer les situations',
  'Intermediaire',
  'qcm',
  'Pour creuser une tranchée, 4 ouvriers mettent 6 heures. Combien de temps mettront 12 ouvriers (tous au même rythme) ?',
  NULL,
  '[{"id":"a","label":"18 heures (proportionnalité directe : 3 fois plus d''ouvriers = 3 fois plus de temps)"},{"id":"b","label":"2 heures (proportionnalité inverse : 3 fois plus d''ouvriers = 3 fois moins de temps)"},{"id":"c","label":"6 heures (le nombre d''ouvriers ne change rien)"},{"id":"d","label":"24 heures"}]',
  '{"mode":"single","value":"b"}',
  'C''est une situation de proportionnalité INVERSE. Plus il y a d''ouvriers, moins il faut de temps. Le produit ouvriers × temps est constant : 4 × 6 = 24 « ouvriers-heures ». Avec 12 ouvriers : 12 × t = 24, donc t = 24/12 = 2 heures. Vérification : 12 ouvriers × 2 h = 24 ouvriers-heures = 4 ouvriers × 6 h ✓. Dans la proportionnalité inverse, quand une grandeur est multipliée par k, l''autre est divisée par k. Ici : ouvriers ×3, temps ÷3. La proportionnalité inverse est un obstacle majeur au cycle 3 car les élèves appliquent spontanément le modèle « plus... plus... » de la proportionnalité directe.',
  'Appliquer la proportionnalité directe (3 × plus d''ouvriers = 3 × plus de temps = 18 h). C''est l''erreur de ne pas reconnaître la situation inverse.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

INSERT INTO public.exercises (
  id, subject, subdomain, topic_key, topic_label, level,
  exercise_type, instruction, support_text, choices, expected_answer,
  detailed_explanation, common_mistake, validation_status, source, access_tier, is_published
) VALUES (
  'c0160000-0000-0000-0000-000000000007',
  'Mathematiques',
  'nombres_calcul',
  'math_proportionnel_ou_non',
  'Proportionnel ou non ? — Distinguer les situations',
  'Intermediaire',
  'qcm',
  'Un enseignant propose : « Pierre a 8 ans et mesure 1,20 m. Quelle sera sa taille à 16 ans ? » Un élève répond 2,40 m. Quel est le diagnostic ?',
  NULL,
  '[{"id":"a","label":"L''élève applique abusivement la proportionnalité à une situation non proportionnelle (la taille n''est pas proportionnelle à l''âge)"},{"id":"b","label":"L''élève a fait une erreur de calcul"},{"id":"c","label":"L''élève a confondu mètres et centimètres"},{"id":"d","label":"La réponse de l''élève est plausible"}]',
  '{"mode":"single","value":"a"}',
  'L''élève a raisonné : « 16 = 2 × 8, donc taille = 2 × 1,20 = 2,40 m ». C''est un raisonnement proportionnel appliqué à une situation qui N''EST PAS proportionnelle. La taille n''est pas proportionnelle à l''âge : un adulte de 16 ans ne mesure pas 2,40 m ! Cette erreur illustre l''« illusion de linéarité » (De Bock et al.) : la tendance à appliquer le modèle proportionnel à toute situation impliquant deux grandeurs qui varient. C''est l''un des obstacles les plus documentés en didactique des mathématiques. Au CRPE, savoir identifier cette erreur et proposer des contre-exemples est une compétence attendue.',
  'Ne pas identifier l''illusion de linéarité. L''élève ne fait pas une « erreur de calcul » — il applique un modèle (la proportionnalité) à un contexte où il ne s''applique pas.',
  'valide',
  'Génération Claude — Terminologie Éduscol',
  'free',
  true
) ON CONFLICT (id) DO NOTHING;

-- math_puissances_notation (nombres_calcul) : 3 -> 10 questions
INSERT INTO public.exercises (
