) VALUES (
  'f8040000-0000-0000-0000-000000000001', 'Mathematiques', 'nombres_calcul', 'math_puissances_notation', 'Puissances de 10 et notation scientifique', 'Intermediaire',
  'qcm', 'Que vaut 10³ ?', NULL,
